    private final Runnable networkRescanTick = new Runnable() {
        @Override
        public void run() {
            if (!isNetworkRescanActive()) return;
            // 2026-07-15 — Periodic Wi‑Fi/BT scans when menus are closed fight typing latency.
            // Keep live while user is inside Wi‑Fi/BT UI; otherwise wait for input idle.
            boolean wifiUiLive = (themedContextMenu != null && themedContextMenu.isShowing()
                    && isWifiTierMounted())
                    || currentScreenState == STATE_WIFI;
            boolean btUiLive = (themedContextMenu != null && themedContextMenu.isShowing()
                    && isBtTierMounted())
                    || currentScreenState == STATE_BLUETOOTH;
            if (isInputPriorityBusy() && !wifiUiLive && !btUiLive) {
                networkRescanHandler.postDelayed(this, Math.max(1000L, msUntilInputIdle()));
                return;
            }
            if (themedContextMenu != null && themedContextMenu.isShowing()
                    && isWifiTierMounted() && !contextTierConfirmOpen && isWifiContextExpanded()
                    && !wifiConnectInProgress) {
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("branch", "wifiExpandedScan");
                    d.put("inputBusy", isInputPriorityBusy());
                    com.solar.launcher.Debug0f5debLog.log(MainActivity.this,
                            "MainActivity.networkRescanTick", "wifi scan tick", "WIFI-A", d);
                } catch (Exception ignored) {}
                // #endregion
                try {
                    WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
                    if (wm != null && wm.isWifiEnabled()) wm.startScan();
                } catch (Exception ignored) {}
                refreshContextWifiTierImmediate(false, true);
            } else if (themedContextMenu != null && themedContextMenu.isShowing()
                    && isWifiTierMounted() && !contextTierConfirmOpen && !isWifiContextExpanded()
                    && (wifiContextPendingEnable || wifiContextPendingDisable)) {
                refreshContextWifiTierImmediate(false, true);
            } else if (currentScreenState == STATE_WIFI) {
                try {
                    WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
                    if (wm != null && wm.isWifiEnabled()) wm.startScan();
                } catch (Exception ignored) {}
            }
            if (themedContextMenu != null && themedContextMenu.isShowing()
                    && isBtTierMounted() && !contextTierConfirmOpen
                    && isBluetoothContextExpanded()) {
                collectBluetoothDevicesForContext();
                startBtContextDiscoveryIfNeeded();
                refreshContextBluetoothTier(false, false);
            } else if (currentScreenState == STATE_BLUETOOTH) {
                if (!hasActiveBluetoothAudioSink()) {
                    triggerBluetoothDiscovery(false);
                } else {
                    startBluetoothScan(false);
                }
            }
            updateNetworkRescanLoop();
        }
    };

