    private Handler clockHandler = new Handler();
    private Runnable clockTask = new Runnable() {
        @Override
        public void run() {
            // 2026-07-19 — Stem/Mix exclusive: skip heavy title ticks so pads stay snappy.
            if (StemOrMixSession.isActive()) {
                clockHandler.postDelayed(this, 2000);
                return;
            }
            updateStatusBarTitle();
            clockHandler.postDelayed(this, 1000);
        }
    };

    private Handler progressHandler = new Handler();
    private Runnable updateProgressTask = new Runnable() {
        @Override
        public void run() {
            try {
                // 2026-07-19 — Stem/Mix jam owns CPU — pause NP progress redraws.
                if (StemOrMixSession.isActive()) {
                    progressHandler.postDelayed(this, 2000);
                    return;
                }
                // 2026-07-15 — Off-NP + user typing: skip progress thrash; wake after idle.
                // Layman: YouTube search keys beat redrawing a hidden progress bar.
                // Keep live updates on Now Playing / video / active Reach partial.
                if (isInputPriorityBusy()
                        && currentScreenState != STATE_PLAYER
                        && currentScreenState != MediaSuiteHost.STATE_VIDEO_PLAYER
                        && currentScreenState != MediaSuiteHost.STATE_RADIO_FM_PLAYER
                        && !reachPartialPlaybackStarted) {
                    progressHandler.postDelayed(this, Math.max(500L, msUntilInputIdle()));
                    return;
                }
                if (podcastEpisodeLoading) {
                    progressHandler.postDelayed(this, 500);
                    return;
                }
                // 2026-07-18 — Pending scrub catch-up even while decoder is paused buffering.
                // Layman: keep watching download progress after you jump ahead of the buffer.
                if (playerPendingSeekMs >= 0) {
                    maybeCompletePendingAudioSeek();
                }
                if (playback.isPodcastActive() && podcastIjkPlayer != null && podcastIjkPlayer.isPlaying()) {
                    if (playerPendingSeekMs >= 0) {
                        maybeCompletePendingAudioSeek();
                    }
                    if (playerScrubCursorActive) {
                        progressHandler.postDelayed(this, 500);
                        return;
                    }
                    int current = podcastIjkPlayer.getCurrentPosition();
                    lastPodcastPlayPositionMs = current;
                    refreshPodcastTimeUi();
                    if (avrcpTrackInfoWriter != null) {
                        avrcpTrackInfoWriter.tickPlayingPosition(current);
                    }
                    if (!podcastResumeKey.isEmpty()
                            && System.currentTimeMillis() - lastPodcastResumeSaveMs > 5000) {
                        PodcastResumeStore.save(getApplicationContext(), podcastResumeKey, current,
                                podcastResumeDurationForSave());
                        lastPodcastResumeSaveMs = System.currentTimeMillis();
                    }
                    if (podcastGrowingCacheFile != null
                            && (podcastDownloadInProgress || podcastPartialPlaybackStarted)) {
                        int mpDur = podcastIjkPlayer.getDuration();
                        if (mpDur > 0 && current >= mpDur - PODCAST_GROWING_EXTEND_MS) {
                            maybeExtendPodcastGrowingPlayback(playback.podcastIndex(),
                                    podcastLoadGeneration, false);
                        }
                        if (podcastDownloadInProgress && podcastPartialPlaybackStarted) {
                            long now = System.currentTimeMillis();
                            if (now - podcastDownloadLastProgressMs > 15000
                                    && currentScreenState == STATE_PLAYER && !podcastDownloadPaused) {
                                podcastDownloadLastProgressMs = now;
                                maybeRecoverPodcastStream(playback.podcastIndex(), podcastLoadGeneration);
                            }
                        }
                        if (podcastPartialPlaybackStarted && !podcastDownloadInProgress
                                && currentScreenState == STATE_PLAYER && !podcastDownloadPaused) {
                            int bufferedMs = podcastBufferedSeekLimitMs();
                            if (bufferedMs > 0 && current >= bufferedMs - 2500) {
                                maybeRecoverPodcastStream(playback.podcastIndex(), podcastLoadGeneration);
                            }
                        }
                    }
                    progressHandler.postDelayed(this, 500);
                    return;
                }
                // 2026-07-15 — Music-on-IJK progress (software EQ path).
                if (isMusicIjkActive() && musicIjkPlayer.isPlaying()) {
                    if (playerPendingSeekMs >= 0) {
                        maybeCompletePendingAudioSeek();
                    }
                    if (playerScrubCursorActive) {
                        progressHandler.postDelayed(this, 500);
                        return;
                    }
                    int current = musicIjkPlayer.getCurrentPosition();
                    int duration = musicIjkPlayer.getDuration();
                    if (tvPlayerTimeCurrent != null) tvPlayerTimeCurrent.setText(formatTime(current));
                    if (tvPlayerTimeTotal != null && duration > 0) {
                        if (playerPendingSeekMs >= 0) {
                            tvPlayerTimeTotal.setText(getString(R.string.stream_seek_buffering,
                                    formatTime(playerPendingSeekMs)));
                        } else {
                            tvPlayerTimeTotal.setText(formatTime(duration));
                        }
                    }
                    if (playerProgress != null && duration > 0) {
                        int progress = (int) (((float) current / duration) * 100);
                        if (progress > 100) progress = 100;
                        playerProgress.setProgress(progress);
                    }
                    if (avrcpTrackInfoWriter != null) {
                        avrcpTrackInfoWriter.tickPlayingPosition(current);
                    }
                    progressHandler.postDelayed(this, 500);
                    return;
                }
                if (mediaPlayer != null && mediaPlayer.isPlaying()) {
                    if (playerPendingSeekMs >= 0) {
                        maybeCompletePendingAudioSeek();
                    }
                    if (playerScrubCursorActive) {
                        progressHandler.postDelayed(this, 500);
                        return;
                    }
                    int current = mediaPlayer.getCurrentPosition();
                    lastPodcastPlayPositionMs = current;
                    int duration;
                    if (podcastGrowingCacheFile != null && podcastDownloadInProgress) {
                        duration = podcastGrowingDisplayDurationMs();
                        if (duration <= 0) duration = mediaPlayer.getDuration();
                    } else {
                        duration = mediaPlayer.getDuration();
                    }
                    if (duration > 0) {
                        int progress = (int) (((float) current / duration) * 100);
                        if (progress > 100) progress = 100;
                        playerProgress.setProgress(progress);
                        tvPlayerTimeCurrent.setText(formatTime(current));
                        String totalStr = formatTime(duration);
                        if (playback.isPodcastActive() && playbackSpeed != 1.0f) {
                            totalStr = formatTime((int) (duration / playbackSpeed))
                                    + " (" + String.format(java.util.Locale.US, "%.2f", playbackSpeed) + "x)";
                            tvPlayerTimeCurrent.setText(formatTime((int) (current / playbackSpeed)));
                        }
                        tvPlayerTimeTotal.setText(totalStr);
                    }
                    if (avrcpTrackInfoWriter != null) {
                        avrcpTrackInfoWriter.tickPlayingPosition(current);
                    }
                    if (playback.isMusicActive() && lyricsHost != null
                            && npOverlay != null && npOverlay.isLyricsShowing()) {
                        lyricsHost.syncToPositionMs(current);
                    }
                    if (playback.isPodcastActive() && !podcastResumeKey.isEmpty()
                            && System.currentTimeMillis() - lastPodcastResumeSaveMs > 5000) {
                        PodcastResumeStore.save(getApplicationContext(), podcastResumeKey, current,
                                podcastResumeDurationForSave());
                        lastPodcastResumeSaveMs = System.currentTimeMillis();
                    }
                    if (podcastGrowingCacheFile != null
                            && (podcastDownloadInProgress || podcastPartialPlaybackStarted)) {
                        int mpDur = mediaPlayer.getDuration();
                        if (mpDur > 0 && current >= mpDur - PODCAST_GROWING_EXTEND_MS) {
                            maybeExtendPodcastGrowingPlayback(playback.podcastIndex(),
                                    podcastLoadGeneration, false);
                        }
                        if (podcastDownloadInProgress && podcastPartialPlaybackStarted) {
                            long now = System.currentTimeMillis();
                            if (now - podcastDownloadLastProgressMs > 15000
                                    && currentScreenState == STATE_PLAYER && !podcastDownloadPaused) {
                                podcastDownloadLastProgressMs = now;
                                maybeRecoverPodcastStream(playback.podcastIndex(), podcastLoadGeneration);
                            }
                        }
                        if (podcastPartialPlaybackStarted && !podcastDownloadInProgress
                                && currentScreenState == STATE_PLAYER && !podcastDownloadPaused) {
                            int bufferedMs = podcastBufferedSeekLimitMs();
                            if (bufferedMs > 0 && current >= bufferedMs - 2500) {
                                maybeRecoverPodcastStream(playback.podcastIndex(), podcastLoadGeneration);
                            }
                        }
                    }
                    if (reachPartialPlaybackStarted && reachGrowingCacheFile != null) {
                        int displayDur = reachGrowingDisplayDurationMs();
                        if (displayDur > 0) {
                            int progress = Math.min(100, current * 100 / displayDur);
                            playerProgress.setProgress(progress);
                            tvPlayerTimeCurrent.setText(formatTime(current));
                            tvPlayerTimeTotal.setText(formatTime(displayDur));
                        }
                        int edgeMs = reachGrowingDecodeEdgeMs();
                        if (edgeMs > 0 && current >= edgeMs - REACH_GROWING_EXTEND_MS) {
                            // #region agent log
                            try {
                                org.json.JSONObject d = new org.json.JSONObject();
                                d.put("current", current);
                                d.put("edgeMs", edgeMs);
                                d.put("mpDur", mediaPlayer.getDuration());
                                d.put("fileLen", reachGrowingCacheFile.length());
                                d.put("totalBytes", reachGrowingTotalBytes);
                                DebugAgentLog.log(MainActivity.this, "MainActivity.updateProgressTask",
                                        "extend at decode edge", "H-STREAM-A", d);
                            } catch (Exception ignored) {}
                            // #endregion
                            maybeExtendReachGrowingPlayback(false);
                        } else if (reachDownloadInProgress() && !isPausedByHand) {
                            // ponytail: MP3 headers report full length — stall at byte edge without onCompletion.
                            boolean playing = false;
                            try {
                                playing = mediaPlayer.isPlaying();
                            } catch (Exception ignored) {}
                            if (!playing) {
                                maybeExtendReachGrowingPlayback(false);
                            }
                        }
                        refreshReachGrowingBufferUi();
                    }
                } else if (mediaPlayer != null && podcastGrowingCacheFile != null
                        && (podcastDownloadInProgress || podcastPartialPlaybackStarted)) {
                    updatePodcastGrowingTimeUi();
                } else if (mediaPlayer != null && reachPartialPlaybackStarted && reachGrowingCacheFile != null) {
                    updateReachGrowingTimeUi();
                    refreshReachGrowingBufferUi();
                }
            } catch (Exception e) {
            }
            // Quiet path: 500ms. Input-busy off player already returned early above.
            progressHandler.postDelayed(this, 500);
        }
    };

    private Handler volumeHandler = new Handler();
    private Runnable hideVolumeContextTask = new Runnable() {
        @Override
        public void run() {
            if (contextMenuVolumeOnly && themedContextMenu != null && themedContextMenu.isShowing()) {
                dismissThemedContextMenu();
            }
        }
    };

    private BroadcastReceiver systemStatusReceiver = new BroadcastReceiver() {
        @Override
        public void onReceive(Context context, Intent intent) {
            String action = intent.getAction();

            if (Intent.ACTION_SCREEN_OFF.equals(action)) {
                isScreenSleeping = true;
                centerSleepHoldHandled = false;
                clockHandler.removeCallbacks(centerSleepHoldRunnable);
                soulseekScreenSleepArmed = false;
                // 2026-07-15 — Sleep dismisses stuck menus/USB prompt (wake must not leave shells up).
                dismissOverlaysAndUsbPromptForScreenSleep("SCREEN_OFF");
                scheduleWifiSleepOff();
                scheduleSoulseekSharePolicyRefresh();
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("charging", soulseekCharging);
                    d.put("messaging", soulseekMessagingEnabled);
                    d.put("sharing", soulseekSharingEnabled);
                    d.put("clientAlive", soulseekClient != null);
                    DebugSessionLog.log("MainActivity.systemStatusReceiver",
                            "SCREEN_OFF", "H2", d);
                } catch (Exception ignored) {}
                // #endregion
            } else if (Intent.ACTION_SCREEN_ON.equals(action)) {
                isScreenSleeping = false;
                centerSleepHoldHandled = false;
                clockHandler.removeCallbacks(centerSleepHoldRunnable);
                soulseekScreenSleepArmed = false;
                cancelWifiSleepOff();
                maybeRestoreWifiAfterSleepPolicy();
                lastScreenOnTime = System.currentTimeMillis();
                scheduleSoulseekSharePolicyRefresh();
                // #region agent log
                try {
                    DebugSessionLog.log("MainActivity.systemStatusReceiver",
                            "SCREEN_ON", "H2", null);
                } catch (Exception ignored) {}
                // #endregion
            } else if (Intent.ACTION_BATTERY_CHANGED.equals(action)) {
                updateBatteryUi(intent);
            } else if (Intent.ACTION_HEADSET_PLUG.equals(action)) {
                int state = intent.getIntExtra("state", -1);
                if (state == 1) {
                    ivStatusHeadphone.setVisibility(View.VISIBLE);
                    applyThemedStatusIcon(ivStatusHeadphone, "headsetWithMic", "headsetWithoutMic",
                            R.drawable.ic_headphone, 0xFFFFFFFF);
                } else {
                    ivStatusHeadphone.setVisibility(View.GONE);
                }
            } else if (BluetoothAdapter.ACTION_STATE_CHANGED.equals(action)) {
                int state = intent.getIntExtra(BluetoothAdapter.EXTRA_STATE, BluetoothAdapter.ERROR);
                if (state == BluetoothAdapter.STATE_ON) {
                    btContextPendingDisable = false;
                    try {
                        BluetoothAdapter onAdapter = BluetoothAdapter.getDefaultAdapter();
                        if (onAdapter != null && onAdapter.isEnabled()) {
                            btContextPendingEnable = false;
                        }
                    } catch (Exception ignored) {
                        btContextPendingEnable = false;
                    }
                    ivStatusBluetooth.setVisibility(View.VISIBLE);
                    applyThemedStatusIcon(ivStatusBluetooth, "blConnected", null,
                            R.drawable.ic_bluetooth, 0xFF5555FF);
                    ensureA2dpProfile();
                    reconnectLastBluetoothAudio();
                    ensureContextBluetoothListVisibleAfterEnable();
                } else if (state == BluetoothAdapter.STATE_OFF) {
                    btContextPendingEnable = false;
                    btContextPendingDisable = false;
                    ivStatusBluetooth.setVisibility(View.GONE);
                    connectedA2dpAddress = null;
                } else {
                    ivStatusBluetooth.setVisibility(View.GONE);
                    connectedA2dpAddress = null;
                }
                if (currentScreenState == STATE_SETTINGS)
                    buildSettingsUI();
                else if (currentScreenState == STATE_BLUETOOTH)
                    startBluetoothScan();
                if (themedContextMenu != null && themedContextMenu.isShowing()
                        && isBtTierMounted()) {
                    refreshContextBluetoothTier(false, false);
                }
            } else if (WifiManager.WIFI_STATE_CHANGED_ACTION.equals(action)) {
                int state = intent.getIntExtra(WifiManager.EXTRA_WIFI_STATE, WifiManager.WIFI_STATE_UNKNOWN);
                WifiManager wifiMgr = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
                // Silent background wake (NTP/diag): keep icon and menus looking Off.
                final boolean silentMask = SolarSilentWifi.isUiHidden();
                if (state == WifiManager.WIFI_STATE_ENABLED) {
                    wifiContextPendingDisable = false;
                    if (!silentMask && wifiMgr != null && wifiMgr.isWifiEnabled()) {
                        wifiContextPendingEnable = false;
                    }
                    if (silentMask) {
                        if (ivStatusWifi != null) ivStatusWifi.setVisibility(View.GONE);
                    } else {
                        ivStatusWifi.setVisibility(View.VISIBLE);
                        refreshWifiStatusIcon();
                        if (wifiMgr != null) {
                            try {
                                wifiMgr.startScan();
                            } catch (Exception ignored) {}
                        }
                        ensureContextWifiListVisibleAfterEnable();
                    }
                } else if (state == WifiManager.WIFI_STATE_DISABLED) {
                    wifiContextPendingDisable = false;
                    wifiContextPendingEnable = false;
                    cancelWifiContextScanFollowUps();
                    ivStatusWifi.setVisibility(View.GONE);
                } else {
                    if (!silentMask) ivStatusWifi.setVisibility(View.GONE);
                }
                if (!silentMask) {
                    if (currentScreenState == STATE_SETTINGS)
                        scheduleConnectivityGatedMenusRefresh();
                    else if (currentScreenState == STATE_WIFI)
                        startWifiScan();
                }
                onWifiConnectivityChanged();
                if (!silentMask && themedContextMenu != null && themedContextMenu.isShowing()
                        && isWifiTierMounted()) {
                    scheduleContextWifiRefresh(false);
                }
            } else if (WifiManager.RSSI_CHANGED_ACTION.equals(action)
                    || WifiManager.NETWORK_STATE_CHANGED_ACTION.equals(action)) {
                NetworkInfo networkInfo = intent.getParcelableExtra(WifiManager.EXTRA_NETWORK_INFO);
                if (WifiManager.NETWORK_STATE_CHANGED_ACTION.equals(action)) {
                    // #region agent log
                    try {
                        org.json.JSONObject d = new org.json.JSONObject();
                        d.put("connected", networkInfo != null && networkInfo.isConnected());
                        d.put("wifiConnectInProgress", wifiConnectInProgress);
                        d.put("detailedState", networkInfo != null ? String.valueOf(networkInfo.getDetailedState()) : "null");
                        DebugSessionLog.log("MainActivity.broadcastReceiver", "NETWORK_STATE_CHANGED", "H2", d);
                    } catch (Exception ignored) {}
                    // #endregion
                    if (networkInfo != null && networkInfo.isConnected()) {
                        if (currentScreenState == STATE_WIFI && !wifiConnectInProgress)
                            startWifiScan();
                    }
                    onWifiConnectivityChanged();
                    if (themedContextMenu != null && themedContextMenu.isShowing()
                            && shouldRefreshWifiContextUi() && !contextTierConfirmOpen
                            && !wifiConnectInProgress) {
                        scheduleContextWifiRefresh(false);
                    }
                }
                refreshWifiStatusIcon();
            } else if (ConnectivityManager.CONNECTIVITY_ACTION.equals(action)) {
                onWifiConnectivityChanged();
            } else if (BluetoothDevice.ACTION_FOUND.equals(action)) {
                BluetoothDevice device = intent.getParcelableExtra(BluetoothDevice.EXTRA_DEVICE);
                if (device == null) return;
                String deviceAddress = device.getAddress();
                if (deviceAddress != null && !foundBtDevices.contains(deviceAddress)) {
                    foundBtDevices.add(deviceAddress);
                    if (currentScreenState == STATE_BLUETOOTH) {
                        addBluetoothItemToUI(bluetoothDeviceDisplayName(device), device, false, false);
                    } else if (themedContextMenu != null && themedContextMenu.isShowing()
                            && isContextTierActive("bt")) {
                        refreshContextBluetoothTier(false, false);
                    }
                }
            } else if (BluetoothDevice.ACTION_BOND_STATE_CHANGED.equals(action)) {
                BluetoothDevice device = intent.getParcelableExtra(BluetoothDevice.EXTRA_DEVICE);
                if (device == null) return;
                int bondState = intent.getIntExtra(BluetoothDevice.EXTRA_BOND_STATE, BluetoothDevice.ERROR);
                int bondReason = intent.getIntExtra("android.bluetooth.device.extra.REASON", -1);
                android.util.Log.d("SolarBT", "BOND_STATE_CHANGED addr=" + device.getAddress()
                        + " state=" + bondState + " reason=" + bondReason);
                if (bondState == BluetoothDevice.BOND_BONDED) {
                    prefs.edit().putString(PREF_LAST_BT_AUDIO, device.getAddress()).apply();
                    connectBluetoothAudio(device, true);
                }
                // Stale link key: remote forgot Y1 — retry bond on AUTH_FAILED during reconnect.
                if (bondState == BluetoothDevice.BOND_NONE
                        && bondReason == 1 /* AUTH_FAILED */
                        && pairingDeviceAddress == null
                        && btConnectingAddress != null
                        && btConnectingAddress.equals(device.getAddress())) {
                    android.util.Log.d("SolarBT", "stale link key on " + device.getAddress() + " — retrying bond");
                    endBtConnect();
                    pairingDeviceAddress = device.getAddress();
                    beginBtConnect(device);
                    if (!createBluetoothBond(device)) {
                        pairingDeviceAddress = null;
                        endBtConnect();
                    }
                }
                if (currentScreenState == STATE_BLUETOOTH) {
                    if (bondState == BluetoothDevice.BOND_BONDED) {
                        Toast.makeText(MainActivity.this, getString(R.string.toast_paired, device.getName()), Toast.LENGTH_SHORT).show();
                        pairingDeviceAddress = null;
                        // Skip discovery restart while A2DP connect is in-flight (MT6572).
                        if (pendingA2dpDevice == null && connectedA2dpAddress == null) {
                            startBluetoothScan();
                        }
                    } else if (bondState == BluetoothDevice.BOND_NONE
                            && pairingDeviceAddress != null
                            && pairingDeviceAddress.equals(device.getAddress())) {
                        Toast.makeText(MainActivity.this, getString(R.string.toast_pairing_failed), Toast.LENGTH_SHORT).show();
                        pairingDeviceAddress = null;
                        endBtConnect();
                    }
                }
            } else if (BluetoothDevice.ACTION_PAIRING_REQUEST.equals(action)) {
                BluetoothDevice device = intent.getParcelableExtra(BluetoothDevice.EXTRA_DEVICE);
                if (device != null) {
                    int variant = intent.getIntExtra(BluetoothDevice.EXTRA_PAIRING_VARIANT, BluetoothDevice.ERROR);
                    android.util.Log.d("SolarBT", "PAIRING_REQUEST addr=" + device.getAddress()
                            + " variant=" + variant);
                    boolean handled = handleBluetoothPairingRequest(device, variant);
                    android.util.Log.d("SolarBT", "PAIRING_REQUEST handled=" + handled);
                    if (handled) {
                        abortBroadcast();
                    }
                }
            } else if (BluetoothA2dp.ACTION_CONNECTION_STATE_CHANGED.equals(action)) {
                BluetoothDevice device = intent.getParcelableExtra(BluetoothDevice.EXTRA_DEVICE);
                int state = intent.getIntExtra(BluetoothProfile.EXTRA_STATE, BluetoothProfile.STATE_DISCONNECTED);
                if (device != null && state == BluetoothProfile.STATE_CONNECTED) {
                    connectedA2dpAddress = device.getAddress();
                    endBtConnect();
                    prefs.edit().putString(PREF_LAST_BT_AUDIO, device.getAddress()).apply();
                    BluetoothAudioRepair.rememberLastAudioDevice(MainActivity.this, device);
                    cancelBluetoothDiscoveryIfActive();
                    if (avrcpTrackInfoWriter != null) avrcpTrackInfoWriter.ensureReady();
                    kickY1BridgeMediaService();
                    routeAudioToBluetoothA2dp();
                    BluetoothAudioRepair.requestRepair(MainActivity.this, device);
                    syncAvrcpTrackInfo(true);
                    if (userInitiatedA2dpConnect) {
                        userInitiatedA2dpConnect = false;
                        resumeBluetoothAudioPlayback();
                    }
                    // ponytail: Samsung TVs miss playstate if only metadata was sent before AVRCP ready.
                    new Handler().postDelayed(new Runnable() {
                        @Override public void run() {
                            syncAvrcpTrackInfo(false);
                        }
                    }, 600);
                    Toast.makeText(MainActivity.this, getString(R.string.toast_audio_connected, device.getName()), Toast.LENGTH_SHORT).show();
                } else if (device != null && state == BluetoothProfile.STATE_DISCONNECTED) {
                    if (device.getAddress().equals(connectedA2dpAddress)) {
                        connectedA2dpAddress = null;
                    }
                    if (btConnectingAddress != null
                            && btConnectingAddress.equals(device.getAddress())) {
                        endBtConnect();
                    }
                } else if (device != null && state == BluetoothProfile.STATE_CONNECTING) {
                    refreshBtConnectUi();
                }
                if (themedContextMenu != null && themedContextMenu.isShowing()
                        && isBtTierMounted()) {
                    refreshContextBluetoothTier(false, false);
                }
                if (currentScreenState == STATE_BLUETOOTH) startBluetoothScan();
            } else if (BluetoothAdapter.ACTION_DISCOVERY_FINISHED.equals(action)) {
                updateStatusBarTitle();
                if (themedContextMenu != null && themedContextMenu.isShowing()
                        && isContextTierActive("bt")) {
                    refreshContextBluetoothTier(false, false);
                }
            } else if (WifiManager.SCAN_RESULTS_AVAILABLE_ACTION.equals(action)) {
                WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
                if (wm != null) {
                    List<ScanResult> results = wm.getScanResults();
                    if (!wifiConnectInProgress) {
                        updateWifiUI(results);
                    }
                    if (themedContextMenu != null && themedContextMenu.isShowing()
                            && shouldRefreshWifiContextUi() && !contextTierConfirmOpen
                            && !wifiConnectInProgress) {
                        collectWifiNetworksFromScan();
                        scheduleContextWifiScanDebounce();
                    }
                }
                updateStatusBarTitle();
            }
            // 🚀 [여기에 추가!] 시스템 미디어 스캐너 감지 센서
            else if (Intent.ACTION_MEDIA_SCANNER_STARTED.equals(action)) {
                isMediaScanning = true;
            } else if (Intent.ACTION_MEDIA_SCANNER_FINISHED.equals(action)) {
                isMediaScanning = false;

            } else if (Intent.ACTION_MEDIA_MOUNTED.equals(action)) {
                // 2026-07-17 — UMS disable remounts volumes; full theme+library work right after
                // unplug froze the UI for new users. Defer when we just left disk mode.
                if (shouldDeferPostUmsStorageWork()) {
                    scheduleDeferredPostUmsStorageMount();
                } else {
                    reloadThemeAfterStorageReady();
                    // ponytail: remount alone doesn't rescan — only ingest paths not yet in SQLite.
                    refreshLibraryAfterStorageMount();
                }
            }
        }
    };

    private void reloadThemeAfterStorageReady() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                // 2026-07-17 — MicroSD mount: async 1:1 mirror, then load from internal store.
                ThemeManager.ensureThemesRootReady(MainActivity.this);
                ThemeManager.scheduleThemeLibrarySync(MainActivity.this, true);
                ThemeManager.ensureBundledDefault(MainActivity.this);
                ActiveThemeEngine.loadThemes(MainActivity.this);
                if (!ActiveThemeEngine.isJjMode()) {
                    String savedPath = prefs != null ? prefs.getString("app_theme_path", null) : null;
                    String savedFolder = prefs != null ? prefs.getString("app_theme_folder", null) : null;
                    if (savedPath != null || savedFolder != null) {
                        ThemeManager.restoreSavedThemeFromPrefs(MainActivity.this);
                    }
                    ThemeManager.ensureActiveThemeOrFallback(MainActivity.this);
                    ThemeManager.cacheActiveTheme(MainActivity.this);
                }
                runOnUiThreadSafe(new Runnable() {
                    @Override
                    public void run() {
                        if (isFinishing()) return;
                        applyThemeToMainMenu();
                        scheduleRebuildHomeMenuIfVisible();
                    }
                });
            }
        }, "ThemeStorageReady").start();
    }

    private void rebuildHomeMenuIfVisible() {
        if (currentScreenState == STATE_MENU && layoutMainMenu != null
                && layoutMainMenu.getVisibility() == View.VISIBLE) {
            buildHomeMenu();
        }
    }

    /** Coalesce rapid home menu rebuilds from connectivity/theme callbacks. */
    private void scheduleRebuildHomeMenuIfVisible() {
        clockHandler.removeCallbacks(homeMenuRebuildRunnable);
        // 2026-07-15 — Don't rebuild home under the wheel; wait for input idle.
        long delay = Math.max(100L, msUntilInputIdle());
        clockHandler.postDelayed(homeMenuRebuildRunnable, delay);
    }

    /** Asset-only theme for first paint — full SD scan/copy deferred off onCreate. */
    private void bootstrapThemeFast() {
        ThemeManager.ensureFastStartupTheme(this);
    }

    /** ponytail: register receivers, library scan, and full theme bootstrap after home is visible. */
    private void scheduleDeferredColdStartWork() {
        Runnable work = new Runnable() {
            @Override
            public void run() {
                registerDeferredSystemReceivers();
                triggerAutoReconnect();
                if (consumePendingAlbumArtCacheRebuild()) {
                    if (!customLibrary.isEmpty()) {
                        scheduleAlbumArtCacheRebuild(false);
                    } else if (!libraryScanRunning && !isUsbMassStorageUiLocked()) {
                        startLibraryScan(false);
                    }
                } else if (customLibrary.isEmpty() && !libraryScanRunning && !isUsbMassStorageUiLocked()) {
                    startLibraryScan(false);
                }
            }
        };
        long delayMs = 250L;
        if (layoutMainMenu != null) {
            layoutMainMenu.postDelayed(work, delayMs);
        } else {
            clockHandler.postDelayed(work, delayMs);
        }
        new Thread(new Runnable() {
            @Override
            public void run() {
                waitForAppThemeBootstrapThenRefreshUi();
            }
        }, "ThemeUiRefresh").start();
    }

    /** 2026-07-05 — UI-only theme refresh; Application bootstrap owns heavy I/O. */
    private void waitForAppThemeBootstrapThenRefreshUi() {
        while (!ThemeManager.isAppThemeBootstrapComplete() && !isFinishing()) {
            try {
                Thread.sleep(200L);
            } catch (InterruptedException e) {
                return;
            }
        }
        runOnUiThreadSafe(new Runnable() {
            @Override
            public void run() {
                if (isFinishing()) return;
                ActiveThemeEngine.loadThemes(MainActivity.this);
                ThemeManager.cacheActiveTheme(MainActivity.this);
                ThemeManager.preferInternalCacheForActiveTheme(MainActivity.this);
                applyThemeToMainMenu();
                scheduleRebuildHomeMenuIfVisible();
            }
        });
    }

    private void registerDeferredSystemReceivers() {
        IntentFilter filter = new IntentFilter();
        filter.addAction(Intent.ACTION_MEDIA_SCANNER_STARTED);
        filter.addAction(Intent.ACTION_MEDIA_SCANNER_FINISHED);
        filter.addAction(Intent.ACTION_BATTERY_CHANGED);
        filter.addAction(Intent.ACTION_HEADSET_PLUG);
        filter.addAction(BluetoothAdapter.ACTION_STATE_CHANGED);
        filter.addAction(WifiManager.WIFI_STATE_CHANGED_ACTION);
        filter.addAction(WifiManager.NETWORK_STATE_CHANGED_ACTION);
        filter.addAction(ConnectivityManager.CONNECTIVITY_ACTION);
        filter.addAction(BluetoothDevice.ACTION_FOUND);
        filter.addAction(BluetoothDevice.ACTION_BOND_STATE_CHANGED);
        filter.addAction(BluetoothDevice.ACTION_PAIRING_REQUEST);
        filter.addAction(BluetoothAdapter.ACTION_DISCOVERY_FINISHED);
        filter.addAction(BluetoothA2dp.ACTION_CONNECTION_STATE_CHANGED);
        filter.addAction(WifiManager.SCAN_RESULTS_AVAILABLE_ACTION);
        filter.addAction(WifiManager.RSSI_CHANGED_ACTION);
        filter.addAction(Intent.ACTION_SCREEN_OFF);
        filter.addAction(Intent.ACTION_SCREEN_ON);
        filter.setPriority(IntentFilter.SYSTEM_HIGH_PRIORITY);
        registerReceiver(systemStatusReceiver, filter);

        IntentFilter mediaFilter = new IntentFilter(Intent.ACTION_MEDIA_MOUNTED);
        mediaFilter.addDataScheme("file");
        registerReceiver(systemStatusReceiver, mediaFilter);
        // #region agent log
        try {
            DebugSessionLog.log("registerDeferredSystemReceivers", "receivers registered", "H3", null);
        } catch (Exception ignored) {}
        // #endregion
    }

    /** ponytail: one guard — clear sibling browse layers before any list rebuild. */
    public void resetBrowserListHost() {
        if (scrollViewBrowser != null) scrollViewBrowser.setVisibility(View.VISIBLE);
        if (listVirtualSongs != null) {
            listVirtualSongs.setVisibility(View.GONE);
            listVirtualSongs.setAdapter(null);
        }
        if (containerBrowserItems != null) containerBrowserItems.removeAllViews();
    }

    /** Show virtualized song list or scroll browse — enforces mutual exclusion. */
    public void showVirtualSongList(boolean virtual) {
        if (scrollViewBrowser != null) {
            scrollViewBrowser.setVisibility(virtual ? View.GONE : View.VISIBLE);
        }
        if (listVirtualSongs != null) {
            listVirtualSongs.setVisibility(virtual ? View.VISIBLE : View.GONE);
        }
    }

