    /**
     * 2026-07-15 — Letter bubble only on alpha/numeric name-sorted catalogs (see FastScrollLetterPolicy).
     */
    private boolean isFastScrollLetterEligible() {
        boolean themeGallery = currentScreenState == STATE_SETTINGS && isThemeListActive();
        boolean serverBrowse = currentScreenState == STATE_NAVIDROME
                || currentScreenState == STATE_PLEX
                || currentScreenState == STATE_JELLYFIN
                || currentScreenState == STATE_DEEZER;
        boolean mediaBrowse = currentScreenState == STATE_PODCASTS
                || currentScreenState == MediaSuiteHost.STATE_VIDEOS
                || currentScreenState == MediaSuiteHost.STATE_VIDEO_HUB;
        int artistSort = libraryBrowsePrefs != null
                ? libraryBrowsePrefs.artistSort() : LibraryBrowsePrefs.ARTIST_SORT_NAME;
        int songSort = libraryBrowsePrefs != null
                ? libraryBrowsePrefs.songSort() : LibraryBrowsePrefs.SONG_SORT_TITLE;
        int albumRackSort = libraryBrowsePrefs != null
                ? libraryBrowsePrefs.albumRackSort() : LibraryBrowsePrefs.ALBUM_RACK_SORT_TITLE;
        int albumSongSort = libraryBrowsePrefs != null
                ? libraryBrowsePrefs.albumSongSort() : LibraryBrowsePrefs.SONG_SORT_ALBUM;
        return FastScrollLetterPolicy.isEligible(
                currentScreenState, currentBrowserMode, virtualQueryType,
                artistSort, songSort, albumRackSort, albumSongSort,
                themeGallery, serverBrowse, mediaBrowse);
    }

    private void showFastScrollLetter(String rawText) {
        // 2026-07-15 — Gate + selectitem chrome. Was always-on solid focused fill @ 50sp.
        if (!isFastScrollLetterEligible()) {
            hideFastScrollLetter();
            return;
        }
        if (tvFastScrollLetter == null || rawText == null) {
            hideFastScrollLetter();
            return;
        }
        String clean = rawText.replace("📁 ", "").replace("👤 ", "")
                .replace("💿 ", "").replace("🎵 ", "")
                .replace("📦 [INSTALL] ", "").trim();
        if (clean.isEmpty()) {
            hideFastScrollLetter();
            return;
        }
        String firstChar = WheelSectionIndex.normalize(clean);
        if (firstChar.isEmpty()) firstChar = "#";
        tvFastScrollLetter.setText(firstChar);
        int boxW = tvFastScrollLetter.getLayoutParams() != null
                ? tvFastScrollLetter.getLayoutParams().width : 0;
        int boxH = tvFastScrollLetter.getLayoutParams() != null
                ? tvFastScrollLetter.getLayoutParams().height : 0;
        if (boxW <= 0) boxW = (int) (56 * getResources().getDisplayMetrics().density);
        if (boxH <= 0) boxH = boxW;
        android.graphics.drawable.Drawable selBg = ThemeManager.getItemRowBackgroundScaled(
                getResources(), true, boxW, boxH);
        if (selBg != null) {
            tvFastScrollLetter.setBackground(selBg);
        } else {
            // Fallback: old solid selection fill when theme has no selectitem PNG.
            int bgColor = ThemeManager.getListButtonFocusedBg();
            tvFastScrollLetter.setBackgroundColor((bgColor & 0xFFFFFF) | 0xDD000000);
        }
        int textColor = ThemeManager.getItemTextColorSelected();
        if (ThemeManager.getCustomFont() != null) {
            tvFastScrollLetter.setTypeface(ThemeManager.getCustomFont());
        }
        ThemeManager.applyThemedTextStyle(tvFastScrollLetter, textColor);
        tvFastScrollLetter.setVisibility(View.VISIBLE);
        if (android.os.SystemClock.elapsedRealtimeNanos() >= suppressOverlayHapticUntilNanos) {
            wheelDetentFeedback(true);
        }
        fastScrollHandler.removeCallbacks(hideFastScrollTask);
        fastScrollHandler.postDelayed(hideFastScrollTask, 800);
    }

    private void setTextIfChanged(android.widget.TextView view, CharSequence text) {
        if (view != null && !android.text.TextUtils.equals(view.getText(), text)) {
            view.setText(text);
        }
    }

    private void wheelDetentFeedback(boolean section) {
        long now = android.os.SystemClock.elapsedRealtimeNanos();
        long throttle = section ? 35_000_000L : 30_000_000L;
        if (now - lastWheelHapticNanos < throttle) return;
        lastWheelHapticNanos = now;
        vibrateCached(section ? 25 : 10);
    }

    private void vibrateCached(long durationMs) {
        if (!isVibrationEnabled || cachedVibrator == null) return;
        try {
            cachedVibrator.vibrate(durationMs);
        } catch (Exception ignored) {}
    }

    private void ensureWheelSectionIndex() {
        android.widget.ListAdapter adapter =
                listVirtualSongs != null ? listVirtualSongs.getAdapter() : null;
        if (adapter == wheelIndexedAdapter) return;
        if (wheelIndexedAdapter != null) {
            try { wheelIndexedAdapter.unregisterDataSetObserver(wheelDataObserver); } catch (Exception ignored) {}
        }
        wheelIndexedAdapter = adapter;
        wheelSectionIndex = WheelSectionIndex.EMPTY;
        if (adapter != null) {
            try { adapter.registerDataSetObserver(wheelDataObserver); } catch (Exception ignored) {}
        }
        scheduleWheelSectionIndex();
    }

    private void scheduleWheelSectionIndex() {
        final android.widget.ListAdapter adapter = wheelIndexedAdapter;
        final int generation = ++wheelIndexGeneration;
        if (adapter == null) {
            wheelSectionIndex = WheelSectionIndex.EMPTY;
            return;
        }
        final int count = adapter.getCount();
        final String[] labels = new String[count];
        boolean useBrowseLabels = currentScrollIndexList != null
                && currentScrollIndexList.size() == count;
        for (int i = 0; i < count; i++) {
            if (useBrowseLabels) {
                labels[i] = currentScrollIndexList.get(i);
                continue;
            }
            Object item = adapter.getItem(i);
            if (item instanceof SongItem) {
                labels[i] = ((SongItem) item).title;
            } else {
                labels[i] = item != null ? item.toString() : "";
            }
        }
        WHEEL_IO.execute(new Runnable() {
            @Override public void run() {
                final WheelSectionIndex built = WheelSectionIndex.build(labels);
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (generation == wheelIndexGeneration && adapter == wheelIndexedAdapter
                                && adapter.getCount() == built.itemCount()) {
                            wheelSectionIndex = built;
                        }
                    }
                });
            }
        });
    }

    private int currentWheelPosition() {
        if (listVirtualSongs == null) return 0;
        int position = listVirtualSongs.getSelectedItemPosition();
        if (position != ListView.INVALID_POSITION) return position;
        View focused = getCurrentFocus();
        if (focused != null) {
            position = listVirtualSongs.getPositionForView(focused);
            if (position != ListView.INVALID_POSITION) return position;
        }
        return listVirtualSongs.getFirstVisiblePosition();
    }

    private boolean moveWheelSelection(int targetPosition) {
        if (listVirtualSongs == null) return false;
        android.widget.ListAdapter adapter = listVirtualSongs.getAdapter();
        if (adapter == null || adapter.getCount() == 0) return false;
        int target = Math.max(0, Math.min(adapter.getCount() - 1, targetPosition));
        int current = currentWheelPosition();
        if (target == current) return false;
        String oldLetter = wheelSectionIndex.letterAtPosition(current);
        String newLetter = wheelSectionIndex.letterAtPosition(target);
        // 2026-07-11 — Edge-only iPod/feature-phone scroll; was sticky-Y setSelectionFromTop(anchor)
        // which scrolled the whole list every tick. Reversal: restore sticky-Y anchor path.
        FocusScrollHelper.ensureListPositionVisible(listVirtualSongs, target);
        // 2026-07-16 — Mid-list focus is applied inside FocusScrollHelper; only post fallback
        // when the target row is not yet a child (off-screen jump).
        int first = listVirtualSongs.getFirstVisiblePosition();
        int childIdx = target - first;
        if (childIdx < 0 || childIdx >= listVirtualSongs.getChildCount()) {
            pendingWheelFocusPosition = target;
            pendingWheelFocusRetried = false;
            listVirtualSongs.removeCallbacks(wheelFocusTask);
            listVirtualSongs.post(wheelFocusTask);
        } else {
            pendingWheelFocusPosition = ListView.INVALID_POSITION;
        }
        boolean changed = !android.text.TextUtils.equals(oldLetter, newLetter);
        if (changed) {
            showFastScrollLetter(newLetter);
        } else {
            suppressOverlayHapticUntilNanos =
                    android.os.SystemClock.elapsedRealtimeNanos() + 100_000_000L;
            wheelDetentFeedback(false);
        }
        return true;
    }

    /**
     * 2026-07-16 — Apply coalesced wheel steps to the song/browse ListView.
     * Layman: one jump for a burst of dial clicks so long lists do not feel "behind".
     * Technical: flywheel already sized the step; do not amplify again (double boost caused
     * post-release coast). Section letter jump only when the flywheel asked for it via large n.
     * 2026-07-18 — Frame-drop paint: selection always moves; preview/art deferred via ScrollIdleGate
     * (Rockbox FRAMEDROP). Reversal: restore unconditional preview refresh when n≤1.
     */
    private boolean applyCoalescedListWheelSteps(int signedSteps) {
        if (listVirtualSongs == null || signedSteps == 0) return false;
        if (listVirtualSongs.getVisibility() != View.VISIBLE) return false;
        // Mic lift mid-frame — drop residual only; still apply this signed step if non-zero.
        long nowMs = android.os.SystemClock.uptimeMillis();
        if (micScratchSense != null) {
            micScrollBoost.onFeatures(
                    micScratchSense.volumeLevel(),
                    micScratchSense.hfLevel(),
                    micScratchSense.scratchLevel());
        }
        // Note: shouldDropGhostScroll is never true within LIVE_KEY_MS of a notch.
        ensureWheelSectionIndex();
        int direction = signedSteps > 0 ? 1 : -1;
        int n = Math.abs(signedSteps);
        int current = currentWheelPosition();
        int listCount = 0;
        android.widget.ListAdapter ad = listVirtualSongs.getAdapter();
        if (ad != null) listCount = ad.getCount();
        // iPod-like: on huge libraries, prefer letter section jump when spinning hard.
        boolean hugeLibrary = listCount >= 5000;
        boolean sectionOk = isFastScrollLetterEligible()
                && (n >= ListWheelCoalescer.MAX_STEPS_PER_FLUSH
                || (hugeLibrary && n >= 3)
                || (hugeLibrary && wheelResult.sectionJump));
        int target;
        if (sectionOk) {
            target = wheelSectionIndex.jumpTarget(current, direction);
            if (target < 0 || target == current) {
                // Fall back: multi-row page hop (still one setSelection — O(1) layout).
                int hop = hugeLibrary
                        ? Math.min(n * 3, ListWheelCoalescer.MAX_STEPS_PER_FLUSH * 4)
                        : Math.min(n, ListWheelCoalescer.MAX_STEPS_PER_FLUSH);
                target = current + direction * hop;
            }
        } else {
            // 1:1 with flywheel — one selection move per frame.
            target = current + direction * Math.min(n, ListWheelCoalescer.MAX_STEPS_PER_FLUSH);
        }
        scrollIdleGate.markActivity();
        boolean frameDrop = scrollIdleGate.shouldFrameDropPaint(n, listWheelCoalescer.pendingDepth())
                || hugeLibrary && n > 1;
        boolean moved = moveWheelSelection(target);
        // #region agent log
        if (Debug0f5debLog.ENABLED) {
            try {
                int firstBefore = listVirtualSongs.getFirstVisiblePosition();
                int lastBefore = listVirtualSongs.getLastVisiblePosition();
                boolean offscreenTarget = target < firstBefore || target > lastBefore;
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("steps", signedSteps);
                d.put("n", n);
                d.put("cur", current);
                d.put("target", target);
                d.put("first", firstBefore);
                d.put("last", lastBefore);
                d.put("offscreen", offscreenTarget);
                d.put("moved", moved);
                d.put("frameDrop", frameDrop);
                d.put("pending", listWheelCoalescer.pendingDepth());
                d.put("vel", wheelPhysics.velocity());
                d.put("listCount", listCount);
                Debug0f5debLog.log(this, "MainActivity.applyCoalescedListWheelSteps",
                        "list wheel apply", "H2", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        if (moved) {
            // Skip heavy work during multi-step / frame-drop / huge list spin (keeps 50k fluid).
            if (!frameDrop && n <= 1 && !hugeLibrary) clickFeedback();
            if (!frameDrop) {
                refreshBrowsePreviewFromSelectionIfNeeded();
            }
        }
        return moved;
    }

    /**
     * 2026-07-18 — Dual-pane server browse preview — only when not frame-dropping.
     * Layman: art pane updates when the dial pauses, not on every notch.
     */
    private void refreshBrowsePreviewFromSelectionIfNeeded() {
        // 2026-07-18 — P3: dual-pane cover decode only when not mid-spin.
        if (scrollIdleGate.isSpinning()) {
            deferArtUntilScrollIdle(new Runnable() {
                @Override
                public void run() {
                    refreshBrowsePreviewFromSelectionNow();
                }
            });
            return;
        }
        refreshBrowsePreviewFromSelectionNow();
    }

    /** Apply Navidrome/Plex/Jellyfin dual-pane cover for the focused list row. */
    private void refreshBrowsePreviewFromSelectionNow() {
        if (currentScreenState == STATE_NAVIDROME) {
            refreshNavidromeBrowsePreviewFromSelection();
        } else if (currentScreenState == STATE_PLEX) {
            refreshPlexBrowsePreviewFromSelection();
        } else if (currentScreenState == STATE_JELLYFIN) {
            refreshJellyfinBrowsePreviewFromSelection();
        }
    }

    /**
     * 2026-07-18 — Idle catch-up after wheel spin (ScrollIdleGate).
     * Was: mid-spin previews skipped with no recovery. Now: one preview pass when quiet.
     * 2026-07-18 — Also flush deferred theme/podcast/apps cover loads (P3).
     */
    private void onListWheelScrollIdle() {
        if (listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE) {
            refreshBrowsePreviewFromSelectionIfNeeded();
        }
        if (currentScreenState == STATE_MENU && focusedHomeMenuIndex >= 0) {
            scheduleHomeMenuPreviewUpdate(focusedHomeMenuIndex);
        }
        // 2026-07-19 — Settings preview catch-up after spin (was mid-spin StatFs/icon thrash).
        if (currentScreenState == STATE_SETTINGS && pendingSettingsPreviewKey != null) {
            if (containerSettingsItems != null) {
                containerSettingsItems.removeCallbacks(settingsPreviewApplyRunnable);
                containerSettingsItems.post(settingsPreviewApplyRunnable);
            } else {
                settingsPreviewApplyRunnable.run();
            }
        }
        // 2026-07-19 — Marquee only after pause so spin does not start N marquees.
        enableFocusedRowMarqueeAfterIdle();
        Runnable art = pendingIdleArtRefresh;
        pendingIdleArtRefresh = null;
        if (art != null) {
            try {
                art.run();
            } catch (Throwable ignored) {
            }
        }
        if (isThemeListActive() && themeBrowserFocus >= 0
                && themeBrowserFocus < themeBrowserRows.size()) {
            ThemeBrowser.Row row = themeBrowserRows.get(themeBrowserFocus);
            if (row != null) scheduleThemeRowPreviewNow(row);
        }
    }

    /**
     * 2026-07-19 — Start marquee on the focused row once the dial is quiet.
     * Layman: while spinning, titles stay truncated; when you pause, the focused line scrolls.
     * Technical: re-apply home style / enableMarquee on focused TextView. Reversal: always marquee on focus.
     */
    private void enableFocusedRowMarqueeAfterIdle() {
        if (currentScreenState == STATE_MENU && focusedHomeMenuIndex >= 0) {
            applyHomeMenuRowStyleAt(focusedHomeMenuIndex, true);
            return;
        }
        View foc = getCurrentFocus();
        if (foc instanceof TextView) {
            enableMarquee((TextView) foc);
            foc.setSelected(true);
        }
    }

    /**
     * 2026-07-18 — Queue cover/preview work until the dial is quiet (Rockbox talk delay).
     * Layman: spinning only moves the highlight; art waits for a pause.
     * Technical: stash Runnable; run now if not spinning, else onScrollIdle.
     * Reversal: call refresh runnables directly from focus handlers.
     */
    private void deferArtUntilScrollIdle(final Runnable refresh) {
        if (refresh == null) return;
        pendingIdleArtRefresh = refresh;
        scrollIdleGate.markActivity();
        ensureScrollIdleGateListener();
        if (!scrollIdleGate.isSpinning()) {
            pendingIdleArtRefresh = null;
            try {
                refresh.run();
            } catch (Throwable ignored) {
            }
        }
    }

    /** 2026-07-18 — Last live list-wheel direction (±1); reverse drops queued same-dir catch-up. */
    private int listWheelLiveDir;
    /** EventTime epoch after reverse — older same-queue ticks from the old direction are dropped. */
    private long listWheelReverseEpochEventTime;

    /**
     * 2026-07-17 — Keyevents that sat in the queue after the finger stopped.
     * Layman: the dial already stopped but Android still delivers old ticks — treat as dead.
     */
    private static final long WHEEL_STALE_EVENT_MS = 120L;

    private boolean isStaleWheelEvent(KeyEvent event) {
        if (event == null) return false;
        long age = android.os.SystemClock.uptimeMillis() - event.getEventTime();
        return age > WHEEL_STALE_EVENT_MS;
    }

    /**
     * 2026-07-18 — True when this KEY is from before a reverse we already honored.
     * Layman: after you turn back, leftover “still scrolling down” ticks in the queue are junk.
     * Technical: eventTime &lt; reverse epoch and direction still matches the pre-reverse dir.
     */
    private boolean isPreReverseWheelCatchup(KeyEvent event, int direction) {
        if (event == null || direction == 0 || listWheelReverseEpochEventTime <= 0L) {
            return false;
        }
        if (event.getEventTime() >= listWheelReverseEpochEventTime) return false;
        // Drop old-direction leftovers only (new direction after epoch is live).
        return listWheelLiveDir != 0 && direction != listWheelLiveDir;
    }

    /**
     * 2026-07-18 — Note CW↔CCW flip: clear coalesce backlog + flywheel; stamp event epoch.
     * Was: reverse only netted pendingSteps (slow drain). Now: interrupt immediately.
     */
    private void noteListWheelDirection(int direction, KeyEvent event) {
        if (direction == 0) return;
        if (listWheelLiveDir != 0 && direction != listWheelLiveDir) {
            dropListWheelBacklogOnly();
            wheelPhysics.reset();
            listWheelCoalescer.armImmediateFlush();
            if (event != null) {
                listWheelReverseEpochEventTime = event.getEventTime();
            } else {
                listWheelReverseEpochEventTime = android.os.SystemClock.uptimeMillis();
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("from", listWheelLiveDir);
                d.put("to", direction);
                d.put("epoch", listWheelReverseEpochEventTime);
                Debug0f5debLog.probe("MainActivity.noteListWheelDirection", "list reverse",
                        "H-rev", d);
            } catch (Exception ignored) {}
            // #endregion
        }
        listWheelLiveDir = direction;
    }

    /**
     * Drop coalescer backlog only — live KEY notches must still move the UI.
     * Mic quiet after a scrape uses this; does not eat the current detent.
     */
    private void dropListWheelBacklogOnly() {
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("pending", listWheelCoalescer.pendingDepth());
            d.put("vel", wheelPhysics.velocity());
            d.put("pos", currentWheelPosition());
            d.put("keepsFlywheel", true);
            DebugFa8512Log.log(this, "MainActivity.dropListWheelBacklogOnly",
                    "drop backlog keep flywheel", "H4", d);
        } catch (Exception ignored) {}
        // #endregion
        listWheelCoalescer.dropPending();
        wheelPhysics.setMicBoost(1f);
        micScrollBoost.clearContactSpin();
        clockHandler.removeCallbacks(micGhostScrollWatch);
    }

    /**
     * Full stop (stale queue / leave list) — reset flywheel state.
     */
    private void hardStopListWheel() {
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("pending", listWheelCoalescer.pendingDepth());
            d.put("vel", wheelPhysics.velocity());
            d.put("pos", listVirtualSongs != null ? currentWheelPosition() : -1);
            Debug0f5debLog.log(this, "MainActivity.hardStopListWheel",
                    "hard stop wheel", "H3", d);
        } catch (Exception ignored) {}
        // #endregion
        listWheelCoalescer.dropPending();
        scrollIdleGate.reset();
        pendingIdleArtRefresh = null;
        wheelPhysics.reset();
        wheelPhysics.setMicBoost(1f);
        micScrollBoost.reset();
        clockHandler.removeCallbacks(micGhostScrollWatch);
        listWheelLiveDir = 0;
        listWheelReverseEpochEventTime = 0L;
    }

    /** 2026-07-16 — Wire coalescer to listVirtualSongs after adapter attach. */
    private void bindListWheelCoalescer() {
        if (listVirtualSongs == null) return;
        listWheelCoalescer.setLiveGate(listWheelLiveGate);
        ensureScrollIdleGateListener();
        listWheelCoalescer.bind(listVirtualSongs, new ListWheelCoalescer.Apply() {
            @Override
            public boolean applySteps(int signedSteps) {
                return applyCoalescedListWheelSteps(signedSteps);
            }
        });
    }

    /**
     * 2026-07-16 — Attach song adapter + subtitle cache + wheel coalescer.
     * Layman: one place so every “open this song list” path stays fast under the dial.
     */
    private void setSongListAdapter(List<SongItem> targetSongs, boolean numbered) {
        rebuildSongListSubtitleCache(targetSongs);
        SongListAdapter adapter = new SongListAdapter(targetSongs, numbered);
        listVirtualSongs.setAdapter(adapter);
        bindListWheelCoalescer();
        ensureWheelSectionIndex();
    }

    private android.graphics.drawable.StateListDrawable getY1RowStateBackground(
            int widthPx, int rowKind) {
        android.graphics.drawable.StateListDrawable states =
                new android.graphics.drawable.StateListDrawable();
        android.graphics.drawable.Drawable sel = getY1RowBackground(true, widthPx, rowKind);
        android.graphics.drawable.Drawable norm = getY1RowBackground(false, widthPx, rowKind);
        states.addState(new int[] { android.R.attr.state_focused }, sel);
        states.addState(new int[] { android.R.attr.state_pressed }, sel);
        states.addState(new int[] {}, norm);
        return states;
    }

    private void refreshBatteryStatus() {
        try {
            Intent intent = registerReceiver(null, new IntentFilter(Intent.ACTION_BATTERY_CHANGED));
            if (intent != null) {
                updateBatteryUi(intent);
            } else if (cachedBatteryLevel > 0 && tvStatusBattery != null) {
                setTextIfChanged(tvStatusBattery, cachedBatteryLevel + "%");
            }
        } catch (Exception ignored) {}
    }

    private void updateBatteryUi(Intent intent) {
        if (tvStatusBattery == null) return;
        int level = intent.getIntExtra(BatteryManager.EXTRA_LEVEL, -1);
        int scale = intent.getIntExtra(BatteryManager.EXTRA_SCALE, -1);
        int status = intent.getIntExtra(BatteryManager.EXTRA_STATUS, -1);
        boolean isCharging = (status == BatteryManager.BATTERY_STATUS_CHARGING
                || status == BatteryManager.BATTERY_STATUS_FULL);
        int batteryPct = scale > 0 ? (int) ((level / (float) scale) * 100) : 0;
        cachedBatteryLevel = batteryPct;
        cachedBatteryCharging = isCharging;
        setTextIfChanged(tvStatusBattery, batteryPct + "%");

        int idx = ThemeManager.batteryLevelIndex(batteryPct);
        Bitmap themedBattery = ThemeManager.getBatteryIcon(idx, isCharging);
        if (themedBattery != null && ivStatusBatteryThemed != null) {
            int batH = y1BatteryIconHeightPx > 0 ? y1BatteryIconHeightPx
                    : (int) (20 * getResources().getDisplayMetrics().density);
            int bw = (int) (themedBattery.getWidth() * (batH / (float) themedBattery.getHeight()));
            if (bw < 1) bw = 1;
            Bitmap scaled = Bitmap.createScaledBitmap(themedBattery, bw, batH, true);
            ivStatusBatteryThemed.setImageBitmap(scaled);
            ivStatusBatteryThemed.setVisibility(View.VISIBLE);
            tvStatusBattery.setVisibility(View.VISIBLE);
            ThemeManager.applyThemedTextStyle(tvStatusBattery, ThemeManager.getStatusBarTextColor());
            if (batteryIconView != null) batteryIconView.setVisibility(View.GONE);
        } else {
            if (ivStatusBatteryThemed != null) ivStatusBatteryThemed.setVisibility(View.GONE);
            tvStatusBattery.setVisibility(View.VISIBLE);
            ThemeManager.applyThemedTextStyle(tvStatusBattery, ThemeManager.getStatusBarTextColor());
            if (batteryIconView != null) {
                batteryIconView.setVisibility(View.VISIBLE);
                batteryIconView.setBatteryLevel(batteryPct, isCharging);
            }
        }
        if (widgetBatteryView != null) {
            widgetBatteryView.setBatteryLevel(batteryPct, isCharging);
        }
        if (soulseekCharging != isCharging) {
            soulseekCharging = isCharging;
            if (isCharging) {
                // 2026-07-18 — Charging ≠ USB host; do not open USB Connection / storage enable.
                // Layman: battery bolt on does not mean a computer is asking for disk mode.
                // Tech: host dialog stays on USB_STATE host path; wall USB still charges.
                // Reversal: restore maybeShowUsbConnectionPrompt(intent) under isCharging.
                SolarDeveloperOutbox.flushIfDue(this, prefs, soulseekClient,
                        hasInternetConnection(), true);
                cancelWifiSleepOff();
                maybeRestoreWifiAfterSleepPolicy();
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("isCharging", true);
                    d.put("plugged", intent.getIntExtra(BatteryManager.EXTRA_PLUGGED, -1));
                    d.put("skippedUsbPrompt", true);
                    Debug0f5debLog.log(this, "MainActivity.updateBatteryUi",
                            "charging started — no USB storage prompt", "H5", d);
                } catch (Exception ignored) {}
                // #endregion
            } else {
                // 2026-07-18 — Discharging: treat as likely USB host gone; unlock UMS usage blocks.
                // Layman: when the charge icon goes away, stop blocking the player for USB disk mode.
                // Tech: BATTERY_CHANGED !charging → same UI clear as USB_STATE disconnect + UMS teardown.
                // Reversal: only unlock via Y1UsbFocusHelper confirm-unplug (ignore charge-loss).
                // #region agent log
                try {
                    int pluggedDbg = intent.getIntExtra(BatteryManager.EXTRA_PLUGGED, -1);
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("isCharging", false);
                    d.put("plugged", pluggedDbg);
                    d.put("batStatus", status);
                    d.put("usbMassStorageLocked", usbMassStorageLocked);
                    d.put("screenState", currentScreenState);
                    d.put("uiLocked", isUsbMassStorageUiLocked());
                    d.put("userSession", UsbMassStorageController.isUserSessionActive());
                    d.put("kernelUms", UsbMassStorageController.isKernelMassStorageMode());
                    d.put("exported", UsbMassStorageController.isMassStorageExported());
                    d.put("cachedUmsExported", cachedUmsExported);
                    Debug0f5debLog.log(this, "MainActivity.updateBatteryUi",
                            "charge lost — USB lock snapshot", "H1,H2,H3", d);
                } catch (Exception ignored) {}
                // #endregion
                onChargingLostClearUsbStorageBlocks();
                if (isScreenSleeping) {
                    scheduleWifiSleepOff();
                }
            }
            scheduleSoulseekSharePolicyRefresh();
        }
    }

    private void applyMenuPanelBackground(FrameLayout host, int widthPx, int heightPx, int defaultHeightPx) {
        if (host == null) return;
        // ponytail: home menu rows carry their own chrome — transparent host shows theme wallpaper.
        if (host == menuListHost) {
            host.setBackgroundColor(0x00000000);
            if (menuScroll != null) menuScroll.setBackgroundColor(0x00000000);
            if (containerHomeMenuItems != null) containerHomeMenuItems.setBackgroundColor(0x00000000);
            return;
        }
        int h = heightPx > 0 ? heightPx : defaultHeightPx;
        int w = widthPx > 0 ? widthPx : (int) getResources().getDimension(R.dimen.y1_menu_width);
        android.graphics.drawable.Drawable panel =
                ThemeManager.getMenuPanelBackgroundScaled(getResources(), w, h);
        if (panel != null) {
            host.setBackground(panel);
        } else {
            host.setBackgroundColor(0x00000000);
        }
    }

    /** [arrowW, arrowH, labelRightMargin] from scaled themed arrow bitmap */
    private int[] y1ArrowLayout(Bitmap arrowBmp) {
        return y1ArrowLayout(arrowBmp, 0);
    }

    private int[] y1ArrowLayout(Bitmap arrowBmp, int extraMarginEndPx) {
        int marginEnd = (int) getResources().getDimension(R.dimen.y1_arrow_margin_end) + extraMarginEndPx;
        if (arrowBmp == null) {
            int fallback = (int) (12 * getResources().getDisplayMetrics().density);
            return new int[] { fallback, y1RowHeightPx, fallback + marginEnd };
        }
        int w = arrowBmp.getWidth();
        int h = arrowBmp.getHeight();
        if (h > y1RowHeightPx) {
            float scale = y1RowHeightPx / (float) h;
            w = Math.max(1, (int) (w * scale));
            h = y1RowHeightPx;
        }
        return new int[] { w, h, w + marginEnd };
    }

    private void enableMarquee(TextView tv) {
        if (tv == null) return;
        tv.setSingleLine(true);
        tv.setEllipsize(TextUtils.TruncateAt.MARQUEE);
        tv.setMarqueeRepeatLimit(-1);
        tv.setHorizontallyScrolling(true);
    }

    /** Status bar context title — marquee when long (Solar Development, thread peers, etc.). */
    private void applyStatusBarTitleMarquee() {
        if (tvStatusClock == null) return;
        enableMarquee(tvStatusClock);
        // Toggle selected so API 17 restarts horizontal scroll after each title change.
        tvStatusClock.setSelected(false);
        tvStatusClock.setSelected(true);
    }

    private void stopSettingsPreviewVerticalMarquee() {
        if (settingsPreviewScrollHandler != null && settingsPreviewScrollRunnable != null) {
            settingsPreviewScrollHandler.removeCallbacks(settingsPreviewScrollRunnable);
            settingsPreviewScrollRunnable = null;
        }
        if (settingsPreviewStateScroll != null) {
            settingsPreviewStateScroll.scrollTo(0, 0);
        }
    }

    private void startSettingsPreviewVerticalMarquee(final ScrollView scroll) {
        stopSettingsPreviewVerticalMarquee();
        if (scroll == null || tvSettingsPreviewState == null || isFullWidthMenus) return;
        scroll.post(new Runnable() {
            @Override
            public void run() {
                final int contentH = tvSettingsPreviewState.getHeight();
                final int viewH = scroll.getHeight();
                if (contentH <= viewH + 4) return;
                if (settingsPreviewScrollHandler == null) {
                    settingsPreviewScrollHandler = new Handler();
                }
                settingsPreviewScrollRunnable = new Runnable() {
                    private int pauseTicks;

                    @Override
                    public void run() {
                        if (scroll != settingsPreviewStateScroll || settingsPreviewScrollRunnable != this) {
                            return;
                        }
                        int maxScroll = Math.max(0, contentH - viewH);
                        int y = scroll.getScrollY();
                        if (pauseTicks > 0) {
                            pauseTicks--;
                        } else if (y >= maxScroll) {
                            scroll.scrollTo(0, 0);
                            pauseTicks = 40;
                        } else {
                            scroll.scrollBy(0, 1);
                        }
                        settingsPreviewScrollHandler.postDelayed(this, 50);
                    }
                };
                settingsPreviewScrollHandler.postDelayed(settingsPreviewScrollRunnable, 1500);
            }
        });
    }

    private void applySettingsPreviewStateText(CharSequence text, boolean verticalMarquee) {
        stopSettingsPreviewVerticalMarquee();
        if (settingsPreviewStateScroll != null) {
            settingsPreviewStateScroll.setVisibility(text != null && text.length() > 0
                    ? View.VISIBLE : View.GONE);
        }
        if (tvSettingsPreviewState == null) return;
        tvSettingsPreviewState.setSingleLine(false);
        tvSettingsPreviewState.setEllipsize(null);
        tvSettingsPreviewState.setHorizontallyScrolling(false);
        tvSettingsPreviewState.setGravity(verticalMarquee
                ? (android.view.Gravity.CENTER_HORIZONTAL | android.view.Gravity.TOP)
                : android.view.Gravity.CENTER);
        tvSettingsPreviewState.setText(text != null ? text : "");
        tvSettingsPreviewState.setVisibility(text != null && text.length() > 0
                ? View.VISIBLE : View.GONE);
        if (verticalMarquee && text != null && text.length() > 0) {
            startSettingsPreviewVerticalMarquee(settingsPreviewStateScroll);
        }
    }

    private void applySettingsPreviewCappedText(CharSequence text) {
        stopSettingsPreviewVerticalMarquee();
        if (settingsPreviewStateScroll == null || tvSettingsPreviewState == null) return;
        boolean show = text != null && text.length() > 0;
        settingsPreviewStateScroll.setVisibility(show ? View.VISIBLE : View.GONE);
        tvSettingsPreviewState.setVisibility(show ? View.VISIBLE : View.GONE);
        if (!show) return;
        int maxH = VerticalTextMarqueeHelper.defaultMaxHeightPx(this);
        int cappedH = VerticalTextMarqueeHelper.computePanelHeight(this, text, maxH,
                settingsPreviewStateScroll.getWidth() > 0
                        ? settingsPreviewStateScroll.getWidth()
                        : screenWidthPx);
        ViewGroup.LayoutParams scrollLp = settingsPreviewStateScroll.getLayoutParams();
        if (scrollLp != null) {
            scrollLp.height = cappedH;
            settingsPreviewStateScroll.setLayoutParams(scrollLp);
        }
        tvSettingsPreviewState.setSingleLine(false);
        tvSettingsPreviewState.setEllipsize(null);
        tvSettingsPreviewState.setHorizontallyScrolling(false);
        tvSettingsPreviewState.setGravity(android.view.Gravity.START | android.view.Gravity.TOP);
        tvSettingsPreviewState.setText(text);
    }

    private String formatProfileNoteAndBio(String username, String bio) {
        String note = SoulseekPeerNotes.getNoteSync(this, username);
        StringBuilder sb = new StringBuilder();
        if (note != null && !note.trim().isEmpty()) {
            sb.append(getString(R.string.soulseek_user_note_label)).append("\n");
            sb.append(note.trim());
        }
        String bioText = bio != null && !bio.trim().isEmpty()
                ? bio.trim() : getString(R.string.soulseek_profile_no_bio);
        if (sb.length() > 0) sb.append("\n\n");
        sb.append(bioText);
        return sb.toString();
    }

