    private boolean isThemeListActive() {
        return listThemes != null && listThemes.getVisibility() == View.VISIBLE
                && (isThemeGalleryActive() || isThemeVariantPickerActive());
    }

    /** Index-driven theme browser scroll — ListView DPAD dispatch is unreliable on API 17. */
    private boolean moveThemeListFocus(int delta) {
        if (listThemes == null || themeBrowserRows.isEmpty() || delta == 0) return false;
        int pos = themeBrowserListPosition();
        if (pos < 0) pos = themeBrowserFocus;
        int next = pos + (delta < 0 ? -1 : 1);
        if (next < 0 || next >= themeBrowserRows.size()) return false;
        themeBrowserFocus = next;
        scrollThemesToListPos(next);
        ThemeBrowser.Row row = themeBrowserRows.get(next);
        if (row != null) scheduleThemeRowPreview(row);
        return true;
    }

    private void dispatchThemeListKey(int keyCode) {
        moveThemeListFocus(Y1InputKeys.isWheelUp(keyCode) ? -1 : 1);
    }

    private void clearThemeGalleryPreview() {
        themeGalleryPreviewGen++;
        themePreviewHandler.removeCallbacksAndMessages(null);
        themePreviewPending = null;
        stopSettingsPreviewVerticalMarquee();
        if (storagePieView != null) storagePieView.setVisibility(View.GONE);
        if (tvSettingsPreviewTitle != null) {
            tvSettingsPreviewTitle.setText("");
            tvSettingsPreviewTitle.setVisibility(View.GONE);
        }
        if (tvSettingsPreviewState != null) {
            applySettingsPreviewStateText("", false);
        }
        if (ivSettingsPreviewIcon != null) {
            ivSettingsPreviewIcon.setImageDrawable(null);
            ivSettingsPreviewIcon.setVisibility(View.GONE);
        }
        // Blank the portrait lower pane so Get More / Back / filters leave no stale theme cover.
        syncThemePreviewToPortraitStrip();
    }

    /** Debounce preview loads while wheel-scrolling — avoids OOM from stacked cover decode threads. */
    private void scheduleThemeRowPreview(final ThemeBrowser.Row row) {
        if (row == null || !themeSecondaryPaneActive()) return;
        // 2026-07-18 — P3: no cover decode mid-spin; idle catch-up paints the landed row.
        deferArtUntilScrollIdle(new Runnable() {
            @Override
            public void run() {
                scheduleThemeRowPreviewNow(row);
            }
        });
    }

    /**
     * 2026-07-18 — Actually schedule theme cover decode (after idle / debounce).
     * Layman: load the theme picture for the row you stopped on.
     */
    private void scheduleThemeRowPreviewNow(final ThemeBrowser.Row row) {
        if (row == null || !themeSecondaryPaneActive()) return;
        themePreviewHandler.removeCallbacksAndMessages(null);
        themePreviewPending = new Runnable() {
            @Override
            public void run() {
                themePreviewPending = null;
                if (row.kind == ThemeBrowser.KIND_INSTALLED && row.themeIndex >= 0
                        && row.themeIndex < ThemeManager.availableThemes.size()) {
                    updateInstalledThemePreview(ThemeManager.availableThemes.get(row.themeIndex));
                } else if (row.catalog != null) {
                    updateThemeGalleryPreview(row.catalog, row.variant);
                } else {
                    // No right-pane/strip content for Back, Get More, filter, section, status rows.
                    clearThemeGalleryPreview();
                }
            }
        };
        themePreviewHandler.postDelayed(themePreviewPending, THEME_PREVIEW_DEBOUNCE_MS);
    }

    private void updateThemeGalleryPreview(final ThemeDownloader.CatalogEntry entry,
                                           final ThemeDownloader.ThemeVariant variant) {
        if (entry == null || !themeSecondaryPaneActive() || tvSettingsPreviewTitle == null) return;
        final String title = variant != null ? variant.displayName(entry.name) : entry.name;
        final String author = entry.author != null && !entry.author.isEmpty()
                ? entry.author : "Unknown author";
        tvSettingsPreviewTitle.setVisibility(View.VISIBLE);
        tvSettingsPreviewTitle.setText(title);
        tvSettingsPreviewTitle.setSelected(true);
        enableMarquee(tvSettingsPreviewTitle);
        ThemeManager.applyThemedTextStyle(tvSettingsPreviewTitle, ThemeManager.getTextColorPrimary());
        if (tvSettingsPreviewState != null) {
            applySettingsPreviewStateText(author, false);
            ThemeManager.applyThemedTextStyle(tvSettingsPreviewState, ThemeManager.getTextColorSecondary());
        }
        if (storagePieView != null) storagePieView.setVisibility(View.GONE);
        if (ivSettingsPreviewIcon != null) {
            ivSettingsPreviewIcon.setVisibility(View.VISIBLE);
            ivSettingsPreviewIcon.setImageDrawable(null);
        }
        syncThemePreviewToPortraitStrip();
        final int gen = ++themeGalleryPreviewGen;
        final int maxH = themeGalleryCoverMaxPx();
        // #region agent log
        final String previewFolder = entry.folder;
        // #endregion
        new Thread(new Runnable() {
            @Override
            public void run() {
                // ponytail: scroll preview uses cache only — network fetch on every focus OOMs Y1
                final Bitmap cover = ThemeDownloader.loadCachedCoverBitmap(entry, variant, maxH);
                runOnUiThreadSafe(new Runnable() {
                    @Override
                    public void run() {
                        if (isFinishing() || gen != themeGalleryPreviewGen || ivSettingsPreviewIcon == null) return;
                        // #region agent log
                        try {
                            org.json.JSONObject d = new org.json.JSONObject();
                            d.put("folder", previewFolder);
                            d.put("cachedCover", cover != null);
                            d.put("gen", gen);
                            DebugAgentLog.log(MainActivity.this, "MainActivity.updateThemeGalleryPreview",
                                    "preview bound", "H-OOM", d);
                        } catch (Exception ignored) {}
                        // #endregion
                        recycleImageViewBitmap(ivSettingsPreviewIcon);
                        if (cover != null) {
                            ivSettingsPreviewIcon.setImageBitmap(cover);
                            ivSettingsPreviewIcon.setVisibility(View.VISIBLE);
                        } else {
                            ivSettingsPreviewIcon.setVisibility(View.GONE);
                        }
                        syncThemePreviewToPortraitStrip();
                    }
                });
            }
        }, "ThemeCoverPreview").start();
    }

    /** Drop the old bitmap before binding a new one so scroll previews do not OOM. */
    private static void recycleImageViewBitmap(android.widget.ImageView iv) {
        if (iv == null) return;
        android.graphics.drawable.Drawable d = iv.getDrawable();
        iv.setImageDrawable(null);
        if (d instanceof android.graphics.drawable.BitmapDrawable) {
            android.graphics.Bitmap b = ((android.graphics.drawable.BitmapDrawable) d).getBitmap();
            if (b != null && !b.isRecycled()) b.recycle();
        }
    }

    private void bindThemeGalleryListButton(final Button btn, final ThemeDownloader.CatalogEntry entry,
                                            final ThemeDownloader.ThemeVariant variant,
                                            final View.OnClickListener onActivate) {
        btn.setTag(entry.folder + (variant != null ? "\0" + variant.gallerySubpath : ""));
        btn.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                int w = btn.getWidth() > 0 ? btn.getWidth()
                        : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());
                btn.setBackground(getY1RowBackground(hasFocus, w, Y1_ROW_MENU));
                ThemeManager.applyThemedTextStyle(btn, hasFocus
                        ? y1RowTextColorSelected(Y1_ROW_MENU) : y1RowTextColorNormal(Y1_ROW_MENU));
                btn.setSelected(hasFocus);
                if (hasFocus) {
                    showFastScrollLetter(btn.getText().toString());
                    if (themeSecondaryPaneActive()) updateThemeGalleryPreview(entry, variant);
                }
            }
        });
        btn.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                onActivate.onClick(v);
            }
        });
    }

    private void hideThemeGalleryInterstitial() {
        themeGalleryInterstitialEntry = null;
        themeGalleryInterstitialVariant = null;
        if (themeGalleryInterstitial != null) themeGalleryInterstitial.setVisibility(View.GONE);
    }

    private void showThemeGalleryInterstitial(final ThemeDownloader.CatalogEntry entry,
                                              final ThemeDownloader.ThemeVariant variant) {
        if (themeGalleryInterstitial == null) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("entry", entry != null ? entry.folder : "null");
                d.put("variant", variant != null);
                DebugA6d897Log.log(this, "MainActivity.showThemeGalleryInterstitial",
                        "null view — direct download", "E", d);
            } catch (Exception ignored) {}
            // #endregion
            if (variant != null) downloadAndApplyThemeVariant(entry, variant);
            else downloadAndApplyTheme(entry);
            return;
        }
        themeGalleryInterstitialEntry = entry;
        themeGalleryInterstitialVariant = variant;
        final String title = variant != null ? variant.displayName(entry.name) : entry.name;
        final String author = entry.author != null && !entry.author.isEmpty()
                ? entry.author : "Unknown author";
        if (tvThemeInterstitialTitle != null) {
            tvThemeInterstitialTitle.setText(title);
            tvThemeInterstitialTitle.setSelected(true);
            enableMarquee(tvThemeInterstitialTitle);
        }
        if (tvThemeInterstitialAuthor != null) tvThemeInterstitialAuthor.setText(author);
        if (ivThemeInterstitialCover != null) {
            ivThemeInterstitialCover.setVisibility(View.GONE);
            ivThemeInterstitialCover.setImageDrawable(null);
        }
        themeGalleryInterstitial.setVisibility(View.VISIBLE);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("entry", entry != null ? entry.folder : "null");
            d.put("title", title);
            d.put("fullWidth", isFullWidthMenus);
            d.put("btnDlNull", btnThemeInterstitialDownload == null);
            d.put("btnBackNull", btnThemeInterstitialBack == null);
            d.put("listThemesVis", listThemes != null ? listThemes.getVisibility() : -1);
            d.put("w", themeGalleryInterstitial.getWidth());
            d.put("h", themeGalleryInterstitial.getHeight());
            if (btnThemeInterstitialDownload != null) {
                d.put("dlTop", btnThemeInterstitialDownload.getTop());
                d.put("dlH", btnThemeInterstitialDownload.getHeight());
                d.put("dlShown", btnThemeInterstitialDownload.getVisibility() == View.VISIBLE);
            }
            DebugA6d897Log.log(this, "MainActivity.showThemeGalleryInterstitial",
                    "interstitial shown", "C,E", d);
        } catch (Exception ignored) {}
        // #endregion
        final int maxH = themeGalleryCoverMaxPx();
        new Thread(new Runnable() {
            @Override
            public void run() {
                final Bitmap cover = ThemeDownloader.loadCoverBitmap(entry, variant, maxH);
                runOnUiThreadSafe(new Runnable() {
                    @Override
                    public void run() {
                        if (isFinishing() || themeGalleryInterstitial == null
                                || themeGalleryInterstitial.getVisibility() != View.VISIBLE) return;
                        if (ivThemeInterstitialCover == null) return;
                        if (cover != null) {
                            ivThemeInterstitialCover.setImageBitmap(cover);
                            ivThemeInterstitialCover.setVisibility(View.VISIBLE);
                        }
                    }
                });
            }
        }, "ThemeCoverInterstitial").start();
        if (btnThemeInterstitialDownload != null) {
            btnThemeInterstitialDownload.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    // #region agent log
                    try {
                        org.json.JSONObject d = new org.json.JSONObject();
                        d.put("entry", entry != null ? entry.folder : "null");
                        d.put("variant", variant != null);
                        d.put("focused", v != null && v.isFocused());
                        DebugA6d897Log.log(MainActivity.this,
                                "MainActivity.btnThemeInterstitialDownload",
                                "download click fired", "C", d);
                    } catch (Exception ignored) {}
                    // #endregion
                    clickFeedback();
                    hideThemeGalleryInterstitial();
                    if (variant != null) downloadAndApplyThemeVariant(entry, variant);
                    else downloadAndApplyTheme(entry);
                }
            });
            btnThemeInterstitialDownload.requestFocus();
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("dlFocusedAfter", btnThemeInterstitialDownload.isFocused());
                View focused = getCurrentFocus();
                d.put("focusClass", focused != null ? focused.getClass().getSimpleName() : "null");
                d.put("focusId", focused != null ? focused.getId() : -1);
                DebugA6d897Log.log(this, "MainActivity.showThemeGalleryInterstitial",
                        "after requestFocus download", "D", d);
            } catch (Exception ignored) {}
            // #endregion
        }
    }

    private void startThemeGalleryActivation(final ThemeDownloader.CatalogEntry entry,
                                             final ThemeDownloader.ThemeVariant variant) {
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("fullWidth", isFullWidthMenus);
            d.put("entry", entry != null ? entry.folder : "null");
            d.put("variant", variant != null);
            d.put("portraitChrome", A5PortraitChrome.usePortraitChrome(this));
            d.put("forcePortraitTheme", A5NavigationMode.forcePortraitThemeRules(this));
            DebugA6d897Log.log(this, "MainActivity.startThemeGalleryActivation",
                    "activation route", "E", d);
        } catch (Exception ignored) {}
        // #endregion
        // 2026-07-15 — Portrait: OK downloads now (lower strip already showed cover).
        // Was: any full-width → interstitial confirm. Landscape full-width still confirms.
        // Reversal: if (isFullWidthMenus) showThemeGalleryInterstitial(...);
        boolean needsInterstitial = isFullWidthMenus && !A5PortraitChrome.usePortraitChrome(this);
        if (needsInterstitial) {
            showThemeGalleryInterstitial(entry, variant);
        } else if (variant != null) {
            downloadAndApplyThemeVariant(entry, variant);
        } else {
            downloadAndApplyTheme(entry);
        }
    }

