    /** Debug Menu — Soulseek/Deezer download error toasts (success toasts stay visible). */
    private boolean shouldShowDownloadErrorToasts() {
        return prefs != null && prefs.getBoolean(PREF_DEBUG_SHOW_ERROR_TOASTS, false);
    }

    private void toastReachDownloadError(CharSequence message) {
        if (!shouldShowDownloadErrorToasts() || message == null || message.length() == 0) return;
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }

    private void toastStreamDownloadWarning(CharSequence message) {
        toastReachDownloadError(message);
    }

    private void onNetworkConnectivityChanged() {
        refreshConnectivityGatedMenus();
    }

    private void refreshConnectivityGatedMenus() {
        scheduleConnectivityGatedMenusRefresh();
    }

    private void scheduleConnectivityGatedMenusRefresh() {
        connectivityUiDebounceHandler.removeCallbacks(connectivityUiDebounceRunnable);
        connectivityUiDebounceHandler.postDelayed(connectivityUiDebounceRunnable, CONNECTIVITY_UI_DEBOUNCE_MS);
    }

    private void refreshConnectivityGatedMenusNow() {
        if (currentScreenState == STATE_MENU) {
            buildHomeMenu();
        } else if (currentScreenState == STATE_MORE) {
            buildMoreMenuUI();
        } else if (currentScreenState == STATE_SETTINGS && settingsSubScreenKey == null) {
            buildSettingsUI();
        }
        if (currentScreenState == STATE_SETTINGS && SettingsScreens.THEMES.equals(settingsSubScreenKey)) {
            if (themeBrowserMode == THEME_BROWSER_MAIN || themeBrowserMode == THEME_BROWSER_GET_MORE) {
                rebuildThemeBrowserRows();
                refreshThemeBrowserList();
            }
        }
        if (currentScreenState == STATE_BROWSER && currentBrowserMode == BROWSER_ROOT && !isPickingBackground) {
            buildFileBrowserUI();
        }
    }

    private void onWifiConnectivityChanged() {
        // Menu rebuild already deferred to input-idle via connectivityUiDebounceRunnable.
        refreshConnectivityGatedMenus();
        // 2026-07-17 — Never run internet hooks on the wheel path: yield until input idle.
        if (isInputPriorityBusy()) {
            postWhenInputIdle(connectivityUiDebounceHandler, new Runnable() {
                @Override
                public void run() {
                    runDeferredInternetAvailabilityHooks();
                }
            });
            return;
        }
        runDeferredInternetAvailabilityHooks();
    }

    /** NTP / geo / Reach probes — disk+network; must not run mid-scroll. */
    private void runDeferredInternetAvailabilityHooks() {
        if (hasInternetConnection() && soulseekReachEnabled) {
            SolarDiagnosticReporter.onReachInternetAvailable(this, prefs);
        }
        if (hasInternetConnection()) {
            SolarAutoTime.onInternetAvailable(this);
            SolarGeoRegion.onInternetAvailable(this);
        }
        scheduleSoulseekSharePolicyRefresh();
    }

    private void scheduleSoulseekSharePolicyRefresh() {
        // 2026-07-17 — No policy ticks / share walks / warm connections when Soulseek is off.
        if (!soulseekActive()) {
            soulseekPolicyDebounceHandler.removeCallbacks(soulseekPolicyDebounceRunnable);
            return;
        }
        soulseekPolicyDebounceHandler.removeCallbacks(soulseekPolicyDebounceRunnable);
        soulseekPolicyDebounceHandler.postDelayed(soulseekPolicyDebounceRunnable,
                SOULSEEK_POLICY_DEBOUNCE_MS);
    }

    /** ponytail: after 15 min asleep off-charger, drop Wi-Fi unless transfers need it. */
    private void scheduleWifiSleepOff() {
        soulseekUiHandler.removeCallbacks(wifiSleepOffRunnable);
        if (!isWifiSleepPowerOffEnabled()) return;
        if (!isScreenSleeping || soulseekCharging) return;
        soulseekUiHandler.postDelayed(wifiSleepOffRunnable, WIFI_SLEEP_OFF_MS);
    }

    private boolean isWifiSleepPowerOffEnabled() {
        return prefs != null && prefs.getBoolean(WifiSleepPolicy.PREF_ENABLED, true);
    }

    private void cancelWifiSleepOff() {
        soulseekUiHandler.removeCallbacks(wifiSleepOffRunnable);
        soulseekScreenSleepArmed = false;
    }

    /** Re-enable Wi-Fi after sleep policy turned it off — screen on or charger plugged in. */
    private void maybeRestoreWifiAfterSleepPolicy() {
        boolean persisted = prefs != null
                && prefs.getBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, false);
        if (!WifiSleepPolicy.shouldRestore(wifiDisabledBySleepPolicy, persisted)) return;
        wifiDisabledBySleepPolicy = false;
        if (prefs != null) {
            prefs.edit().putBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, false).commit();
        }
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            if (wm != null && !wm.isWifiEnabled()) {
                wm.setWifiEnabled(true);
                triggerAutoReconnect();
            }
        } catch (Exception ignored) {}
    }

    /**
     * Silent Wi-Fi off for sleep policy — light diag flush first (no "sending logs" UX).
     * Screen is usually off; no toast. Radio drops after a short time-boxed ship.
     */
    private void tryWifiSleepPowerOff() {
        if (!isWifiSleepPowerOffEnabled()) return;
        if (!isScreenSleeping || soulseekCharging) return;
        final WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm == null || !wm.isWifiEnabled()) return;
        if (wifiSleepBlockedByActiveUse()) {
            // ponytail: retry while playback / transfers / upload server still need the radio.
            soulseekUiHandler.removeCallbacks(wifiSleepOffRunnable);
            soulseekUiHandler.postDelayed(wifiSleepOffRunnable, 60_000L);
            return;
        }
        wifiContextPendingEnable = false;
        wifiContextPendingDisable = true;
        cancelWifiContextScanFollowUps();
        // 2026-07-16 — Ship light logs while still online, then drop radio (no log-ship toast).
        SolarDiagnosticReporter.runBeforeWifiDisable(this, false, new Runnable() {
            @Override
            public void run() {
                try {
                    if (wm.isWifiEnabled()) {
                        wm.setWifiEnabled(false);
                    }
                } catch (Exception ignored) {}
                wifiDisabledBySleepPolicy = true;
                if (prefs != null) {
                    prefs.edit().putBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, true).commit();
                }
                // #region agent log
                try {
                    org.json.JSONObject d = soulseekSleepDecisionSnapshot();
                    d.put("wifiWasEnabled", true);
                    DebugSessionLog.log("MainActivity.tryWifiSleepPowerOff", "wifi sleep off", "H-WIFI", d);
                } catch (Exception ignored) {}
                // #endregion
            }
        });
    }

    /** Real transfers only — not {@link SoulseekClient#isBusy()} policy keep-alive. */
    private boolean shouldKeepSoulseekAwakeForTransfers() {
        if (hasActiveReachDownload() || reachDownloadInProgress()) return true;
        if (isDeezerStreamDownloadInProgress()) return true;
        if (reachPartialPlaybackStarted) return true;
        if (soulseekSearchInProgress) return true;
        if (soulseekClient != null) {
            if (soulseekClient.isTransferActive()) return true;
            if (soulseekClient.isUploadInProgress()) return true;
            if (soulseekClient.isSearchActive()) return true;
        }
        return false;
    }

    private boolean shouldSoulseekSleepForScreen() {
        return soulseekScreenSleepArmed && isScreenSleeping && !soulseekCharging
                && !shouldKeepSoulseekAwakeForTransfers();
    }

    private void triggerAutoReconnect() {
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            if (wm != null && wm.isWifiEnabled()) {
                wm.reconnect();
            }
            BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
            if (ba != null && ba.isEnabled()) {
                java.util.Set<BluetoothDevice> pairedDevices = ba.getBondedDevices();
            }
        } catch (Exception e) {
        }
    }

    private void toggleWebServer() {
        if (isServerRunning) {
            stopWebServer();
        } else {
            startWebServerIfNeeded();
        }
    }

    private void startWebServerIfNeeded() {
        if (isServerRunning) return;
        if (!ConnectivityHelper.hasLocalNetwork(this)) {
            Toast.makeText(this, getString(R.string.toast_network_required), Toast.LENGTH_SHORT).show();
            return;
        }
        webServer = new SolarWebServer(getApplicationContext(), rootFolder);
        webServer.start();
        isServerRunning = true;
        android.util.Log.i("DeezerDbg", "webserver started ip=" + webServer.getLocalIpAddress());
    }

    private void stopWebServer() {
        if (webServer != null) webServer.stopServer();
        isServerRunning = false;
    }

    private void updateWebServerUI() {
        if (currentScreenState == STATE_DEEZER_SETUP) {
            updateDeezerSetupUI();
            return;
        }
        if (isServerRunning) {
            tvServerStatus.setText(getString(R.string.webserver_running));
            ThemeManager.applyThemedTextStyle(tvServerStatus, ThemeManager.getItemTextColorNormal());
            tvServerIp.setText("http://" + webServer.getLocalIpAddress() + ":8080");
            ThemeManager.applyThemedTextStyle(tvServerIp, ThemeManager.getItemTextColorNormal());
            btnServerToggle.setText(getString(R.string.webserver_stop));
        } else {
            tvServerStatus.setText(getString(R.string.webserver_stopped));
            styleSecondaryLabel(tvServerStatus);
            tvServerIp.setText("http://---.---.---.---:8080");
            styleSecondaryLabel(tvServerIp);
            btnServerToggle.setText(getString(R.string.webserver_start));
        }
        if (tvWebserverHint != null) {
            ThemeManager.applyThemedTextStyle(tvWebserverHint, ThemeManager.getHintTextColor());
        }
    }

    private void updateDeezerSetupUI() {
        if (btnServerToggle != null) btnServerToggle.setVisibility(View.GONE);
        if (isServerRunning) {
            tvServerStatus.setText(getString(R.string.deezer_setup_running));
            ThemeManager.applyThemedTextStyle(tvServerStatus, ThemeManager.getItemTextColorNormal());
            String ip = webServer != null ? webServer.getLocalIpAddress() : ConnectivityHelper.localIpv4(this);
            if (ip == null) ip = "---";
            tvServerIp.setText(getString(R.string.deezer_setup_ip_format, ip));
            ThemeManager.applyThemedTextStyle(tvServerIp, ThemeManager.getItemTextColorNormal());
        } else {
            tvServerStatus.setText(getString(R.string.deezer_setup_stopped));
            styleSecondaryLabel(tvServerStatus);
            tvServerIp.setText(getString(R.string.deezer_setup_ip_format, "---"));
            styleSecondaryLabel(tvServerIp);
        }
        if (tvWebserverHint != null) {
            tvWebserverHint.setText(getString(R.string.deezer_setup_hint));
            ThemeManager.applyThemedTextStyle(tvWebserverHint, ThemeManager.getHintTextColor());
        }
    }

    private void startWebServerForDeezerSetup() {
        webServerStartedForDeezerSetup = false;
        if (isServerRunning) return;
        startWebServerIfNeeded();
        webServerStartedForDeezerSetup = isServerRunning;
    }

    private void openDeezerSetupScreen() {
        openDeezerSetupScreen(false);
    }

    private void openDeezerSetupScreen(boolean preserveReturn) {
        if (!ConnectivityHelper.hasLocalNetwork(this)) {
            Toast.makeText(this, getString(R.string.toast_requires_wifi), Toast.LENGTH_SHORT).show();
            return;
        }
        if (preserveReturn) {
            screenBackReturnTo = currentScreenState;
            changeScreen(STATE_DEEZER_SETUP);
        } else {
            openScreenWithReturn(STATE_DEEZER_SETUP);
        }
    }

    private void returnFromDeezerSetup() {
        if (webServerStartedForDeezerSetup && isServerRunning) {
            stopWebServer();
        }
        webServerStartedForDeezerSetup = false;
        returnFromAuxScreen();
    }

    private void updateMainMenuBackground() {
        if (currentScreenState == STATE_MENU) {
            updateScreenBackground(STATE_MENU);
        } else if (currentScreenState == STATE_PLAYER) {
            updateScreenBackground(STATE_PLAYER);
        }
    }

    private Bitmap loadSelectedThemeWallpaper(int screenState) {
        String pick = prefs.getString(PREF_BG_THEME_WALLPAPER, null);
        if (pick != null) {
            Bitmap picked = ThemeManager.loadWallpaperPick(pick);
            if (picked != null) return picked;
        }
        return loadThemeWallpaperForScreen(screenState);
    }

    private boolean hasEffectiveWallpaper() {
        if (BG_MODE_CUSTOM.equals(getBackgroundMode())) {
            return loadCustomBackgroundBitmap() != null;
        }
        String pick = prefs.getString(PREF_BG_THEME_WALLPAPER, null);
        if (pick != null && ThemeManager.loadWallpaperPick(pick) != null) return true;
        return ThemeManager.hasThemeWallpaper();
    }

    private Bitmap loadThemeWallpaperForScreen(int screenState) {
        String prefKey = null;
        if (screenState == STATE_MENU) prefKey = PREF_BG_HOME;
        else if (screenState == STATE_BROWSER) prefKey = PREF_BG_LIBRARY;
        else if (screenState == STATE_SETTINGS) prefKey = PREF_BG_SETTINGS;
        else if (screenState == STATE_PLAYER) prefKey = PREF_BG_NOW_PLAYING;
        if (prefKey != null) {
            String pick = prefs.getString(prefKey, null);
            if (pick != null) {
                Bitmap b = ThemeManager.loadWallpaperPick(pick);
                if (b != null) return b;
            }
        }
        // 2026-07-14 — Portrait chrome: prefer global wall on Home/Settings/NP (masks already off).
        // Was: Home tried desktop first. Reversal: drop this branch.
        if (A5PortraitChrome.usePortraitChrome(this)
                && (screenState == STATE_MENU || screenState == STATE_SETTINGS
                || screenState == STATE_PLAYER)) {
            Bitmap global = ThemeManager.getWallpaper(false);
            if (global != null) return global;
            Bitmap desk = ThemeManager.getWallpaper(true);
            if (desk != null) return desk;
            return null;
        }
        Bitmap wall;
        if (screenState == STATE_MENU) {
            wall = ThemeManager.getWallpaper(true);
            if (wall == null) wall = ThemeManager.getWallpaper(false);
        } else {
            wall = ThemeManager.getWallpaper(false);
            if (wall == null) wall = ThemeManager.getWallpaper(true);
        }
        return wall;
    }

    private Bitmap loadThemeMaskForScreen(int screenState) {
        if (screenState == STATE_MENU) return ThemeManager.getDesktopMask();
        if (screenState == STATE_SETTINGS) return ThemeManager.getSettingMask();
        return null;
    }

    private boolean hasAlbumArtForBlur() {
        return lastAlbumArtBytes != null && lastAlbumArtBytes.length > 0;
    }

    private void applyOverlayBackgrounds() {
        int overlay = hasEffectiveWallpaper()
                ? 0x00000000 : ThemeManager.getOverlayBackgroundColor();
        if (layoutBrowserMode != null) layoutBrowserMode.setBackgroundColor(overlay);
        if (layoutSettingsMode != null) layoutSettingsMode.setBackgroundColor(overlay);
        if (layoutBluetoothMode != null) layoutBluetoothMode.setBackgroundColor(overlay);
        if (layoutWifiMode != null) layoutWifiMode.setBackgroundColor(overlay);
        if (layoutWifiKeyboard != null) layoutWifiKeyboard.setBackgroundColor(overlay);
        if (layoutBrightnessMode != null) layoutBrightnessMode.setBackgroundColor(overlay);
        if (layoutStorageMode != null) layoutStorageMode.setBackgroundColor(overlay);
        if (layoutWebServerMode != null) layoutWebServerMode.setBackgroundColor(overlay);
    }

    private void updateScreenBackground(int screenState) {
        if (ivMainBg == null) return;
        try {
            applyOverlayBackgrounds();
            com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot snap =
                    resolveBackdropSnapshot(screenState);
            applyBackdropSnapshot(snap, ivMainBg, ivScreenMask);
            if (screenState == STATE_PLAYER) {
                bindPlayerBlurBackdrop();
            }
            refreshRightPanePreviewLayout();
        } catch (Throwable t) {
            ivMainBg.setImageResource(R.drawable.default_back);
            applyScreenMask(null);
            refreshRightPanePreviewLayout();
        }
    }

    /** Build cropped wall + mask for backdrop transition or static apply. */
    private com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot resolveBackdropSnapshot(
            int screenState) {
        Bitmap wall = null;
        Bitmap mask = null;
        boolean defaultWall = false;
        String mode = getBackgroundMode();

        if (BG_MODE_CUSTOM.equals(mode)) {
            wall = loadCustomBackgroundBitmap();
        } else {
            wall = loadSelectedThemeWallpaper(screenState);
            mask = loadThemeMaskForScreen(screenState);
        }

        if (isFullWidthMenus || settingsBrowseFullWidth) {
            mask = null;
        }
        if (screenState == STATE_MENU && anyHomeWidgetActive()) {
            mask = null;
        }

        Bitmap croppedWall = null;
        Bitmap croppedMask = null;
        if (wall != null && screenWidthPx > 0 && screenHeightPx > 0) {
            croppedWall = ThemeManager.centerCropBitmap(wall, screenWidthPx, screenHeightPx);
        } else if (screenState != STATE_PLAYER) {
            defaultWall = true;
        }
        if (mask != null && screenWidthPx > 0 && screenHeightPx > 0) {
            croppedMask = ThemeManager.centerCropBitmap(mask, screenWidthPx, screenHeightPx);
        }
        return new com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot(
                screenState, croppedWall, croppedMask, defaultWall);
    }

    private void applyBackdropSnapshot(
            com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot snap,
            ImageView wallView, ImageView maskView) {
        if (snap == null || wallView == null) return;
        if (snap.wall != null) {
            wallView.setImageBitmap(snap.wall);
        } else if (snap.defaultWall) {
            wallView.setImageResource(R.drawable.default_back);
        } else {
            wallView.setImageResource(R.drawable.default_back);
        }
        applyScreenMaskToView(maskView, snap != null ? snap.mask : null);
    }

    private void applyScreenMask(Bitmap mask) {
        applyScreenMaskToView(ivScreenMask, mask);
    }

    private void applyScreenMaskToView(ImageView maskView, Bitmap mask) {
        if (maskView == null) return;
        if (mask != null) {
            if (maskView == ivScreenMask && screenWidthPx > 0 && screenHeightPx > 0) {
                maskView.setImageBitmap(ThemeManager.centerCropBitmap(mask, screenWidthPx, screenHeightPx));
            } else {
                maskView.setImageBitmap(mask);
            }
            maskView.setVisibility(View.VISIBLE);
        } else {
            maskView.setVisibility(View.GONE);
        }
    }
    /**
     * 2026-07-11 — Now Playing backdrop: album blur when enabled+art, else theme wallpaper
     * (globalWallpaper first — Karliky editor parity for non-home screens).
     * Was: callers cleared ivPlayerBgBlur to empty/#111111 so NP lost Cupertino global wall.
     * Reversal: setImageResource(0) at those sites again.
     */
    private void bindPlayerBlurBackdrop() {
        if (ivPlayerBgBlur == null) return;
        String mode = getBackgroundMode();
        if (playerAlbumBlurEnabled && hasAlbumArtForBlur()) {
            BitmapFactory.Options optsBg = new BitmapFactory.Options();
            optsBg.inSampleSize = 4;
            Bitmap sourceBg = BitmapFactory.decodeByteArray(
                    lastAlbumArtBytes, 0, lastAlbumArtBytes.length, optsBg);
            if (sourceBg != null) {
                Bitmap blurredBg = applyGaussianBlur(sourceBg);
                ivPlayerBgBlur.setImageBitmap(blurredBg);
                if (sourceBg != blurredBg) sourceBg.recycle();
                if (playerBgScrim != null) playerBgScrim.setVisibility(View.VISIBLE);
                return;
            }
        }
        Bitmap bg = BG_MODE_CUSTOM.equals(mode)
                ? loadCustomBackgroundBitmap()
                : loadSelectedThemeWallpaper(STATE_PLAYER);
        if (bg != null) {
            ivPlayerBgBlur.setImageBitmap(
                    ThemeManager.centerCropBitmap(bg, screenWidthPx, screenHeightPx));
        } else {
            ivPlayerBgBlur.setImageDrawable(null);
        }
        // Theme wallpaper matches the editor — no dark scrim on top.
        if (playerBgScrim != null) playerBgScrim.setVisibility(View.GONE);
    }

    /** Copy live Now Playing blur onto the global outgoing backdrop for slide-down exits. */
    private void bindOutgoingPlayerBackdrop(ImageView wall, ImageView mask) {
        if (wall == null || ivPlayerBgBlur == null) return;
        android.graphics.drawable.Drawable d = ivPlayerBgBlur.getDrawable();
        if (d instanceof android.graphics.drawable.BitmapDrawable) {
            android.graphics.Bitmap bmp =
                    ((android.graphics.drawable.BitmapDrawable) d).getBitmap();
            if (bmp != null) {
                wall.setImageBitmap(bmp);
            }
        } else {
            bindPlayerBlurBackdrop();
            d = ivPlayerBgBlur.getDrawable();
            if (d instanceof android.graphics.drawable.BitmapDrawable) {
                android.graphics.Bitmap bmp =
                        ((android.graphics.drawable.BitmapDrawable) d).getBitmap();
                if (bmp != null) wall.setImageBitmap(bmp);
            }
        }
        if (mask != null) mask.setVisibility(View.GONE);
    }

    private String backdropCacheKey(int screenState) {
        StringBuilder sb = new StringBuilder();
        sb.append(screenState).append('|').append(getBackgroundMode());
        sb.append('|').append(isFullWidthMenus).append('|').append(settingsBrowseFullWidth);
        sb.append('|').append(prefs.getString(PREF_BG_THEME_WALLPAPER, ""));
        if (screenState == STATE_MENU) sb.append('|').append(prefs.getString(PREF_BG_HOME, ""));
        else if (screenState == STATE_BROWSER) sb.append('|').append(prefs.getString(PREF_BG_LIBRARY, ""));
        else if (screenState == STATE_SETTINGS) sb.append('|').append(prefs.getString(PREF_BG_SETTINGS, ""));
        else if (screenState == STATE_PLAYER) sb.append('|').append(prefs.getString(PREF_BG_NOW_PLAYING, ""));
        if (screenState == STATE_PLAYER && playerAlbumBlurEnabled && hasAlbumArtForBlur()) {
            sb.append('|').append(lastAlbumArtBytes.length);
        }
        return sb.toString();
    }

    private final com.solar.launcher.ui.ScreenBackdropTransition.Resolver backdropResolver =
            new com.solar.launcher.ui.ScreenBackdropTransition.Resolver() {
                @Override
                public com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot resolveSnapshot(
                        int screenState) {
                    return resolveBackdropSnapshot(screenState);
                }

                @Override
                public void bindPlayerBlurEarly() {
                    bindPlayerBlurBackdrop();
                }

                @Override
                public void bindOutgoingPlayerBackdrop(ImageView wall, ImageView mask) {
                    MainActivity.this.bindOutgoingPlayerBackdrop(wall, mask);
                }

                @Override
                public int screenWidthPx() {
                    return MainActivity.this.screenWidthPx;
                }

                @Override
                public int screenHeightPx() {
                    return MainActivity.this.screenHeightPx;
                }
            };

    private void prepareTransitionBackdrop(int from, int to) {
        screenBackdropTransition.prepareIncoming(backdropResolver, from, to,
                backdropCacheKey(from), backdropCacheKey(to));
    }

    private void commitTransitionBackdrop(int to) {
        screenBackdropTransition.commit(to, backdropResolver);
        if (to != STATE_PLAYER) {
            syncStaticBackdropAfterTransition(to);
        }
    }

    /** Lightweight overlay refresh after backdrop commit — skips full decode when already bound. */
    private void syncStaticBackdropAfterTransition(int screenState) {
        applyOverlayBackgrounds();
        refreshRightPanePreviewLayout();
    }

    private Bitmap loadCustomBackgroundBitmap() {
        String savedBgPath = prefs.getString("bg_path", null);
        if (savedBgPath == null || savedBgPath.isEmpty()) return null;
        File bgFile = new File(savedBgPath);
        if (!bgFile.exists()) return null;
        BitmapFactory.Options opts = new BitmapFactory.Options();
        opts.inJustDecodeBounds = true;
        BitmapFactory.decodeFile(savedBgPath, opts);
        int scale = 1;
        int maxDim = Math.max(opts.outWidth, opts.outHeight);
        while (maxDim / scale > 800) scale *= 2;
        opts.inJustDecodeBounds = false;
        opts.inSampleSize = scale;
        return BitmapFactory.decodeFile(savedBgPath, opts);
    }

    /** Desktop/setting mask frames the right preview pane — tighten art and hide titles when active. */
    private boolean isHomeDesktopMaskActive() {
        return ivScreenMask != null
                && ivScreenMask.getVisibility() == View.VISIBLE
                && currentScreenState == STATE_MENU
                && !isFullWidthMenus
                && !anyHomeWidgetActive();
    }

    private boolean isSettingsPaneMaskActive() {
        return ivScreenMask != null
                && ivScreenMask.getVisibility() == View.VISIBLE
                && currentScreenState == STATE_SETTINGS
                && !isFullWidthMenus
                && !settingsAboutFullWidth
                && !settingsBrowseFullWidth;
    }

    private void refreshRightPanePreviewLayout() {
        if (isFinishing()) return;
        boolean homeMask = isHomeDesktopMaskActive();
        MenuPreviewLayout.Spec homeSpec = MenuPreviewLayout.homeSpec(this, homeMask);
        if (ivMenuPreview != null && ivMenuPreview.getVisibility() == View.VISIBLE) {
            MenuPreviewLayout.applyImagePreview(ivMenuPreview, homeSpec);
        }
        if (layoutWidgets != null) {
            boolean widgetsVisible = layoutWidgets.getVisibility() == View.VISIBLE;
            MenuPreviewLayout.Spec widgetSpec = MenuPreviewLayout.homeSpec(this, widgetsVisible ? false : homeMask);
            MenuPreviewLayout.applyLinearPreview(layoutWidgets, widgetSpec);
            if (widgetsVisible) {
                MenuPreviewLayout.applyWidgetAlbum(ivWidgetAlbum, layoutWidgets, widgetSpec);
            }
        }
        if (homeMask) {
            if (tvMenuPreviewTitle != null) tvMenuPreviewTitle.setVisibility(View.GONE);
            if (tvMenuPreviewArtist != null) tvMenuPreviewArtist.setVisibility(View.GONE);
        }
        applySettingsPreviewPaneLayout(isSettingsPaneMaskActive());
    }

    private void applySettingsPreviewPaneLayout(boolean maskActive) {
        if (settingsPreviewPane == null || settingsPreviewPane.getVisibility() != View.VISIBLE) return;
        MenuPreviewLayout.Spec spec = MenuPreviewLayout.settingsSpec(this, maskActive);
        MenuPreviewLayout.applySettingsPreviewPane(settingsPreviewPane, ivSettingsPreviewIcon, spec, maskActive, this);
        if (maskActive) {
            if (tvSettingsPreviewTitle != null) tvSettingsPreviewTitle.setVisibility(View.GONE);
            if (settingsPreviewStateScroll != null) settingsPreviewStateScroll.setVisibility(View.GONE);
        }
    }


    // 💡 [추가] 테마 색상과 '둥글기(Radius)'를 혼합해서 버튼의 배경 디자인을 찍어내는 도구
    private android.graphics.drawable.GradientDrawable createButtonBackground(int color) {
        android.graphics.drawable.GradientDrawable shape = new android.graphics.drawable.GradientDrawable();
        shape.setColor(color); // 테마 색상 주입
        // 테마에 설정된 둥글기(Radius) 값 주입 (dp 단위를 픽셀로 변환하여 적용)
        float radius = ThemeManager.getButtonRadius() * getResources().getDisplayMetrics().density;
        shape.setCornerRadius(radius);
        return shape;
    }

    /** ponytail: stock Y1 — home=item rows, settings=menu rows, lists=item rows */
    private void initY1LayoutMetrics() {
        float density = getResources().getDisplayMetrics().density;
        // 2026-07-14 — A5 portrait: real 240×320 full-width. A5 landscape: Y1 dimens × 240/360.
        // Was: landscape also used full-width 320×240 (only rowH scaled) — dual-pane never appeared.
        // Reversal: landscape branch same as portrait (full-width screenWidthPx metrics).
        if (DeviceFeatures.isA5()) {
            boolean portrait = A5NavigationMode.isPortrait(this);
            android.util.DisplayMetrics dmNow = getResources().getDisplayMetrics();
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("portrait", portrait);
                d.put("orientPref", A5NavigationMode.orientation(this));
                d.put("physW", dmNow.widthPixels);
                d.put("physH", dmNow.heightPixels);
                d.put("density", density);
                d.put("portraitChrome", A5PortraitChrome.usePortraitChrome(this));
                d.put("landGate", A5NavigationMode.isLandscape(this));
                int rawMenu = (int) getResources().getDimension(R.dimen.y1_menu_width);
                int rawSettings = (int) getResources().getDimension(R.dimen.y1_settings_menu_width);
                float scale = A5NavigationMode.landscapeThemeScale(this);
                d.put("rawMenuDimen", rawMenu);
                d.put("rawSettingsDimen", rawSettings);
                d.put("scale", scale);
                // Expected Y1 parity: authoring dp × 320/480 (ignore device density).
                d.put("expectedMenuW", Math.round(204f * 320f / 480f));
                d.put("expectedSettingsW", Math.round(218f * 320f / 480f));
                d.put("scaledMenuViaDimen", A5NavigationMode.scaleLayoutPx(rawMenu, scale));
                d.put("scaledSettingsViaDimen", A5NavigationMode.scaleLayoutPx(rawSettings, scale));
                Debug1fc727Log.log(this, "MainActivity.initY1LayoutMetrics",
                        "A5 metrics branch", "L1,L2,L3", d);
            } catch (Exception ignored) {}
            // #endregion
            if (portrait) {
                screenWidthPx = A5NavigationMode.portraitWidthPx();
                screenHeightPx = A5NavigationMode.portraitHeightPx();
                y1RowWidthPx = screenWidthPx;
                y1RowHeightPx = (int) getResources().getDimension(R.dimen.y1_menu_item_height);
                // 2026-07-14 — Keep stock library row height so title+artist fit (was menu item H —
                // clipped the subtitle). Reversal: y1LibraryRowHeightPx = y1RowHeightPx.
                y1LibraryRowHeightPx = (int) getResources().getDimension(R.dimen.y1_library_row_height);
                listRowWidthPx = Math.max(1, screenWidthPx - (int) (20 * density));
                y1ThemeCoverHeightPx = (int) getResources().getDimension(R.dimen.y1_theme_cover_height);
                y1BatteryIconHeightPx = (int) getResources().getDimension(R.dimen.y1_battery_icon_height);
                settingsMenuWidthPx = screenWidthPx;
                menuListHeightPx = Math.max(1, screenHeightPx
                        - (int) getResources().getDimension(R.dimen.y1_status_bar_height));
                return;
            }
            // A5 landscape — normal Y1 dual-pane atoms scaled to 320×240 (240p height).
            float scale = A5NavigationMode.landscapeThemeScale(this);
            screenWidthPx = A5NavigationMode.landscapeWidthPx();
            screenHeightPx = A5NavigationMode.landscapeHeightPx();
            y1RowWidthPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_menu_width));
            y1RowHeightPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_menu_item_height));
            y1LibraryRowHeightPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_library_row_height));
            listRowWidthPx = Math.max(1, screenWidthPx - (int) (20 * density * scale));
            y1ThemeCoverHeightPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_theme_cover_height));
            y1BatteryIconHeightPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_battery_icon_height));
            settingsMenuWidthPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_settings_menu_width));
            menuListHeightPx = A5NavigationMode.scaleLayoutPx(this,
                    (int) getResources().getDimension(R.dimen.y1_menu_height));
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("screenW", screenWidthPx);
                d.put("screenH", screenHeightPx);
                d.put("y1RowWidthPx", y1RowWidthPx);
                d.put("settingsMenuWidthPx", settingsMenuWidthPx);
                d.put("y1RowHeightPx", y1RowHeightPx);
                d.put("scale", scale);
                Debug1fc727Log.log(this, "MainActivity.initY1LayoutMetrics",
                        "A5 landscape metrics applied", "L2,L3", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        }
        // 2026-07-14 — Y1/Y2 portrait experiment: full-width tall metrics from live buffer (~360×480).
        // Was: always 480×360 dimens even when upright — lists laid out against landscape atoms.
        // Reversal: fall through to landscape dimens below.
        if (A5PortraitChrome.usePortraitChrome(this)) {
            android.util.DisplayMetrics dm = getResources().getDisplayMetrics();
            screenWidthPx = Math.max(1, dm.widthPixels);
            screenHeightPx = Math.max(1, dm.heightPixels);
            y1RowWidthPx = screenWidthPx;
            y1RowHeightPx = (int) getResources().getDimension(R.dimen.y1_menu_item_height);
            y1LibraryRowHeightPx = (int) getResources().getDimension(R.dimen.y1_library_row_height);
            listRowWidthPx = Math.max(1, screenWidthPx - (int) (20 * density));
            y1ThemeCoverHeightPx = (int) getResources().getDimension(R.dimen.y1_theme_cover_height);
            y1BatteryIconHeightPx = (int) getResources().getDimension(R.dimen.y1_battery_icon_height);
            settingsMenuWidthPx = screenWidthPx;
            menuListHeightPx = Math.max(1, screenHeightPx
                    - (int) getResources().getDimension(R.dimen.y1_status_bar_height));
            return;
        }
        y1RowWidthPx = (int) (getResources().getDimension(R.dimen.y1_menu_width));
        y1RowHeightPx = (int) (getResources().getDimension(R.dimen.y1_menu_item_height));
        y1LibraryRowHeightPx = (int) (getResources().getDimension(R.dimen.y1_library_row_height));
        listRowWidthPx = (int) (getResources().getDimension(R.dimen.y1_screen_width) - 20 * density);
        y1ThemeCoverHeightPx = (int) (getResources().getDimension(R.dimen.y1_theme_cover_height));
        y1BatteryIconHeightPx = (int) (getResources().getDimension(R.dimen.y1_battery_icon_height));
        screenWidthPx = (int) getResources().getDimension(R.dimen.y1_screen_width);
        screenHeightPx = (int) getResources().getDimension(R.dimen.y1_screen_height);
        settingsMenuWidthPx = (int) getResources().getDimension(R.dimen.y1_settings_menu_width);
        menuListHeightPx = (int) getResources().getDimension(R.dimen.y1_menu_height);
    }

    /**
     * 2026-07-14 — After orient / portrait-or-landscape experiment change: recompute metrics + chrome.
     * Layman: resize menus when flipping between tall and sideways.
     * Tech: initY1LayoutMetrics → full-width flag → applyFullWidthMenusLayout + reach layout.
     * Was: A5-only. Now: also Y1/Y2 portrait experiment. Reversal: early-return if !isA5().
     */
    private void refreshA5LayoutMetricsAfterOrientChange() {
        boolean a5 = DeviceFeatures.isA5();
        // Available (not only enabled) so toggling Off still restores landscape metrics.
        boolean y1Family = Y1PortraitExperiment.isAvailable();
        if (!a5 && !y1Family) return;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("runId", "freeze-pre");
            d.put("depth", debug391149ConfigDepth);
            d.put("orient", a5 ? A5NavigationMode.orientation(this) : "y1_portrait_exp");
            d.put("land", A5NavigationMode.isLandscape(this));
            d.put("reqOrient", getRequestedOrientation());
            d.put("screenW", screenWidthPx);
            d.put("screenH", screenHeightPx);
            Debug391149Log.log(this, "MainActivity.refreshA5LayoutMetricsAfterOrientChange",
                    "refresh enter", "H-B,H-D", d);
            if (debug391149ConfigDepth >= 6) {
                Debug391149Log.log(this, "MainActivity.refreshA5LayoutMetricsAfterOrientChange",
                        "CONFIG_RECURSION_ABORT", "H-B", d);
                return;
            }
        } catch (Exception ignored) {}
        // #endregion
        LandscapeOrientationGuard.enforceForDevice(this);
        initY1LayoutMetrics();
        isFullWidthMenus = A5NavigationMode.forcePortraitThemeRules(this)
                || prefs.getBoolean("full_width_menus", false);
        if (a5) {
            applyA5ScaledSystemChrome();
        }
        applyFullWidthMenusLayout();
        applyReachBrowseLayoutMode();
        applyA5PortraitChrome();
        updateScreenBackground(currentScreenState);
    }

    // #region agent log
    /** 2026-07-14 — Debug 391149 helper: landscape remap recursion sample. */
    private void debug391149LogRemapAbort(int rawCode, int mappedCode) {
        try {
            org.json.JSONObject abort = new org.json.JSONObject();
            abort.put("runId", "freeze-pre");
            abort.put("depth", debug391149A5RemapDepth);
            abort.put("rawCode", rawCode);
            abort.put("mapped", mappedCode);
            abort.put("land", A5NavigationMode.isLandscape(this));
            Debug391149Log.log(this, "MainActivity.dispatchKeyEvent",
                    "RECURSION_ABORT", "H-A", abort);
        } catch (Throwable ignored) {}
    }
    // #endregion

    /**
     * 2026-07-14 — Scale status bar + full NP chrome by landscapeThemeScale (identity in portrait).
     * Layman: shrink the top clock strip and the whole Now Playing page for sideways A5.
     * Reversal: no-op; leave XML dimens alone.
     */
    private void applyA5ScaledSystemChrome() {
        if (!DeviceFeatures.isA5()) return;
        int statusH = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_status_bar_height));
        View statusBar = findViewById(R.id.layout_status_bar);
        if (statusBar != null) {
            ViewGroup.LayoutParams lp = statusBar.getLayoutParams();
            if (lp != null && lp.height != statusH) {
                lp.height = statusH;
                statusBar.setLayoutParams(lp);
            }
        }
        applyA5ScaledNowPlayingLayout();
    }

    /**
     * 2026-07-14 — Full Y1 NP replica on A5 landscape 320×240 (art + info + transport + pads).
     * Was: only art/info cell widths scaled — status/transport pads, −overshoot, and meta rows
     * stayed 360p → sideways NP looked like a portrait stack crushed into 240p, not a mini Y1.
     * Fail-open: tall panel + landscape pref → isLandscape false → portrait stack owns LPs.
     * Layman: shrink the whole Now Playing page the same way as menus.
     * Reversal: scale artW/infoW only; leave XML pads/transport/overshoot alone.
     */
    private void applyA5ScaledNowPlayingLayout() {
        if (!DeviceFeatures.isA5() || playerAlbumContainer == null) return;
        boolean land = A5NavigationMode.isLandscape(this);
        int artW = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_art_width));
        int artSlotH = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_art_slot_height));
        int artCoverH = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_art_cover_height));
        int artOver = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_art_top_overshoot));
        int infoW = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_info_width));
        int infoH = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_info_height));
        int infoML = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_info_margin_left));
        int padLeft = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_content_pad_left));
        int statusH = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_status_bar_height));
        int transportH = A5NavigationMode.scaleLayoutPx(this,
                (int) getResources().getDimension(R.dimen.y1_player_transport_height));
        float dens = getResources().getDisplayMetrics().density;
        int infoPadTop = land
                ? A5NavigationMode.scaleLayoutPx(this, Math.max(1, Math.round(8 * dens)))
                : Math.max(1, Math.round(8 * dens));

        // Content/visualizer pads + transport strip — landscape uses 240p scale; portrait XML/full.
        int contentPadLeft = land ? padLeft
                : (int) getResources().getDimension(R.dimen.y1_player_content_pad_left);
        int contentStatus = land ? statusH
                : (int) getResources().getDimension(R.dimen.y1_status_bar_height);
        int contentTransport = land ? transportH
                : (int) getResources().getDimension(R.dimen.y1_player_transport_height);
        if (playerContentRow != null) {
            playerContentRow.setPadding(contentPadLeft, contentStatus, 0, contentTransport);
        }
        if (playerVisualizerContainer != null) {
            int vizPad = land
                    ? A5NavigationMode.scaleLayoutPx(this, Math.max(1, Math.round(10 * dens)))
                    : Math.max(1, Math.round(10 * dens));
            playerVisualizerContainer.setPadding(vizPad, contentStatus, vizPad, contentTransport);
        }
        View transportBar = findViewById(R.id.player_transport_bar);
        if (transportBar != null) {
            ViewGroup.LayoutParams tlp = transportBar.getLayoutParams();
            if (tlp != null) {
                tlp.height = contentTransport;
                transportBar.setLayoutParams(tlp);
            }
        }

        ViewGroup.LayoutParams alpRaw = playerAlbumContainer.getLayoutParams();
        if (alpRaw instanceof LinearLayout.LayoutParams) {
            LinearLayout.LayoutParams alp = (LinearLayout.LayoutParams) alpRaw;
            if (land) {
                // Scaled Y1: slot height + negative overshoot so cover tops align with info.
                alp.width = artW;
                alp.height = artSlotH;
                alp.weight = 0f;
                alp.leftMargin = 0;
                alp.topMargin = -artOver;
            }
            // Portrait: applyNowPlayingPortrait owns MATCH_PARENT / weight — leave alone.
            playerAlbumContainer.setLayoutParams(alp);
        }
        if (ivAlbumArt != null) {
            ViewGroup.LayoutParams ilp = ivAlbumArt.getLayoutParams();
            if (ilp instanceof FrameLayout.LayoutParams) {
                FrameLayout.LayoutParams flp = (FrameLayout.LayoutParams) ilp;
                if (land) {
                    flp.height = artCoverH;
                    flp.topMargin = artOver;
                    ivAlbumArt.setLayoutParams(flp);
                }
            } else if (ilp != null && land) {
                ilp.height = artCoverH;
                ivAlbumArt.setLayoutParams(ilp);
            }
        }
        if (ivPauseOverlay != null && land) {
            ViewGroup.LayoutParams plp = ivPauseOverlay.getLayoutParams();
            if (plp instanceof FrameLayout.LayoutParams) {
                FrameLayout.LayoutParams flp = (FrameLayout.LayoutParams) plp;
                int pause = A5NavigationMode.scaleLayoutPx(this, Math.max(1, Math.round(70 * dens)));
                flp.width = pause;
                flp.height = pause;
                flp.topMargin = artOver;
                ivPauseOverlay.setLayoutParams(flp);
            }
        }
        if (playerInfoColumn != null) {
            ViewGroup.LayoutParams raw = playerInfoColumn.getLayoutParams();
            if (raw instanceof LinearLayout.LayoutParams) {
                LinearLayout.LayoutParams ilp = (LinearLayout.LayoutParams) raw;
                if (land) {
                    ilp.width = infoW;
                    ilp.height = infoH;
                    ilp.leftMargin = infoML;
                    ilp.weight = 0f;
                    playerInfoColumn.setPadding(playerInfoColumn.getPaddingLeft(), infoPadTop,
                            playerInfoColumn.getPaddingRight(), playerInfoColumn.getPaddingBottom());
                } else {
                    ilp.width = LinearLayout.LayoutParams.MATCH_PARENT;
                    ilp.height = LinearLayout.LayoutParams.WRAP_CONTENT;
                    ilp.leftMargin = 0;
                    ilp.weight = 0f;
                }
                playerInfoColumn.setLayoutParams(ilp);
            }
        }
        // Refresh info bars for current scale (landscape shrink / portrait restore to identity).
        applyPlayerInfoStyle();
    }

    private android.graphics.drawable.Drawable getY1RowBackground(boolean focused, int widthPx, int rowKind) {
        boolean selected = focused;
        android.graphics.drawable.Drawable scaled;
        if (rowKind == Y1_ROW_HOME || rowKind == Y1_ROW_ITEM) {
            scaled = ThemeManager.getItemRowBackgroundScaled(
                    getResources(), selected, widthPx, y1RowHeightPx);
        } else {
            scaled = ThemeManager.getMenuRowBackgroundScaled(
                    getResources(), selected, widthPx, y1RowHeightPx);
        }
        if (scaled != null) return scaled;
        boolean menuRows = rowKind == Y1_ROW_MENU;
        // 2026-07-11 — Empty itemBackground → home may use solid; named but missing PNG → transparent.
        // Was: opaque list fill when Habbo @Be_itemBackground failed to decode. Reversal: always solid.
        if (!selected) {
            if (ThemeManager.y1UnselectedRowTransparent(menuRows)) {
                if (rowKind == Y1_ROW_HOME) {
                    return new android.graphics.drawable.ColorDrawable(ThemeManager.getListButtonNormalBg());
                }
                return new android.graphics.drawable.ColorDrawable(0x00000000);
            }
            return new android.graphics.drawable.ColorDrawable(0x00000000);
        }
        return createButtonBackground(ThemeManager.getRowSelectionFillColor());
    }

    private android.graphics.drawable.Drawable getY1RowBackground(boolean focused, int widthPx) {
        return getY1RowBackground(focused, widthPx, y1RowKindForScreen());
    }

    private int y1ActiveRowWidthPx() {
        if (isFullWidthMenus && screenWidthPx > 0) return screenWidthPx;
        if (currentScreenState == STATE_SETTINGS) {
            if (settingsBrowseFullWidth && screenWidthPx > 0) {
                return screenWidthPx;
            }
            if (soulseekConversationHost != null
                    && soulseekConversationHost.getVisibility() == View.VISIBLE
                    && screenWidthPx > 0) {
                return screenWidthPx;
            }
            return settingsMenuWidthPx > 0 ? settingsMenuWidthPx : y1RowWidthPx;
        }
        if (currentScreenState == STATE_MENU) return y1RowWidthPx;
        return listRowWidthPx;
    }

    private void configureReachListView(ListView list) {
        if (list == null) return;
        Y1ScrollIndicators.applyVerticalListView(list);
        list.setDivider(null);
        list.setSelector(new android.graphics.drawable.ColorDrawable(0));
        list.setItemsCanFocus(true);
        list.setChoiceMode(ListView.CHOICE_MODE_SINGLE);
        list.setDescendantFocusability(ViewGroup.FOCUS_AFTER_DESCENDANTS);
        list.setScrollingCacheEnabled(false);
        // ponytail: smooth scrollbars NPE in View.onDrawScrollBars on API 17 (Y1 Messages inbox).
        list.setSmoothScrollbarEnabled(false);
    }

    private void focusFirstReachBrowseDataRow() {
        if (listReachBrowse == null) return;
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad instanceof ReachInterestsAdapter) {
            ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
            int first = ia.firstSelectablePosition();
            if (first >= 0) {
                int pos = reachBrowseHeaderOffset() + first;
                FocusScrollHelper.focusListPosition(listReachBrowse, pos);
                return;
            }
        }
        if (ad instanceof ReachInboxAdapter) {
            ReachInboxAdapter ia = (ReachInboxAdapter) ad;
            if (SettingsScreens.SOULSEEK_MESSAGES.equals(settingsSubScreenKey)) {
                focusSoulseekMessagesInbox(ia);
                return;
            }
            if (ia.getDataCount() <= 0) {
                if (!reachBrowseHeaderViews.isEmpty()) {
                    focusReachBrowseHeaderIndex(0);
                    return;
                }
                listReachBrowse.requestFocus();
                return;
            }
        }
        if (ad instanceof ReachUsersAdapter) {
            focusFindReachUsersBrowse((ReachUsersAdapter) ad);
            return;
        }
        if (ad instanceof ReachChatRoomsAdapter) {
            focusReachChatRoomsBrowse((ReachChatRoomsAdapter) ad);
            return;
        }
        if (ad == null || ad.getCount() == 0) {
            if (!reachBrowseHeaderViews.isEmpty()) {
                int headerIdx = 0;
                if (SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(settingsSubScreenKey)
                        && reachBrowseHeaderViews.size() >= 2) {
                    headerIdx = 1;
                }
                focusReachBrowseHeaderIndex(headerIdx);
                return;
            }
            listReachBrowse.requestFocus();
            return;
        }
        int pos = reachBrowseHeaderOffset();
        applyReachBrowseAdapterSelection(pos);
        FocusScrollHelper.focusListPosition(listReachBrowse, pos);
    }

    /** Find other Reach users — focus first directory row with adapter highlight synced. */
    private void focusFindReachUsersBrowse(final ReachUsersAdapter ua) {
        if (listReachBrowse == null || ua == null) return;
        listReachBrowse.setSelectionFromTop(0, 0);
        if (ua.getDataCount() <= 0) {
            if (!reachBrowseHeaderViews.isEmpty()) focusReachBrowseHeaderIndex(0);
            return;
        }
        final int listPos = reachBrowseHeaderOffset();
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                ua.setSelectedPosition(0);
                applyReachBrowseAdapterSelection(listPos);
                FocusScrollHelper.focusListPosition(listReachBrowse, listPos);
            }
        });
    }

    /** Chat rooms search results — sync highlight with first selectable room row. */
    private void focusReachChatRoomsBrowse(final ReachChatRoomsAdapter ca) {
        if (listReachBrowse == null || ca == null) return;
        listReachBrowse.setSelectionFromTop(0, 0);
        if (ca.getDataCount() <= 0) {
            int headerIdx = 0;
            if (SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(settingsSubScreenKey)
                    && reachBrowseHeaderViews.size() >= 2) {
                headerIdx = 1;
            }
            if (!reachBrowseHeaderViews.isEmpty()) focusReachBrowseHeaderIndex(headerIdx);
            return;
        }
        final int listPos = reachBrowseHeaderOffset();
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                ca.setSelectedPosition(0);
                applyReachBrowseAdapterSelection(listPos);
                FocusScrollHelper.focusListPosition(listReachBrowse, listPos);
            }
        });
    }

    /** Messages inbox: first conversation when present, else New message (not Back or status row). */
    private void focusSoulseekMessagesInbox(final ReachInboxAdapter ia) {
        if (listReachBrowse == null || ia == null) return;
        // ponytail: reset scroll — prior Reach browse can leave the list scrolled down off-screen.
        listReachBrowse.setSelectionFromTop(0, 0);
        final int dataCount = ia.getDataCount();
        if (dataCount > 0) {
            final int listPos = reachBrowseHeaderOffset();
            ia.setSelectedPosition(0);
            listReachBrowse.post(new Runnable() {
                @Override
                public void run() {
                    applyReachBrowseAdapterSelection(listPos);
                    FocusScrollHelper.focusListPosition(listReachBrowse, listPos);
                    // #region agent log
                    try {
                        org.json.JSONObject d = new org.json.JSONObject();
                        d.put("mode", "first_peer");
                        d.put("listPos", listPos);
                        d.put("dataCount", dataCount);
                        d.put("selected", listReachBrowse.getSelectedItemPosition());
                        DebugSessionLog.log("MainActivity.focusSoulseekMessagesInbox",
                                "focused", "H-M7", d);
                    } catch (Exception ignored) {}
                    // #endregion
                }
            });
            return;
        }
        final int headerIdx = reachBrowseHeaderViews.size() >= 2 ? 1 : 0;
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                focusReachBrowseHeaderIndex(headerIdx);
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("mode", "new_message_header");
                    d.put("headerIdx", headerIdx);
                    d.put("dataCount", dataCount);
                    DebugSessionLog.log("MainActivity.focusSoulseekMessagesInbox",
                            "focused", "H-M7", d);
                } catch (Exception ignored) {}
                // #endregion
            }
        });
    }

    private int indexOfReachBrowseHeader(View v) {
        if (v == null) return -1;
        for (int i = 0; i < reachBrowseHeaderViews.size(); i++) {
            View h = reachBrowseHeaderViews.get(i);
            if (h == v || isViewDescendantOf(v, h)) return i;
        }
        return -1;
    }

    /** Header row for wheel nav — real focus or tracked index when ListView still owns selection. */
    private int reachBrowseActiveHeaderIndex() {
        int idx = indexOfReachBrowseHeader(getCurrentFocus());
        if (idx >= 0) {
            reachBrowseHeaderFocusIdx = idx;
            return idx;
        }
        if (reachBrowseHeaderFocusIdx >= 0 && reachBrowseHeaderFocusIdx < reachBrowseHeaderViews.size()) {
            View h = reachBrowseHeaderViews.get(reachBrowseHeaderFocusIdx);
            if (h != null && (h.hasFocus() || h.isFocused())) return reachBrowseHeaderFocusIdx;
        }
        return -1;
    }

    private boolean focusReachBrowseHeaderIndex(final int idx) {
        if (idx < 0 || idx >= reachBrowseHeaderViews.size()) return false;
        final View h = reachBrowseHeaderViews.get(idx);
        if (h == null || !h.isFocusable()) return false;
        reachBrowseHeaderFocusIdx = idx;
        clearReachBrowseAdapterSelection(listReachBrowse != null ? listReachBrowse.getAdapter() : null);
        if (h.requestFocus()) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("headerIdx", idx);
                d.put("focused", true);
                DebugSessionLog.log("MainActivity.focusReachBrowseHeaderIndex",
                        "chrome focus", "H-HEADER", d);
            } catch (Exception ignored) {}
            // #endregion
            return true;
        }
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                h.requestFocus();
            }
        });
        return true;
    }

    private void clearReachBrowseAdapterSelection(android.widget.ListAdapter ad) {
        if (ad instanceof ReachInboxAdapter) {
            ((ReachInboxAdapter) ad).clearSelectedPosition();
        } else if (ad instanceof ReachUsersAdapter) {
            ((ReachUsersAdapter) ad).clearSelectedPosition();
        } else if (ad instanceof ReachChatRoomsAdapter) {
            ((ReachChatRoomsAdapter) ad).setSelectedPosition(-1);
        } else if (ad instanceof ReachUsersAdapter) {
            ((ReachUsersAdapter) ad).setSelectedPosition(-1);
        } else if (ad instanceof ReachInterestsAdapter) {
            ((ReachInterestsAdapter) ad).setSelectedPosition(-1);
        }
    }

    /** List position for wheel nav — prefer adapter highlight index over ListView selection. */
    private int reachBrowseFocusedListPosition(android.widget.ListAdapter ad) {
        int headerCount = reachBrowseHeaderOffset();
        if (ad instanceof ReachInboxAdapter) {
            int sel = ((ReachInboxAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        } else if (ad instanceof ReachChatRoomsAdapter) {
            int sel = ((ReachChatRoomsAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        } else if (ad instanceof ReachUsersAdapter) {
            int sel = ((ReachUsersAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        } else if (ad instanceof ReachInterestsAdapter) {
            int sel = ((ReachInterestsAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        }
        int pos = listReachBrowse != null ? listReachBrowse.getSelectedItemPosition() : -1;
        if (pos >= headerCount) return pos;
        if (listReachBrowse != null) {
            View focus = getCurrentFocus();
            if (focus != null) {
                int idx = listReachBrowse.getPositionForView(focus);
                if (idx != android.widget.AdapterView.INVALID_POSITION && idx >= headerCount) {
                    return idx;
                }
            }
        }
        return headerCount;
    }

    private int conversationRowWidthPx() {
        return messagingRowWidthPx();
    }

    private int messagingRowWidthPx() {
        if (isFullWidthMenus || settingsBrowseFullWidth) {
            return screenWidthPx > 0 ? screenWidthPx : y1ActiveRowWidthPx();
        }
        return settingsMenuWidthPx > 0 ? settingsMenuWidthPx : y1RowWidthPx;
    }

    private static boolean isReachBrowseScreen(String key) {
        return SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(key)
                || SettingsScreens.SOULSEEK_CHAT_ROOM_THREAD.equals(key)
                || SettingsScreens.SOULSEEK_CHAT_ROOM_WALL.equals(key)
                || SettingsScreens.SOULSEEK_MESSAGES.equals(key)
                || SettingsScreens.SOULSEEK_MESSAGES_THREAD.equals(key)
                || SettingsScreens.SOULSEEK_FIND_REACH.equals(key)
                || SettingsScreens.SOULSEEK_FIND_USER.equals(key)
                || SettingsScreens.SOULSEEK_INTERESTS.equals(key)
                || SettingsScreens.SOULSEEK_USER_PROFILE.equals(key);
    }

    /** Debug / Flow / Report toggles use full-width list rows — labels are too long for dual-pane preview. */
    private static boolean isSettingsFullWidthSubScreen(String key) {
        return SettingsScreens.DEBUG.equals(key)
                || SettingsScreens.FLOW.equals(key)
                || SettingsScreens.EQ.equals(key)
                || SettingsScreens.XPOSED_MODULES.equals(key)
                || SettingsScreens.XPOSED_MODULE_DETAIL.equals(key);
    }

    /**
     * 2026-07-15 — Force full-width list chrome for Reach + media suite catalogs.
     * Layman: big lists (YouTube, radio, videos) use the whole screen, not a skinny left column.
     * Was: Soulseek/Deezer/settings keys only — YouTube detail left an empty dual-pane right side.
     * Reversal: drop MediaSuiteHost.isMediaSuiteState from the OR.
     */
    private void applyReachBrowseLayoutMode() {
        settingsBrowseFullWidth = isReachBrowseScreen(settingsSubScreenKey)
                || isSettingsFullWidthSubScreen(settingsSubScreenKey)
                || currentScreenState == STATE_DEEZER
                || currentScreenState == STATE_SOULSEEK
                || MediaSuiteHost.isMediaSuiteState(currentScreenState);
        applyFullWidthMenusLayout();
    }

    /** @deprecated use applyReachBrowseLayoutMode */
    private void applyMessagingLayoutMode() {
        applyReachBrowseLayoutMode();
    }

    private void showReachBrowseList(boolean show) {
        if (settingsScrollView != null) {
            settingsScrollView.setVisibility(show ? View.GONE : View.VISIBLE);
        }
        if (reachBrowseHost != null) {
            reachBrowseHost.setVisibility(show ? View.VISIBLE : View.GONE);
        }
        if (listReachBrowse != null && show) {
            listReachBrowse.setDescendantFocusability(ViewGroup.FOCUS_AFTER_DESCENDANTS);
        }
        if (soulseekConversationHost != null && show) {
            soulseekConversationHost.setVisibility(View.GONE);
        }
        if (show) {
            stopSettingsPreviewVerticalMarquee();
            if (settingsPreviewPane != null) {
                settingsPreviewPane.setVisibility(View.GONE);
            }
        } else if (settingsPreviewPane != null && !isFullWidthMenus && !settingsAboutFullWidth
                && !settingsBrowseFullWidth) {
            settingsPreviewPane.setVisibility(View.VISIBLE);
        }
    }

    private void clearReachBrowseList() {
        if (listReachBrowse == null) return;
        listReachBrowse.setAdapter(null);
        int headers = listReachBrowse.getHeaderViewsCount();
        for (int i = headers - 1; i >= 0; i--) {
            listReachBrowse.removeHeaderView(listReachBrowse.getChildAt(i));
        }
        // removeHeaderView needs the actual view reference — track headers instead
    }

    private final java.util.ArrayList<View> reachBrowseHeaderViews = new java.util.ArrayList<View>();
    /** Wheel highlight on fixed chrome rows above the peer list (Back / New message). */
    private int reachBrowseHeaderFocusIdx = -1;
    /** Legacy ListView header host — removed when chrome moved outside the list. */
    private LinearLayout reachBrowseHeaderHost;

    private void resetReachBrowseHeaders() {
        if (listReachBrowse == null) return;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("adapterAttached", listReachBrowse.getAdapter() != null);
            d.put("headerCount", reachBrowseHeaderViews.size());
            d.put("listHeaderViews", listReachBrowse.getHeaderViewsCount());
            DebugSessionLog.log("MainActivity.resetReachBrowseHeaders", "before reset", "H-M1", d);
        } catch (Exception ignored) {}
        // #endregion
        listReachBrowse.setAdapter(null);
        listReachBrowse.setOnItemSelectedListener(null);
        if (reachBrowseHeaderHost != null) {
            try {
                listReachBrowse.removeHeaderView(reachBrowseHeaderHost);
            } catch (Exception ignored) {}
            reachBrowseHeaderHost = null;
        }
        if (reachBrowseChromeHost != null) {
            reachBrowseChromeHost.removeAllViews();
        }
        reachBrowseHeaderViews.clear();
        reachBrowseHeaderFocusIdx = -1;
    }

    private void ensureReachBrowseHeaderHost() {
        if (reachBrowseChromeHost == null) return;
        // Fixed chrome host is declared in activity_main.xml — no ListView header view.
    }

    private void addReachBrowseHeader(View header) {
        if (header == null) return;
        ensureReachBrowseHeaderHost();
        if (reachBrowseChromeHost == null) return;
        header.setLayoutParams(new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT));
        reachBrowseChromeHost.addView(header);
        reachBrowseHeaderViews.add(header);
    }

    /** Chrome rows sit outside the ListView — adapter index equals list position. */
    private int reachBrowseHeaderOffset() {
        return 0;
    }

    private int reachBrowseAdapterIndex(int listPosition) {
        return listPosition - reachBrowseHeaderOffset();
    }

    private void applyReachBrowseAdapterSelection(int listPosition) {
        if (listReachBrowse == null) return;
        if (listPosition >= reachBrowseHeaderOffset()) {
            reachBrowseHeaderFocusIdx = -1;
        }
        int adapterIndex = reachBrowseAdapterIndex(listPosition);
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad instanceof ReachChatRoomsAdapter) {
            ((ReachChatRoomsAdapter) ad).setSelectedPosition(adapterIndex);
        } else if (ad instanceof ReachInboxAdapter) {
            ((ReachInboxAdapter) ad).setSelectedPosition(adapterIndex);
        } else if (ad instanceof ReachUsersAdapter) {
            ((ReachUsersAdapter) ad).setSelectedPosition(adapterIndex);
        } else if (ad instanceof ReachInterestsAdapter) {
            ((ReachInterestsAdapter) ad).setSelectedPosition(adapterIndex);
        }
    }

    private void onReachBrowseListItemSelected(int listPosition) {
        if (listReachBrowse == null) return;
        int adapterIndex = reachBrowseAdapterIndex(listPosition);
        if (adapterIndex < 0) return;
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad instanceof ReachInterestsAdapter) {
            ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
            if (!ia.isSelectable(adapterIndex)) return;
        }
        applyReachBrowseAdapterSelection(listPosition);
        if (ad instanceof ReachChatRoomsAdapter) {
            ReachChatRoomsAdapter ca = (ReachChatRoomsAdapter) ad;
            if (ca.isShowMorePosition(adapterIndex)) {
                ca.showMore();
                return;
            }
        }
        if (ad instanceof ReachInboxAdapter) {
            String peer = ((ReachInboxAdapter) ad).peerAt(adapterIndex);
            if (peer != null) watchSoulseekPeer(peer);
        } else if (ad instanceof ReachUsersAdapter) {
            ReachDirectoryUser u = ((ReachUsersAdapter) ad).userAt(adapterIndex);
            if (u != null) watchSoulseekPeer(u.username);
        }
    }

    private boolean isReachBrowseListActive() {
        return currentScreenState == STATE_SETTINGS
                && reachBrowseHost != null
                && reachBrowseHost.getVisibility() == View.VISIBLE
                && listReachBrowse != null
                && listReachBrowse.getAdapter() != null;
    }

    private boolean isReachBrowseFocusValid() {
        if (!isReachBrowseListActive()) return false;
        View f = getCurrentFocus();
        if (f != null && f.isShown() && f.isFocusable()) {
            if (indexOfReachBrowseHeader(f) >= 0) return true;
            if (listReachBrowse != null && isViewDescendantOf(f, listReachBrowse)) return true;
        }
        if (reachBrowseHeaderFocusIdx >= 0 && reachBrowseHeaderFocusIdx < reachBrowseHeaderViews.size()) {
            View h = reachBrowseHeaderViews.get(reachBrowseHeaderFocusIdx);
            if (h != null && h.isShown() && (h.hasFocus() || h.isFocused())) return true;
        }
        return false;
    }

    /** Re-seed wheel focus when Reach browse list lost highlight (API 17 ListView quirk). */
    private boolean ensureReachBrowseListFocus() {
        if (!isReachBrowseListActive()) return false;
        if (isReachBrowseFocusValid()) return false;
        focusFirstReachBrowseDataRow();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("screen", settingsSubScreenKey);
            DebugSessionLog.log("MainActivity.ensureReachBrowseListFocus", "reseed", "H-FOCUS1", d);
        } catch (Exception ignored) {}
        // #endregion
        return true;
    }

    /**
     * 2026-07-17 — Home + Settings (and similar) wheel before focused children eat DPAD.
     * Same API-17 trap as Reach/browser: after first notch, focus sits on a row and
     * {@code super.dispatchKeyEvent} never reaches {@link #onKeyDown} for DPAD 19/20.
     * MEDIA_PLAY/PAUSE (real Y1 wheel) also routed here for one consistent path.
     */
    private boolean handleHomeSettingsMenuWheelKeyDown(int keyCode, KeyEvent event) {
        if (event == null || event.getAction() != KeyEvent.ACTION_DOWN) return false;
        if (!Y1InputKeys.isWheelKey(keyCode)) return false;
        if (themedContextMenuOwnsKeys()) return false;
        if (usbEnablePromptSession || isUsbEnablePromptShowing()) return false;
        if (isUsbMassStorageUiLocked()
                && !(usbEnablePromptSession || isUsbEnablePromptShowing())) {
            return false; // USB lock path above already toasts
        }
        if (currentScreenState == STATE_MENU) {
            boolean moved = applyWheelAccelFocus(keyCode, event, new WheelFocusMover() {
                @Override
                public boolean move(int delta) {
                    return moveHomeMenuFocus(delta);
                }
            }, true);
            if (moved) clickFeedback();
            return true; // consume even at edge so focused row cannot steal DPAD
        }
        if (currentScreenState == STATE_SETTINGS && !isThemeListActive()
                && !isConversationThreadActive() && !isReachBrowseListActive()) {
            boolean moved = applyWheelAccelFocus(keyCode, event, new WheelFocusMover() {
                @Override
                public boolean move(int delta) {
                    return moveSettingsListFocus(delta);
                }
            }, true);
            if (moved) clickFeedback();
            return true;
        }
        if (currentScreenState == STATE_MORE || currentScreenState == STATE_APPS
                || currentScreenState == STATE_BLUETOOTH) {
            // Fall through to existing onKeyDown handlers via super — only home/settings
            // need early intercept for focusable LinearLayout rows.
            return false;
        }
        return false;
    }

    /**
     * Reach Messages / chat rooms / conversation thread wheel nav.
     * ponytail: DPAD_UP/DOWN (19/20) are swallowed by ListView before Activity.onKeyDown on API 17 —
     * call from dispatchKeyEvent before super so index-driven highlight always runs.
     */
    private boolean handleReachSettingsWheelKeyDown(int keyCode, KeyEvent event) {
        if (currentScreenState != STATE_SETTINGS || event.getAction() != KeyEvent.ACTION_DOWN) {
            return false;
        }
        if (!Y1InputKeys.isWheelKey(keyCode)) return false;
        if (isThemeListActive()) return false;
        if (isConversationThreadActive()) {
            int delta = Y1InputKeys.isWheelUp(keyCode) ? -1 : 1;
            if (moveConversationListFocus(delta) || ensureConversationListFocus()) {
                clickFeedback();
            }
            return true;
        }
        if (!isReachBrowseListActive()) return false;
        // 2026-07-19 — Pace Reach browse wheel paints (≥48 ms) like home/settings.
        boolean moved = applyWheelAccelFocus(keyCode, event, new WheelFocusMover() {
            @Override
            public boolean move(int delta) {
                return moveReachBrowseListFocus(delta) || ensureReachBrowseListFocus();
            }
        }, true);
        if (moved) clickFeedback();
        // #region agent log
        if (event.getRepeatCount() == 0) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("keyCode", keyCode);
                d.put("moved", moved);
                d.put("screen", settingsSubScreenKey);
                DebugSessionLog.log("MainActivity.handleReachSettingsWheelKeyDown",
                        "reach wheel handled", "H-DISPATCH", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        return true;
    }

    private void focusReachBrowseListPosition(int listPosition) {
        reachBrowseHeaderFocusIdx = -1;
        applyReachBrowseAdapterSelection(listPosition);
        FocusScrollHelper.focusListPosition(listReachBrowse, listPosition);
    }

    private boolean moveReachBrowseListFocus(int delta) {
        if (!isReachBrowseListActive() || delta == 0) return false;
        int headerIdx = reachBrowseActiveHeaderIndex();
        if (headerIdx >= 0) {
            int nextHeader = headerIdx + (delta < 0 ? -1 : 1);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("headerIdx", headerIdx);
                d.put("nextHeader", nextHeader);
                d.put("delta", delta);
                DebugSessionLog.log("MainActivity.moveReachBrowseListFocus",
                        "header step", "H-HEADER", d);
            } catch (Exception ignored) {}
            // #endregion
            if (nextHeader >= 0 && nextHeader < reachBrowseHeaderViews.size()) {
                return focusReachBrowseHeaderIndex(nextHeader);
            }
            if (delta > 0) {
                android.widget.ListAdapter ad = listReachBrowse.getAdapter();
                int adapterRows = ad != null ? ad.getCount() : 0;
                if (adapterRows > 0) {
                    int headerCount = reachBrowseHeaderOffset();
                    int next = headerCount;
                    if (ad instanceof ReachInterestsAdapter) {
                        ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ia.isSelectable(next - headerCount)) next++;
                    } else if (ad instanceof ReachUsersAdapter) {
                        ReachUsersAdapter ua = (ReachUsersAdapter) ad;
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ua.isWheelSelectable(next - headerCount)) next++;
                    } else if (ad instanceof ReachChatRoomsAdapter) {
                        ReachChatRoomsAdapter ca = (ReachChatRoomsAdapter) ad;
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ca.isWheelSelectable(next - headerCount)) next++;
                    } else {
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ad.isEnabled(next - headerCount)) next++;
                    }
                    if (next <= headerCount + adapterRows - 1) {
                        focusReachBrowseListPosition(next);
                        return true;
                    }
                }
            }
            return false;
        }
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad == null) return false;
        int adapterRows = ad.getCount();
        int headerCount = reachBrowseHeaderOffset();
        if (adapterRows <= 0) {
            if (!reachBrowseHeaderViews.isEmpty()) {
                int idx = delta < 0 ? reachBrowseHeaderViews.size() - 1 : 0;
                return focusReachBrowseHeaderIndex(idx);
            }
            return false;
        }
        int pos = reachBrowseFocusedListPosition(ad);
        int next = pos + (delta < 0 ? -1 : 1);
        int maxPos = headerCount + adapterRows - 1;
        if (delta < 0 && next < headerCount) {
            return focusReachBrowseHeaderIndex(reachBrowseHeaderViews.size() - 1);
        }
        if (ad instanceof ReachInterestsAdapter) {
            ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
            while (next >= headerCount && next <= maxPos) {
                int adapterIndex = next - headerCount;
                if (ia.isSelectable(adapterIndex)) break;
                next += (delta < 0 ? -1 : 1);
            }
        } else if (ad instanceof ReachUsersAdapter) {
            ReachUsersAdapter ua = (ReachUsersAdapter) ad;
            if (delta > 0) {
                int adapterIndex = pos - headerCount;
                if (adapterIndex == ua.getDataCount() - 1 && ua.hasShowMoreRow()) {
                    ua.showMore();
                    return true;
                }
            }
            while (next >= headerCount && next <= maxPos) {
                int adapterIndex = next - headerCount;
                if (ua.isWheelSelectable(adapterIndex)) break;
                next += (delta < 0 ? -1 : 1);
            }
        } else if (ad instanceof ReachChatRoomsAdapter) {
            ReachChatRoomsAdapter ca = (ReachChatRoomsAdapter) ad;
            if (delta > 0) {
                int adapterIndex = pos - headerCount;
                if (adapterIndex == ca.getDataCount() - 1 && ca.hasShowMoreRow()) {
                    ca.showMore();
                    return true;
                }
            }
            while (next >= headerCount && next <= maxPos) {
                int adapterIndex = next - headerCount;
                if (ca.isWheelSelectable(adapterIndex)) break;
                next += (delta < 0 ? -1 : 1);
            }
        } else {
            while (next >= headerCount && next <= maxPos && !ad.isEnabled(next - headerCount)) {
                next += (delta < 0 ? -1 : 1);
            }
        }
        if (next < headerCount || next > maxPos) {
            // ponytail: disabled/status rows can decrement next below headerCount — step to header, not dead-end.
            if (delta < 0 && next < headerCount && !reachBrowseHeaderViews.isEmpty()) {
                return focusReachBrowseHeaderIndex(reachBrowseHeaderViews.size() - 1);
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("delta", delta);
                d.put("pos", pos);
                d.put("next", next);
                d.put("screen", settingsSubScreenKey);
                DebugSessionLog.log("MainActivity.moveReachBrowseListFocus", "at limit", "H-FOCUS3", d);
            } catch (Exception ignored) {}
            // #endregion
            return false;
        }
        focusReachBrowseListPosition(next);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("delta", delta);
            d.put("next", next);
            d.put("adapterRows", adapterRows);
            d.put("screen", settingsSubScreenKey);
            DebugAgentLog.log(this, "MainActivity.moveReachBrowseListFocus",
                    "adapter row focus", "H-CHAT", d);
        } catch (Exception ignored) {}
        // #endregion
        return true;
    }

