    private void applyAllSettingsRowStyles() {
        if (containerSettingsItems == null) return;
        View focused = getCurrentFocus();
        for (int i = 0; i < containerSettingsItems.getChildCount(); i++) {
            View row = containerSettingsItems.getChildAt(i);
            if (!(row instanceof LinearLayout)) continue;
            boolean hasFocus = row == focused;
            TextView tvLeft = null;
            TextView tvRight = null;
            ImageView arrow = null;
            LinearLayout layout = (LinearLayout) row;
            for (int j = 0; j < layout.getChildCount(); j++) {
                View child = layout.getChildAt(j);
                if (child instanceof TextView) {
                    if ("inline_state".equals(child.getTag())) tvRight = (TextView) child;
                    else if (tvLeft == null) tvLeft = (TextView) child;
                } else if (child instanceof ImageView) {
                    arrow = (ImageView) child;
                }
            }
            if (tvLeft != null) {
                int rowW = row.getWidth() > 0 ? row.getWidth() : y1ActiveRowWidthPx();
                applyY1ListRowStyle(row, hasFocus, tvLeft, tvRight, arrow, Y1_ROW_MENU);
            }
        }
    }

    private void applyY1ListRowStyle(View row, boolean focused, TextView label, TextView value,
                                     ImageView arrow, int rowKind) {
        int w = row.getWidth() > 0 ? row.getWidth() : y1ActiveRowWidthPx();
        // PR #23: prefer StateListDrawable set once at create; only paint if missing.
        if (!(row.getBackground() instanceof android.graphics.drawable.StateListDrawable)) {
            row.setBackground(getY1RowStateBackground(w, rowKind));
        }
        row.setSelected(focused);
        if (label != null) {
            label.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
            ThemeManager.applyThemedTextStyle(label, focused
                    ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
            label.setSelected(focused);
            // 2026-07-19 — Skip marquee start while spinning (animation tax every notch).
            if (focused && !scrollIdleGate.isSpinning()) enableMarquee(label);
            else {
                label.setEllipsize(TextUtils.TruncateAt.END);
                label.setHorizontallyScrolling(false);
            }
        }
        if (value != null) {
            String t = value.getText().toString();
            if (t.equals("ON") || t.equals("ONE") || t.equals("ALL") || t.equals("OFF"))
                ThemeManager.applyThemedTextStyle(value, focused
                        ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
            else if (!t.isEmpty())
                ThemeManager.applyThemedTextStyle(value, focused
                        ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
            if (!scrollIdleGate.isSpinning()) enableMarquee(value);
        }
        if (arrow != null) arrow.setVisibility(focused ? View.VISIBLE : View.GONE);
    }

    private void applyY1ListRowStyle(View row, boolean focused, TextView label, TextView value, ImageView arrow) {
        applyY1ListRowStyle(row, focused, label, value, arrow, y1RowKindForScreen());
    }

    /** Menu rows survive under NP/Flow — defer connectivity scan + removeAllViews until slide ends. */
    private boolean shouldDeferHomeMenuRebuild(int leavingScreen, boolean deferOutgoingHide) {
        if (!deferOutgoingHide || containerHomeMenuItems == null) return false;
        if (containerHomeMenuItems.getChildCount() <= 0) return false;
        return leavingScreen == STATE_PLAYER || leavingScreen == STATE_FLOW;
    }

    private void buildHomeMenu() {
        if (containerHomeMenuItems == null) return;
        if (android.os.Looper.myLooper() != android.os.Looper.getMainLooper()) {
            runOnUiThread(new Runnable() {
                @Override public void run() { buildHomeMenu(); }
            });
            return;
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("buildGen", homeMenuBuildGen + 1);
            d.put("prevChildCount", containerHomeMenuItems.getChildCount());
            d.put("thread", Thread.currentThread().getName());
            DebugAgentLog.log(this, "MainActivity.buildHomeMenu", "build start", "H-E", d);
        } catch (Exception ignored) {}
        // #endregion
        if (ActiveThemeEngine.isJjMode()) {
            buildJjHomeMenu();
            return;
        }
        if (menuScroll != null) menuScroll.setVisibility(View.VISIBLE);
        if (jjHomeOverlay != null && menuListHost != null) {
            menuListHost.removeView(jjHomeOverlay);
            jjHomeOverlay = null;
        }
        final int buildGen = ++homeMenuBuildGen;
        final boolean online = ConnectivityHelper.isOnline(this);
        final boolean onLan = ConnectivityHelper.hasLocalNetwork(this);
        homeMenuEntries = HomeMenuConfig.loadVisibleForDisplay(prefs, online, onLan);
        final boolean showNowPlaying = shouldShowNowPlayingHome();
        if (showNowPlaying) {
            boolean hasNowPlaying = false;
            for (HomeMenuConfig.Entry e : homeMenuEntries) {
                if (HomeMenuConfig.ID_NOW_PLAYING.equals(e.id)) {
                    hasNowPlaying = true;
                    break;
                }
            }
            if (!hasNowPlaying) {
                HomeMenuConfig.Entry np = HomeMenuConfig.find(HomeMenuConfig.ID_NOW_PLAYING);
                if (np != null) homeMenuEntries.add(0, np);
            }
        }
        // 2026-07-15 — FM production: Radio home tile always eligible (Internet still experiment).
        // Was: strip Radio unless Debug → Radio experiment. Reversal: restore radioExperimentOn filter.
        java.util.Iterator<HomeMenuConfig.Entry> homeIt = homeMenuEntries.iterator();
        while (homeIt.hasNext()) {
            HomeMenuConfig.Entry he = homeIt.next();
            if (HomeMenuConfig.ID_NOW_PLAYING.equals(he.id) && !showNowPlaying) {
                homeIt.remove();
            }
        }
        final boolean showMore = HomeMenuConfig.shouldShowMoreTile(prefs, online, onLan);
        final boolean showDegradedBanner =
                SolarRecoveryCoordinator.shouldShowPlatformDegradedBanner(this);
        int totalRows = homeMenuEntries.size() + (showMore ? 1 : 0)
                + (showDegradedBanner ? 1 : 0);
        if (focusedHomeMenuIndex >= totalRows) {
            focusedHomeMenuIndex = Math.max(0, totalRows - 1);
            if (menuScroll != null) menuScroll.scrollTo(0, 0);
        }
        // ponytail: build off-container first — stale-gen abort must not leave removeAllViews() with 0 rows.
        final java.util.ArrayList<View> pendingRows = new java.util.ArrayList<View>(totalRows);
        if (showDegradedBanner) {
            if (buildGen != homeMenuBuildGen) return;
            pendingRows.add(createPlatformDegradedHomeRow());
        }
        for (int i = 0; i < homeMenuEntries.size(); i++) {
            if (buildGen != homeMenuBuildGen) {
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("staleGen", buildGen);
                    d.put("currentGen", homeMenuBuildGen);
                    d.put("abortedAtRow", i);
                    d.put("childCount", containerHomeMenuItems.getChildCount());
                    DebugAgentLog.log(this, "MainActivity.buildHomeMenu",
                            "stale build aborted", "H-HOME-B", d);
                } catch (Exception ignored) {}
                // #endregion
                return;
            }
            pendingRows.add(createHomeMenuRow(homeMenuEntries.get(i), i));
        }
        if (showMore) {
            if (buildGen != homeMenuBuildGen) return;
            pendingRows.add(createHomeMoreTileRow(homeMenuEntries.size()));
        }
        if (buildGen != homeMenuBuildGen) return;
        containerHomeMenuItems.removeAllViews();
        if (menuScroll != null) menuScroll.scrollTo(0, 0);
        for (View row : pendingRows) {
            containerHomeMenuItems.addView(row, homeMenuRowLayoutParams());
        }
        int panelH = menuListHeightPx > 0 ? menuListHeightPx
                : (int) getResources().getDimension(R.dimen.y1_menu_height);
        applyMenuPanelBackground(menuListHost, y1RowWidthPx, panelH,
                (int) getResources().getDimension(R.dimen.y1_menu_height));
        if (buildGen != homeMenuBuildGen) return;
        int childCount = containerHomeMenuItems.getChildCount();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("buildGen", buildGen);
            d.put("expectedRows", totalRows);
            d.put("childCount", childCount);
            d.put("entryCount", homeMenuEntries.size());
            d.put("showMore", showMore);
            d.put("showNowPlaying", showNowPlaying);
            d.put("menuListHeightPx", menuListHeightPx);
            d.put("focusedIndex", focusedHomeMenuIndex);
            java.util.Set<String> idSet = new java.util.HashSet<String>();
            boolean dupEntryIds = false;
            org.json.JSONArray entryIds = new org.json.JSONArray();
            for (HomeMenuConfig.Entry e : homeMenuEntries) {
                entryIds.put(e.id);
                if (!idSet.add(e.id)) dupEntryIds = true;
            }
            d.put("entryIds", entryIds);
            d.put("dupEntryIds", dupEntryIds);
            org.json.JSONArray rowLabels = new org.json.JSONArray();
            java.util.Set<String> labelSet = new java.util.HashSet<String>();
            boolean dupLabels = false;
            boolean musicTwice = false;
            int musicCount = 0;
            for (int i = 0; i < childCount; i++) {
                View row = containerHomeMenuItems.getChildAt(i);
                String lbl = "";
                if (row != null) {
                    TextView tv = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
                    if (tv != null && tv.getText() != null) lbl = tv.getText().toString();
                }
                rowLabels.put(i + ":" + lbl);
                if (!lbl.isEmpty() && !labelSet.add(lbl)) dupLabels = true;
                if (getString(R.string.home_menu_music).equals(lbl)) musicCount++;
            }
            d.put("rowLabels", rowLabels);
            d.put("dupLabels", dupLabels);
            d.put("musicLabelCount", musicCount);
            d.put("musicTwice", musicCount >= 2);
            if (menuScroll != null && containerHomeMenuItems != null) {
                d.put("scrollY", menuScroll.getScrollY());
                d.put("scrollHeight", menuScroll.getHeight());
                d.put("contentHeight", containerHomeMenuItems.getHeight());
            }
            d.put("countMismatch", childCount != totalRows);
            d.put("panelSolid", false);
            d.put("thread", Thread.currentThread().getName());
            DebugAgentLog.log(this, "MainActivity.buildHomeMenu", "home menu built", "H-HOME", d);
            // #region agent log
            try {
                org.json.JSONObject ds = new org.json.JSONObject();
                ds.put("childCount", childCount);
                ds.put("totalRows", totalRows);
                ds.put("entryCount", homeMenuEntries.size());
                ds.put("focusedIndex", focusedHomeMenuIndex);
                ds.put("buildGen", buildGen);
                DebugSessionLog.log("MainActivity.buildHomeMenu", "home built", "H-HOME", ds);
            } catch (Exception ignored) {}
            // #endregion
        } catch (Exception ignored) {}
        // #endregion
        if (childCount != totalRows) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("expected", totalRows);
                d.put("actual", childCount);
                DebugAgentLog.log(this, "MainActivity.buildHomeMenu", "row count mismatch", "H-B", d);
            } catch (Exception ignored) {}
        }
        if (childCount == 0 && totalRows > 0) {
            scheduleRebuildHomeMenuIfVisible();
        }
        scrollHomeMenuToIndex(focusedHomeMenuIndex);
        refreshHomeMenuRowStyles();
        if (containerHomeMenuItems != null) containerHomeMenuItems.requestLayout();
        // 2026-07-16 — Home painted; first-ready wait can lift if prep is done.
        if (firstReadyOverlayActive) {
            scheduleFirstReadyCheck(200L);
        }
        nowPlayingHomeMenuVisible = shouldShowNowPlayingHome();
    }

    /** JJ experimental home: absolute {@code main_menu[]} layout from active JJ theme. */
    private void buildJjHomeMenu() {
        if (android.os.Looper.myLooper() != android.os.Looper.getMainLooper()) {
            runOnUiThread(new Runnable() {
                @Override public void run() { buildJjHomeMenu(); }
            });
            return;
        }
        final int buildGen = ++homeMenuBuildGen;
        clearHomeMenuPreviewCache();
        lastHomeMenuRowStyleFocus = -1;
        containerHomeMenuItems.removeAllViews();
        if (menuScroll != null) menuScroll.setVisibility(View.GONE);
        if (jjHomeOverlay != null && menuListHost != null) {
            menuListHost.removeView(jjHomeOverlay);
            jjHomeOverlay = null;
        }
        if (menuListHost == null) return;

        float density = getResources().getDisplayMetrics().density;
        jjHomeOverlay = new FrameLayout(this);
        jjHomeOverlay.setFocusable(false);
        menuListHost.addView(jjHomeOverlay, new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT));

        JjThemeManager.ThemeData theme = JjThemeManager.getCurrentTheme();
        int panelH = menuListHeightPx > 0 ? menuListHeightPx
                : (int) getResources().getDimension(R.dimen.y1_menu_height);
        applyMenuPanelBackground(menuListHost, y1RowWidthPx, panelH,
                (int) getResources().getDimension(R.dimen.y1_menu_height));

        final List<JjThemeManager.MenuElement> elements = theme.menuElements;
        int focusIdx = 0;
        for (int i = 0; i < elements.size(); i++) {
            if (buildGen != homeMenuBuildGen) return;
            final JjThemeManager.MenuElement el = elements.get(i);
            if (!"button".equals(el.type)) continue;
            final int rowIdx = i;
            Button btn = createListButton(el.textNormal != null && !el.textNormal.isEmpty()
                    ? el.textNormal : " ");
            int w = el.width > 0 ? (int) (el.width * density) : y1ActiveRowWidthPx();
            int h = el.height > 0 ? (int) (el.height * density) : y1RowHeightPx;
            FrameLayout.LayoutParams lp = new FrameLayout.LayoutParams(w, h);
            lp.leftMargin = (int) (el.x * density);
            lp.topMargin = (int) (el.y * density);
            final String homeId = mapJjActionToHomeId(el.action);
            btn.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    clickFeedback();
                    if (homeId != null) onHomeMenuActivate(homeId);
                }
            });
            btn.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    if (hasFocus) {
                        focusedHomeMenuIndex = rowIdx;
                        updateStatusBarTitle();
                    }
                }
            });
            jjHomeOverlay.addView(btn, lp);
            if (el.focusIndex > 0 && focusIdx == 0) {
                focusIdx = rowIdx;
            }
        }
        if (buildGen != homeMenuBuildGen) return;
        if (jjHomeOverlay.getChildCount() > 0) {
            int child = Math.min(focusedHomeMenuIndex, jjHomeOverlay.getChildCount() - 1);
            if (child < 0) child = 0;
            jjHomeOverlay.getChildAt(child).requestFocus();
        }
    }

    private String mapJjActionToHomeId(String action) {
        if (action == null) return null;
        if ("OPEN_PLAYER".equals(action)) return HomeMenuConfig.ID_NOW_PLAYING;
        if ("OPEN_BROWSER".equals(action)) return HomeMenuConfig.ID_MUSIC;
        if ("OPEN_BLUETOOTH".equals(action)) return HomeMenuConfig.ID_BLUETOOTH;
        if ("OPEN_SETTINGS".equals(action)) return HomeMenuConfig.ID_SETTINGS;
        if ("OPEN_WEBSERVER".equals(action)) return HomeMenuConfig.ID_PC_UPLOAD;
        return null;
    }

    private void applyJjThemeSelection(int index) {
        ActiveThemeEngine.applyJjThemeIndex(this, index);
        JjThemeManager.ThemeData theme = JjThemeManager.availableThemes.get(index);
        Toast.makeText(this, getString(R.string.toast_theme_applied, theme.name), Toast.LENGTH_SHORT).show();
        applyThemeToMainMenu();
        scheduleRebuildHomeMenuIfVisible();
        rebuildThemeBrowserRows();
        refreshThemeBrowserList();
    }

    private LinearLayout.LayoutParams homeMenuRowLayoutParams() {
        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                isFullWidthMenus ? LinearLayout.LayoutParams.MATCH_PARENT : y1ActiveRowWidthPx(),
                y1RowHeightPx);
        lp.setMargins(0, 1, 0, 1);
        return lp;
    }

    private FrameLayout createHomeMenuRow(final HomeMenuConfig.Entry entry, final int idx) {
        FrameLayout row = createHomeMenuRowShell(y1HomeArrowExtraInsetPx());
        TextView label = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
        ImageView arrow = (ImageView) row.getTag(HOME_MENU_TAG_ARROW);
        label.setText(getString(entry.labelResId));
        row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                if (hasFocus) {
                    focusedHomeMenuIndex = idx;
                    updateStatusBarTitle();
                    // 2026-07-19 — Was sync updateHomeMenuPreview; raced deferred path + hitch every notch.
                    // Layman: highlight moves now; cover pane waits for dial pause.
                    // Technical: idle-gate + schedule only. Reversal: call updateHomeMenuPreview(idx) here.
                    scrollIdleGate.markActivity();
                    ensureScrollIdleGateListener();
                    scheduleHomeMenuPreviewUpdate(idx);
                }
                refreshHomeMenuRowStyles();
            }
        });
        row.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                onHomeMenuActivate(entry.id);
            }
        });
        applyY1ListRowStyle(row, idx == focusedHomeMenuIndex, label, null, arrow, Y1_ROW_HOME);
        attachA5RowLongPress(row);
        return row;
    }

    /** 2026-07-05 — One-time home row when platform prep left gaps (non-blocking). */
    private FrameLayout createPlatformDegradedHomeRow() {
        FrameLayout row = createHomeMenuRowShell(y1HomeArrowExtraInsetPx());
        TextView label = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
        ImageView arrow = (ImageView) row.getTag(HOME_MENU_TAG_ARROW);
        label.setText(getString(R.string.home_platform_degraded));
        if (arrow != null) arrow.setVisibility(View.GONE);
        row.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                SolarRecoveryCoordinator.dismissPlatformDegradedBanner(MainActivity.this);
                changeScreen(STATE_SETTINGS);
                setSettingsSubScreen(SettingsScreens.DEVICE);
            }
        });
        applyY1ListRowStyle(row, false, label, null, arrow, Y1_ROW_HOME);
        return row;
    }

    private FrameLayout createHomeMoreTileRow(final int idx) {
        FrameLayout row = createHomeMenuRowShell(y1HomeArrowExtraInsetPx());
        TextView label = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
        ImageView arrow = (ImageView) row.getTag(HOME_MENU_TAG_ARROW);
        label.setText(getString(R.string.home_menu_more));
        arrow.setVisibility(View.VISIBLE);
        row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                if (hasFocus) {
                    focusedHomeMenuIndex = idx;
                    updateStatusBarTitle();
                    ivMenuPreview.setVisibility(View.GONE);
                    if (tvMenuPreviewTitle != null) tvMenuPreviewTitle.setVisibility(View.GONE);
                    if (tvMenuPreviewArtist != null) tvMenuPreviewArtist.setVisibility(View.GONE);
                }
                refreshHomeMenuRowStyles();
            }
        });
        row.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                onHomeMenuActivate(HomeMenuConfig.ID_MORE);
            }
        });
        applyY1ListRowStyle(row, idx == focusedHomeMenuIndex, label, null, arrow, Y1_ROW_HOME);
        return row;
    }

    /** Home list host has no outer padding — nudge selection arrows left so they are not clipped. */
    private int y1HomeArrowExtraInsetPx() {
        return (int) getResources().getDimension(R.dimen.y1_home_arrow_extra_inset);
    }

    /** ponytail: ListView recycles rows — tag label/arrow on shell for getView */
    private FrameLayout createHomeMenuRowShell() {
        return createHomeMenuRowShell(0);
    }

    private FrameLayout createHomeMenuRowShell(int extraArrowInsetEndPx) {
        int textPadLeft = (int) getResources().getDimension(R.dimen.y1_menu_text_pad_left);
        float menuTextPx = getResources().getDimension(R.dimen.y1_menu_text_size);
        Bitmap arrowBmp = ThemeManager.getScaledItemRightArrow(y1RowHeightPx);
        int[] arrowLayout = y1ArrowLayout(arrowBmp, extraArrowInsetEndPx);
        int arrowMarginEnd = (int) getResources().getDimension(R.dimen.y1_arrow_margin_end)
                + extraArrowInsetEndPx;

        FrameLayout row = new FrameLayout(this) {
            @Override
            public void setOnClickListener(OnClickListener l) {
                if (l == null) {
                    super.setOnClickListener(null);
                    return;
                }
                // 2026-07-15 — A5 home rows: short-tap open (A5FocusConfirm touch UP).
                super.setOnClickListener(A5FocusConfirm.wrap(this, l));
            }
        };
        row.setFocusable(true);
        row.setFocusableInTouchMode(true);
        A5FocusConfirm.prepareRow(row);
        row.setSoundEffectsEnabled(false);

        TextView label = new TextView(this);
        label.setFocusable(false);
        label.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        label.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX, menuTextPx);
        label.setSingleLine(true);
        label.setEllipsize(TextUtils.TruncateAt.END);
        label.setGravity(android.view.Gravity.CENTER_VERTICAL | android.view.Gravity.START);
        label.setIncludeFontPadding(false);
        label.setBackgroundColor(0x00000000);
        ThemeManager.applyThemedTextStyle(label, ThemeManager.getHomeMenuTextColorNormal());
        FrameLayout.LayoutParams labelLp = new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT);
        labelLp.gravity = android.view.Gravity.CENTER_VERTICAL;
        labelLp.leftMargin = textPadLeft;
        labelLp.rightMargin = arrowLayout[2];
        row.addView(label, labelLp);

        ImageView arrow = new ImageView(this);
        arrow.setFocusable(false);
        arrow.setScaleType(ImageView.ScaleType.FIT_CENTER);
        if (arrowBmp != null) arrow.setImageBitmap(arrowBmp);
        arrow.setVisibility(View.GONE);
        FrameLayout.LayoutParams arrowLp = new FrameLayout.LayoutParams(arrowLayout[0], arrowLayout[1]);
        arrowLp.gravity = android.view.Gravity.CENTER_VERTICAL | android.view.Gravity.END;
        arrowLp.rightMargin = arrowMarginEnd;
        row.addView(arrow, arrowLp);

        row.setTag(HOME_MENU_TAG_LABEL, label);
        row.setTag(HOME_MENU_TAG_ARROW, arrow);
        // PR #23: assign StateListDrawable once; focus walks flip state only.
        row.setBackground(getY1RowStateBackground(y1ActiveRowWidthPx(), Y1_ROW_HOME));
        return row;
    }

    /** Coalesce home scroll posts — rapid wheel was queuing one heavy runnable per notch. */
    private int pendingHomeScrollIndex = -1;
    private final Runnable homeScrollApplyRunnable = new Runnable() {
        @Override
        public void run() {
            int index = pendingHomeScrollIndex;
            pendingHomeScrollIndex = -1;
            applyHomeMenuScrollToIndexNow(index);
        }
    };

    private void scrollHomeMenuToIndex(int index) {
        if (containerHomeMenuItems == null || containerHomeMenuItems.getChildCount() == 0) return;
        if (index < 0 || index >= containerHomeMenuItems.getChildCount()) return;
        // 2026-07-17 — Immediate focus styles for snappy highlight; defer preview/status to next frame.
        focusedHomeMenuIndex = index;
        refreshHomeMenuRowStyles();
        pendingHomeScrollIndex = index;
        if (containerHomeMenuItems != null) {
            containerHomeMenuItems.removeCallbacks(homeScrollApplyRunnable);
            containerHomeMenuItems.post(homeScrollApplyRunnable);
        }
    }

    /**
     * 2026-07-17 — One scroll/focus/preview pass for the latest home index.
     * Layman: spin the dial fast — highlight keeps up; art pane catches up after the jump.
     */
    private void applyHomeMenuScrollToIndexNow(int index) {
        if (containerHomeMenuItems == null || containerHomeMenuItems.getChildCount() == 0) return;
        if (index < 0 || index >= containerHomeMenuItems.getChildCount()) return;
        if (homeMenuBuildGen < 0) return;
        View target = getHomeMenuRow(index);
        if (target != null) {
            target.requestFocus();
            if (menuScroll != null) {
                FocusScrollHelper.ensureChildVisible(menuScroll, target);
            }
        }
        refreshHomeMenuRowStyles();
        updateStatusBarTitle();
        // Preview is the expensive path (bitmap + layout) — never block the wheel loop.
        // 2026-07-18 — Deliberate single notches paint soon; accel/spin waits for ScrollIdleGate.
        scrollIdleGate.markActivity();
        ensureScrollIdleGateListener();
        if (!wheelPhysics.suppressWrapAround()) {
            scheduleHomeMenuPreviewUpdate(index);
        }
    }

    /**
     * 2026-07-18 — Ensure idle catch-up is wired even on home (no ListView coalescer).
     * Layman: when you stop spinning the home dial, the cover pane updates once.
     */
    private void ensureScrollIdleGateListener() {
        scrollIdleGate.setListener(new ScrollIdleGate.IdleListener() {
            @Override
            public void onScrollIdle() {
                onListWheelScrollIdle();
            }
        });
    }

    private int pendingHomePreviewIndex = -1;
    private final Runnable homePreviewApplyRunnable = new Runnable() {
        @Override
        public void run() {
            int idx = pendingHomePreviewIndex;
            pendingHomePreviewIndex = -1;
            if (idx >= 0) {
                updateHomeMenuPreview(idx);
            }
        }
    };

    private void scheduleHomeMenuPreviewUpdate(int index) {
        pendingHomePreviewIndex = index;
        if (containerHomeMenuItems == null) return;
        containerHomeMenuItems.removeCallbacks(homePreviewApplyRunnable);
        // Slight delay so a burst of notches only paints the final row's art.
        containerHomeMenuItems.postDelayed(homePreviewApplyRunnable, 48L);
    }

    /**
     * 2026-07-19 — Defer settings dual-pane preview until dial idle (same contract as home art).
     * Layman: spinning settings only moves the blue bar; icons/storage text catch up when you pause.
     * Technical: stash key + ScrollIdleGate; skip StatFs while spinning. Reversal: call updateSettingsPreview sync.
     */
    private void scheduleSettingsPreviewUpdate(String rowKey) {
        if (rowKey == null) return;
        pendingSettingsPreviewKey = rowKey;
        scrollIdleGate.markActivity();
        ensureScrollIdleGateListener();
        if (containerSettingsItems == null) return;
        containerSettingsItems.removeCallbacks(settingsPreviewApplyRunnable);
        if (scrollIdleGate.isSpinning() || wheelPhysics.suppressWrapAround()) {
            return; // onListWheelScrollIdle paints once
        }
        containerSettingsItems.postDelayed(settingsPreviewApplyRunnable, 48L);
    }

    private boolean shouldShowNowPlayingPreviewArt() {
        if (!playback.hasAnyQueue()) return false;
        if (currentScreenState == STATE_PLAYER) return true;
        try {
            return mediaPlayer != null && mediaPlayer.getDuration() > 0;
        } catch (Exception e) {
            return false;
        }
    }

    private void updateHomeMenuPreview(int index) {
        final long t0 = android.os.SystemClock.uptimeMillis();
        boolean a5Strip = A5PortraitChrome.usePortraitChrome(this);
        if ((!a5Strip && isFullWidthMenus) || index < 0 || index >= homeMenuEntries.size()) return;

        String id = homeMenuEntries.get(index).id;
        final String cacheKey = homeMenuPreviewCacheKey(id);
        final boolean skipBitmap = cacheKey.equals(lastHomeMenuPreviewAppliedKey);
        boolean decoded = false;
        boolean cacheHit = skipBitmap;

        if (!skipBitmap) {
            final boolean hadCache = homeMenuPreviewBitmapCache.containsKey(cacheKey);
            Bitmap preview = loadHomeMenuPreviewBitmap(id, cacheKey);
            decoded = !hadCache && preview != null;
            cacheHit = hadCache;
            // 2026-07-14 — A5 portrait strip: load art on ivMenuPreview but never show the Y1
            // right pane (was floating Music_YS over the full-width list). Dual-pane uses VISIBLE.
            // Reversal: drop a5Gone; always VISIBLE when preview bitmap exists.
            final int previewVis = a5Strip ? View.GONE : View.VISIBLE;
            if (HomeMenuConfig.ID_NOW_PLAYING.equals(id)) {
                if (shouldShowNowPlayingPreviewArt()) {
                    if (preview != null) {
                        ivMenuPreview.setImageBitmap(preview);
                        ivMenuPreview.setVisibility(previewVis);
                    } else {
                        setMenuPreviewDefaultAlbumArt();
                        ivMenuPreview.setVisibility(previewVis);
                        decoded = true;
                    }
                    if (tvMenuPreviewTitle != null && tvMenuPreviewArtist != null && tvPlayerTitle != null) {
                        // 2026-07-11 — Title/artist under home NP art is opt-in (settingsShow_Now_Playing_Info).
                        if (!a5Strip && ThemeManager.isShowNowPlayingInfoEnabled(prefs)) {
                            tvMenuPreviewTitle.setVisibility(View.VISIBLE);
                            tvMenuPreviewArtist.setVisibility(View.VISIBLE);
                            tvMenuPreviewTitle.setText(tvPlayerTitle.getText());
                            tvMenuPreviewArtist.setText(tvPlayerArtist != null ? tvPlayerArtist.getText() : "");
                        } else {
                            tvMenuPreviewTitle.setVisibility(View.GONE);
                            tvMenuPreviewArtist.setVisibility(View.GONE);
                        }
                    }
                } else {
                    if (preview != null) {
                        ivMenuPreview.setImageBitmap(preview);
                        ivMenuPreview.setVisibility(previewVis);
                    } else {
                        ivMenuPreview.setVisibility(View.GONE);
                    }
                    if (tvMenuPreviewTitle != null && tvMenuPreviewArtist != null) {
                        tvMenuPreviewTitle.setVisibility(View.GONE);
                        tvMenuPreviewArtist.setVisibility(View.GONE);
                    }
                }
            } else {
                if (preview != null) {
                    ivMenuPreview.setImageBitmap(preview);
                    ivMenuPreview.setVisibility(previewVis);
                } else {
                    ivMenuPreview.setVisibility(View.GONE);
                }
                if (tvMenuPreviewTitle != null && tvMenuPreviewArtist != null) {
                    tvMenuPreviewTitle.setVisibility(View.GONE);
                    tvMenuPreviewArtist.setVisibility(View.GONE);
                }
            }
            lastHomeMenuPreviewAppliedKey = cacheKey;
        } else if (!a5Strip && HomeMenuConfig.ID_NOW_PLAYING.equals(id) && shouldShowNowPlayingPreviewArt()
                && ThemeManager.isShowNowPlayingInfoEnabled(prefs)
                && tvMenuPreviewTitle != null && tvMenuPreviewArtist != null && tvPlayerTitle != null) {
            tvMenuPreviewTitle.setVisibility(View.VISIBLE);
            tvMenuPreviewArtist.setVisibility(View.VISIBLE);
            tvMenuPreviewTitle.setText(tvPlayerTitle.getText());
            tvMenuPreviewArtist.setText(tvPlayerArtist != null ? tvPlayerArtist.getText() : "");
        } else if (HomeMenuConfig.ID_NOW_PLAYING.equals(id)
                && tvMenuPreviewTitle != null && tvMenuPreviewArtist != null
                && !ThemeManager.isShowNowPlayingInfoEnabled(prefs)) {
            tvMenuPreviewTitle.setVisibility(View.GONE);
            tvMenuPreviewArtist.setVisibility(View.GONE);
        }
        // 2026-07-14 — Skip Y1 dual-pane layout math on A5 portrait (strip owns the preview).
        if (!a5Strip) {
            MenuPreviewLayout.Spec previewSpec = MenuPreviewLayout.homeSpec(this, isHomeDesktopMaskActive());
            if (ivMenuPreview.getVisibility() == View.VISIBLE) {
                ivMenuPreview.setAlpha(1f);
                MenuPreviewLayout.applyImagePreview(ivMenuPreview, previewSpec);
            }
            if (previewSpec.hideTitlesBelowArt) {
                if (tvMenuPreviewTitle != null) tvMenuPreviewTitle.setVisibility(View.GONE);
                if (tvMenuPreviewArtist != null) tvMenuPreviewArtist.setVisibility(View.GONE);
            } else if (HomeMenuConfig.ID_NOW_PLAYING.equals(id) && shouldShowNowPlayingPreviewArt()
                    && ThemeManager.isShowNowPlayingInfoEnabled(prefs)
                    && tvMenuPreviewTitle != null && tvMenuPreviewTitle.getVisibility() == View.VISIBLE) {
                int gap = (int) getResources().getDimension(R.dimen.y1_preview_title_gap);
                MenuPreviewLayout.layoutTitlesBelowArt(ivMenuPreview, tvMenuPreviewTitle, tvMenuPreviewArtist, gap);
                alignHomePreviewTitleWidth(tvMenuPreviewTitle, previewSpec);
                alignHomePreviewTitleWidth(tvMenuPreviewArtist, previewSpec);
            }
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("runId", "power-strip-1");
            d.put("ms", android.os.SystemClock.uptimeMillis() - t0);
            d.put("index", index);
            d.put("entryId", id);
            d.put("a5Strip", a5Strip);
            d.put("screen", currentScreenState);
            d.put("previewVis", ivMenuPreview != null ? ivMenuPreview.getVisibility() : -1);
            d.put("stripVis", a5BottomStrip != null ? a5BottomStrip.getVisibility() : -1);
            d.put("stripIconVis", ivA5StripIcon != null ? ivA5StripIcon.getVisibility() : -1);
            d.put("isFullWidthMenus", isFullWidthMenus);
            DebugB4208eLog.log("MainActivity.updateHomeMenuPreview", "preview/strip visibility", "S-B,S-D", d);
        } catch (Exception ignored) {}
        // #endregion
        if (a5Strip) syncA5BottomStripFromHome(id, index);
    }

    private void alignHomePreviewTitleWidth(TextView tv, MenuPreviewLayout.Spec spec) {
        if (tv == null || spec == null) return;
        ViewGroup.LayoutParams raw = tv.getLayoutParams();
        if (!(raw instanceof FrameLayout.LayoutParams)) return;
        FrameLayout.LayoutParams lp = (FrameLayout.LayoutParams) raw;
        lp.width = spec.paneWidthPx;
        lp.rightMargin = spec.marginEndPx;
        tv.setLayoutParams(lp);
    }

    private boolean shouldShowNowPlayingHome() {
        boolean show = playback.hasAnyQueue()
                || playback.isMusicActive() || playback.isPodcastActive()
                || playback.isFmActive();
        if (!show) {
            try {
                show = mediaPlayer != null && mediaPlayer.isPlaying();
            } catch (Exception ignored) {}
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("show", show);
            d.put("queueSize", playback.unifiedQueue().size());
            d.put("musicActive", playback.isMusicActive());
            d.put("podcastActive", playback.isPodcastActive());
            d.put("screen", currentScreenState);
            d.put("npVisible", nowPlayingHomeMenuVisible);
            DebugAgentLog.log(this, "MainActivity.shouldShowNowPlayingHome", "gate", "H1-H3", d);
        } catch (Exception ignored) {}
        // #endregion
        return show;
    }

    private void syncNowPlayingHomeVisibility() {
        boolean show = shouldShowNowPlayingHome();
        if (show == nowPlayingHomeMenuVisible) return;
        nowPlayingHomeMenuVisible = show;
        if (!show) {
            lastAlbumArtBytes = null;
        }
        if (currentScreenState == STATE_MENU && containerHomeMenuItems != null) {
            scheduleRebuildHomeMenuIfVisible();
        }
        refreshContextQuickBarIfShowing();
    }

    private void refreshContextQuickBarIfShowing() {
        if (themedContextMenu == null || !themedContextMenu.isShowing()
                || themedContextMenu.isVolumeOnlyMode()) return;
        applyContextQuickBarChrome();
        themedContextMenu.replaceQuickBar(buildContextQuickBar());
    }

    /** Volume/brightness chips are array slots 7/6 — must be set before quick-bar chips are built. */
    private void applyContextQuickBarChrome() {
        if (themedContextMenu == null) return;
        themedContextMenu.setPrimaryEndQuickIndex(CONTEXT_QUICK_QUEUE_INDEX);
        themedContextMenu.setMediaSliderQuickIndices(CONTEXT_QUICK_VOLUME_INDEX,
                CONTEXT_QUICK_BRIGHTNESS_INDEX);
    }

    private void onHomeMenuActivate(String id) {
        if (HomeMenuConfig.ID_NOW_PLAYING.equals(id)) {
            if (playback.hasAnyQueue()) {
                changeScreen(STATE_PLAYER);
            } else {
                currentBrowserMode = BROWSER_ROOT;
                changeScreen(STATE_BROWSER);
            }
        } else if (HomeMenuConfig.ID_MUSIC.equals(id)) {
            currentBrowserMode = BROWSER_ROOT;
            changeScreen(STATE_BROWSER);
        } else if (HomeMenuConfig.ID_BLUETOOTH.equals(id)) {
            if (!BluetoothExperiment.isEnabled(prefs)) {
                openAndroidBluetoothSettings();
                return;
            }
            openScreenWithReturn(STATE_BLUETOOTH);
        } else if (HomeMenuConfig.ID_SETTINGS.equals(id)) {
            changeScreen(STATE_SETTINGS);
        } else if (HomeMenuConfig.ID_RADIO.equals(id) || HomeMenuConfig.ID_FM.equals(id)) {
            // 2026-07-16 — Radio/FM behind Debug experiment (off by default).
            if (!com.solar.launcher.radio.RadioExperiment.isEnabled(prefs)) {
                Toast.makeText(this, getString(R.string.settings_debug_radio_experiment_hint),
                        Toast.LENGTH_LONG).show();
                return;
            }
            if (playback.isFmActive()) {
                changeScreen(STATE_PLAYER);
            } else if (com.solar.launcher.radio.RadioExperiment.isInternetRadioEnabled(prefs)) {
                changeScreen(MediaSuiteHost.STATE_RADIO);
            } else if (mediaSuite != null) {
                mediaSuite.openFmFromHome();
            } else {
                changeScreen(MediaSuiteHost.STATE_RADIO_FM_PLAYER);
            }
        } else if (HomeMenuConfig.ID_PC_UPLOAD.equals(id)) {
            if (!ConnectivityHelper.hasLocalNetwork(this)) {
                Toast.makeText(this, getString(R.string.toast_requires_wifi), Toast.LENGTH_SHORT).show();
                return;
            }
            openScreenWithReturn(STATE_WEBSERVER);
        } else if (HomeMenuConfig.ID_PODCASTS.equals(id)) {
            if (ConnectivityHelper.isOnline(this)) {
                changeScreen(STATE_PODCASTS);
            } else if (com.solar.launcher.podcast.PodcastLibrary.hasSavedContent()) {
                changeScreen(STATE_PODCASTS);
                buildPodcastSavedShowsUI();
            } else {
                Toast.makeText(this, getString(R.string.toast_internet_required), Toast.LENGTH_SHORT).show();
            }
        } else if (HomeMenuConfig.ID_SOULSEEK.equals(id)) {
            if (!requireInternet(R.string.toast_internet_required)) return;
            openGetMusicScreen();
        } else if (HomeMenuConfig.ID_THEMES.equals(id) || HomeMenuConfig.ID_GET_THEMES.equals(id)) {
            openThemesScreen(null);
        } else if (HomeMenuConfig.ID_MORE.equals(id)) {
            changeScreen(STATE_MORE);
        } else if (HomeMenuConfig.ID_VIDEOS.equals(id)) {
            changeScreen(MediaSuiteHost.STATE_VIDEO_HUB);
        } else if (HomeMenuConfig.ID_PHOTOS.equals(id)) {
            changeScreen(MediaSuiteHost.STATE_PHOTOS);
        } else if (HomeMenuConfig.ID_AUDIOBOOKS.equals(id)) {
            openAudiobookLibrary();
        } else if (HomeMenuConfig.ID_APPS.equals(id)) {
            changeScreen(STATE_APPS);
        }
    }

    private void updateStatusBarTitle() {
        if (tvStatusClock == null) return;
        if (statusBarFlowHandoffCrossfade && FlowPlayerHandoff.isHandoffAnimating()) {
            return;
        }
        if (!statusBarShowsTitle && currentScreenState == STATE_MENU) {
            boolean is24 = android.text.format.DateFormat.is24HourFormat(this);
            if (statusClockFormat == null || cachedClockIs24Hour != is24) {
                cachedClockIs24Hour = is24;
                statusClockFormat = new SimpleDateFormat(is24 ? "HH:mm" : "h:mm a", Locale.US);
            }
            setTextIfChanged(tvStatusClock, statusClockFormat.format(new java.util.Date()));
        } else {
            setTextIfChanged(tvStatusClock, getStatusBarContextTitle());
        }
        if (!statusBarFlowHandoffCrossfade) {
            tvStatusClock.setAlpha(1f);
            View statusBar = findViewById(R.id.layout_status_bar);
            if (statusBar != null) statusBar.setAlpha(1f);
        }
        applyStatusBarTitleMarquee();
        syncStatusBarLoadingThrobber();
    }

    /**
     * 2026-07-15 — Small indeterminate spinner beside status title while work is in flight.
     * 2026-07-18 — Renamed from search-only; also track change / Flow / seek / UiBusy tokens.
     * 2026-07-18 — Soft fade in/out so show/hide does not pop on the status strip.
     * Layman: spinning next to the title so a wait feels intentional, not frozen.
     * Technical: ProgressBar tinted with {@link ThemeManager#getStatusBarTextColor()}; not on home clock.
     * Reversal: call isStatusBarSearchLoading() only (drop UiBusy.isBusy()); hard VISIBLE/GONE without animate.
     */
    private void syncStatusBarLoadingThrobber() {
        if (pbStatusLoading == null) return;
        boolean show = isStatusBarLoading();
        if (show) {
            int color = ThemeManager.getStatusBarTextColor();
            try {
                android.graphics.drawable.Drawable d = pbStatusLoading.getIndeterminateDrawable();
                if (d != null) {
                    d = d.mutate();
                    d.setColorFilter(color, android.graphics.PorterDuff.Mode.SRC_IN);
                    pbStatusLoading.setIndeterminateDrawable(d);
                }
            } catch (Throwable ignored) {}
            pbStatusLoading.animate().cancel();
            if (pbStatusLoading.getVisibility() != View.VISIBLE) {
                pbStatusLoading.setAlpha(0f);
                pbStatusLoading.setVisibility(View.VISIBLE);
                pbStatusLoading.animate().alpha(1f)
                        .setDuration(STATUS_THROBBER_FADE_MS)
                        .setListener(null)
                        .start();
            } else if (pbStatusLoading.getAlpha() < 0.99f) {
                pbStatusLoading.animate().alpha(1f)
                        .setDuration(STATUS_THROBBER_FADE_MS)
                        .setListener(null)
                        .start();
            }
        } else {
            fadeOutStatusBarLoadingThrobber();
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("show", show);
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            d.put("media", isStatusBarMediaLoading());
            d.put("search", isStatusBarSearchLoading());
            d.put("wifiConnect", wifiConnectInProgress);
            d.put("wifiScanCtx", wifiContextScanActive);
            d.put("btConnect", btConnectInProgress);
            d.put("vis", pbStatusLoading != null ? pbStatusLoading.getVisibility() : -1);
            Debug0f5debLog.log(this, "MainActivity.syncStatusBarLoadingThrobber",
                    "throbber sync", "H5", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    /**
     * 2026-07-18 — Fade the status spinner out, then GONE (keeps layout calm).
     * Layman: spinner gently disappears when loading finishes.
     * Technical: alpha anim → View.GONE; cancel mid-fade if work restarts.
     */
    private void fadeOutStatusBarLoadingThrobber() {
        if (pbStatusLoading == null) return;
        if (pbStatusLoading.getVisibility() == View.GONE) return;
        pbStatusLoading.animate().cancel();
        final ProgressBar bar = pbStatusLoading;
        bar.animate().alpha(0f)
                .setDuration(STATUS_THROBBER_FADE_MS)
                .setListener(new android.animation.AnimatorListenerAdapter() {
                    @Override
                    public void onAnimationEnd(android.animation.Animator animation) {
                        if (bar != pbStatusLoading) return;
                        // Re-armed mid-fade — leave visible.
                        if (isStatusBarLoading()) {
                            bar.setAlpha(1f);
                            bar.setVisibility(View.VISIBLE);
                            return;
                        }
                        bar.setVisibility(View.GONE);
                        bar.setAlpha(1f);
                    }
                })
                .start();
    }

    /** @deprecated use {@link #syncStatusBarLoadingThrobber()} */
    private void syncStatusBarSearchThrobber() {
        syncStatusBarLoadingThrobber();
    }

    /**
     * True when status spinner should show — search flags OR any {@link com.solar.launcher.ui.UiBusy} token
     * OR in-flight media buffer / download / podcast / YouTube resolve.
     * Layman: Solar is still loading something the user is waiting on.
     */
    private boolean isStatusBarLoading() {
        if (statusBarFlowHandoffCrossfade) return false;
        // Quiet home clock: no spinner unless a named busy reason is active.
        if (!statusBarShowsTitle && currentScreenState == STATE_MENU
                && !com.solar.launcher.ui.UiBusy.isBusy()
                && !isStatusBarMediaLoading()) {
            return false;
        }
        if (com.solar.launcher.ui.UiBusy.isBusy()) return true;
        if (isStatusBarMediaLoading()) return true;
        return isStatusBarSearchLoading();
    }

    /**
     * 2026-07-18 — Online / buffer waits not yet mirrored into UiBusy tokens.
     * Layman: downloading, buffering podcast, or resolving YouTube still counts as loading.
     * Technical: OR of episode/download flags + MediaSuite YouTube resolve/buffer UI.
     * Reversal: drop method; rely only on UiBusy + search flags.
     */
    private boolean isStatusBarMediaLoading() {
        if (podcastEpisodeLoading || podcastDownloadInProgress) return true;
        if (soulseekUiMode == SOULSEEK_UI_DOWNLOAD && soulseekActiveDownload != null
                && !soulseekDownloadUiFailed) {
            return true;
        }
        if (mediaSuite != null && mediaSuite.isMediaBusyForStatusThrobber()) return true;
        return false;
    }

    /** True when a search is still filling the active results list (wheel may still jump). */
    private boolean isStatusBarSearchLoading() {
        if (statusBarFlowHandoffCrossfade) return false;
        if (!statusBarShowsTitle && currentScreenState == STATE_MENU) return false;
        if (getMusicSearchInProgress && isGetMusicUnifiedUi()) return true;
        if (soulseekSearchInProgress
                && (currentScreenState == STATE_SOULSEEK || isGetMusicUnifiedUi())) {
            return true;
        }
        if (currentScreenState == STATE_PODCASTS && podcastSearchLoading) return true;
        if (currentScreenState == STATE_BROWSER
                && currentBrowserMode == BROWSER_LIBRARY_SEARCH
                && (librarySearchReachSearching || librarySearchNavidromeSearching
                        || librarySearchPlexSearching || librarySearchJellyfinSearching)) {
            return true;
        }
        if (currentScreenState == STATE_DEEZER && deezerScreen != null
                && deezerScreen.searchInProgress()) {
            return true;
        }
        if (mediaSuite != null && mediaSuite.isYoutubeBrowseLoading()) return true;
        return false;
    }

    /**
     * 2026-07-15 — Capture focused browser row identity before list mutation.
     * @return tag key string, or null when focus is outside result rows
     */
    private String captureBrowserFocusKey() {
        View foc = getCurrentFocus();
        if (foc == null || containerBrowserItems == null) return null;
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View row = containerBrowserItems.getChildAt(i);
            if (row == foc || isViewDescendantOf(foc, row)) {
                Object tag = row.getTag();
                if (tag instanceof MusicSearchEntry) {
                    return musicSearchEntryDebugKey((MusicSearchEntry) tag);
                }
                if (tag instanceof SoulseekClient.Result) {
                    return soulseekResultKey((SoulseekClient.Result) tag);
                }
                if (row instanceof android.widget.TextView) {
                    CharSequence t = ((android.widget.TextView) row).getText();
                    return t != null ? t.toString() : null;
                }
                return "idx:" + i;
            }
        }
        return null;
    }

    /**
     * Restore focus/scroll after search rows rebuild when focus was lost.
     * 2026-07-15 — Never steal the wheel: if a browser row still has focus, leave it.
     * Was: always requestFocus(key) after append → A5 face L/R felt dead while results streamed.
     */
    private void restoreBrowserFocusKey(final String key, final int scrollYBefore) {
        if (containerBrowserItems == null) return;
        // Append-only / live focus: user already moved the highlight — do not yank it back.
        View focNow = getCurrentFocus();
        if (focNow != null) {
            for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
                View row = containerBrowserItems.getChildAt(i);
                if (row == focNow || isViewDescendantOf(focNow, row)) {
                    return;
                }
            }
        }
        if (scrollViewBrowser instanceof android.widget.ScrollView && scrollYBefore >= 0
                && focNow == null) {
            final android.widget.ScrollView sv = (android.widget.ScrollView) scrollViewBrowser;
            sv.post(new Runnable() {
                @Override
                public void run() {
                    sv.scrollTo(0, scrollYBefore);
                }
            });
        }
        if (key == null || key.length() == 0) return;
        containerBrowserItems.post(new Runnable() {
            @Override
            public void run() {
                if (containerBrowserItems == null) return;
                // Re-check: a key event may have focused a row since we posted.
                View foc = getCurrentFocus();
                if (foc != null) {
                    for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
                        View row = containerBrowserItems.getChildAt(i);
                        if (row == foc || isViewDescendantOf(foc, row)) {
                            return;
                        }
                    }
                }
                View match = null;
                for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
                    View row = containerBrowserItems.getChildAt(i);
                    Object tag = row.getTag();
                    String rowKey = null;
                    if (tag instanceof MusicSearchEntry) {
                        rowKey = musicSearchEntryDebugKey((MusicSearchEntry) tag);
                    } else if (tag instanceof SoulseekClient.Result) {
                        rowKey = soulseekResultKey((SoulseekClient.Result) tag);
                    } else if (row instanceof android.widget.TextView) {
                        CharSequence t = ((android.widget.TextView) row).getText();
                        rowKey = t != null ? t.toString() : null;
                    } else if (("idx:" + i).equals(key)) {
                        rowKey = key;
                    }
                    if (key.equals(rowKey)) {
                        match = row;
                        break;
                    }
                }
                if (match != null && match.isFocusable()) {
                    match.requestFocus();
                    if (scrollViewBrowser instanceof android.widget.ScrollView) {
                        FocusScrollHelper.ensureChildVisible(
                                (android.widget.ScrollView) scrollViewBrowser, match);
                    }
                }
            }
        });
    }

    /** Prep status bar for reverse handoff — title swaps during reveal, not on changeScreen. */
    private void beginReverseStatusBarHandoff() {
        statusBarFlowHandoffCrossfade = true;
    }

    /** Fade status bar out on Back — pairs with reveal crossfade after flyer morph. */
    private void beginReverseStatusBarFadeOut() {
        beginReverseStatusBarHandoff();
        final View statusBar = findViewById(R.id.layout_status_bar);
        if (statusBar == null) return;
        statusBar.setVisibility(View.VISIBLE);
        statusBar.setAlpha(1f);
        final int gen = ++statusBarHandoffFadeGen;
        final long startMs = System.currentTimeMillis();
        final Runnable tick = new Runnable() {
            @Override
            public void run() {
                if (gen != statusBarHandoffFadeGen) return;
                float t = (System.currentTimeMillis() - startMs) / (float) STATUS_BAR_HANDOFF_FADE_MS;
                if (t >= 1f) {
                    statusBar.setAlpha(0f);
                    return;
                }
                float eased = 1f - (1f - t) * (1f - t);
                statusBar.setAlpha(1f - eased);
                statusBar.postOnAnimation(this);
            }
        };
        statusBar.postOnAnimation(tick);
    }

    /** Ease Flow status title in after flyer lands — avoids pop when changeScreen runs. */
    private void applyReverseStatusBarReveal(float eased) {
        View statusBar = findViewById(R.id.layout_status_bar);
        if (tvStatusClock == null || !statusBarFlowHandoffCrossfade) return;
        if (statusBar != null) {
            statusBar.setVisibility(View.VISIBLE);
            statusBar.setAlpha(eased);
        }
        String flowTitle = getString(R.string.status_flow);
        if (eased < 0.35f) {
            tvStatusClock.setText(getString(R.string.status_now_playing));
            tvStatusClock.setAlpha(1f);
            return;
        }
        float t = (eased - 0.35f) / 0.65f;
        float alpha = t * (2f - t);
        tvStatusClock.setText(flowTitle);
        tvStatusClock.setAlpha(alpha);
        if (eased >= 1f) {
            tvStatusClock.setAlpha(1f);
            if (statusBar != null) statusBar.setAlpha(1f);
            statusBarFlowHandoffCrossfade = false;
            applyStatusBarTitleMarquee();
        }
    }

    private String getStatusBarContextTitle() {
        // 2026-07-19 — Solo Instrumental/Acapella wait copy overrides screen title while busy.
        if (soloBusyStatusTitle != null && soloBusyStatusTitle.length() > 0) {
            return soloBusyStatusTitle;
        }
        switch (currentScreenState) {
            case STATE_MENU:
                return getString(R.string.status_home);
            case STATE_BROWSER:
                if (stemPickMode) {
                    return getString(R.string.stem_pick_status, stemMashupMarks.size());
                }
                if (mixAssignMode) {
                    if (mixReassignDeck >= 0) {
                        return getString(R.string.mix_reassign_pick, mixReassignDeck + 1);
                    }
                    return getString(R.string.mix_assign_status);
                }
                return browserStatusTitle != null ? browserStatusTitle : getString(R.string.status_library_main);
            case STATE_PLAYER: return getString(R.string.status_now_playing);
            case STATE_STEM_PLAYER: return getString(R.string.status_stem_player);
            case STATE_MIX: return getString(R.string.status_mix);
            case STATE_SETTINGS: return resolveSettingsSubTitle();
            case STATE_BLUETOOTH: return getString(R.string.status_bluetooth_scan);
            case STATE_WIFI: return getString(R.string.status_wifi_networks);
            case STATE_WIFI_KEYBOARD: return getKeyboardStatusBarTitle();
            case STATE_BRIGHTNESS: return getString(R.string.status_brightness);
            case STATE_STORAGE: return getString(R.string.status_storage);
            case STATE_WEBSERVER: return getString(R.string.status_pc_upload);
            case STATE_PODCASTS: return getString(R.string.status_podcasts);
            case STATE_FLOW: return getString(R.string.status_flow);
            case STATE_SOULSEEK:
                return browserStatusTitle != null && isGetMusicUnifiedUi()
                        ? browserStatusTitle : getString(R.string.status_soulseek);
            case STATE_DEEZER: return getString(R.string.status_deezer);
            case STATE_DEEZER_SETUP: return getString(R.string.status_deezer_setup);
            case STATE_APPS: return getString(R.string.status_apps);
            case STATE_MORE: return getString(R.string.path_more);
            case STATE_USB_STORAGE: return "USB Storage";
            default:
                if (mediaSuite != null) {
                    String mediaTitle = mediaSuite.statusTitleForState(currentScreenState);
                    if (mediaTitle != null && !mediaTitle.isEmpty()) return mediaTitle;
                }
                return getString(R.string.status_home);
        }
    }

