    private void applyThemedStatusIcon(ImageView view, String primaryKey, String secondaryKey, int fallbackRes, int fallbackTint) {
        if (view == null) return;
        Bitmap icon = ThemeManager.getStatusIcon(primaryKey);
        if (icon == null && secondaryKey != null) icon = ThemeManager.getStatusIcon(secondaryKey);
        if (icon != null) {
            view.setImageBitmap(icon);
            view.clearColorFilter();
        } else {
            view.setImageResource(fallbackRes);
            view.setColorFilter(fallbackTint);
        }
    }

    private void updatePlaybackStatusIcon() {
        if (ivStatusPlayback == null) return;
        boolean playing = false;
        try {
            if (playback.isPodcastActive() && podcastIjkPlayer != null) {
                playing = podcastIjkPlayer.isPlaying();
            } else if (isMusicIjkActive()) {
                playing = musicIjkPlayer.isPlaying();
            } else {
                playing = mediaPlayer != null && mediaPlayer.isPlaying();
            }
        } catch (Exception ignored) {}
        boolean hasQueue = playback.hasAnyQueue();
        if (!playing && !hasQueue) {
            ivStatusPlayback.setVisibility(View.GONE);
            return;
        }
        Bitmap icon = ThemeManager.getStatusIcon(playing ? "playing" : "pause");
        int fallbackRes = playing ? R.drawable.ic_play : R.drawable.ic_pause;
        if (icon == null && !playing) {
            // ponytail: old themes may define stop but not pause.
            icon = ThemeManager.getStatusIcon("stop");
        }
        if (icon != null) {
            ivStatusPlayback.setImageBitmap(icon);
            ivStatusPlayback.clearColorFilter();
        } else {
            ivStatusPlayback.setImageResource(fallbackRes);
            ivStatusPlayback.setColorFilter(ThemeManager.getTextColorPrimary());
        }
        ivStatusPlayback.setVisibility(View.VISIBLE);
        refreshContextQueueTierIfOpen();
    }

    private void openScreenWithReturn(int state) {
        if (state != currentScreenState) {
            screenBackReturnTo = currentScreenState;
        }
        changeScreen(state);
    }

    private void openAndroidBluetoothSettings() {
        Intent intent = new Intent(Settings.ACTION_BLUETOOTH_SETTINGS);
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
        try {
            isIntentionalFocusLoss = true;
            beginExternalInputHandoff();
            startActivity(intent);
        } catch (Exception first) {
            try {
                Intent fallback = new Intent(Settings.ACTION_WIRELESS_SETTINGS);
                fallback.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
                startActivity(fallback);
            } catch (Exception second) {
                isIntentionalFocusLoss = false;
                endExternalInputHandoff();
                Toast.makeText(this, getString(R.string.apps_launch_failed), Toast.LENGTH_SHORT).show();
            }
        }
    }

    /** adb: am start -n com.solar.launcher/.MainActivity --ez solar_adb_open_soulseek_messages true */
    private void scheduleAdbOpenSoulseekMessagesIfRequested() {
        final boolean requested = getIntent() != null
                && getIntent().getBooleanExtra("solar_adb_open_soulseek_messages", false);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("requested", requested);
            DebugSessionLog.log("MainActivity.scheduleAdbOpenSoulseekMessagesIfRequested",
                    "check extra", "H-M6", d);
        } catch (Exception ignored) {}
        // #endregion
        if (!requested) return;
        getIntent().removeExtra("solar_adb_open_soulseek_messages");
        new Handler().postDelayed(new Runnable() {
            @Override public void run() {
                try {
                    changeScreen(STATE_SETTINGS);
                    buildReachSettingsUI(2);
                    buildSoulseekSettingsUI();
                    buildSoulseekMessagesUI();
                    SolarAdbTest.pass("soulseek_messages_opened");
                } catch (Exception e) {
                    SolarAdbTest.fail("messages_" + e.getClass().getSimpleName());
                }
            }
        }, 500);
    }

    /** adb: am start -n com.solar.launcher/.MainActivity --es theme_auto_variant 'StrangerThings::Robin' */
    private void scheduleThemeAutoVariantIfRequested() {
        Intent intent = getIntent();
        if (intent == null) return;
        final String themeAutoVariant = intent.getStringExtra("theme_auto_variant");
        // #region agent log
        try {
            org.json.JSONObject themeAdbDbg = new org.json.JSONObject();
            themeAdbDbg.put("extra", themeAutoVariant != null ? themeAutoVariant : "");
            DebugSessionLog.log("MainActivity.scheduleThemeAutoVariant", "extra", "H-ADB", themeAdbDbg);
        } catch (Exception ignored) {}
        // #endregion
        if (themeAutoVariant == null || !themeAutoVariant.contains("::")) return;
        intent.removeExtra("theme_auto_variant");
        final String[] parts = themeAutoVariant.split("::", 2);
        final String themeName = parts[0].trim();
        final String variantSlug = parts[1].trim();
        new Handler().postDelayed(new Runnable() {
            @Override
            public void run() {
                changeScreen(STATE_SETTINGS);
                setSettingsSubScreen(SettingsScreens.THEMES);
                updateStatusBarTitle();
                prepareThemeGalleryPreviewPane();
                new Thread(new Runnable() {
                    @Override
                    public void run() {
                        try {
                            List<ThemeDownloader.CatalogEntry> catalog = ThemeDownloader.fetchCatalog();
                            ThemeDownloader.CatalogEntry entry = null;
                            for (ThemeDownloader.CatalogEntry e : catalog) {
                                if (themeName.equalsIgnoreCase(e.name)
                                        || themeName.equalsIgnoreCase(e.folder)
                                        || themeName.replace(" ", "").equalsIgnoreCase(
                                                e.name.replace(" ", ""))) {
                                    entry = e;
                                    break;
                                }
                            }
                            if (entry == null) throw new Exception("theme not in catalog: " + themeName);
                            List<ThemeDownloader.ThemeVariant> variants =
                                    ThemeDownloader.fetchReachableVariants(entry);
                            ThemeDownloader.ThemeVariant pick = null;
                            for (ThemeDownloader.ThemeVariant v : variants) {
                                if (variantSlug.equalsIgnoreCase(v.folderSlug)
                                        || variantSlug.equalsIgnoreCase(v.label)) {
                                    pick = v;
                                    break;
                                }
                            }
                            if (pick == null) throw new Exception("variant not found: " + variantSlug);
                            final ThemeDownloader.CatalogEntry fe = entry;
                            final ThemeDownloader.ThemeVariant fv = pick;
                            runOnUiThreadSafe(new Runnable() {
                                @Override
                                public void run() {
                                    if (isFinishing()) return;
                                    applyThemeCatalog(catalog);
                                    buildUnifiedThemesUI();
                                    downloadAndApplyThemeVariant(fe, fv);
                                }
                            });
                        } catch (final Exception e) {
                            ThemeDownloader.dlLogError("theme_auto_variant", e);
                        }
                    }
                }).start();
            }
        }, 4000);
    }

    /** adb: am start -n com.solar.launcher/.MainActivity -e open_webserver true */
    private void handleLaunchIntentExtras() {
        Intent intent = getIntent();
        if (intent == null) return;
        if (OverlayTriggers.ACTION_OPEN_CONTEXT_MENU.equals(intent.getAction())
                || intent.getBooleanExtra(OverlayTriggers.EXTRA_CONTEXT_POWER_HOLD, false)) {
            handleContextPowerHoldIntent();
            return;
        }
        if (intent.getBooleanExtra(ScanTriggerReceiver.EXTRA_TRIGGER, false)) {
            intent.removeExtra(ScanTriggerReceiver.EXTRA_TRIGGER);
            scanMediaLibraryAsync();
            return;
        }
        if (intent.getBooleanExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_PROMPT, false)) {
            handlePairingPinPromptIfRequested(intent);
            return;
        }
        routeUsbOverlayLaunchExtras(intent);
        boolean open = intent.getBooleanExtra("open_webserver", false);
        if (!open) {
            String s = intent.getStringExtra("open_webserver");
            open = s != null && ("true".equalsIgnoreCase(s) || "1".equals(s));
        }
        if (!open) return;
        intent.removeExtra("open_webserver");
        if (!ConnectivityHelper.hasLocalNetwork(this)) {
            Toast.makeText(this, getString(R.string.toast_network_required), Toast.LENGTH_SHORT).show();
            return;
        }
        openScreenWithReturn(STATE_WEBSERVER);
    }

