    int deviceTestExpectedHomeMenuRowCount() {
        final boolean online = ConnectivityHelper.isOnline(this);
        final boolean onLan = ConnectivityHelper.hasLocalNetwork(this);
        List<HomeMenuConfig.Entry> entries = HomeMenuConfig.loadVisibleForDisplay(prefs, online, onLan);
        final boolean showNowPlaying = shouldShowNowPlayingHome();
        if (showNowPlaying) {
            boolean hasNowPlaying = false;
            for (HomeMenuConfig.Entry e : entries) {
                if (HomeMenuConfig.ID_NOW_PLAYING.equals(e.id)) {
                    hasNowPlaying = true;
                    break;
                }
            }
            if (!hasNowPlaying) {
                HomeMenuConfig.Entry np = HomeMenuConfig.find(HomeMenuConfig.ID_NOW_PLAYING);
                if (np != null) entries.add(0, np);
            }
        }
        java.util.Iterator<HomeMenuConfig.Entry> it = entries.iterator();
        while (it.hasNext()) {
            if (HomeMenuConfig.ID_NOW_PLAYING.equals(it.next().id) && !showNowPlaying) {
                it.remove();
            }
        }
        int total = entries.size();
        if (HomeMenuConfig.shouldShowMoreTile(prefs, online, onLan)) total++;
        return total;
    }

    private void changeScreen(int state) {
        changeScreen(state, false);
    }

    private void changeScreen(int state, boolean isBack) {
        if (otaSystemReplaceInProgress) return;
        if (isUsbMassStorageUiLocked() && state != STATE_USB_STORAGE) {
            // 2026-07-17 — Prefer session + cached export (no dual sysfs on every changeScreen).
            // Layman: eject screen owns the device until the cable is unplugged.
            boolean umsActive = usbMassStorageLocked
                    || UsbMassStorageController.isUserSessionActive()
                    || cachedUmsExported
                    || UsbMassStorageController.isMassStorageExported();
            if (umsActive) {
                Toast.makeText(this,
                        getString(R.string.usb_storage_mode_body, DeviceFeatures.productModelLabel()),
                        Toast.LENGTH_SHORT).show();
                if (currentScreenState != STATE_USB_STORAGE) {
                    enterUsbMassStorageLock();
                }
                return;
            }
            clearStaleUsbMassStorageLockIfNeeded();
            if (isUsbMassStorageUiLocked()) {
                return;
            }
        }
        if (com.solar.launcher.radio.RadioExperiment.isBlockedScreenState(state, prefs)) {
            return;
        }
        if (com.solar.launcher.youtube.YouTubeExperiment.isBlockedScreenState(state, prefs)) {
            return;
        }
        state = com.solar.launcher.radio.RadioExperiment.resolveRadioHomeTarget(state, prefs);
        if (state == STATE_BLUETOOTH && !BluetoothExperiment.isEnabled(prefs)) {
            return;
        }
        if (ScreenTransition.isAnimating() || ListDrillTransition.isAnimating()
                || FlowPlayerHandoff.isHandoffAnimating()) {
            if (isBack) {
                ScreenTransition.cancel();
            } else {
                // 2026-07-18 — Skip/select during PODCASTS→NP push still must kill dual-pane chrome.
                // Layman: skipping episodes must not leave the old cover column on Now Playing.
                if (state == STATE_PLAYER) {
                    hideBrowsePreviewChromeForNowPlaying("changeScreen-anim-blocked");
                }
                return;
            }
        }
        dismissThemedContextMenu();
        hideFastScrollLetter();
        if (currentScreenState == STATE_SOULSEEK && state != STATE_SOULSEEK && shouldConfirmReachDownloadLeave(state)) {
            if (soulseekBailWithoutConfirm()) {
                cancelSoulseekDownloadSilent();
                soulseekDownloadStalled = false;
                soulseekDownloadUiFailed = false;
                soulseekFailedResult = null;
                applyScreenChange(state);
                return;
            }
            pendingScreenChange = state;
            confirmStopReachDownload(new Runnable() {
                @Override
                public void run() {
                    int target = pendingScreenChange;
                    pendingScreenChange = -1;
                    if (target >= 0) changeScreen(target, isBack);
                }
            });
            return;
        }
        final int from = currentScreenState;
        // 2026-07-18 — Status throbber on every menu hop (animated or instant).
        // Layman: spinner says the next screen is loading so OK never feels ignored.
        // Technical: REASON_TRANSITION for all from≠to; coordinator/clear or sync clear below.
        // Was: only ScreenTransitionCoordinator.run armed busy — Kind.NONE / anim-off skipped.
        // Reversal: remove begin/clear here; restore begin only inside coordinator.run.
        if (from != state) {
            com.solar.launcher.ui.UiBusy.beginAutoEnd(
                    com.solar.launcher.ui.UiBusy.REASON_TRANSITION, 6_000L);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("from", from);
                d.put("to", state);
                d.put("isBack", isBack);
                d.put("willAnimate", ScreenTransitionCoordinator.shouldRun(
                        screenTransitionHost, from, state, isBack));
                Debug0f5debLog.log(this, "MainActivity.changeScreen",
                        "transition busy armed", "H1", d);
            } catch (Exception ignored) {}
            // #endregion
        }
        if (from != state && ScreenTransitionCoordinator.shouldRun(screenTransitionHost, from, state, isBack)) {
            ScreenTransitionCoordinator.run(screenTransitionHost, from, state, isBack);
            return;
        }
        applyScreenChange(state);
        if (from != state) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("path", "sync-clear");
                d.put("from", from);
                d.put("to", state);
                d.put("isBack", isBack);
                Debug0f5debLog.log(this, "MainActivity.changeScreen",
                        "sync clear transition same-stack", "H1", d);
            } catch (Exception ignored) {}
            // #endregion
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_TRANSITION);
        }
    }

