    private java.util.List<PlayQueue.QueueItem> collectMusicQueueItemsForPlaylist() {
        java.util.ArrayList<PlayQueue.QueueItem> out = new java.util.ArrayList<PlayQueue.QueueItem>();
        for (PlayQueue.QueueItem q : playback.unifiedQueue().items()) {
            if (q.kind == PlayQueue.ItemKind.PODCAST_EPISODE) continue;
            if (q.kind == PlayQueue.ItemKind.MUSIC_FILE || q.kind == PlayQueue.ItemKind.REACH_STREAM
                    || q.kind == PlayQueue.ItemKind.DEEZER_STREAM) {
                out.add(q);
            }
        }
        return out;
    }

    private static final int PLAYLIST_STREAM_SAVE_RETRIES = 3;

    /** Silently materialize Deezer/Reach stream rows into library paths for a saved M3U. */
    private void materializePlaylistStreamTracksAsync(final File m3uFile,
            final java.util.List<PlayQueue.QueueItem> items) {
        if (m3uFile == null || items == null || items.isEmpty()) return;
        boolean hasStream = false;
        for (PlayQueue.QueueItem q : items) {
            if (q.file != null && isStreamTempFile(q.file)) {
                hasStream = true;
                break;
            }
        }
        if (!hasStream) return;
        new Thread(new Runnable() {
            @Override
            public void run() {
                for (final PlayQueue.QueueItem q : items) {
                    if (q.file == null || !isStreamTempFile(q.file)) continue;
                    File libraryFile = null;
                    String fail = null;
                    for (int attempt = 0; attempt < PLAYLIST_STREAM_SAVE_RETRIES && libraryFile == null; attempt++) {
                        try {
                            if (q.kind == PlayQueue.ItemKind.DEEZER_STREAM && q.deezerTrackId > 0) {
                                libraryFile = downloadDeezerTrackToLibrarySync(q.deezerTrackId, q.deezerMeta);
                            } else if (!isStreamTrackStillBuffering(q.file)) {
                                libraryFile = promoteStreamFileToLibrarySync(q.file);
                            } else if (q.kind == PlayQueue.ItemKind.REACH_STREAM) {
                                fail = getString(R.string.soulseek_save_wait_download);
                            }
                        } catch (Exception e) {
                            fail = e.getMessage() != null ? e.getMessage() : "Save failed";
                        }
                        if (libraryFile == null && attempt + 1 < PLAYLIST_STREAM_SAVE_RETRIES) {
                            try { Thread.sleep(800L * (attempt + 1)); } catch (InterruptedException ignored) {}
                        }
                    }
                    if (libraryFile != null && libraryFile.isFile()) {
                        final File old = q.file;
                        final File lib = libraryFile;
                        replacePathInM3u(m3uFile, old, lib);
                        runOnUiThread(new Runnable() {
                            @Override public void run() {
                                playback.finishStreamFileInQueue(old, lib, lib.getName());
                            }
                        });
                    } else if (fail != null) {
                        final String msg = fail;
                        final String title = q.streamMeta();
                        runOnUiThread(new Runnable() {
                            @Override public void run() {
                                showGlobalContextAlert(title,
                                        getString(R.string.playlist_stream_save_failed, msg));
                            }
                        });
                    }
                }
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        scanMediaLibraryAsync();
                        purgeUnreferencedReachCache();
                    }
                });
            }
        }, "PlaylistStreamMat").start();
    }

    private File promoteStreamFileToLibrarySync(File src) {
        if (src == null || !src.isFile() || isStreamTrackStillBuffering(src)) return null;
        File dest = SoulseekClient.uniqueFile(rootFolder, src.getName());
        final String oldPath = src.getAbsolutePath();
        if (src.renameTo(dest)) {
            ReachTrackProvenance.renamePath(prefs, oldPath, dest.getAbsolutePath());
            return dest;
        }
        try {
            java.io.FileInputStream in = new java.io.FileInputStream(src);
            java.io.FileOutputStream out = new java.io.FileOutputStream(dest);
            byte[] buf = new byte[8192];
            int n;
            while ((n = in.read(buf)) >= 0) out.write(buf, 0, n);
            in.close();
            out.close();
            src.delete();
            ReachTrackProvenance.renamePath(prefs, oldPath, dest.getAbsolutePath());
            return dest;
        } catch (Exception e) {
            return null;
        }
    }

    private File downloadDeezerTrackToLibrarySync(long trackId, String meta) throws Exception {
        DeezerClient client = new DeezerClient(prefs);
        if (!client.isSessionValid()) client.initSession();
        DeezerDownloader downloader = new DeezerDownloader(client);
        String title = meta != null ? meta : ("track_" + trackId);
        DeezerResult track = new DeezerResult(trackId, title, "", "", 0, 0, "", "");
        final Object lock = new Object();
        final File[] dest = {null};
        final String[] err = {null};
        downloader.download(track, rootFolder, client.fileExtension(), new DeezerDownloader.Listener() {
            @Override public void onProgress(long doneBytes, long totalBytes) {}
            @Override public void onPartialReady(File d, long bytesRead) {}
            @Override public void onComplete(File d, DeezerTrackData t) {
                dest[0] = d;
                synchronized (lock) { lock.notifyAll(); }
            }
            @Override public void onError(String message) {
                err[0] = message;
                synchronized (lock) { lock.notifyAll(); }
            }
        });
        synchronized (lock) {
            while (dest[0] == null && err[0] == null) {
                lock.wait(300000);
            }
        }
        if (err[0] != null) throw new Exception(err[0]);
        return dest[0];
    }

    /** ponytail: line scan — fine for Y1-sized M3U files */
    private void replacePathInM3u(File m3u, File oldF, File newF) {
        if (m3u == null || oldF == null || newF == null || !m3u.isFile()) return;
        try {
            java.io.BufferedReader in = new java.io.BufferedReader(
                    new java.io.FileReader(m3u));
            StringBuilder sb = new StringBuilder();
            String line;
            String oldPath = oldF.getAbsolutePath();
            String newPath = newF.getAbsolutePath();
            while ((line = in.readLine()) != null) {
                if (line.equals(oldPath)) line = newPath;
                sb.append(line).append('\n');
            }
            in.close();
            java.io.FileOutputStream out = new java.io.FileOutputStream(m3u);
            out.write(sb.toString().getBytes("UTF-8"));
            out.close();
        } catch (Exception ignored) {}
    }

    private void rebuildContextReachPeerTier(boolean focusList) {
        final String peer = contextReachPeerUser;
        if (peer == null) return;
        final SoulseekUserDirectory.UserInfo info = contextReachPeerInfo;
        final boolean hasFiles = info != null && info.files > 0;
        final boolean blocked = SoulseekPeerPrefs.isBlocked(prefs, peer);
        final boolean favorited = SoulseekPeerPrefs.isFavorite(prefs, peer);

        StringBuilder detail = new StringBuilder();
        String note = SoulseekPeerNotes.getNoteSync(MainActivity.this, peer);
        if (note != null && !note.trim().isEmpty()) {
            detail.append(getString(R.string.soulseek_user_note_label)).append("\n");
            detail.append(note.trim()).append("\n\n");
        }
        if (info != null) {
            String status = info.isOnline()
                    ? getString(R.string.soulseek_user_online) : getString(R.string.soulseek_user_offline);
            String filesLine = info.files > 0
                    ? getString(R.string.soulseek_peer_files, info.files)
                    : getString(R.string.soulseek_user_no_files);
            detail.append(getString(R.string.soulseek_reach_status_line, peer, status, filesLine));
        } else {
            detail.append(peer);
        }

        java.util.ArrayList<String> labels = new java.util.ArrayList<String>();
        java.util.ArrayList<String> states = new java.util.ArrayList<String>();
        java.util.ArrayList<String> iconKeys = new java.util.ArrayList<String>();
        java.util.ArrayList<Boolean> headers = new java.util.ArrayList<Boolean>();
        java.util.ArrayList<Runnable> actions = new java.util.ArrayList<Runnable>();

        String cc = info != null && info.country != null ? info.country : soulseekPeerCountryCode(peer);
        labels.add(detail.toString());
        states.add(null);
        iconKeys.add(cc != null ? "flag." + cc.toLowerCase(Locale.US) : null);
        headers.add(Boolean.TRUE);
        actions.add(null);

        if (hasFiles) {
            labels.add(getString(R.string.soulseek_browse_user));
            states.add(null);
            iconKeys.add(null);
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override
                public void run() {
                    dismissThemedContextMenu();
                    if (!requireReachPeerConnectivity()) return;
                    openSoulseekBrowse(peer, "");
                }
            });
        }
        labels.add(getString(R.string.soulseek_view_profile));
        states.add(null);
        iconKeys.add(null);
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override
            public void run() {
                dismissThemedContextMenu();
                openSoulseekUserProfile(peer, null);
            }
        });
        if (soulseekMessagingEnabled) {
            labels.add(getString(R.string.soulseek_compose_message));
            states.add(null);
            iconKeys.add(null);
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override
                public void run() {
                    dismissThemedContextMenu();
                    soulseekMessagePeer = peer;
                    buildSoulseekConversationUI(peer);
                }
            });
        }
        labels.add(getString(R.string.soulseek_edit_user_note));
        states.add(null);
        iconKeys.add(null);
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override
            public void run() {
                dismissThemedContextMenu();
                openSoulseekPeerNoteEditor(peer);
            }
        });
        if (note != null && !note.trim().isEmpty()) {
            labels.add(getString(R.string.soulseek_clear_user_note));
            states.add(null);
            iconKeys.add(null);
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override
                public void run() {
                    dismissThemedContextMenu();
                    SoulseekPeerNotes.clearNote(MainActivity.this, peer);
                    rebuildContextReachPeerTier(true);
                }
            });
        }
        if (!SolarDeveloperAccounts.isVirtualPeer(peer)) {
            labels.add(getString(blocked ? R.string.soulseek_unblock_user : R.string.soulseek_block_user));
            states.add(null);
            iconKeys.add(null);
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override
                public void run() {
                    dismissThemedContextMenu();
                    toggleSoulseekPeerBlocked(peer, !blocked);
                }
            });
        }
        labels.add(getString(favorited ? R.string.soulseek_remove_friend : R.string.soulseek_add_friend));
        states.add(null);
        iconKeys.add(null);
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override
            public void run() {
                dismissThemedContextMenu();
                toggleSoulseekPeerFavorite(peer, !favorited);
            }
        });

        showContextMenuTierInPlace(peer, labels, states, iconKeys, headers, actions, focusList);
    }

    private static final String[] REACH_REACTION_EMOJIS =
            new String[] {"\uD83D\uDC4D", "\u2764", "\uD83D\uDE02", "\uD83D\uDE2E", "\uD83D\uDE22"};

    private static final String[] REACH_REACTION_LEGACY =
            new String[] {"+1", ":)", "\u2764", "\u263A"};

    private void rebuildContextReachReactTier(boolean focusList) {
        final String quote = contextReachReactQuote;
        final String peer = contextReachPeerUser != null ? contextReachPeerUser : soulseekMessagePeer;
        if (quote == null || quote.isEmpty()) return;

        java.util.ArrayList<String> labels = new java.util.ArrayList<String>();
        java.util.ArrayList<String> states = new java.util.ArrayList<String>();
        java.util.ArrayList<Boolean> headers = new java.util.ArrayList<Boolean>();
        java.util.ArrayList<Runnable> actions = new java.util.ArrayList<Runnable>();

        labels.add(quote);
        states.add(null);
        headers.add(Boolean.TRUE);
        actions.add(null);

        final String[] emojis = (isRoomThreadScreenActive() && soulseekChatRoomName != null)
                ? REACH_REACTION_EMOJIS
                : (ReachPeerCapabilities.useWireReactions(prefs, peer)
                        ? REACH_REACTION_EMOJIS : REACH_REACTION_LEGACY);
        final String reactAuthor = contextReachPeerUser;
        for (final String emoji : emojis) {
            labels.add(emoji);
            states.add(null);
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override
                public void run() {
                    dismissThemedContextMenu();
                    if (isRoomThreadScreenActive() && soulseekChatRoomName != null) {
                        sendSoulseekRoomReaction(reactAuthor, quote, emoji);
                    } else {
                        sendSoulseekReaction(peer, quote, emoji);
                    }
                }
            });
        }

        showContextMenuTierInPlace(getString(R.string.soulseek_react_to_message),
                labels, states, null, headers, actions, focusList);
    }

    private void sendSoulseekReaction(final String peer, final String quoteText, final String emoji) {
        if (peer == null || peer.trim().isEmpty() || quoteText == null || quoteText.trim().isEmpty()) {
            return;
        }
        final String to = peer.trim();
        final String quote = quoteText.trim();
        final boolean wire = ReachPeerCapabilities.useWireReactions(prefs, to);
        final String outbound = wire
                ? ReachMessageFormat.formatReactionWire(quote, emoji)
                : emoji;
        if (SolarDeveloperAccounts.isVirtualPeer(to)) {
            SoulseekClient client = ensureSoulseekClient();
            if (client != null) client.warmConnectionAsync();
            SolarDiagSessionManager.ensureSession(this, prefs);
            SolarDeveloperMessaging.sendUserMessage(this, prefs, client, outbound,
                    new SoulseekClient.MessageSendCallback() {
                @Override
                public void onSent() {
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            soulseekConversationFocusLastMessage = true;
                            buildSoulseekConversationUI(SolarDeveloperAccounts.VIRTUAL_PEER);
                        }
                    });
                }

                @Override
                public void onError(final String reason) {
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            soulseekConversationFocusLastMessage = true;
                            buildSoulseekConversationUI(SolarDeveloperAccounts.VIRTUAL_PEER);
                        }
                    });
                }
            });
            return;
        }
        ensureSoulseekClient().sendPrivateMessage(to, outbound, new SoulseekClient.MessageSendCallback() {
            @Override
            public void onSent() {
                SoulseekMessaging.append(MainActivity.this, prefs, new SoulseekMessaging.Message(
                        0, (int) (System.currentTimeMillis() / 1000L), to, outbound, false));
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        Toast.makeText(MainActivity.this, getString(R.string.soulseek_message_sent),
                                Toast.LENGTH_SHORT).show();
                        soulseekConversationFocusLastMessage = true;
                        buildSoulseekConversationUI(to);
                    }
                });
            }

            @Override
            public void onError(final String reason) {
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        Toast.makeText(MainActivity.this, reason, Toast.LENGTH_LONG).show();
                        buildSoulseekConversationUI(to);
                    }
                });
            }
        });
    }

    private void restoreConversationAfterKeyboard() {
        currentScreenState = STATE_SETTINGS;
        if (layoutWifiKeyboard != null) layoutWifiKeyboard.setVisibility(View.GONE);
        if (layoutSettingsMode != null) layoutSettingsMode.setVisibility(View.VISIBLE);
        updateStatusBarTitle();
    }

    /** After PM compose: open conversation when launched from context alert; else refresh in-thread. */
    private void finishPmComposeNavigation(String peer) {
        restoreConversationAfterKeyboard();
        final int composeReturn = keyboardComposeReturnScreen;
        keyboardComposeFromContextPm = false;
        keyboardComposeReturnScreen = -1;
        soulseekConversationFocusLastMessage = true;
        if (composeReturn >= 0) {
            soulseekConversationReturnScreen = composeReturn;
            soulseekConversationReturnSubKey = null;
        }
        buildSoulseekConversationUI(peer);
        keyboardReturnSettingsSubKey = null;
    }

    private void openKeyboard() {
        typedPassword = keyboardPrefill != null ? keyboardPrefill : "";
        keyboardPrefill = null;
        keyboardIndex = 0;
        keyboardPpLongDoCase = true;
        // 2026-07-15 — Reset paint caches so first frame styles input + current key.
        keyboardLastInputShown = null;
        keyboardLastPlaceholder = !keyboardInputIsPlaceholder(); // force style once
        keyboardLastStyledIndex = Integer.MIN_VALUE;
        if (tvKeyboardSsid != null) {
            tvKeyboardSsid.setText(getKeyboardScreenTitle());
        }
        if (tvKeyboardHint != null) {
            // 2026-07-18 — Y1/Y2: theme-tinted button glyphs. A5: prose Vol/Back legend.
            // Was: always R.string.keyboard_hint prose (glyphs only on IME SolarWheelKeyboardUi).
            // Reversal: setText(getString(R.string.keyboard_hint)) for all devices.
            if (A5KeyboardKeys.active()) {
                tvKeyboardHint.setText(getString(R.string.keyboard_hint_a5));
            } else {
                tvKeyboardHint.setText(HardwareButtonGlyph.keyboardHint(this));
            }
            tvKeyboardHint.setVisibility(View.VISIBLE);
            // #region agent log
            try {
                CharSequence t = tvKeyboardHint.getText();
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("a5", A5KeyboardKeys.active());
                d.put("hintLen", t != null ? t.length() : -1);
                d.put("hasImageSpan", t instanceof android.text.Spanned
                        && ((android.text.Spanned) t).getSpans(0, t.length(),
                        android.text.style.ImageSpan.class).length > 0);
                d.put("vis", tvKeyboardHint.getVisibility());
                d.put("backAssetOk", HardwareButtonGlyph.loadRaw(this,
                        HardwareButtonGlyph.Button.BACK) != null);
                Debug0f5debLog.log(this, "MainActivity.openKeyboard",
                        "keyboard hint applied", "KB-H1,KB-H3", d);
            } catch (Exception ignored) {}
            // #endregion
        }
        updateStatusBarTitle();
        applyKeyboardTheme();
        // Re-apply glyphs after theme paint (typeface/size) so spans are not left as prose-only.
        if (tvKeyboardHint != null && !A5KeyboardKeys.active()) {
            tvKeyboardHint.setText(HardwareButtonGlyph.keyboardHint(this));
            tvKeyboardHint.setVisibility(View.VISIBLE);
        }
        updateKeyboardUI();
        // 2026-07-14 — Touch focus + drag scroll on in-app key strip (same as IME).
        attachInAppKeyboardTouch();
    }

    /**
     * 2026-07-14 — Wire A5/touch strip on MainActivity's five key TextViews.
     * Layman: poke letters to focus/type; drag sideways to scroll the alphabet.
     * Tech: SolarWheelKeyboardUi.attachTouch with adapter over keyboardIndex / typedPassword.
     * Reversal: no-op; keyboard stays key-only on MainActivity.
     */
    private void attachInAppKeyboardTouch() {
        if (tvKeyPprev == null || !A5FocusConfirm.enabled()) return;
        View stripParent = tvKeyCurrent != null ? (View) tvKeyCurrent.getParent() : null;
        SolarWheelKeyboardUi.attachTouchSlots(
                new TextView[] { tvKeyPprev, tvKeyPrev, tvKeyCurrent, tvKeyNext, tvKeyNnext },
                stripParent,
                new SolarWheelKeyboardUi.TouchHost() {
                    @Override
                    public int getIndex() {
                        return keyboardIndex;
                    }

                    @Override
                    public int charsetLength() {
                        return KEYBOARD_CHARS.length;
                    }

                    @Override
                    public void setIndex(int idx) {
                        if (idx < 0 || idx >= KEYBOARD_CHARS.length) return;
                        keyboardIndex = idx;
                        // 2026-07-15 — Wheel only: letters strip, not full theme restyle.
                        updateKeyboardKeyStripTexts();
                    }

                    @Override
                    public void confirmCurrent() {
                        handleKeyboardInput();
                    }

                    @Override
                    public void wheelBy(int steps) {
                        int len = KEYBOARD_CHARS.length;
                        if (len <= 0) return;
                        keyboardIndex = (keyboardIndex + steps % len + len) % len;
                        updateKeyboardKeyStripTexts();
                    }
                });
    }

