    private void buildDeezerSettingsUI() {
        setSettingsSubScreen(SettingsScreens.DEEZER);
        updateStatusBarTitle();
        DeezerAccount.migrateLegacyArl(this, prefs);
        containerSettingsItems.removeAllViews();
        Button back = createListButton(getString(R.string.common_cancel_back));
        styleSecondaryLabel(back);
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                buildReachSettingsUI(3);
            }
        });
        containerSettingsItems.addView(back);

        LinearLayout btnEnable = createSettingsRow(RowKeys.DEEZER_ENABLED,
                R.string.common_enable, false);
        btnEnable.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                deezerEnabled = !deezerEnabled;
                prefs.edit().putBoolean(DeezerAccount.PREF_ENABLED, deezerEnabled).commit();
                applyReachServiceState();
                buildDeezerSettingsUI();
                refreshSettingsPreview(RowKeys.DEEZER_ENABLED);
            }
        });
        containerSettingsItems.addView(btnEnable);

        if (!deezerActive()) {
            if (containerSettingsItems.getChildCount() > 1) {
                containerSettingsItems.getChildAt(1).requestFocus();
            }
            refreshSettingsPreview(RowKeys.DEEZER_ENABLED);
            return;
        }

        final boolean userConfigured = DeezerAccount.isUserArlConfigured(prefs);

        Button search = createListButton(getString(R.string.deezer_search_row));
        search.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                deezerReturnScreen = STATE_SETTINGS;
                openDeezerScreen(true, false);
            }
        });
        containerSettingsItems.addView(search);

        Button setup = createListButton(getString(userConfigured
                ? R.string.deezer_change_account_pc : R.string.deezer_setup_pc));
        setup.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                deezerReturnScreen = STATE_SETTINGS;
                openDeezerSetupScreen(true);
            }
        });
        containerSettingsItems.addView(setup);

        String status;
        if (!userConfigured) {
            status = getString(R.string.deezer_account_not_logged_in);
        } else {
            status = getString(R.string.deezer_account_status);
            if (DeezerAccount.displayUser(prefs).isEmpty()) refreshDeezerSessionFromPrefs(true);
        }
        Button account = createListButton(status);
        account.setEnabled(false);
        containerSettingsItems.addView(account);

        if (userConfigured) {
            Button clear = createListButton(getString(R.string.deezer_reset_to_demo));
            clear.setOnClickListener(new View.OnClickListener() {
                @Override public void onClick(View v) {
                    clickFeedback();
                    DeezerAccount.clear(prefs);
                    ConnectivityHelper.setDeezerLoginOk(false);
                    Toast.makeText(MainActivity.this, getString(R.string.deezer_reset_to_demo_done),
                            Toast.LENGTH_SHORT).show();
                    refreshDeezerSessionFromPrefs(true);
                    buildDeezerSettingsUI();
                    buildHomeMenu();
                }
            });
            containerSettingsItems.addView(clear);
        }
        if (containerSettingsItems.getChildCount() > 0) containerSettingsItems.getChildAt(0).requestFocus();
    }

    private void restoreSettingsAfterSoulseekAccount() {
        soulseekReplyQuoteText = "";
        final String returnKey = keyboardReturnSettingsSubKey;
        keyboardReturnSettingsSubKey = null;
        if (keyboardComposeFromContextPm) {
            keyboardComposeFromContextPm = false;
            layoutWifiKeyboard.setVisibility(View.GONE);
            final int backScreen = keyboardComposeReturnScreen;
            keyboardComposeReturnScreen = -1;
            if (backScreen == STATE_SETTINGS && returnKey != null) {
                currentScreenState = STATE_SETTINGS;
                layoutSettingsMode.setVisibility(View.VISIBLE);
                restorePmComposeReturnScreen(returnKey);
                updateStatusBarTitle();
            } else if (backScreen >= 0) {
                changeScreen(backScreen);
            } else {
                changeScreen(STATE_MENU);
            }
            return;
        }
        if (returnKey != null && SettingsScreens.isSoulseek(returnKey)) {
            currentScreenState = STATE_SETTINGS;
            layoutWifiKeyboard.setVisibility(View.GONE);
            layoutSettingsMode.setVisibility(View.VISIBLE);
            restoreSoulseekSettingsScreen(returnKey);
            updateStatusBarTitle();
        } else if (SettingsScreens.isSoulseek(returnKey)) {
            currentScreenState = STATE_SETTINGS;
            layoutWifiKeyboard.setVisibility(View.GONE);
            layoutSettingsMode.setVisibility(View.VISIBLE);
            restoreSoulseekSettingsScreen(returnKey);
            updateStatusBarTitle();
        } else {
            changeScreen(STATE_SETTINGS);
        }
    }

    private void restorePmComposeReturnScreen(String returnKey) {
        if (SettingsScreens.SOULSEEK_MESSAGES_THREAD.equals(returnKey)) {
            buildSoulseekConversationUI(soulseekMessagePeer);
        } else if (SettingsScreens.isSoulseek(returnKey)) {
            restoreSoulseekSettingsScreen(returnKey);
        } else {
            buildSettingsUI();
        }
    }

