    private void handleKeyboardEnter() {
        if (keyboardPurpose == KEYBOARD_WIFI) connectToWifi();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_USER) finishSoulseekUserEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_SEARCH) finishSoulseekSearchEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_FIND) finishSoulseekFindEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_MSG) finishSoulseekMsgEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_CONTACT) finishSoulseekContactEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_ROOM_WALL) finishSoulseekRoomWallEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_ROOM) finishSoulseekRoomMsgEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_INTEREST) finishSoulseekInterestEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_PEER_NOTE) finishSoulseekPeerNoteEntry();
        else if (keyboardPurpose == KEYBOARD_SOULSEEK_ROOM_SEARCH) finishSoulseekRoomSearchEntry();
        else if (keyboardPurpose == KEYBOARD_DEEZER_SEARCH) finishDeezerSearchEntry();
        else if (keyboardPurpose == KEYBOARD_PODCAST_SEARCH) finishPodcastSearchEntry();
        else if (keyboardPurpose == KEYBOARD_PLAYLIST_NAME) finishPlaylistNameEntry();
        else if (keyboardPurpose == KEYBOARD_BT_PAIRING_PIN) finishBtPairingPinEntry();
        else if (keyboardPurpose == KEYBOARD_LIBRARY_SEARCH) finishLibrarySearchEntry();
        else if (keyboardPurpose == KEYBOARD_YOUTUBE_SEARCH) finishYouTubeSearchEntry();
        else if (keyboardPurpose == KEYBOARD_LALAL_KEY) finishLalalKeyEntry();
        else if (keyboardPurpose == NavidromeSettingsHost.KEYBOARD_URL
                || keyboardPurpose == NavidromeSettingsHost.KEYBOARD_USER
                || keyboardPurpose == NavidromeSettingsHost.KEYBOARD_PASS) {
            if (navidromeSettingsHost != null) navidromeSettingsHost.finishKeyboard(keyboardPurpose, typedPassword.trim());
            changeScreen(STATE_SETTINGS);
            buildNavidromeSettingsUI();
        }
        else if (keyboardPurpose == PlexSettingsHost.KEYBOARD_URL
                || keyboardPurpose == PlexSettingsHost.KEYBOARD_TOKEN) {
            if (plexSettingsHost != null) plexSettingsHost.finishKeyboard(keyboardPurpose, typedPassword.trim());
            changeScreen(STATE_SETTINGS);
            buildPlexSettingsUI();
        }
        else if (keyboardPurpose == NavidromeScreenHost.KEYBOARD_SEARCH) {
            changeScreen(STATE_NAVIDROME);
            if (navidromeScreenHost != null) {
                navidromeScreenHost.finishSearchKeyboard(typedPassword.trim());
            }
        }
        else if (keyboardPurpose == PlexScreenHost.KEYBOARD_SEARCH) {
            changeScreen(STATE_PLEX);
            if (plexScreenHost != null) {
                plexScreenHost.finishSearchKeyboard(typedPassword.trim());
            }
        }
        else if (keyboardPurpose == com.solar.launcher.jellyfin.JellyfinSettingsHost.KEYBOARD_URL
                || keyboardPurpose == com.solar.launcher.jellyfin.JellyfinSettingsHost.KEYBOARD_USER
                || keyboardPurpose == com.solar.launcher.jellyfin.JellyfinSettingsHost.KEYBOARD_PASS) {
            if (jellyfinSettingsHost != null) jellyfinSettingsHost.finishKeyboard(keyboardPurpose, typedPassword.trim());
            changeScreen(STATE_SETTINGS);
            buildJellyfinSettingsUI();
        }
        else if (keyboardPurpose == com.solar.launcher.jellyfin.JellyfinScreenHost.KEYBOARD_SEARCH) {
            changeScreen(STATE_JELLYFIN);
            if (jellyfinScreenHost != null) {
                jellyfinScreenHost.finishSearchKeyboard(typedPassword.trim());
            }
        }
        else if (keyboardPurpose == com.solar.launcher.scrobble.ScrobbleSettingsHost.KEYBOARD_LASTFM_USER
                || keyboardPurpose == com.solar.launcher.scrobble.ScrobbleSettingsHost.KEYBOARD_LASTFM_PASS
                || keyboardPurpose == com.solar.launcher.scrobble.ScrobbleSettingsHost.KEYBOARD_LISTENBRAINZ_TOKEN) {
            if (scrobbleSettingsHost != null) scrobbleSettingsHost.finishKeyboard(keyboardPurpose, typedPassword.trim());
            changeScreen(STATE_SETTINGS);
            buildScrobblingSettingsUI();
        }
        else finishSoulseekPassEntry();
    }

