    private void handleKeyboardPlayPauseLongPress() {
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("indexBefore", keyboardIndex);
            d.put("ppLongDoCase", keyboardPpLongDoCase);
            DebugAgentLog.log(this, "MainActivity.handleKeyboardPlayPauseLongPress",
                    "charset switch long press", "H2", d);
        } catch (Exception ignored) {}
        // #endregion
        clickFeedback();
        if (keyboardPpLongDoCase) {
            int flipped = keyboardFlipCaseIndex(keyboardIndex);
            keyboardIndex = flipped != keyboardIndex ? flipped : keyboardMapToNextCharset(keyboardIndex);
        } else {
            keyboardIndex = keyboardMapToNextCharset(keyboardIndex);
        }
        keyboardPpLongDoCase = !keyboardPpLongDoCase;
        updateKeyboardUI();
    }

    private void connectToWifi() {
        final String ssid = targetWifiSsid;
        final String password = typedPassword;
        final boolean open = isTargetWifiOpen;
        Toast.makeText(this, getString(R.string.toast_wifi_connecting, ssid), Toast.LENGTH_SHORT).show();
        beginWifiConnect();
        WifiConnector.connect(this, ssid, password, open, new WifiConnector.Callback() {
            @Override
            public void onComplete(boolean success) {
                endWifiConnect();
                if (!success) {
                    Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_connect_failed),
                            Toast.LENGTH_SHORT).show();
                }
                prefetchWifiConfiguredNetworksAsync();
                changeScreen(STATE_WIFI);
            }
        });
    }

    private void performWifiConnection(String ssid, String password, boolean open) {
        Toast.makeText(this, getString(R.string.toast_wifi_connecting, ssid), Toast.LENGTH_SHORT).show();
        beginWifiConnect();
        WifiConnector.connect(this, ssid, password, open, wrapWifiConnectCallback(wifiConnectResultCallback()));
    }

    private void beginWifiConnect() {
        wifiConnectInProgress = true;
        WifiConnector.cancelPending();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("screen", currentScreenState);
            d.put("tierTop", contextMenuTopTier());
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            Debug0f5debLog.log(this, "MainActivity.beginWifiConnect",
                    "wifi connect no UiBusy yet", "H2", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    private void endWifiConnect() {
        wifiConnectInProgress = false;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            Debug0f5debLog.log(this, "MainActivity.endWifiConnect",
                    "wifi connect end", "H2", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    private WifiConnector.Callback wrapWifiConnectCallback(final WifiConnector.Callback inner) {
        return new WifiConnector.Callback() {
            @Override
            public void onComplete(boolean success) {
                endWifiConnect();
                prefetchWifiConfiguredNetworksAsync();
                if (inner != null) inner.onComplete(success);
            }
        };
    }

    private boolean isWifiNetworkOpen(String capabilities) {
        if (capabilities == null || capabilities.isEmpty()) return true;
        String caps = capabilities.toUpperCase(Locale.US);
        return !caps.contains("WPA") && !caps.contains("WEP") && !caps.contains("PSK")
                && !caps.contains("EAP");
    }

    private boolean isWifiSsidConnected(String ssid) {
        if (ssid == null || ssid.isEmpty()) return false;
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            WifiInfo info = wm != null ? wm.getConnectionInfo() : null;
            String connected = info != null && info.getSSID() != null ? info.getSSID().replace("\"", "") : "";
            return ssid.equals(connected);
        } catch (Exception ignored) {
            return false;
        }
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void rebuildWifiScanCache() {
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            applyWifiScanCache(wm != null ? wm.getScanResults() : null);
        } catch (Exception e) {
            SolarLog.w("MainActivity", "rebuildWifiScanCache: " + e.getMessage());
        }
    }

    private void applyWifiScanCache(List<ScanResult> results) {
        wifiScanCacheBySsid.clear();
        if (results == null) return;
        for (ScanResult result : results) {
            if (result.SSID != null && !result.SSID.isEmpty()) {
                wifiScanCacheBySsid.put(result.SSID, result);
            }
        }
    }

    @android.annotation.SuppressLint("MissingPermission")
    private int wifiRssiForSsid(String ssid) {
        if (ssid == null || ssid.isEmpty()) return -100;
        ScanResult cached = wifiScanCacheBySsid.get(ssid);
        if (cached != null) return cached.level;
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            if (wm == null) return -100;
            java.util.List<ScanResult> results = wm.getScanResults();
            if (results != null) {
                for (ScanResult result : results) {
                    if (ssid.equals(result.SSID)) return result.level;
                }
            }
            if (isWifiSsidConnected(ssid)) {
                WifiInfo info = wm.getConnectionInfo();
                if (info != null) return info.getRssi();
            }
        } catch (Exception ignored) {}
        return -100;
    }

    private String wifiContextIconKeyForSsid(String ssid) {
        String caps = wifiCapabilitiesForSsid(ssid);
        if (!isWifiNetworkOpen(caps) && !isWifiSsidConnected(ssid)) {
            return "wifi.lock";
        }
        return "wifi.sig." + ThemeManager.wifiSignalIndex(wifiRssiForSsid(ssid));
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void startBluetoothScan() {
        startBluetoothScan(true);
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void startBluetoothScan(boolean requestFocus) {
        updateStatusBarTitle();
        syncBluetoothContextPendingFlags();
        final String restoreFocusAddress = requestFocus ? null : bluetoothFocusedAddress();
        final BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
        boolean isOn = false;
        String statusText = "OFF";
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("requestFocus", requestFocus);
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            d.put("btConnect", btConnectInProgress);
            Debug0f5debLog.log(this, "MainActivity.startBluetoothScan",
                    "bt scan rebuild no UiBusy yet", "H3", d);
        } catch (Exception ignored) {}
        // #endregion

        if (ba != null) {
            int state = ba.getState();
            boolean powerOn = isBluetoothPowerOn();
            if (!powerOn && (btContextPendingEnable || btContextPendingDisable
                    || state == BluetoothAdapter.STATE_TURNING_ON
                    || state == BluetoothAdapter.STATE_TURNING_OFF)) {
                statusText = "Wait...";
            } else if (powerOn) {
                isOn = true;
                statusText = "ON";
            }
        }

        View existingToggle = containerBtItems.findViewById(999991);
        if (existingToggle == null) {
            final LinearLayout btnToggle = createSettingRow(RowKeys.BT_POWER, R.string.bluetooth_power, statusText);
            btnToggle.setId(999991);
            btnToggle.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    clickFeedback();
                    applyBluetoothPowerState(!isBluetoothPowerOn());
                    TextView tvRight = (TextView) btnToggle.getChildAt(1);
                    tvRight.setText("Wait...");
                    if (!btnToggle.hasFocus())
                        ThemeManager.applyThemedTextStyle(tvRight, y1RowTextColorSelected(Y1_ROW_MENU));
                }
            });
            containerBtItems.addView(btnToggle, 0);
        } else {
            LinearLayout btnToggle = (LinearLayout) existingToggle;
            TextView tvRight = (TextView) btnToggle.getChildAt(1);
            tvRight.setText(statusText);
            if (!btnToggle.hasFocus())
                ThemeManager.applyThemedTextStyle(tvRight, y1InlineStateColor(statusText, false));
            for (int i = containerBtItems.getChildCount() - 1; i > 0; i--) {
                containerBtItems.removeViewAt(i);
            }
        }

        if (!isOn) {
            restoreBluetoothListFocus(restoreFocusAddress, requestFocus);
            updateNetworkRescanLoop();
            return;
        }

        foundBtDevices.clear();

        try {
            java.util.Set<BluetoothDevice> pairedDevices = ba.getBondedDevices();
            if (pairedDevices != null && pairedDevices.size() > 0) {
                for (BluetoothDevice device : pairedDevices) {
                    foundBtDevices.add(device.getAddress());
                    addBluetoothItemToUI(device.getName() != null ? device.getName() : "Unknown Device", device, true, isBluetoothAudioConnected(device));
                }
            }
        } catch (Exception e) {
        }

        restoreBluetoothListFocus(restoreFocusAddress, requestFocus);

        triggerBluetoothDiscovery(false);
        updateNetworkRescanLoop();
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void triggerBluetoothDiscovery(boolean requestFocus) {
        final BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
        if (ba == null || !isBluetoothPowerOn()) return;
        // ponytail: MTK BT stack drops A2DP during inquiry — never scan while audio sink is up.
        if (hasActiveBluetoothAudioSink()) {
            // #region agent log
            if (DebugAgentLog.ENABLED) {
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("connectedAddr", connectedA2dpAddress);
                    d.put("screen", currentScreenState);
                    DebugAgentLog.log(this, "MainActivity.triggerBluetoothDiscovery",
                            "skip_discovery_a2dp_active", "H-BT5", d);
                } catch (Exception ignored) {}
            }
            // #endregion
            return;
        }
        if (ba.isDiscovering()) return;
        ba.startDiscovery();
        if (requestFocus && currentScreenState == STATE_BLUETOOTH
                && containerBtItems != null && containerBtItems.getChildCount() > 0) {
            containerBtItems.getChildAt(0).requestFocus();
        }
    }

    // Device row: name on the left, Paired / connecting throbber / ✓ on the right (no colour prefixes).
    private void addBluetoothItemToUI(String name, final BluetoothDevice device, boolean isPaired, boolean isConnected) {
        final LinearLayout row = createBluetoothDeviceRow(name, device);
        row.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                pairBluetoothDevice(device);
            }
        });
        containerBtItems.addView(row);
    }

    @android.annotation.SuppressLint("MissingPermission")
    private String bluetoothFocusedAddress() {
        View c = getCurrentFocus();
        while (c != null) {
            Object tag = c.getTag();
            if (tag instanceof BluetoothDevice) {
                return ((BluetoothDevice) tag).getAddress();
            }
            if (c == containerBtItems) return null;
            Object parent = c.getParent();
            c = parent instanceof View ? (View) parent : null;
        }
        return null;
    }

    private boolean isBluetoothListFocusValid() {
        View focused = getCurrentFocus();
        return focused != null && focused.isShown() && focused.isFocusable()
                && containerBtItems != null && isViewDescendantOf(focused, containerBtItems);
    }

    @android.annotation.SuppressLint("MissingPermission")
    private boolean restoreBluetoothListFocus(String preferredAddress, boolean forceFirst) {
        if (containerBtItems == null || containerBtItems.getChildCount() == 0) return false;
        if (!forceFirst && preferredAddress == null && isBluetoothListFocusValid()) return true;
        if (!forceFirst && preferredAddress != null) {
            for (int i = 0; i < containerBtItems.getChildCount(); i++) {
                View row = containerBtItems.getChildAt(i);
                Object tag = row != null ? row.getTag() : null;
                if (!(tag instanceof BluetoothDevice)) continue;
                String addr = ((BluetoothDevice) tag).getAddress();
                if (preferredAddress.equals(addr) && row.requestFocus()) return true;
            }
        }
        if (!forceFirst && isBluetoothListFocusValid()) return true;
        for (int i = 0; i < containerBtItems.getChildCount(); i++) {
            View row = containerBtItems.getChildAt(i);
            if (row != null && row.getVisibility() == View.VISIBLE && row.isEnabled()
                    && row.isFocusable() && row.requestFocus()) {
                return true;
            }
        }
        return false;
    }

    /** Bluetooth settings list row — themed like other Y1 menus with inline connection state. */
    private LinearLayout createBluetoothDeviceRow(String name, BluetoothDevice device) {
        final int rowKind = y1RowKindForScreen();
        final LinearLayout layout = new LinearLayout(this);
        layout.setTag(device);
        layout.setSoundEffectsEnabled(false);
        layout.setOrientation(LinearLayout.HORIZONTAL);
        applySettingsRowFocusability(layout);
        layout.setGravity(android.view.Gravity.CENTER_VERTICAL);
        int hPad = (int) (10 * getResources().getDisplayMetrics().density);
        layout.setPadding(hPad, 0, hPad, 0);
        int rowW = listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx();
        layout.setBackground(getY1RowBackground(false, rowW, rowKind));

        final TextView tvLeft = new TextView(this);
        tvLeft.setFocusable(false);
        tvLeft.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        tvLeft.setText(name);
        ThemeManager.applyThemedTextStyle(tvLeft, y1RowTextColorNormal(rowKind));
        tvLeft.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size));
        enableMarquee(tvLeft);
        tvLeft.setLayoutParams(new LinearLayout.LayoutParams(
                0, LinearLayout.LayoutParams.WRAP_CONTENT, 1.0f));
        layout.addView(tvLeft);

        final android.widget.FrameLayout stateSlot = new android.widget.FrameLayout(this);
        int spinSize = (int) (y1RowHeightPx * 0.55f);
        int stateSlotW = Math.max(spinSize + hPad, (int) (76 * getResources().getDisplayMetrics().density));
        stateSlot.setLayoutParams(new LinearLayout.LayoutParams(
                stateSlotW, y1RowHeightPx));
        applyBluetoothRowState(stateSlot, bluetoothDeviceStateText(device), spinSize, hPad);
        layout.addView(stateSlot);

        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT, y1RowHeightPx);
        lp.setMargins(0, 1, 0, 1);
        layout.setLayoutParams(lp);

        layout.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                int w = layout.getWidth() > 0 ? layout.getWidth()
                        : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());
                layout.setBackground(getY1RowBackground(hasFocus, w, rowKind));
                ThemeManager.applyThemedTextStyle(tvLeft, hasFocus
                        ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                layout.setSelected(hasFocus);
                if (hasFocus) showFastScrollLetter(name);
            }
        });
        return layout;
    }

    /** Right slot on BT menu rows — muted status text, spinner while connecting, or checkmark. */
    private void applyBluetoothRowState(android.widget.FrameLayout slot, String stateText,
            int spinSize, int marginEnd) {
        if (slot == null) return;
        slot.removeAllViews();
        if (ThemedContextMenu.STATE_CONNECTING.equals(stateText)) {
            ProgressBar spin = new ProgressBar(this, null, android.R.attr.progressBarStyleSmall);
            spin.setTag(TAG_BT_ROW_SPIN);
            android.widget.FrameLayout.LayoutParams spinLp = new android.widget.FrameLayout.LayoutParams(
                    spinSize, spinSize);
            spinLp.gravity = android.view.Gravity.CENTER_VERTICAL | android.view.Gravity.END;
            spinLp.rightMargin = marginEnd / 2;
            slot.addView(spin, spinLp);
            return;
        }
        TextView state = new TextView(this);
        state.setTag(TAG_BT_ROW_STATE);
        state.setFocusable(false);
        state.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        state.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size) * 0.9f);
        state.setSingleLine(true);
        state.setGravity(android.view.Gravity.CENTER_VERTICAL | android.view.Gravity.END);
        ThemeManager.applyThemedTextStyle(state, ThemeManager.getTextColorSecondary());
        if (stateText != null && stateText.length() > 0) {
            state.setText(stateText);
        }
        slot.addView(state, new android.widget.FrameLayout.LayoutParams(
                android.widget.FrameLayout.LayoutParams.MATCH_PARENT,
                android.widget.FrameLayout.LayoutParams.MATCH_PARENT));
    }

    private String bluetoothDeviceStateText(BluetoothDevice device) {
        if (device == null) return "";
        try {
            if (isBluetoothAudioConnected(device)) return getString(R.string.common_check);
            if (isBtDeviceConnecting(device)) return ThemedContextMenu.STATE_CONNECTING;
            if (device.getBondState() == BluetoothDevice.BOND_BONDED) {
                return getString(R.string.bluetooth_status_paired);
            }
            return getString(R.string.bluetooth_status_nearby);
        } catch (Exception ignored) {}
        return "";
    }

    private boolean isBtDeviceConnecting(BluetoothDevice device) {
        if (device == null) return false;
        String addr = device.getAddress();
        if (addr == null) return false;
        if (pairingDeviceAddress != null && pairingDeviceAddress.equals(addr)) return true;
        if (!btConnectInProgress || btConnectingAddress == null) return false;
        if (!btConnectingAddress.equals(addr)) return false;
        if (isBluetoothAudioConnected(device)) return false;
        return System.currentTimeMillis() - btConnectingStartedAt < BT_CONNECT_THROBBER_MS;
    }

    private void beginBtConnect(BluetoothDevice device) {
        if (device == null) return;
        btConnectingAddress = device.getAddress();
        btConnectingStartedAt = System.currentTimeMillis();
        btConnectInProgress = true;
        progressHandler.removeCallbacks(btConnectTimeoutRunnable);
        progressHandler.removeCallbacks(btConnectUiTickRunnable);
        progressHandler.postDelayed(btConnectTimeoutRunnable, BT_CONNECT_THROBBER_MS);
        progressHandler.post(btConnectUiTickRunnable);
        refreshBtConnectUi();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("addr", btConnectingAddress);
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            Debug0f5debLog.log(this, "MainActivity.beginBtConnect",
                    "bt connect no UiBusy yet", "H3", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    private void endBtConnect() {
        if (!btConnectInProgress && btConnectingAddress == null) return;
        btConnectInProgress = false;
        btConnectingAddress = null;
        progressHandler.removeCallbacks(btConnectTimeoutRunnable);
        progressHandler.removeCallbacks(btConnectUiTickRunnable);
        refreshBtConnectUi();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            Debug0f5debLog.log(this, "MainActivity.endBtConnect", "bt connect end", "H3", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    private void refreshBtConnectUi() {
        if (currentScreenState == STATE_BLUETOOTH) {
            startBluetoothScan(false);
        }
        if (themedContextMenu != null && themedContextMenu.isShowing() && isBtTierMounted()) {
            refreshContextBluetoothTier(false, false);
        }
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void pairBluetoothDevice(BluetoothDevice device) {
        if (device == null) return;
        try {
            if (device.getBondState() == BluetoothDevice.BOND_BONDED) {
                if (isBluetoothAudioConnected(device)) {
                    // #region agent log
                    try {
                        org.json.JSONObject d = new org.json.JSONObject();
                        d.put("addr", device.getAddress());
                        d.put("action", "disconnect_a2dp");
                        DebugAgentLog.log(this, "MainActivity.pairBluetoothDevice", "toggle", "H-BT3", d);
                    } catch (Exception ignored) {}
                    // #endregion
                    disconnectBluetoothAudio(device);
                    refreshBtConnectUi();
                } else {
                    // #region agent log
                    try {
                        org.json.JSONObject d = new org.json.JSONObject();
                        d.put("addr", device.getAddress());
                        d.put("action", "connect_a2dp");
                        DebugAgentLog.log(this, "MainActivity.pairBluetoothDevice", "toggle", "H-BT3", d);
                    } catch (Exception ignored) {}
                    // #endregion
                    userInitiatedA2dpConnect = true;
                    beginBtConnect(device);
                    connectBluetoothAudio(device, true);
                }
                progressHandler.postDelayed(new Runnable() {
                    @Override public void run() {
                        if (currentScreenState == STATE_BLUETOOTH) startBluetoothScan(false);
                        if (themedContextMenu != null && themedContextMenu.isShowing()
                                && isBtTierMounted()) {
                            refreshContextBluetoothTier(false, false);
                        }
                    }
                }, 800);
                return;
            }
            BluetoothAdapter adapter = BluetoothAdapter.getDefaultAdapter();
            boolean wasDiscovering = adapter != null && adapter.isDiscovering();
            if (wasDiscovering) adapter.cancelDiscovery();
            android.util.Log.d("SolarBT", "pairBluetoothDevice: bondState="
                    + device.getBondState() + " wasDiscovering=" + wasDiscovering
                    + " addr=" + device.getAddress());
            pairingDeviceAddress = device.getAddress();
            beginBtConnect(device);
            Toast.makeText(this, getString(R.string.toast_pairing, device.getName()), Toast.LENGTH_SHORT).show();
            // MT6572: defer createBond 500ms after cancelDiscovery so inquiry stops at controller.
            final BluetoothDevice deviceToBond = device;
            progressHandler.postDelayed(new Runnable() {
                @Override public void run() {
                    if (pairingDeviceAddress == null) return;
                    if (!createBluetoothBond(deviceToBond)) {
                        pairingDeviceAddress = null;
                        endBtConnect();
                        Toast.makeText(MainActivity.this,
                                getString(R.string.toast_pairing_failed), Toast.LENGTH_SHORT).show();
                    }
                }
            }, wasDiscovering ? 500L : 0L);
        } catch (Exception e) {
            pairingDeviceAddress = null;
            endBtConnect();
            Toast.makeText(this, getString(R.string.toast_pairing_failed), Toast.LENGTH_SHORT).show();
        }
    }

    private boolean createBluetoothBond(BluetoothDevice device) {
        try {
            Method createBond = device.getClass().getMethod("createBond");
            Object result = createBond.invoke(device);
            boolean ok = !(result instanceof Boolean) || (Boolean) result;
            android.util.Log.d("SolarBT", "createBond(" + device.getAddress() + ") = " + result + " ok=" + ok);
            return ok;
        } catch (Exception e) {
            android.util.Log.w("SolarBT", "createBond(" + device.getAddress() + ") threw: " + e);
            return false;
        }
    }

    private boolean handleBluetoothPairingRequest(BluetoothDevice device, int variant) {
        try {
            if (variant == BluetoothDevice.PAIRING_VARIANT_PIN) {
                byte[] pin = bluetoothPinBytes("0000");
                boolean ok = (Boolean) device.getClass()
                        .getMethod("setPin", byte[].class).invoke(device, pin);
                android.util.Log.d("SolarBT", "setPin(0000) ok=" + ok);
            } else if (variant == BluetoothDevice.PAIRING_VARIANT_PASSKEY_CONFIRMATION
                    || variant == 3 /* PAIRING_VARIANT_CONSENT */) {
                // CONSENT (Just Works) and passkey confirm — auto-confirm for Y1 as source.
                boolean ok = (Boolean) device.getClass()
                        .getMethod("setPairingConfirmation", boolean.class).invoke(device, true);
                android.util.Log.d("SolarBT", "setPairingConfirmation(true) ok=" + ok);
            } else {
                android.util.Log.d("SolarBT", "PAIRING_REQUEST variant=" + variant + " not handled, deferring to system");
                return false;
            }
            return true;
        } catch (Exception e) {
            android.util.Log.w("SolarBT", "PAIRING_REQUEST handling failed: " + e);
            return false;
        }
    }

    private static byte[] bluetoothPinBytes(String pin) {
        try {
            Method convert = BluetoothDevice.class.getMethod("convertPinToBytes", String.class);
            return (byte[]) convert.invoke(null, pin);
        } catch (Exception e) {
            return pin.getBytes();
        }
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void ensureA2dpProfile() {
        if (bluetoothA2dp != null) return;
        BluetoothAdapter adapter = BluetoothAdapter.getDefaultAdapter();
        if (adapter == null || !adapter.isEnabled()) return;
        adapter.getProfileProxy(this, a2dpProfileListener, BluetoothProfile.A2DP);
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void reconnectLastBluetoothAudio() {
        String addr = prefs.getString(PREF_LAST_BT_AUDIO, null);
        if (addr == null) return;
        BluetoothAdapter adapter = BluetoothAdapter.getDefaultAdapter();
        if (adapter == null || !adapter.isEnabled()) return;
        java.util.Set<BluetoothDevice> bonded = adapter.getBondedDevices();
        if (bonded == null) return;
        for (BluetoothDevice device : bonded) {
            if (addr.equals(device.getAddress())) {
                connectBluetoothAudio(device, true);
                return;
            }
        }
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void connectBluetoothAudio(BluetoothDevice device) {
        connectBluetoothAudio(device, false);
    }

    /** Disconnect other A2DP sinks before connecting (RB Meta vs Living Room TV). */
    @android.annotation.SuppressLint("MissingPermission")
    private void connectBluetoothAudio(BluetoothDevice device, boolean exclusive) {
        if (device == null) return;
        BluetoothAudioRepair.rememberLastAudioDevice(this, device);
        ensureA2dpProfile();
        BluetoothAdapter adapter = BluetoothAdapter.getDefaultAdapter();
        if (adapter != null && adapter.isDiscovering()) adapter.cancelDiscovery();
        if (exclusive && bluetoothA2dp != null && adapter != null) {
            try {
                Method disconnect = bluetoothA2dp.getClass().getMethod("disconnect", BluetoothDevice.class);
                java.util.Set<BluetoothDevice> bonded = adapter.getBondedDevices();
                if (bonded != null) {
                    for (BluetoothDevice other : bonded) {
                        if (other == null || device.getAddress().equals(other.getAddress())) continue;
                        try {
                            if (bluetoothA2dp.getConnectionState(other)
                                    == BluetoothProfile.STATE_CONNECTED) {
                                disconnect.invoke(bluetoothA2dp, other);
                            }
                        } catch (Exception ignored) {}
                    }
                }
            } catch (Exception ignored) {}
        }
        pendingA2dpDevice = device;
        if (bluetoothA2dp != null) {
            connectA2dpNow(device);
            pendingA2dpDevice = null;
        }
    }

    /** Drop cached A2DP address so UI reverts from ✓ to Paired without waiting for broadcast. */
    private void clearBluetoothConnectedAddress(BluetoothDevice device) {
        if (device == null) return;
        try {
            String addr = device.getAddress();
            if (addr != null && addr.equals(connectedA2dpAddress)) {
                connectedA2dpAddress = null;
            }
        } catch (Exception ignored) {}
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void disconnectBluetoothAudio(BluetoothDevice device) {
        if (device == null) return;
        clearBluetoothConnectedAddress(device);
        ensureA2dpProfile();
        if (bluetoothA2dp == null) {
            Toast.makeText(this, getString(R.string.toast_audio_connect_failed), Toast.LENGTH_SHORT).show();
            return;
        }
        try {
            Method disconnect = bluetoothA2dp.getClass().getMethod("disconnect", BluetoothDevice.class);
            Object ok = disconnect.invoke(bluetoothA2dp, device);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("addr", device.getAddress());
                d.put("ok", ok);
                DebugAgentLog.log(this, "MainActivity.disconnectBluetoothAudio", "a2dp disconnect", "H4", d);
            } catch (Exception ignored) {}
            // #endregion
            if (ok instanceof Boolean && !(Boolean) ok) {
                Toast.makeText(this, getString(R.string.toast_audio_connect_failed), Toast.LENGTH_SHORT).show();
            }
        } catch (Exception e) {
            Toast.makeText(this, getString(R.string.toast_audio_connect_failed), Toast.LENGTH_SHORT).show();
        }
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void connectA2dpNow(BluetoothDevice device) {
        try {
            boolean ok = BluetoothAudioRepair.connectA2dp(this, bluetoothA2dp, device, true);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("addr", device.getAddress());
                d.put("ok", ok);
                d.put("a2dpOn", audioManager != null && audioManager.isBluetoothA2dpOn());
                DebugAgentLog.log(this, "MainActivity.connectA2dpNow", "connect", "H-BT4", d);
            } catch (Exception ignored) {}
            // #endregion
            if (!ok) {
                Toast.makeText(this, getString(R.string.toast_audio_connect_failed), Toast.LENGTH_SHORT).show();
                endBtConnect();
            } else {
                routeAudioToBluetoothA2dp();
                BluetoothAudioRepair.requestRepair(this, device);
            }
        } catch (Exception e) {
            Toast.makeText(this, getString(R.string.toast_audio_connect_failed), Toast.LENGTH_SHORT).show();
            endBtConnect();
        }
    }

    /** API 17: route music stream to A2DP sink after connect. */
    private void routeAudioToBluetoothA2dp() {
        BluetoothAudioRepair.forceA2dpRoute(this, audioManager);
    }

    /**
     * After user connects a TV/speaker: prepare queue if needed and start playback on A2DP.
     * ponytail: reconnectLastBluetoothAudio on boot does not call this — only explicit Connect.
     */
    private void resumeBluetoothAudioPlayback() {
        routeAudioToBluetoothA2dp();
        if (!playback.hasAnyQueue() || playback.musicPlaylist().isEmpty()) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("hasQueue", playback.hasAnyQueue());
                d.put("musicSize", playback.musicPlaylist().size());
                DebugAgentLog.log(this, "MainActivity.resumeBluetoothAudioPlayback",
                        "no_music_to_play", "H-PLAY-BT", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        }
        isPausedByHand = false;
        boolean mpNull = mediaPlayer == null;
        boolean playing = false;
        try {
            playing = mediaPlayer != null && mediaPlayer.isPlaying();
        } catch (Exception ignored) {}
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("mpNull", mpNull);
            d.put("wasPlaying", playing);
            d.put("index", playback.musicIndex());
            DebugAgentLog.log(this, "MainActivity.resumeBluetoothAudioPlayback",
                    "resume", "H-PLAY-BT", d);
        } catch (Exception ignored) {}
        // #endregion
        if (mpNull) {
            prepareMusicTrack(playback.musicIndex());
            return;
        }
        if (!playing) {
            try {
                mediaPlayer.start();
                applyPlaybackSpeed();
                updatePlayerUI();
                syncAvrcpTrackInfo(false);
            } catch (Exception ignored) {}
        }
    }

    private boolean putGlobalIntPrivileged(String key, int value) {
        if (key == null || key.trim().isEmpty()) return false;
        return runSuCommandSilently("settings put global " + shQuote(key) + " " + value);
    }

    private boolean runSuCommandSilently(String command) {
        for (String su : new String[] {"/system/xbin/su", "su"}) {
            java.io.DataOutputStream os = null;
            Process process = null;
            try {
                process = Runtime.getRuntime().exec(su);
                os = new java.io.DataOutputStream(process.getOutputStream());
                os.writeBytes(command + "\n");
                os.writeBytes("exit\n");
                os.flush();
                int exit = process.waitFor();
                if (exit == 0) return true;
            } catch (Throwable ignored) {
            } finally {
                if (os != null) {
                    try { os.close(); } catch (Exception ignored) {}
                }
                if (process != null) process.destroy();
            }
        }
        return false;
    }

    private static String shQuote(String s) {
        return "'" + s.replace("'", "'\\''") + "'";
    }

    private void ensurePrivilegedPermissionsAsync() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                tryGrantPrivilegedPermission("android.permission.WRITE_SECURE_SETTINGS");
                tryGrantPrivilegedPermission("android.permission.BLUETOOTH_PRIVILEGED");
            }
        }).start();
    }

    private void tryGrantPrivilegedPermission(String permission) {
        if (permission == null || permission.trim().isEmpty()) return;
        runSuCommandSilently("pm grant " + shQuote(getPackageName()) + " " + shQuote(permission));
    }

    @android.annotation.SuppressLint("MissingPermission")
    private boolean hasActiveBluetoothAudioSink() {
        if (connectedA2dpAddress != null) return true;
        BluetoothAdapter adapter = BluetoothAdapter.getDefaultAdapter();
        if (adapter == null || bluetoothA2dp == null) return false;
        try {
            java.util.Set<BluetoothDevice> bonded = adapter.getBondedDevices();
            if (bonded == null) return false;
            for (BluetoothDevice device : bonded) {
                if (device != null
                        && bluetoothA2dp.getConnectionState(device) == BluetoothProfile.STATE_CONNECTED) {
                    return true;
                }
            }
        } catch (Exception ignored) {}
        return false;
    }

    @android.annotation.SuppressLint("MissingPermission")
    private void cancelBluetoothDiscoveryIfActive() {
        try {
            BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
            if (ba != null && ba.isDiscovering()) ba.cancelDiscovery();
        } catch (Exception ignored) {}
    }

    @android.annotation.SuppressLint("MissingPermission")
    private boolean isBluetoothAudioConnected(BluetoothDevice device) {
        if (device == null) return false;
        try {
            String addr = device.getAddress();
            if (addr != null && addr.equals(connectedA2dpAddress)) return true;
            if (bluetoothA2dp != null) {
                return bluetoothA2dp.getConnectionState(device) == BluetoothProfile.STATE_CONNECTED;
            }
        } catch (Exception ignored) {}
        return false;
    }

    private void startWifiScan() {
        updateStatusBarTitle();
        prefetchWifiConfiguredNetworksAsync();
        WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        // User opened Wi‑Fi setup — claim radio so silent mask does not hide networks.
        if (wm != null && wm.isWifiEnabled() && SolarSilentWifi.isUiHidden()) {
            SolarSilentWifi.onUserWifiIntent();
        }
        boolean isOn = isWifiPowerOn();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("isOn", isOn);
            d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
            d.put("wifiConnect", wifiConnectInProgress);
            Debug0f5debLog.log(this, "MainActivity.startWifiScan",
                    "wifi scan no UiBusy yet", "H2", d);
        } catch (Exception ignored) {}
        // #endregion
        updateWifiUI(null);

        if (isOn && wm != null) {
            foundWifiNetworks.clear();
            wm.startScan();
        }
        if (containerWifiItems.getChildCount() > 0) {
            containerWifiItems.getChildAt(0).requestFocus();
        }
        updateNetworkRescanLoop();
    }

    private void updateWifiUI(List<ScanResult> results) {
        final WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        boolean isOn = false;
        String statusText = "OFF";

        if (wm != null && !SolarSilentWifi.isUiHidden()) {
            int state = wm.getWifiState();
            if (state == WifiManager.WIFI_STATE_ENABLED) {
                isOn = true;
                statusText = "ON";
            } else if (state == WifiManager.WIFI_STATE_ENABLING || state == WifiManager.WIFI_STATE_DISABLING) {
                statusText = "Wait...";
            }
        }

        View existingToggle = containerWifiItems.findViewById(999992);
        if (existingToggle == null) {
            final LinearLayout btnToggle = createSettingRow(RowKeys.WIFI_POWER, R.string.wifi_power, statusText);
            btnToggle.setId(999992);
            btnToggle.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    clickFeedback();
                    if (wm != null) {
                        // User intent: unmask silent wake first so Off→On claim keeps radio up.
                        boolean silent = SolarSilentWifi.isUiHidden();
                        boolean radioOn = false;
                        try {
                            radioOn = wm.isWifiEnabled();
                        } catch (Exception ignored) {}
                        if (silent && radioOn) {
                            SolarSilentWifi.onUserWifiIntent();
                            TextView tvRight = (TextView) btnToggle.getChildAt(1);
                            tvRight.setText("ON");
                            startWifiScan();
                            return;
                        }
                        SolarSilentWifi.onUserWifiIntent();
                        boolean isCurrentlyOn = wm.isWifiEnabled();
                        if (isCurrentlyOn) {
                            TextView tvRight = (TextView) btnToggle.getChildAt(1);
                            tvRight.setText("Wait...");
                            if (!btnToggle.hasFocus())
                                ThemeManager.applyThemedTextStyle(tvRight, y1RowTextColorSelected(Y1_ROW_MENU));
                            // "Disconnecting…" + light log flush, then radio off.
                            SolarDiagnosticReporter.runBeforeWifiDisable(MainActivity.this, true,
                                    new Runnable() {
                                        @Override
                                        public void run() {
                                            try {
                                                wm.setWifiEnabled(false);
                                            } catch (Exception ignored) {}
                                        }
                                    });
                        } else {
                            Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_turning_on), Toast.LENGTH_SHORT).show();
                            wm.setWifiEnabled(true);
                            TextView tvRight = (TextView) btnToggle.getChildAt(1);
                            tvRight.setText("Wait...");
                            if (!btnToggle.hasFocus())
                                ThemeManager.applyThemedTextStyle(tvRight, y1RowTextColorSelected(Y1_ROW_MENU));
                        }
                    }
                }
            });
            containerWifiItems.addView(btnToggle, 0);
        } else {
            LinearLayout btnToggle = (LinearLayout) existingToggle;
            TextView tvRight = (TextView) btnToggle.getChildAt(1);
            tvRight.setText(statusText);
            if (!btnToggle.hasFocus())
                ThemeManager.applyThemedTextStyle(tvRight, y1InlineStateColor(statusText, false));
            for (int i = containerWifiItems.getChildCount() - 1; i > 0; i--) {
                containerWifiItems.removeViewAt(i);
            }
        }

        if (!isOn)
            return;

        if (results != null) {
            applyWifiScanCache(results);
            foundWifiNetworks.clear();
            WifiManager manager = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            WifiInfo wifiInfo = manager.getConnectionInfo();
            String connectedSSID = "";
            if (wifiInfo != null && wifiInfo.getSSID() != null) {
                connectedSSID = wifiInfo.getSSID().replace("\"", "");
            }

            // 🚀 1순위: 현재 연결된 와이파이를 가장 먼저 찾아서 최상단에 배치!
            for (ScanResult result : results) {
                if (result.SSID != null && !result.SSID.isEmpty()
                        && !WifiScanFilter.isHiddenSsid(result.SSID)
                        && !foundWifiNetworks.contains(result.SSID)) {
                    if (result.SSID.equals(connectedSSID)) {
                        foundWifiNetworks.add(result.SSID);
                        addWifiItemToUI(result.SSID, result.capabilities, true);
                    }
                }
            }

            // 🚀 2순위: 연결되지 않은 나머지 잡다한 와이파이들을 그 밑으로 나열
            for (ScanResult result : results) {
                if (result.SSID != null && !result.SSID.isEmpty()
                        && !WifiScanFilter.isHiddenSsid(result.SSID)
                        && !foundWifiNetworks.contains(result.SSID)) {
                    foundWifiNetworks.add(result.SSID);
                    addWifiItemToUI(result.SSID, result.capabilities, false);
                }
            }
        }
    }

    // 💡 연결 상태(isConnected)를 파라미터로 직접 전달받도록 개조된 함수
    private void addWifiItemToUI(final String ssid, String capabilities, final boolean isConnected) {
        final boolean isOpen = !capabilities.contains("WPA") && !capabilities.contains("WEP");
        String lockIcon = isOpen ? "📶 " : "🔒 ";

        // 연결된 기기 앞에는 투박한 글씨 대신 애플처럼 예쁜 체크마크(✔) 부여!
        String prefix = isConnected ? "✔ " : "";

        Button btnWifi = createListButton(prefix + lockIcon + ssid);

        if (isConnected) {
            btnWifi.setTextColor(0xFF00FF00); // 눈에 확 띄는 초록색!
            btnWifi.setTypeface(null, android.graphics.Typeface.BOLD); // 굵은 글씨로 강조!
        }

        btnWifi.setTag(ssid);
        btnWifi.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                if (isConnected) {
                    Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_already_connected), Toast.LENGTH_SHORT).show();
                    return;
                }

                Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_connecting, ssid),
                        Toast.LENGTH_SHORT).show();
                beginWifiConnect();
                WifiConnector.connectFromMenu(MainActivity.this, ssid, isOpen, null,
                        new WifiConnector.MenuCallback() {
                            @Override
                            public void onNeedPassword() {
                                endWifiConnect();
                                isTargetWifiOpen = false;
                                openWifiKeyboard(ssid);
                            }

                            @Override
                            public void onComplete(boolean success) {
                                wrapWifiConnectCallback(wifiConnectResultCallback()).onComplete(success);
                            }
                        });
            }
        });
        containerWifiItems.addView(btnWifi);
    }

