    private void updatePodcastPreviewEpisode(final OpenRssClient.Episode ep, boolean saved, boolean resume) {
        if (!podcastDualPaneActive() || ep == null) return;
        String showName = podcastSelected != null ? podcastSelected.title : "";
        if (tvPodcastPreviewShow != null) {
            tvPodcastPreviewShow.setText(ep.title);
            tvPodcastPreviewShow.setVisibility(View.VISIBLE);
        }
        if (tvPodcastPreviewEpisode != null) {
            tvPodcastPreviewEpisode.setText(getString(R.string.podcast_detail_show, showName));
            tvPodcastPreviewEpisode.setVisibility(showName.length() > 0 ? View.VISIBLE : View.GONE);
        }
        if (tvPodcastPreviewMeta != null) {
            String date = OpenRssClient.formatPodcastDate(ep.pubDate);
            if (date.length() == 0) date = getString(R.string.podcast_detail_unknown_date);
            String dur = OpenRssClient.formatDuration(ep.durationSec);
            if (dur.length() == 0) dur = getString(R.string.podcast_detail_unknown_duration);
            StringBuilder meta = new StringBuilder();
            meta.append(getString(R.string.podcast_detail_released, date));
            meta.append("\n").append(getString(R.string.podcast_detail_duration, dur));
            if (saved) meta.append("\n").append(getString(R.string.podcasts_saved_badge));
            if (resume) meta.append(" ").append(getString(R.string.podcasts_resume_badge));
            tvPodcastPreviewMeta.setText(meta.toString());
            tvPodcastPreviewMeta.setVisibility(View.VISIBLE);
        }
        if (podcastSelected != null) loadPodcastPreviewArt(podcastSelected.artworkUrl);
    }

    private void updatePodcastPreviewSavedFile(final File file, final String showFolder) {
        if (!podcastDualPaneActive() || file == null) return;
        String stem = file.getName();
        int dot = stem.lastIndexOf('.');
        if (dot > 0) stem = stem.substring(0, dot);
        if (tvPodcastPreviewShow != null) {
            tvPodcastPreviewShow.setText(stem);
            tvPodcastPreviewShow.setVisibility(View.VISIBLE);
        }
        if (tvPodcastPreviewEpisode != null) {
            tvPodcastPreviewEpisode.setText(getString(R.string.podcast_detail_show, showFolder));
            tvPodcastPreviewEpisode.setVisibility(View.VISIBLE);
        }
        String date = OpenRssClient.formatPodcastDate(
                new java.text.SimpleDateFormat("EEE, dd MMM yyyy", Locale.getDefault())
                        .format(new java.util.Date(file.lastModified())));
        boolean resume = PodcastResumeStore.hasResume(getApplicationContext(),
                PodcastResumeStore.keyForFile(file));
        updatePodcastPreviewSavedMeta(file, showFolder, date, resume, getString(R.string.podcast_detail_unknown_duration));
        probeSavedPodcastDuration(file, showFolder, date, resume);
        clearPodcastPreviewArt();
    }

    private void updatePodcastPreviewSavedMeta(File file, String showFolder, String date,
            boolean resume, String durationLabel) {
        if (tvPodcastPreviewMeta == null) return;
        StringBuilder meta = new StringBuilder();
        meta.append(getString(R.string.podcast_detail_released, date));
        meta.append("\n").append(getString(R.string.podcast_detail_duration, durationLabel));
        if (resume) meta.append("\n").append(getString(R.string.podcasts_resume_badge));
        tvPodcastPreviewMeta.setText(meta.toString());
        tvPodcastPreviewMeta.setVisibility(View.VISIBLE);
    }

    private void clearPodcastPreviewArt() {
        podcastPreviewArtGen++;
        if (ivPodcastPreviewArt != null) {
            ivPodcastPreviewArt.setImageDrawable(null);
            ivPodcastPreviewArt.setVisibility(View.GONE);
        }
    }

    private void loadPodcastPreviewArt(final String url) {
        if (ivPodcastPreviewArt == null) return;
        if (url == null || url.trim().isEmpty()) {
            clearPodcastPreviewArt();
            return;
        }
        final int gen = ++podcastPreviewArtGen;
        final String artUrl = url.trim();
        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    byte[] raw = com.solar.launcher.net.SolarHttp.getBytes(artUrl, "image/*", OpenRssClient.UA);
                    if (raw == null || raw.length == 0) return;
                    BitmapFactory.Options opts = new BitmapFactory.Options();
                    opts.inSampleSize = 2;
                    final android.graphics.Bitmap bmp = BitmapFactory.decodeByteArray(raw, 0, raw.length, opts);
                    if (bmp == null) return;
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            if (gen != podcastPreviewArtGen || !podcastDualPaneActive()) return;
                            ivPodcastPreviewArt.setImageBitmap(bmp);
                            ivPodcastPreviewArt.setVisibility(View.VISIBLE);
                        }
                    });
                } catch (Exception ignored) {}
            }
        }).start();
    }

    /** Feed/show artwork URL for the episode currently being prepared. */
    private String resolvePodcastArtworkUrl() {
        if (podcastSelected != null && podcastSelected.artworkUrl != null
                && !podcastSelected.artworkUrl.trim().isEmpty()) {
            return podcastSelected.artworkUrl.trim();
        }
        return "";
    }

    /** Now Playing cover — streamed show art, else embedded art from a saved episode file. */
    private void loadPodcastNowPlayingArt(final String url, final File localEpisodeFile) {
        ++podcastNowPlayingArtGen;
        final int gen = podcastNowPlayingArtGen;
        final String artUrl = url != null ? url.trim() : "";
        if (artUrl.isEmpty() && (localEpisodeFile == null || !localEpisodeFile.isFile())) return;
        new Thread(new Runnable() {
            @Override
            public void run() {
                byte[] raw = null;
                if (!artUrl.isEmpty()) {
                    try {
                        raw = com.solar.launcher.net.SolarHttp.getBytes(artUrl, "image/*", OpenRssClient.UA);
                    } catch (Exception ignored) {}
                }
                if ((raw == null || raw.length == 0) && localEpisodeFile != null && localEpisodeFile.isFile()) {
                    try {
                        AudioTags.Info tags = AudioTags.read(localEpisodeFile, prefs);
                        if (tags.embeddedArt != null && tags.embeddedArt.length > 0) {
                            raw = tags.embeddedArt;
                        }
                    } catch (Exception ignored) {}
                }
                if (raw == null || raw.length == 0) return;
                BitmapFactory.Options opts = new BitmapFactory.Options();
                opts.inSampleSize = 2;
                final android.graphics.Bitmap bmp = BitmapFactory.decodeByteArray(raw, 0, raw.length, opts);
                if (bmp == null) return;
                final byte[] artBytes = raw;
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (gen != podcastNowPlayingArtGen || !playback.isPodcastActive()) return;
                        bindPodcastNowPlayingArt(bmp, artBytes);
                    }
                });
            }
        }).start();
    }

    /** Bind podcast cover into the shared Now Playing art slots (flat + 3D). */
    private void bindPodcastNowPlayingArt(android.graphics.Bitmap bmpCenter, byte[] artBytes) {
        if (bmpCenter == null) return;
        bindPlayerAlbumArt(bmpCenter);
        try {
            int centerX = bmpCenter.getWidth() / 2;
            int centerY = (int) (bmpCenter.getHeight() * 0.8);
            currentAlbumColor = bmpCenter.getPixel(centerX, centerY) | 0xFF000000;
        } catch (Exception e) {
            currentAlbumColor = ThemeManager.getListButtonFocusedBg() | 0xFF000000;
        }
        try {
            if (ivPlayerBgBlur != null) {
                // 2026-07-11 — Theme wall when blur off; blur when on (hasAlbumArtForBlur uses lastAlbumArtBytes).
                lastAlbumArtBytes = artBytes;
                bindPlayerBlurBackdrop();
            }
        } catch (Exception ignored) {}
        lastAlbumArtBytes = artBytes;
        updateMainMenuBackground();
        refreshNowPlayingPreview();
    }

    private void probeSavedPodcastDuration(final File file, final String showFolder,
            final String date, final boolean resume) {
        if (file == null) return;
        final String key = file.getAbsolutePath();
        Integer cached = podcastSavedDurationCache.get(key);
        if (cached != null && cached > 0) {
            updatePodcastPreviewSavedMeta(file, showFolder, date, resume,
                    OpenRssClient.formatDuration(cached));
            return;
        }
        new Thread(new Runnable() {
            @Override
            public void run() {
                int sec = 0;
                android.media.MediaMetadataRetriever mmr = new android.media.MediaMetadataRetriever();
                try {
                    mmr.setDataSource(file.getAbsolutePath());
                    String d = mmr.extractMetadata(android.media.MediaMetadataRetriever.METADATA_KEY_DURATION);
                    if (d != null) {
                        long ms = Long.parseLong(d);
                        if (ms > 0) sec = (int) (ms / 1000);
                    }
                } catch (Exception ignored) {
                } finally {
                    try { mmr.release(); } catch (Exception ignored) {}
                }
                if (sec > 0) podcastSavedDurationCache.put(key, sec);
                final int durationSec = sec;
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (!podcastDualPaneActive()) return;
                        View focus = getCurrentFocus();
                        if (focus == null || !(focus.getTag() instanceof File)) return;
                        if (!file.equals(focus.getTag())) return;
                        String dur = durationSec > 0
                                ? OpenRssClient.formatDuration(durationSec)
                                : getString(R.string.podcast_detail_unknown_duration);
                        updatePodcastPreviewSavedMeta(file, showFolder, date, resume, dur);
                    }
                });
            }
        }).start();
    }

    private String podcastEpisodeInlineSubtitle(OpenRssClient.Episode ep) {
        String date = OpenRssClient.formatPodcastDate(ep.pubDate);
        if (date.length() == 0) date = getString(R.string.podcast_detail_unknown_date);
        String dur = OpenRssClient.formatDuration(ep.durationSec);
        if (dur.length() == 0) dur = getString(R.string.podcast_detail_unknown_duration);
        return date + " · " + dur;
    }

    private View createPodcastListRow(String title, String subtitle, View.OnClickListener click,
            View.OnFocusChangeListener focusListener) {
        final int rowKind = y1RowKindForScreen();
        if (isFullWidthMenus && subtitle != null && subtitle.length() > 0) {
            final LinearLayout row = new LinearLayout(this);
            row.setOrientation(LinearLayout.VERTICAL);
            // 2026-07-14 — Same nested-row focus shell as Get Music (BLOCK_DESCENDANTS).
            row.setDescendantFocusability(ViewGroup.FOCUS_BLOCK_DESCENDANTS);
            row.setFocusable(true);
            row.setFocusableInTouchMode(true);
            row.setClickable(true);
            row.setSoundEffectsEnabled(false);
            int hPad = (int) (10 * getResources().getDisplayMetrics().density);
            row.setPadding(hPad, 4, hPad, 4);
            int rowW = listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx();
            row.setBackground(getY1RowBackground(false, rowW, rowKind));
            A5FocusConfirm.setOnClickListener(row, click);
            attachA5RowLongPress(row);

            TextView tvTitle = new TextView(this);
            tvTitle.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
            tvTitle.setText(title);
            ThemeManager.applyThemedTextStyle(tvTitle, y1RowTextColorNormal(rowKind));
            tvTitle.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                    getResources().getDimension(R.dimen.y1_menu_text_size));
            enableMarquee(tvTitle);
            row.addView(tvTitle, new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT));

            TextView tvSub = new TextView(this);
            tvSub.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
            tvSub.setText(subtitle);
            ThemeManager.applyThemedTextStyle(tvSub, ThemeManager.getTextColorSecondary());
            tvSub.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                    getResources().getDimension(R.dimen.y1_menu_text_size) * 0.85f);
            enableMarquee(tvSub);
            row.addView(tvSub, new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT));

            row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    int w = row.getWidth() > 0 ? row.getWidth()
                            : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());
                    row.setBackground(getY1RowBackground(hasFocus, w, rowKind));
                    ThemeManager.applyThemedTextStyle(tvTitle, hasFocus
                            ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                    ThemeManager.applyThemedTextStyle(tvSub, hasFocus
                            ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                    tvTitle.setSelected(hasFocus);
                    tvSub.setSelected(hasFocus);
                    if (hasFocus) showFastScrollLetter(title);
                    if (focusListener != null) focusListener.onFocusChange(v, hasFocus);
                }
            });

            LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT);
            lp.setMargins(0, 1, 0, 1);
            row.setLayoutParams(lp);
            return row;
        }

        Button b = createListButton(title);
        b.setOnClickListener(click);
        if (focusListener != null) {
            b.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    configureY1ThemedButtonFocus(b, hasFocus, rowKind);
                    if (hasFocus) showFastScrollLetter(title);
                    focusListener.onFocusChange(v, hasFocus);
                }
            });
        }
        return b;
    }

    private void configureY1ThemedButtonFocus(Button btn, boolean hasFocus, int rowKind) {
        int w = btn.getWidth() > 0 ? btn.getWidth()
                : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());
        btn.setBackground(getY1RowBackground(hasFocus, w, rowKind));
        ThemeManager.applyThemedTextStyle(btn, hasFocus
                ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
        btn.setSelected(hasFocus);
    }

    private void updateHomeMenuPreviewVisibility() {
        if (ivMenuPreview == null) return;
        boolean hidePreview = isFullWidthMenus
                || (layoutWidgets != null && layoutWidgets.getVisibility() == View.VISIBLE);
        ivMenuPreview.setVisibility(hidePreview ? View.GONE : View.VISIBLE);
        if (tvMenuPreviewTitle != null) {
            tvMenuPreviewTitle.setVisibility(hidePreview ? View.GONE : tvMenuPreviewTitle.getVisibility());
        }
        if (tvMenuPreviewArtist != null) {
            tvMenuPreviewArtist.setVisibility(hidePreview ? View.GONE : tvMenuPreviewArtist.getVisibility());
        }
    }

    private String screenTimeoutIconKey() {
        int ms = TIMEOUT_VALUES[currentTimeoutIndex];
        if (ms <= 10000) return "backlight_10";
        if (ms <= 15000) return "backlight_15";
        if (ms <= 30000) return "backlight_30";
        if (ms <= 45000) return "backlight_45";
        if (ms <= 60000) return "backlight_60";
        if (ms <= 120000) return "backlight_120";
        return "backlight_300";
    }

    private String screenTimeoutStateText() {
        int sec = TIMEOUT_VALUES[currentTimeoutIndex] / 1000;
        if (sec >= 60 && sec % 60 == 0) return getString(R.string.common_timeout_min, sec / 60);
        return getString(R.string.common_timeout_sec, sec);
    }

    private String repeatIconKey() {
        switch (repeatMode) {
            case 1: return "repeatOne";
            case 2: return "repeatAll";
            default: return "repeatOff";
        }
    }

    private String eqIconKey() {
        String n = eqPresetNames.get(currentEqPresetIndex).toLowerCase(Locale.US);
        if (n.contains("classical")) return "equalizer_classical";
        if (n.contains("dance")) return "equalizer_dance";
        if (n.contains("flat")) return "equalizer_flat";
        if (n.contains("folk")) return "equalizer_folk";
        if (n.contains("metal")) return "equalizer_heavymetal";
        if (n.contains("hip hop") || n.contains("hiphop")) return "equalizer_hiphop";
        if (n.contains("jazz")) return "equalizer_jazz";
        if (n.contains("pop")) return "equalizer_pop";
        if (n.contains("rock")) return "equalizer_rock";
        return "equalizer_normal";
    }

    private Bitmap resolveHomeMenuPreviewIconForSettings(String rowKey) {
        if (rowKey != null && rowKey.startsWith("home.shortcut.")) {
            return resolveHomeMenuPreviewIconForId(rowKey.substring("home.shortcut.".length()));
        }
        return null;
    }

    private String resolveSoulseekSolarConfigKey(String rowKey) {
        if (rowKey == null) return null;
        if (RowKeys.SWITCH_ROCKBOX.equals(rowKey)) return "settingsRockbox";
        if (RowKeys.SOULSEEK_SEARCH.equals(rowKey)) return "soulseekSearch";
        if (RowKeys.SOULSEEK_ACCOUNT.equals(rowKey)) return "soulseekAccount";
        if (RowKeys.SOULSEEK_REGENERATE.equals(rowKey)) return "soulseekRegenerate";
        return null;
    }

    private boolean isAppearancePreviewRow(String rowKey) {
        return RowKeys.APPEARANCE.equals(rowKey) || RowKeys.APPEARANCE_STATUS.equals(rowKey)
                || RowKeys.APPEARANCE_LAYOUT.equals(rowKey)
                || RowKeys.HOME_SCREEN.equals(rowKey)
                || RowKeys.NOW_PLAYING.equals(rowKey)
                || RowKeys.STATUS_BAR_LEFT.equals(rowKey) || RowKeys.STATUS_BAR_MATCH_FONT.equals(rowKey)
                || RowKeys.NOW_PLAYING_MATCH_FONT.equals(rowKey)
                || RowKeys.FULL_WIDTH.equals(rowKey)
                || RowKeys.MENU_ITEM_PADDING.equals(rowKey)
                || RowKeys.INFINITE_SCROLL.equals(rowKey)
                || RowKeys.MENU_TRANSITIONS.equals(rowKey)
                || RowKeys.BACKGROUND.equals(rowKey) || RowKeys.THEMES.equals(rowKey)
                || RowKeys.GET_THEMES.equals(rowKey);
    }

    private String resolveSolarSettingAppName(String rowKey) {
        if (rowKey == null) return null;
        if (RowKeys.REACH.equals(rowKey)) return "Reach";
        if (RowKeys.SOULSEEK.equals(rowKey)) return "Soulseek";
        if (RowKeys.WEB_SERVER.equals(rowKey)) return "PC Upload";
        if (RowKeys.GET_THEMES.equals(rowKey) || RowKeys.THEMES.equals(rowKey)) return "Themes";
        if (RowKeys.homeShortcut(HomeMenuConfig.ID_APPS).equals(rowKey)) return "Apps";
        return null;
    }

    private String resolveSettingIconKey(String rowKey) {
        if (RowKeys.SHUFFLE.equals(rowKey)) return isShuffleMode ? "shuffleOn" : "shuffleOff";
        if (RowKeys.REPEAT.equals(rowKey)) return repeatIconKey();
        if (RowKeys.EQ.equals(rowKey)) return eqIconKey();
        if (RowKeys.BUTTON_SOUND.equals(rowKey)) return isSoundEffectEnabled ? "keyToneOn" : "keyToneOff";
        if (RowKeys.BUTTON_VIBRATE.equals(rowKey)) return isVibrationEnabled ? "keyVibrationOn" : "keyVibrationOff";
        if (RowKeys.SCREEN_TIMEOUT.equals(rowKey)) return screenTimeoutIconKey();
        if (RowKeys.POWER_SAVING_SHUTDOWN.equals(rowKey)) {
            return InactivityShutdownConfig.iconKeyForMinutes(inactivityShutdownMinutes());
        }
        if (RowKeys.APP_THEME.equals(rowKey)) return "theme";
        if (RowKeys.BRIGHTNESS.equals(rowKey)) return "brightness";
        if (RowKeys.BACKGROUND.equals(rowKey)) return "wallpaper";
        if (RowKeys.NOW_PLAYING.equals(rowKey)) return "nowPlaying";
        if (RowKeys.DATETIME.equals(rowKey)) return "dateTime";
        if (RowKeys.SWITCH_ROCKBOX.equals(rowKey)) return "launcher";
        return null;
    }

    /** EQ row label — safe before preset list async load finishes. */
    private String eqPresetStateText() {
        if (eqPresetNames == null || eqPresetNames.isEmpty()) {
            return getString(R.string.eq_normal_default);
        }
        int idx = currentEqPresetIndex;
        if (idx < 0 || idx >= eqPresetNames.size()) idx = 0;
        String name = eqPresetNames.get(idx);
        return name != null ? name : getString(R.string.eq_normal_default);
    }

    private String resolveSettingStateText(String rowKey) {
        if (rowKey == null) return "";
        if (RowKeys.SHUFFLE.equals(rowKey)) return stateOnOff(isShuffleMode);
        if (RowKeys.REPEAT.equals(rowKey)) return getRepeatModeText(repeatMode);
        if (RowKeys.EQ.equals(rowKey)) return eqPresetStateText();
        if (RowKeys.BUTTON_SOUND.equals(rowKey)) return stateOnOff(isSoundEffectEnabled);
        if (RowKeys.HEARING_SAFETY.equals(rowKey)) {
            // 2026-07-15 — On/Off for Solar 80% headphone cap (default Off = full range).
            return stateOnOff(HearingSafetyVolume.isEnabled(this));
        }
        if (RowKeys.BUTTON_VIBRATE.equals(rowKey)) return stateOnOff(isVibrationEnabled);
        if (RowKeys.SCREEN_OFF_CTRL.equals(rowKey)) return stateOnOff(isScreenOffControlEnabled);
        if (RowKeys.Y2_HOLD_OK_TO_SLEEP.equals(rowKey)) return stateOnOff(y2HoldOkToSleep);
        if (RowKeys.A5_MENU_NAV.equals(rowKey)) {
            return getString(A5NavigationMode.isFaceNav(this)
                    ? R.string.settings_a5_menu_nav_face : R.string.settings_a5_menu_nav_side);
        }
        if (RowKeys.A5_ORIENTATION.equals(rowKey)) {
            String mode = A5NavigationMode.orientation(this);
            int label = A5NavigationMode.ORIENT_AUTO.equals(mode)
                    ? R.string.settings_a5_orientation_auto
                    : (A5NavigationMode.ORIENT_LANDSCAPE.equals(mode)
                    ? R.string.settings_a5_orientation_landscape
                    : R.string.settings_a5_orientation_portrait);
            return getString(label);
        }
        if (RowKeys.DEBUG_JJ_THEMES.equals(rowKey)) return stateOnOff(ActiveThemeEngine.isJjMode());
        if (RowKeys.DEBUG_WIRELESS_ADB.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean("settings.debug.wireless_adb_enabled", true));
        }
        if (RowKeys.DEBUG_SHOW_ERROR_TOASTS.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean(PREF_DEBUG_SHOW_ERROR_TOASTS, false));
        }
        if (RowKeys.DEBUG_DEV_SUPPORT_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(isDevSupportExperimentEnabled());
        }
        if (RowKeys.DEBUG_BLUETOOTH_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(BluetoothExperiment.isEnabled(prefs));
        }
        if (RowKeys.BLUETOOTH_PAIRING_PIN.equals(rowKey)) {
            return BluetoothAudioRepair.pairingPinForAddress(this, null);
        }
        if (RowKeys.DEBUG_RADIO_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(com.solar.launcher.radio.RadioExperiment.isEnabled(prefs));
        }
        if (RowKeys.DEBUG_YOUTUBE_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(com.solar.launcher.youtube.YouTubeExperiment.isEnabled(prefs));
        }
        if (RowKeys.DEBUG_ROCKBOX_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(RockboxExperiment.isEnabled(prefs));
        }
        if (RowKeys.DEBUG_PLEX_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(com.solar.launcher.plex.PlexExperiment.isEnabled(prefs));
        }
        if (RowKeys.DEBUG_JELLYFIN_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(com.solar.launcher.jellyfin.JellyfinExperiment.isEnabled(prefs));
        }
        if (RowKeys.DEBUG_A5_LANDSCAPE_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(A5LandscapeExperiment.isEnabled(prefs));
        }
        if (RowKeys.DEBUG_Y1_PORTRAIT_EXPERIMENT.equals(rowKey)) {
            // 2026-07-14 — Off / Wheel right / Left-handed (matches A5 orientation-style preview).
            String m = Y1PortraitExperiment.mode(prefs);
            if (Y1PortraitExperiment.MODE_RIGHT.equals(m)) {
                return getString(R.string.settings_debug_y1_portrait_mode_right);
            }
            if (Y1PortraitExperiment.MODE_LEFT.equals(m)) {
                return getString(R.string.settings_debug_y1_portrait_mode_left);
            }
            return stateOnOff(false);
        }
        if (RowKeys.DEBUG_USB_MASS_STORAGE_EXPERIMENT.equals(rowKey)) {
            return stateOnOff(UsbMassStorageExperiment.isEnabled(prefs));
        }
        if (rowKey != null && (rowKey.startsWith(RowKeys.XPOSED_MODULE_ROW_PREFIX)
                || RowKeys.DEBUG_XPOSED_APPLY.equals(rowKey)
                || rowKey.startsWith(RowKeys.XPOSED_MODULE_CONFIG_ROW_PREFIX))) {
            if (xposedModulesSettingsAdapter == null) {
                xposedModulesSettingsAdapter = new XposedModulesSettingsAdapter(this);
            }
            return new XposedModulesSettingsUi(xposedModulesSettingsAdapter).previewForRow(rowKey);
        }
        if (RowKeys.DEBUG_FLOW_ENABLED.equals(rowKey) || RowKeys.FLOW.equals(rowKey)) {
            return stateOnOff(isFlowEnabled());
        }
        if (RowKeys.DEBUG_FLOW_OK_LIBRARY.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean(PREF_DEBUG_FLOW_OK_LIBRARY, false));
        }
        if (RowKeys.DEBUG_FLOW_THEME.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean(PREF_DEBUG_FLOW_THEME, false));
        }
        if (RowKeys.DEBUG_FLOW_NO_REFLECTIONS.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean(PREF_DEBUG_FLOW_NO_REFLECTIONS, false));
        }
        if (RowKeys.FLOW_MULTI_TRACK_ALBUMS.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean(PREF_FLOW_MULTI_TRACK_ALBUMS, false));
        }
        if (RowKeys.DIAG_AUTO_REPORT.equals(rowKey)) return stateOnOff(soulseekDiagAutoReport);
        if (RowKeys.ARTWORK_PERSPECTIVE.equals(rowKey)) {
            return stateOnOff(nowPlaying3dAlbumArt);
        }
        if (RowKeys.APP_THEME.equals(rowKey)) return ThemeManager.getCurrentTheme().name;
        if (RowKeys.STATUS_BAR_LEFT.equals(rowKey)) {
            return statusBarShowsTitle ? getString(R.string.settings_status_title) : getString(R.string.common_clock);
        }
        if (RowKeys.SCREEN_TIMEOUT.equals(rowKey)) return screenTimeoutStateText();
        if (RowKeys.Y2_PRIMARY_STORAGE.equals(rowKey)) {
            String medium = com.solar.launcher.DeviceFeatures.resolvePrimaryMediaPref(this);
            return com.solar.launcher.DeviceFeatures.PRIMARY_MEDIA_INTERNAL.equals(medium)
                    ? getString(R.string.storage_volume_internal)
                    : getString(R.string.storage_volume_microsd);
        }
        if (RowKeys.Y2_INTERNAL_MEDIA.equals(rowKey)) {
            return stateOnOff(com.solar.launcher.DeviceFeatures.useInternalForNewMedia(this));
        }
        if (RowKeys.POWER_SAVING_SHUTDOWN.equals(rowKey)) return inactivityShutdownStateText();
        if (RowKeys.WIFI_SLEEP_POWER_OFF.equals(rowKey)) {
            return stateOnOff(prefs != null && prefs.getBoolean(WifiSleepPolicy.PREF_ENABLED, true));
        }
        if (RowKeys.FULL_WIDTH.equals(rowKey)) return stateOnOff(isFullWidthMenus);
        if (RowKeys.MENU_ITEM_PADDING.equals(rowKey)) {
            return stateOnOff(ThemeManager.isMenuItemPaddingEnabled(prefs, false));
        }
        if (RowKeys.INFINITE_SCROLL.equals(rowKey)) return stateOnOff(isInfiniteScroll);
        if (RowKeys.MENU_TRANSITIONS.equals(rowKey)) return stateOnOff(menuTransitionsEnabled);
        if (RowKeys.AUTO_FETCH.equals(rowKey)) return stateOnOff(isAutoFetchEnabled);
        if (RowKeys.ABOUT.equals(rowKey)) {
            return AppVersion.displayLabel(this);
        }
        if (RowKeys.SWITCH_ROCKBOX.equals(rowKey)) {
            return getString(R.string.settings_switch_rockbox_hint);
        }
        if (RowKeys.NOW_PLAYING_ALBUM_BLUR.equals(rowKey)) return stateOnOff(playerAlbumBlurEnabled);
        if (RowKeys.WIDGET_CLOCK.equals(rowKey)) return stateOnOff(false);
        if (RowKeys.WIDGET_BATTERY.equals(rowKey)) return stateOnOff(false);
        if (RowKeys.WIDGET_ALBUM.equals(rowKey)) return stateOnOff(false);
        if (RowKeys.LANGUAGE.equals(rowKey)) {
            return LocaleHelper.displayLabel(this, prefs.getString(LocaleHelper.PREF_LOCALE, LocaleHelper.LOCALE_SYSTEM));
        }
        if (rowKey != null && rowKey.startsWith("home.shortcut.")) {
            String id = rowKey.substring("home.shortcut.".length());
            HomeMenuConfig.Entry e = HomeMenuConfig.find(id);
            if (e == null) return "";
            if (SettingsScreens.HOME.equals(settingsSubScreenKey)) {
                return "";
            }
            if (HomeMenuConfig.ID_GET_THEMES.equals(id) || HomeMenuConfig.ID_THEMES.equals(id)) {
                return getString(R.string.home_screen_preview_themes);
            }
            if (HomeMenuConfig.ID_VIDEOS.equals(id)) return getString(R.string.home_screen_preview_videos);
            if (HomeMenuConfig.ID_PHOTOS.equals(id)) return getString(R.string.home_screen_preview_photos);
            if (HomeMenuConfig.ID_AUDIOBOOKS.equals(id)) {
                return getString(R.string.status_audiobooks);
            }
            return stateOnOff(HomeMenuConfig.isShortcutEnabled(prefs, id));
        }
        if (RowKeys.HOME_MORE.equals(rowKey)) {
            if (SettingsScreens.HOME.equals(settingsSubScreenKey)) return "";
            return stateOnOff(HomeMenuConfig.isMoreEnabled(prefs));
        }
        if (RowKeys.HOME_MANAGE_MORE.equals(rowKey)) return "";
        if (SettingsScreens.REACH.equals(settingsSubScreenKey)) {
            if (RowKeys.SOULSEEK_REACH_ENABLED.equals(rowKey)) return stateOnOff(soulseekReachEnabled);
            if (RowKeys.SOULSEEK_ENABLED.equals(rowKey)) return stateOnOff(soulseekEnabled);
            if (RowKeys.DEEZER_ENABLED.equals(rowKey)) return stateOnOff(deezerEnabled);
        }
        if (SettingsScreens.SOULSEEK.equals(settingsSubScreenKey)) {
            if (RowKeys.SOULSEEK_ACCOUNT.equals(rowKey)) {
                return SoulseekAccount.displayLabel(SoulseekAccount.load(prefs));
            }
            if (RowKeys.SOULSEEK_HIDE_HIGH_BITRATE.equals(rowKey)) return stateOnOff(soulseekHideHighBitrate);
            if (RowKeys.SOULSEEK_SHARING.equals(rowKey)) return stateOnOff(soulseekSharingEnabled);
            if (RowKeys.SOULSEEK_MESSAGING.equals(rowKey)) return stateOnOff(soulseekMessagingEnabled);
        }
        if (RowKeys.SOULSEEK_ACCOUNT.equals(rowKey) && SettingsScreens.isSoulseek(settingsSubScreenKey)) {
            return SoulseekAccount.displayLabel(SoulseekAccount.load(prefs));
        }
        if (RowKeys.LALAL.equals(rowKey)) {
            // 2026-07-19 — Status + opt-in hint so dual-pane explains unlock.
            String status = com.solar.launcher.stem.LalalAccount.settingsStatusLabel(prefs,
                    getString(R.string.lalal_not_configured),
                    getString(R.string.lalal_configured));
            return status + "\n\n" + getString(R.string.settings_lalal_hint);
        }
        if (RowKeys.STEM_PREMIX.equals(rowKey)) {
            return stateOnOff(com.solar.launcher.stem.LalalAccount.isPremixExperimental(prefs));
        }
        if (RowKeys.DT_AUTO_INTERNET.equals(rowKey)) {
            return stateOnOff(SolarAutoTime.isAutoEnabled(prefs));
        }
        if (RowKeys.DT_TIMEZONE.equals(rowKey)) {
            return SolarAutoTime.displayTimezoneLabel(prefs);
        }
        if (RowKeys.DT_OBSERVE_DST.equals(rowKey)) {
            return stateOnOff(SolarAutoTime.isObserveDst(prefs));
        }
        if (RowKeys.DT_YEAR.equals(rowKey)) return String.valueOf(dtYear);
        if (RowKeys.DT_MONTH.equals(rowKey)) return String.format(Locale.US, "%02d", dtMonth);
        if (RowKeys.DT_DAY.equals(rowKey)) return String.format(Locale.US, "%02d", dtDay);
        if (RowKeys.DT_HOUR.equals(rowKey)) return String.format(Locale.US, "%02d", dtHour);
        if (RowKeys.DT_MINUTE.equals(rowKey)) return String.format(Locale.US, "%02d", dtMinute);
        if (RowKeys.LANG_SYSTEM.equals(rowKey)) return "";
        if (RowKeys.LANG_EN.equals(rowKey) || RowKeys.LANG_KO.equals(rowKey)) return "";
        if (RowKeys.USB_AUTO_CONNECT.equals(rowKey)) return stateOnOff(prefs.getBoolean("usb_auto_connect", false));
        if (RowKeys.USB_SUPPRESS_PROMPT.equals(rowKey)) {
            return stateOnOff(prefs.getBoolean(PREF_USB_SUPPRESS_CONNECT_PROMPT,
                    UsbStorageSessionFlags.DEFAULT_SKIP_SOLAR_PROMPT));
        }
        if (RowKeys.USB_TURN_ON.equals(rowKey)) return "";
        if (RowKeys.STATUS_BAR_MATCH_FONT.equals(rowKey)) return stateOnOff(statusBarMatchFont);
        if (RowKeys.NOW_PLAYING_MATCH_FONT.equals(rowKey)) return stateOnOff(nowPlayingMatchFont);
        if (RowKeys.NOW_PLAYING_BACKDROP.equals(rowKey)) return stateOnOff(nowPlayingBackdrop);
        if (RowKeys.SHOW_NOW_PLAYING_INFO.equals(rowKey)) {
            return stateOnOff(ThemeManager.isShowNowPlayingInfoEnabled(prefs));
        }
        if (RowKeys.NOW_PLAYING_LCD_ART.equals(rowKey)) return stateOnOff(nowPlayingLcdArt);
        if (RowKeys.NOW_PLAYING_3D_ALBUM_ART.equals(rowKey)) return stateOnOff(nowPlaying3dAlbumArt);
        if (SettingsScreens.LIBRARY_BROWSE.equals(settingsSubScreenKey)) {
            if (RowKeys.LIB_SPLIT_CREDITS.equals(rowKey)) return stateOnOff(libraryBrowsePrefs.splitCredits());
            if (RowKeys.LIB_NORM_ALBUM.equals(rowKey)) return stateOnOff(libraryBrowsePrefs.normalizeAlbumCase());
            if (RowKeys.LIB_GUEST_MODE.equals(rowKey)) {
                return getString(LibraryBrowsePrefs.guestBrowseModeLabelRes(libraryBrowsePrefs.guestBrowseMode()));
            }
            if (RowKeys.LIB_ARTIST_FILTER.equals(rowKey)) {
                return getString(LibraryBrowsePrefs.artistFilterLabelRes(libraryBrowsePrefs.artistFilter()));
            }
            if (RowKeys.LIB_ARTIST_SORT.equals(rowKey)) {
                return getString(LibraryBrowsePrefs.artistSortLabelRes(libraryBrowsePrefs.artistSort()));
            }
            if (RowKeys.LIB_SONG_SORT.equals(rowKey)) {
                return getString(LibraryBrowsePrefs.songSortLabelRes(libraryBrowsePrefs.songSort()));
            }
            if (RowKeys.LIB_ALBUM_SONG_SORT.equals(rowKey)) {
                return getString(LibraryBrowsePrefs.songSortLabelRes(
                        libraryBrowsePrefs.albumSongSort(), true));
            }
            if (RowKeys.LIB_ALBUM_RACK_SORT.equals(rowKey)) {
                return getString(LibraryBrowsePrefs.albumRackSortLabelRes(libraryBrowsePrefs.albumRackSort()));
            }
            if (RowKeys.LIB_ALBUM_SUB.equals(rowKey)) return stateOnOff(libraryBrowsePrefs.albumOwnerSubtitles());
            if (RowKeys.LIB_GUEST_SUB.equals(rowKey)) return stateOnOff(libraryBrowsePrefs.guestSongSubtitles());
            if (RowKeys.LIB_SEARCH_REACH.equals(rowKey)) {
                return stateOnOff(libraryBrowsePrefs.includeReachInLibrarySearch());
            }
        }
        if (SettingsScreens.LIBRARY.equals(settingsSubScreenKey)) {
            if (RowKeys.LIST_WRAPAROUND.equals(rowKey)) return stateOnOff(listWraparound);
            if (RowKeys.NAVIDROME_URL.equals(rowKey)) return NavidromeSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.NAVIDROME_USER.equals(rowKey)) return NavidromeSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.NAVIDROME_PASS.equals(rowKey)) return NavidromeSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.PLEX_URL.equals(rowKey) || RowKeys.PLEX_TOKEN.equals(rowKey))
                return PlexSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.JELLYFIN_URL.equals(rowKey) || RowKeys.JELLYFIN_USER.equals(rowKey)
                    || RowKeys.JELLYFIN_PASS.equals(rowKey))
                return com.solar.launcher.jellyfin.JellyfinSettingsHost.previewValue(prefs, rowKey);
        }
        if (SettingsScreens.NAVIDROME.equals(settingsSubScreenKey)) {
            if (RowKeys.NAVIDROME_URL.equals(rowKey)) return NavidromeSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.NAVIDROME_USER.equals(rowKey)) return NavidromeSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.NAVIDROME_PASS.equals(rowKey)) return NavidromeSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.PLEX_URL.equals(rowKey) || RowKeys.PLEX_TOKEN.equals(rowKey))
                return PlexSettingsHost.previewValue(prefs, rowKey);
            if (RowKeys.JELLYFIN_URL.equals(rowKey) || RowKeys.JELLYFIN_USER.equals(rowKey)
                    || RowKeys.JELLYFIN_PASS.equals(rowKey))
                return com.solar.launcher.jellyfin.JellyfinSettingsHost.previewValue(prefs, rowKey);
        }
        if (SettingsScreens.RADIO.equals(settingsSubScreenKey) && mediaSuite != null) {
            if (SettingsScreens.RADIO_FM_BAND.equals(rowKey)) return mediaSuite.fmBandRegionLabel();
            if (SettingsScreens.RADIO_INTERNET_COUNTRY.equals(rowKey)) {
                return mediaSuite.internetCountryLabel();
            }
            if (MediaSuiteHost.ROW_AUTO_DETECT.equals(rowKey)) {
                return stateOnOff(mediaSuite.isAutoDetectRegionEnabled());
            }
            if (MediaSuiteHost.ROW_BUFFER_SD.equals(rowKey)) {
                return stateOnOff(mediaSuite.isBufferOnSdEnabled());
            }
        }
        if (SettingsScreens.VIDEO.equals(settingsSubScreenKey) && mediaSuite != null) {
            if (MediaSuiteHost.ROW_VIDEO_SLEEP.equals(rowKey)) {
                return stateOnOff(mediaSuite.isSleepDuringPlaybackEnabled());
            }
            if (MediaSuiteHost.ROW_VIDEO_CROP.equals(rowKey)) {
                return mediaSuite.videoCropModeLabel();
            }
        }
        // ponytail: Reach blurb only in Reach settings sub-panes — home preview uses appReach icon
        if (RowKeys.SOULSEEK.equals(rowKey)) return "";
        if (SettingsScreens.RESET.equals(settingsSubScreenKey)) {
            if (RowKeys.RESET_ROCKBOX.equals(rowKey)) return stateOnOff(resetPickRockbox);
            if (RowKeys.RESET_SOLAR.equals(rowKey)) return stateOnOff(resetPickSolar);
            if (RowKeys.RESET_THEMES.equals(rowKey)) return stateOnOff(resetPickThemes);
            if (RowKeys.RESET_MICROSD.equals(rowKey)) return stateOnOff(resetPickMicroSd);
            if (RowKeys.RESET_CACHES.equals(rowKey)) return stateOnOff(resetPickCaches);
            if (RowKeys.RESET_EVERYTHING.equals(rowKey)) return stateOnOff(resetPickEverything);
        }
        return "";
    }

    private String resolveResetSettingsPreviewText(String rowKey) {
        if (!SettingsScreens.RESET.equals(settingsSubScreenKey) || rowKey == null) return null;
        if (RowKeys.RESET_ROCKBOX.equals(rowKey)) return getString(R.string.settings_preview_reset_rockbox);
        if (RowKeys.RESET_SOLAR.equals(rowKey)) return getString(R.string.settings_preview_reset_solar);
        if (RowKeys.RESET_THEMES.equals(rowKey)) return getString(R.string.settings_preview_reset_themes);
        if (RowKeys.RESET_MICROSD.equals(rowKey)) return getString(R.string.settings_preview_reset_microsd);
        if (RowKeys.RESET_CACHES.equals(rowKey)) return getString(R.string.settings_preview_reset_caches);
        if (RowKeys.RESET_EVERYTHING.equals(rowKey)) return getString(R.string.settings_preview_reset_everything);
        if (RowKeys.RESET_CONTINUE.equals(rowKey)) return getString(R.string.settings_preview_reset_continue);
        return null;
    }

    private String resolveReachSettingsPreviewText(String rowKey) {
        if (!SettingsScreens.REACH.equals(settingsSubScreenKey) || rowKey == null) return null;
        if (RowKeys.SOULSEEK_REACH_ENABLED.equals(rowKey)) {
            if (!soulseekReachEnabled) {
                return getString(R.string.soulseek_reach_disabled_hint);
            }
            return getString(R.string.soulseek_reach_enabled) + "\n\n" + stateOnOff(true);
        }
        return null;
    }

    private String resolveDeezerSettingsPreviewText(String rowKey) {
        if (!SettingsScreens.DEEZER.equals(settingsSubScreenKey) || rowKey == null) return null;
        if (RowKeys.DEEZER_ENABLED.equals(rowKey)) {
            return getString(R.string.deezer_enabled_hint) + "\n\n" + stateOnOff(deezerEnabled);
        }
        return null;
    }

    private String resolveSoulseekSettingsPreviewText(String rowKey) {
        if (!SettingsScreens.isSoulseek(settingsSubScreenKey) || rowKey == null) return null;
        if (SettingsScreens.SOULSEEK.equals(settingsSubScreenKey)) {
            if (RowKeys.SOULSEEK_ENABLED.equals(rowKey)) {
                return getString(R.string.soulseek_enabled_hint) + "\n\n" + stateOnOff(soulseekEnabled);
            }
            if (RowKeys.SOULSEEK_SHARING.equals(rowKey)) {
                return getString(R.string.soulseek_sharing_hint) + "\n\n" + stateOnOff(soulseekSharingEnabled);
            }
            if (RowKeys.SOULSEEK_MESSAGING.equals(rowKey)) {
                String hint = getString(R.string.soulseek_messaging_hint);
                if (soulseekMessagingEnabled) {
                    SoulseekAccount acct = SoulseekAccount.load(prefs);
                    return hint + "\n\n" + acct.username;
                }
                return hint + "\n\n" + stateOnOff(false);
            }
            if (RowKeys.SOULSEEK_SEARCH.equals(rowKey)) {
                if (!ConnectivityHelper.isReachPeerOk()
                        && ReachPeerConnectivity.state()
                                == ReachPeerConnectivity.State.UNAVAILABLE) {
                    return getString(R.string.reach_unavailable_settings_hint);
                }
                return getString(R.string.soulseek_preview_search);
            }
            if (RowKeys.SOULSEEK_CONNECTION.equals(rowKey)) {
                String base = soulseekListenPortLabel()
                        + "\n\n" + soulseekNatStatusLabel();
                if (!ConnectivityHelper.isReachPeerOk()
                        && ReachPeerConnectivity.state()
                                == ReachPeerConnectivity.State.UNAVAILABLE) {
                    return base + "\n\n" + reachUnavailableDetailText(ReachPeerConnectivity.reason())
                            + "\n\n" + getString(R.string.reach_unavailable_server_ok);
                }
                return soulseekSharingStatusLabel()
                        + "\n\n" + base
                        + "\n\n" + getString(R.string.soulseek_port_forward_hint);
            }
            if (RowKeys.SOULSEEK_ABOUT.equals(rowKey)) {
                return getString(R.string.reach_for_device, DeviceFeatures.deviceModelLabel())
                        + " — Soulseek client. Account and sharing notes.";
            }
            if (RowKeys.SOULSEEK_REGENERATE.equals(rowKey)) {
                return getString(R.string.soulseek_preview_regenerate);
            }
            if (RowKeys.SOULSEEK_FIND_USER.equals(rowKey)) {
                return getString(R.string.soulseek_find_user);
            }
            if (RowKeys.SOULSEEK_FIND_REACH.equals(rowKey)) {
                return getString(R.string.soulseek_find_reach_users);
            }
            if (RowKeys.SOULSEEK_MESSAGES.equals(rowKey)) {
                java.util.List<String> peers = SoulseekMessaging.conversationPeers(MainActivity.this, prefs);
                if (peers.isEmpty()) {
                    return getString(R.string.soulseek_messages_empty_hint);
                }
                return getString(R.string.soulseek_messages_inbox_hint, peers.size());
            }
            if (RowKeys.SOULSEEK_HIDE_HIGH_BITRATE.equals(rowKey)) {
                return stateOnOff(soulseekHideHighBitrate);
            }
            if (RowKeys.SOULSEEK_ACCOUNT.equals(rowKey)) {
                return getString(R.string.soulseek_account_hint)
                        + "\n\n" + SoulseekAccount.displayLabel(SoulseekAccount.load(prefs));
            }
        }
        return null;
    }

