    private void bindSoulseekSubscreenBackPreview(Button btnBack, final Runnable previewUpdater) {
        if (btnBack == null || previewUpdater == null) return;
        btnBack.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                if (hasFocus && currentScreenState == STATE_SETTINGS && !isFullWidthMenus
                        && !settingsBrowseFullWidth) {
                    previewUpdater.run();
                }
            }
        });
    }

    private String homeShortcutConnectivityHint(String id) {
        if (id == null) return null;
        if (HomeMenuConfig.ID_PODCASTS.equals(id)) {
            if (!ConnectivityHelper.isOnline(this)
                    && !com.solar.launcher.podcast.PodcastLibrary.hasSavedContent()) {
                return getString(R.string.home_screen_hint_internet);
            }
            return null;
        }
        if (ConnectivityHelper.itemNeedsInternetForDiscovery(id) && !ConnectivityHelper.isOnline(this)) {
            return getString(R.string.home_screen_hint_internet);
        }
        if (ConnectivityHelper.itemNeedsLocalNetwork(id) && !ConnectivityHelper.hasLocalNetwork(this)) {
            return getString(R.string.home_screen_hint_network);
        }
        return null;
    }

    private void applyHomeShortcutConnectivityHint(View row, String rowKey, boolean hasFocus) {
        if (row == null || rowKey == null || !rowKey.startsWith("home.shortcut.")) return;
        String id = rowKey.substring("home.shortcut.".length());
        String hint = hasFocus ? homeShortcutConnectivityHint(id) : null;
        TextView tvHint = (TextView) row.findViewWithTag("connectivity_hint");
        if (tvHint == null) return;
        if (!isFullWidthMenus) {
            tvHint.setVisibility(View.GONE);
            return;
        }
        if (hint != null && !hint.isEmpty()) {
            tvHint.setText(hint);
            tvHint.setVisibility(View.VISIBLE);
            tvHint.setSelected(hasFocus);
            if (hasFocus) enableMarquee(tvHint);
        } else {
            tvHint.setVisibility(View.GONE);
        }
    }

    private String stateOnOff(boolean on) {
        return getString(on ? R.string.common_on : R.string.common_off);
    }

    private boolean isOnOffToggleRow(String rowKey) {
        if (rowKey == null) return false;
        if (RowKeys.DIAG_AUTO_REPORT.equals(rowKey)) return true;
        String state = resolveSettingStateText(rowKey);
        return getString(R.string.common_on).equals(state)
                || getString(R.string.common_off).equals(state);
    }

    private void applyToggleMarkStyle(TextView tv, String rowKey, boolean rowFocused) {
        if (tv == null || rowKey == null) return;
        String state = resolveSettingStateText(rowKey);
        boolean on = getString(R.string.common_on).equals(state);
        tv.setText(getString(on ? R.string.common_check : R.string.common_cross));
        tv.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        tv.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size));
        ThemeManager.applyThemedTextStyle(tv, on
                ? (rowFocused ? ThemeManager.getSettingMenuTextColorSelected()
                        : ThemeManager.getSettingMenuTextColorNormal())
                : ThemeManager.getTextColorSecondary());
    }

    private LinearLayout createSettingRow(String rowKey, int labelResId, CharSequence rightText, String iconKey) {
        final LinearLayout layout = new LinearLayout(this);
        layout.setTag(rowKey != null ? rowKey : iconKey);
        layout.setSoundEffectsEnabled(false);
        layout.setOrientation(LinearLayout.HORIZONTAL);
        applySettingsRowFocusability(layout);
        layout.setGravity(android.view.Gravity.CENTER_VERTICAL);
        int hPad = (int) (10 * getResources().getDisplayMetrics().density);
        layout.setPadding(hPad, 0, hPad, 0);
        int rowW = y1ActiveRowWidthPx();
        layout.setBackground(getY1RowBackground(false, rowW, Y1_ROW_MENU));

        TextView tvLeft = new TextView(this);
        tvLeft.setFocusable(false);
        tvLeft.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        tvLeft.setText(getString(labelResId));
        ThemeManager.applyThemedTextStyle(tvLeft, ThemeManager.getSettingMenuTextColorNormal());
        tvLeft.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size));
        enableMarquee(tvLeft);

        TextView tvHint = new TextView(this);
        tvHint.setTag("connectivity_hint");
        tvHint.setFocusable(false);
        tvHint.setVisibility(View.GONE);
        tvHint.setSingleLine(true);
        tvHint.setEllipsize(TextUtils.TruncateAt.MARQUEE);
        tvHint.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size) * 0.78f);
        ThemeManager.applyThemedTextStyle(tvHint, ThemeManager.getHintTextColor());

        LinearLayout labelCol = new LinearLayout(this);
        labelCol.setOrientation(LinearLayout.VERTICAL);
        labelCol.setFocusable(false);
        labelCol.setLayoutParams(new LinearLayout.LayoutParams(
                0, LinearLayout.LayoutParams.WRAP_CONTENT, 1.0f));
        labelCol.addView(tvLeft);
        labelCol.addView(tvHint);
        layout.addView(labelCol);

        TextView tvRight = new TextView(this);
        tvRight.setFocusable(false);
        tvRight.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        final boolean showArrow = "〉 ".contentEquals(rightText) || ">".equals(String.valueOf(rightText).trim());
        if (!showArrow) {
            tvRight.setText(rightText);
            tvRight.setGravity(android.view.Gravity.RIGHT);
            String rt = String.valueOf(rightText);
            if (isActiveStateText(rt) || getString(R.string.common_off).equals(rt))
                ThemeManager.applyThemedTextStyle(tvRight, ThemeManager.getSettingMenuTextColorNormal());
            else
                ThemeManager.applyThemedTextStyle(tvRight, ThemeManager.getTextColorSecondary());
            tvRight.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                    getResources().getDimension(R.dimen.y1_menu_text_size));
            tvRight.setLayoutParams(new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.WRAP_CONTENT, LinearLayout.LayoutParams.WRAP_CONTENT));
            layout.addView(tvRight);
        }

        final ImageView rowArrow = new ImageView(this);
        if (showArrow) {
            Bitmap arrowBmp = ThemeManager.getScaledItemRightArrow(y1RowHeightPx);
            int[] arrowLayout = y1ArrowLayout(arrowBmp);
            if (arrowBmp != null) rowArrow.setImageBitmap(arrowBmp);
            rowArrow.setScaleType(ImageView.ScaleType.FIT_CENTER);
            rowArrow.setVisibility(View.GONE);
            int arrowMarginEnd = (int) getResources().getDimension(R.dimen.y1_arrow_margin_end);
            LinearLayout.LayoutParams arrowLp = new LinearLayout.LayoutParams(arrowLayout[0], arrowLayout[1]);
            arrowLp.gravity = android.view.Gravity.CENTER_VERTICAL;
            arrowLp.rightMargin = arrowMarginEnd;
            layout.addView(rowArrow, arrowLp);
        } else {
            rowArrow.setVisibility(View.GONE);
        }

        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT, y1RowHeightPx);
        lp.setMargins(0, 1, 0, 1);
        layout.setLayoutParams(lp);

        layout.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                int rowW = y1ActiveRowWidthPx();
                applyY1ListRowStyle(layout, hasFocus, tvLeft, showArrow ? null : tvRight,
                        showArrow ? rowArrow : null, Y1_ROW_MENU);
                if (hasFocus && currentScreenState == STATE_SETTINGS && rowKey != null) {
                    // 2026-07-19 — Was sync updateSettingsPreview on every focus.
                    scheduleSettingsPreviewUpdate(rowKey);
                    applyHomeShortcutConnectivityHint(layout, rowKey, true);
                } else if (!hasFocus) {
                    applyHomeShortcutConnectivityHint(layout, rowKey, false);
                }
            }
        });

        return layout;
    }

    private void updateSettingsPreview(String rowKey) {
        if (tvSettingsPreviewTitle == null) return;
        if (isThemeGalleryActive() || isThemeVariantPickerActive()) return;
        boolean a5Strip = A5PortraitChrome.usePortraitChrome(this) && !settingsBrowseFullWidth;
        if ((isFullWidthMenus || settingsBrowseFullWidth) && !a5Strip) {
            if (rowKey != null && rowKey.startsWith("home.shortcut.")
                    && SettingsScreens.isHome(settingsSubScreenKey)) {
                View focused = getCurrentFocus();
                if (focused != null) applyHomeShortcutConnectivityHint(focused, rowKey, true);
            }
            return;
        }
        tvSettingsPreviewTitle.setText(rowLabel(rowKey));
        tvSettingsPreviewTitle.setSelected(true);
        tvSettingsPreviewTitle.setTextColor(ThemeManager.getSettingMenuTextColorSelected());

        boolean isStorage = RowKeys.STORAGE.equals(rowKey);
        if (storagePieView != null) storagePieView.setVisibility(isStorage ? View.VISIBLE : View.GONE);
        if (ivSettingsPreviewIcon != null) ivSettingsPreviewIcon.setVisibility(isStorage ? View.GONE : View.VISIBLE);

        if (isStorage) {
            try {
                java.util.List<File> roots = com.solar.launcher.DeviceFeatures.getStorageRoots();
                if (storagePieView != null) {
                    if (roots.size() == 1) {
                        android.os.StatFs stat = new android.os.StatFs(roots.get(0).getAbsolutePath());
                        long total = (long) stat.getBlockCount() * stat.getBlockSize();
                        long avail = (long) stat.getAvailableBlocks() * stat.getBlockSize();
                        long used = total - avail;
                        if (total > 0) storagePieView.setUsedFraction(used / (float) total);
                        storagePieView.setVisibility(View.VISIBLE);
                    } else {
                        storagePieView.setVisibility(View.GONE);
                    }
                }
                if (tvSettingsPreviewState != null) {
                    applySettingsPreviewStateText(buildAllStorageDetailsText(), false);
                    ThemeManager.applyThemedTextStyle(tvSettingsPreviewState, ThemeManager.getTextColorPrimary());
                }
            } catch (Exception e) {
                if (tvSettingsPreviewState != null) applySettingsPreviewStateText("", false);
            }
            return;
        }

        String solarKey = resolveSoulseekSolarConfigKey(rowKey);
        Bitmap icon = ThemeManager.getSettingsRowIcon(this, rowKey,
                com.solar.launcher.theme.SolarTheming.englishSettingsRowLabel(this, rowKey),
                solarKey, resolveSettingIconKey(rowKey), resolveSolarSettingAppName(rowKey));
        if (icon == null && isAppearancePreviewRow(rowKey)) {
            icon = ThemeManager.getThemeSettingBitmap("theme");
        }
        if (icon == null && RowKeys.APP_THEME.equals(rowKey)) {
            Bitmap cover = ThemeManager.getScaledThemeCover(ThemeManager.getCurrentTheme(), y1ThemeCoverHeightPx);
            if (cover != null) icon = cover;
        }
        if (ivSettingsPreviewIcon != null) {
            if (icon != null) {
                ivSettingsPreviewIcon.setImageBitmap(icon);
                ivSettingsPreviewIcon.setVisibility(View.VISIBLE);
            } else {
                ivSettingsPreviewIcon.setVisibility(View.GONE);
            }
        }
        String stateText = resolveSettingStateText(rowKey);
        if (rowKey != null && rowKey.startsWith("home.shortcut.")
                && SettingsScreens.isHome(settingsSubScreenKey)) {
            String id = rowKey.substring("home.shortcut.".length());
            String hint = homeShortcutConnectivityHint(id);
            if (hint != null) {
                stateText = hint;
            }
        }
        if (SettingsScreens.LIBRARY_BROWSE.equals(settingsSubScreenKey)) {
            int previewRes = LibraryBrowsePrefs.previewTextRes(rowKey);
            if (previewRes != 0) {
                String current = resolveSettingStateText(rowKey);
                String desc = getString(previewRes);
                stateText = current != null && !current.isEmpty()
                        ? desc + "\n\n" + getString(R.string.lib_preview_current, current)
                        : desc;
            }
        }
        String reachPreview = resolveReachSettingsPreviewText(rowKey);
        if (reachPreview != null) {
            stateText = reachPreview;
        }
        String soulseekPreview = resolveSoulseekSettingsPreviewText(rowKey);
        if (soulseekPreview != null) {
            stateText = soulseekPreview;
        }
        String deezerPreview = resolveDeezerSettingsPreviewText(rowKey);
        if (deezerPreview != null) {
            stateText = deezerPreview;
        }
        String resetPreview = resolveResetSettingsPreviewText(rowKey);
        if (resetPreview != null) {
            stateText = resetPreview;
        }
        if (RowKeys.USB_AUTO_CONNECT.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_usb_auto_connect) + "\n\n" + (stateText != null ? stateText : "");
        }
        if (RowKeys.USB_SUPPRESS_PROMPT.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_usb_suppress_prompt) + "\n\n" + (stateText != null ? stateText : "");
        }
        if (RowKeys.WIFI_SLEEP_POWER_OFF.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_wifi_sleep_power_off) + "\n\n"
                    + (stateText != null ? stateText : "");
        }
        if (RowKeys.USB_TURN_ON.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_usb_turn_on);
        }
        if (RowKeys.ARTWORK_PERSPECTIVE.equals(rowKey)) {
            stateText = getString(nowPlaying3dAlbumArt
                    ? R.string.settings_artwork_perspective_3d_hint
                    : R.string.settings_artwork_perspective_flat_hint);
        }
        if (RowKeys.INFINITE_SCROLL.equals(rowKey)) {
            stateText = getString(R.string.settings_infinite_scroll_hint) + "\n\n"
                    + (stateText != null ? stateText : "");
        }
        if (RowKeys.MENU_ITEM_PADDING.equals(rowKey)) {
            boolean maskLocks = ThemeManager.menuItemPaddingForcedByMask(false)
                    || ThemeManager.menuItemPaddingForcedByMask(true);
            stateText = getString(maskLocks
                    ? R.string.settings_menu_item_padding_mask_hint
                    : R.string.settings_menu_item_padding_hint) + "\n\n"
                    + (stateText != null ? stateText : "");
        }
        if (RowKeys.DEBUG_WIRELESS_ADB.equals(rowKey)) {
            stateText = getString(R.string.settings_debug_wireless_adb_hint);
        }
        if (RowKeys.DEBUG_MICROSD_FORMAT.equals(rowKey)) {
            stateText = getString(R.string.settings_debug_microsd_format_hint);
        }
        if (RowKeys.FLOW.equals(rowKey)) {
            // 2026-07-18 — Glyph + action (was plain “Hold Play/Pause…” with no button picture).
            applySettingsPreviewStateText(
                    HardwareButtonGlyph.settingsHoldPlayPauseOpenFlow(this), false);
            ThemeManager.applyThemedTextStyle(tvSettingsPreviewState,
                    ThemeManager.getTextColorPrimary());
            applySettingsPreviewPaneLayout(isSettingsPaneMaskActive());
            if (isSettingsPaneMaskActive()) {
                if (tvSettingsPreviewTitle != null) tvSettingsPreviewTitle.setVisibility(View.GONE);
                if (settingsPreviewStateScroll != null) {
                    settingsPreviewStateScroll.setVisibility(View.GONE);
                }
            }
            if (a5Strip) syncA5BottomStripFromSettings(rowKey);
            return;
        }
        if (RowKeys.DIAG_AUTO_REPORT.equals(rowKey)) {
            stateText = getString(soulseekDiagAutoReport
                    ? R.string.settings_diag_auto_report_on_hint
                    : R.string.settings_diag_auto_report_off_hint);
        }
        if (RowKeys.Y2_PRIMARY_STORAGE.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_y2_primary_storage);
        }
        if (RowKeys.Y2_INTERNAL_MEDIA.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_y2_internal_media);
        }
        if (RowKeys.Y2_HOLD_OK_TO_SLEEP.equals(rowKey)) {
            stateText = getString(R.string.settings_preview_y2_hold_ok_to_sleep);
        }
        if (RowKeys.HEARING_SAFETY.equals(rowKey)) {
            // 2026-07-15 — Preview copy for headphone 80% cap vs full-volume bypass.
            stateText = getString(R.string.settings_preview_hearing_safety) + "\n\n"
                    + (stateText != null ? stateText : "");
        }
        if (RowKeys.A5_MENU_NAV.equals(rowKey)) {
            boolean face = A5NavigationMode.isFaceNav(this);
            stateText = getString(face ? R.string.settings_a5_menu_nav_face
                    : R.string.settings_a5_menu_nav_side)
                    + "\n\n" + getString(R.string.settings_preview_a5_menu_nav);
        }
        if (RowKeys.A5_ORIENTATION.equals(rowKey)) {
            String mode = A5NavigationMode.orientation(this);
            int label = A5NavigationMode.ORIENT_AUTO.equals(mode)
                    ? R.string.settings_a5_orientation_auto
                    : (A5NavigationMode.ORIENT_LANDSCAPE.equals(mode)
                    ? R.string.settings_a5_orientation_landscape
                    : R.string.settings_a5_orientation_portrait);
            stateText = getString(label)
                    + "\n\n" + getString(R.string.settings_preview_a5_orientation);
        }
        if (RowKeys.REPORT_ISSUE.equals(rowKey) && settingsSubScreenKey == null) {
            stateText = getString(R.string.support_link_report_issue_intro) + "\n\n"
                    + SolarSupportLinks.githubIssuesUrlForDisplay();
        }
        if (RowKeys.SUPPORT_DEVELOPER.equals(rowKey) && settingsSubScreenKey == null) {
            stateText = getString(R.string.support_link_kofi_intro) + "\n\n"
                    + SolarSupportLinks.kofiUrlForDisplay();
        }
        boolean verticalMarquee = SettingsScreens.isSoulseek(settingsSubScreenKey);
        if (tvSettingsPreviewState != null) {
            applySettingsPreviewStateText(stateText != null ? stateText : "", verticalMarquee);
            ThemeManager.applyThemedTextStyle(tvSettingsPreviewState, ThemeManager.getTextColorPrimary());
        }
        applySettingsPreviewPaneLayout(isSettingsPaneMaskActive());
        if (isSettingsPaneMaskActive()) {
            if (tvSettingsPreviewTitle != null) tvSettingsPreviewTitle.setVisibility(View.GONE);
            if (settingsPreviewStateScroll != null) settingsPreviewStateScroll.setVisibility(View.GONE);
        }
        if (a5Strip) syncA5BottomStripFromSettings(rowKey);
    }

    private String formatStorageLines(long total, long used, long avail) {
        return getString(R.string.common_storage_total, formatBytes(total), formatBytes(used), formatBytes(avail));
    }

    /** One volume block for Settings storage preview and Storage info screen. */
    private String buildStorageVolumeDetails(File root) {
        try {
            android.os.StatFs stat = new android.os.StatFs(root.getAbsolutePath());
            long blockSize = (long) stat.getBlockSize();
            long total = (long) stat.getBlockCount() * blockSize;
            long avail = (long) stat.getAvailableBlocks() * blockSize;
            long used = total - avail;
            String header = com.solar.launcher.DeviceFeatures.storageRootLabel(this, root);
            return header + "\n" + formatStorageLines(total, used, avail);
        } catch (Exception e) {
            return com.solar.launcher.DeviceFeatures.storageRootLabel(this, root) + "\n"
                    + getString(R.string.common_storage_error);
        }
    }

    /** Y2 lists MicroSD + Internal; Y1 shows the single user SD volume. */
    private String buildAllStorageDetailsText() {
        java.util.List<File> roots = com.solar.launcher.DeviceFeatures.getStorageRoots();
        if (roots.isEmpty()) return getString(R.string.common_storage_error);
        if (roots.size() == 1) return buildStorageVolumeDetails(roots.get(0));
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < roots.size(); i++) {
            if (i > 0) sb.append("\n\n");
            sb.append(buildStorageVolumeDetails(roots.get(i)));
        }
        return sb.toString();
    }

    private String formatBytes(long bytes) {
        if (bytes >= 1024L * 1024L * 1024L) {
            return String.format(Locale.US, "%.2f GB", bytes / (1024.0 * 1024.0 * 1024.0));
        }
        return String.format(Locale.US, "%.0f MB", bytes / (1024.0 * 1024.0));
    }

    private boolean suppressCenterSleepForReorder(long heldMs) {
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            if (contextMenuInQueueTier) return true;
            if (contextQueueMoveFrom >= 0) return true;
            if (themedContextMenu.isSubmenuTierOpen()) return true;
        }
        if (isPlaylistMoveActive()) return true;
        if (mediaSuite != null && mediaSuite.isFmPresetMoveActive()) return true;
        if (playlistMoveTutorialShowing) return true;
        if (isPlaylistBrowseContext()) return true;
        // 2026-07-15 — Home editor strip move.
        if (homeEditorMoveFrom >= 0) return true;
        if (canScheduleCenterMovePick() && heldMs < CENTER_MOVE_HOLD_MS + 80) return true;
        return false;
    }

    /**
     * 2026-07-14 — Long OK opens context (Y2 default + A5 middle button).
     * Was: Y2 only. Now: A5 KeyCodeDisp middle→OK also holds for context / move.
     * Reversal: return isY2() && !y2HoldOkToSleep only.
     */
    private boolean y2CenterOpensContextMenu() {
        if (DeviceFeatures.isA5()) return true;
        return DeviceFeatures.isY2() && !y2HoldOkToSleep;
    }

    /**
     * 2026-07-15 — Center hold sleep: Y1 default (~300ms); Y2 only if hold-OK-to-sleep pref; A5 never.
     * Layman: on Y1, hold the middle button to dim the screen — unless you are rearranging a list.
     * Technical: suppressCenterSleepForReorder wins; Y2 uses hardware POWER short-press for sleep.
     * Was: Y1 fall-through could sleep A5. Reversal: drop isA5 early return.
     */
    private boolean centerHoldShouldSleep(long heldMs) {
        if (suppressCenterSleepForReorder(heldMs)) return false;
        if (DeviceFeatures.isA5()) return false;
        if (DeviceFeatures.isY2()) return y2HoldOkToSleep && heldMs >= CENTER_SLEEP_HOLD_MS;
        return heldMs >= CENTER_SLEEP_HOLD_MS;
    }

    private boolean isPlaylistBrowseContext() {
        return currentScreenState == STATE_BROWSER
                && currentBrowserMode == BROWSER_VIRTUAL_SONGS
                && "PLAYLIST".equals(virtualQueryType);
    }

    private boolean isPlaylistMoveActive() {
        return playlistMoveFrom >= 0 && isPlaylistBrowseContext();
    }

    private boolean isVirtualPlaylistView() {
        return isPlaylistBrowseContext()
                && listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE;
    }

    private boolean isFmPresetListContext() {
        return mediaSuite != null
                && MediaSuiteHost.isMediaListBrowseState(currentScreenState)
                && mediaSuite.isFmPresetListActive()
                && listVirtualSongs != null
                && listVirtualSongs.getVisibility() == View.VISIBLE;
    }

    private boolean canScheduleCenterMovePick() {
        if (themedContextMenu != null && themedContextMenu.isShowing() && contextMenuInQueueTier) {
            return contextQueueMoveFrom < 0 && isContextQueueListFocused();
        }
        if (isFmPresetListContext()) {
            return !mediaSuite.isFmPresetMoveActive();
        }
        if (isVirtualPlaylistView()) return playlistMoveFrom < 0 && !playlistMoveTutorialShowing;
        if (isPlaylistBrowseContext()) return playlistMoveFrom < 0 && !playlistMoveTutorialShowing;
        // 2026-07-15 — Home Screen editor reorder lift.
        if (currentScreenState == STATE_SETTINGS && SettingsScreens.HOME.equals(settingsSubScreenKey)
                && homeEditorMoveFrom < 0) {
            return focusedHomeEditorShortcutId() != null;
        }
        return false;
    }

    private void performCenterMovePickUp() {
        if (themedContextMenu != null && themedContextMenu.isShowing() && contextMenuInQueueTier
                && isContextQueueListFocused()) {
            handleContextQueueCenterActivate(true);
            return;
        }
        if (isFmPresetListContext()) {
            handleFmPresetListCenterActivate(true);
            return;
        }
        if (isPlaylistBrowseContext()) {
            handlePlaylistListCenterActivate(true);
            return;
        }
        if (currentScreenState == STATE_SETTINGS && SettingsScreens.HOME.equals(settingsSubScreenKey)
                && homeEditorMoveFrom < 0) {
            String id = focusedHomeEditorShortcutId();
            if (id != null) beginHomeEditorMove(id);
        }
    }

    /**
     * 2026-07-15 — Home editor focused shortcut id (null for Back / headers / Settings / off).
     */
    private String focusedHomeEditorShortcutId() {
        if (containerSettingsItems == null) return null;
        View focused = getCurrentFocus();
        if (focused == null) return null;
        Object tag = focused.getTag();
        if (!(tag instanceof String)) return null;
        String key = (String) tag;
        final String prefix = "home.shortcut.";
        if (!key.startsWith(prefix)) return null;
        String id = key.substring(prefix.length());
        if (HomeMenuConfig.ID_SETTINGS.equals(id)) return null;
        if (!HomeMenuConfig.isVisible(prefs, id)) return null;
        return id;
    }

    /** Center/OK hold ~0.3s — sleep while pressed or on release after threshold. */
    private boolean trackCenterKeyDown(KeyEvent event, boolean fromContextMenu) {
        if (fromContextMenu) {
            suppressListClickUntil = System.currentTimeMillis() + CONTEXT_MENU_CLICK_SUPPRESS_MS;
        }
        if (event.getRepeatCount() == 0) {
            centerMovePickHandled = false;
            centerQuickBarTapHandled = false;
            centerLongPressHandled = false;
            centerSleepHoldHandled = false;
            centerKeyDownTime = System.currentTimeMillis();
            clockHandler.removeCallbacks(centerMovePickRunnable);
            clockHandler.removeCallbacks(centerLongPressRunnable);
            clockHandler.removeCallbacks(centerSleepHoldRunnable);
            clockHandler.removeCallbacks(keyboardDelRepeatRunnable);
            // 2026-07-16 — USB Connection prompt: never arm hold-to-sleep on OK.
            // Layman: pressing the middle button must always mean Turn on or Dismiss.
            final boolean usbEnablePrompt = usbEnablePromptSession || isUsbEnablePromptTierActive();
            if (isKeyboardDelSelected()) {
                clockHandler.postDelayed(keyboardDelRepeatRunnable, 80);
            } else if (canScheduleCenterMovePick()) {
                clockHandler.postDelayed(centerMovePickRunnable, CENTER_MOVE_HOLD_MS);
            } else if (y2CenterOpensContextMenu()) {
                armContextHoldThrobber();
                clockHandler.postDelayed(centerLongPressRunnable, CENTER_LONG_PRESS_MS);
            } else if (!usbEnablePrompt && centerHoldShouldSleep(CENTER_SLEEP_HOLD_MS)) {
                clockHandler.postDelayed(centerSleepHoldRunnable, CENTER_SLEEP_HOLD_MS);
            }
        }
        return true;
    }

    private boolean isKeyboardDelSelected() {
        return currentScreenState == STATE_WIFI_KEYBOARD
                && keyboardIndex >= 0 && keyboardIndex < KEYBOARD_CHARS.length
                && "[DEL]".equals(KEYBOARD_CHARS[keyboardIndex]);
    }

    /** Queue list rows — not quick bar / title / slider while queue tier is open. */
    private boolean isContextQueueListFocused() {
        if (themedContextMenu == null) return false;
        return themedContextMenu.focusZone() == ThemedContextMenu.FocusZone.TIER_CONTENT;
    }

    private boolean handleCenterKeyUp(KeyEvent event, boolean fromContextMenu) {
        long heldMs = centerKeyDownTime > 0 ? System.currentTimeMillis() - centerKeyDownTime : 0;
        clearContextHoldThrobber();
        clockHandler.removeCallbacks(centerMovePickRunnable);
        clockHandler.removeCallbacks(centerLongPressRunnable);
        clockHandler.removeCallbacks(centerSleepHoldRunnable);
        clockHandler.removeCallbacks(keyboardDelRepeatRunnable);
        centerKeyDownTime = 0;
        if (centerSleepHoldHandled) {
            centerSleepHoldHandled = false;
            return true;
        }
        if (fromContextMenu) {
            suppressListClickUntil = System.currentTimeMillis() + CONTEXT_MENU_CLICK_SUPPRESS_MS;
            if (centerQuickBarTapHandled) {
                centerQuickBarTapHandled = false;
                centerKeyDownTime = 0;
                return true;
            }
            if (contextMenuInQueueTier && isContextQueueListFocused()) {
                if (!centerMovePickHandled) {
                    handleContextQueueCenterActivate(false);
                    clickFeedback();
                }
                centerMovePickHandled = false;
                return true;
            }
            centerMovePickHandled = false;
            if (finishUsbQueueBlockFromInput()) {
                return true;
            }
            if (finishQueueTutorialFromInput()) {
                return true;
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("heldMs", heldMs);
                d.put("suppressSleep", suppressCenterSleepForReorder(heldMs));
                d.put("zone", themedContextMenu != null ? themedContextMenu.focusZone().name() : "null");
                d.put("submenuOpen", themedContextMenu != null && themedContextMenu.isSubmenuTierOpen());
                DebugAgentLog.log(this, "MainActivity.handleCenterKeyUp", "context center", "H1-H2", d);
            } catch (Exception ignored) {}
            // #endregion
            if (y2CenterOpensContextMenu() && centerLongPressHandled) {
                centerLongPressHandled = false;
                return true;
            }
            // 2026-07-16 — USB Connection: always fire focused row (Turn on / Dismiss).
            // Was: hold ≥300ms → sleep, so OK felt dead on deliberate presses.
            final boolean usbEnablePrompt = usbEnablePromptSession || isUsbEnablePromptTierActive();
            if (!usbEnablePrompt && centerHoldShouldSleep(heldMs)) {
                performScreenSleep(false);
                return true;
            }
            themedContextMenu.activateFocused();
            clickFeedback();
            return true;
        }
        if (currentScreenState == STATE_FLOW && flowScreenHost != null) {
            return handleFlowCenterKeyUp(heldMs);
        }
        if (finishPlaylistMoveTutorialFromInput()) {
            centerMovePickHandled = false;
            clickFeedback();
            return true;
        }
        if (isFmPresetListContext()) {
            if (!centerMovePickHandled) {
                handleFmPresetListCenterActivate(false);
                clickFeedback();
            }
            centerMovePickHandled = false;
            return true;
        }
        if (isPlaylistMoveActive() || isVirtualPlaylistView()) {
            if (!centerMovePickHandled) {
                handlePlaylistListCenterActivate(false);
                clickFeedback();
            }
            centerMovePickHandled = false;
            return true;
        }
        centerMovePickHandled = false;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("heldMs", heldMs);
            d.put("suppressSleep", suppressCenterSleepForReorder(heldMs));
            d.put("playlist", isVirtualPlaylistView());
            d.put("playlistCtx", isPlaylistBrowseContext());
            d.put("playlistMove", isPlaylistMoveActive());
            d.put("moveFrom", playlistMoveFrom);
            d.put("canPick", canScheduleCenterMovePick());
            DebugAgentLog.log(this, "MainActivity.handleCenterKeyUp", "global center", "H1-H3", d);
        } catch (Exception ignored) {}
        // #endregion
        if (y2CenterOpensContextMenu()) {
            if (centerLongPressHandled) {
                centerLongPressHandled = false;
                return true;
            }
            if (heldMs >= CENTER_LONG_PRESS_MS) {
                if (themedContextMenu != null && themedContextMenu.isShowing()) {
                    if (contextMenuVolumeOnly) {
                        expandVolumeOverlayToFullContext();
                    } else {
                        dismissThemedContextMenu();
                    }
                } else {
                    showThemedContextMenu();
                }
                centerLongPressHandled = true;
                return true;
            }
        }
        if (centerHoldShouldSleep(heldMs)) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("heldMs", heldMs);
                d.put("screen", currentScreenState);
                d.put("keyCode", event.getKeyCode());
                d.put("wifiKeyboard", currentScreenState == STATE_WIFI_KEYBOARD);
                DebugAgentLog.log(this, "MainActivity.handleCenterKeyUp",
                        "center hold triggered screen sleep", "H1", d);
            } catch (Exception ignored) {}
            // #endregion
            performScreenSleep(false);
            return true;
        }
        if (currentScreenState == STATE_PLAYER) {
            // 2026-07-06 — wheel OK (85) and ENTER (66) confirm on NP / FM tune.
            if (isCenterKey(event.getKeyCode())) {
                if (playback.isRadioActive() && mediaSuite != null) {
                    routeFmPlayerCenterOk();
                    clickFeedback();
                    return true;
                }
                // 2026-07-14 — A5 OK: short = play/pause; hold opens context (y2CenterOpensContextMenu).
                // Scrubbing is opt-in via context “Scrubbing” → enterPlayerScrubCursorMode.
                // Was: short OK entered fine scrub (felt like selecting / fighting edge Back).
                // Reversal: drop isA5 branch; always enterPlayerScrubCursorMode on short OK.
                if (DeviceFeatures.isA5()) {
                    if (playerScrubCursorActive) {
                        commitPlayerScrubCursor();
                    } else {
                        playOrPauseMusic();
                    }
                    clickFeedback();
                    return true;
                }
                if (playerScrubCursorActive) {
                    commitPlayerScrubCursor();
                } else {
                    enterPlayerScrubCursorMode();
                }
                clickFeedback();
                return true;
            }
            // 2026-07-10 — Play/pause on NP is transport (handlePlayPauseKeyUp), not scrub.
            // Scrub remains Center/OK only (Y1/Y2). Dead branch kept for clarity if PP ever reaches here.
        }
        if (currentScreenState == MediaSuiteHost.STATE_VIDEO_PLAYER && mediaSuite != null
                && isCenterKey(event.getKeyCode())) {
            mediaSuite.handleVideoCenterOk();
            clickFeedback();
            return true;
        }
        try {
            handleCenterShortClick();
        } catch (Exception ignored) {}
        return true;
    }

    /**
     * 2026-07-14 — A5 edge L/R: dismiss context/overlay or synthesize Back.
     * Layman: swipe from the side like phone edge-back.
     */
    private void handleA5EdgeBack() {
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            dismissContextMenuAnimated();
            return;
        }
        if (shouldRouteKeysToGlobalChipOverlay()) {
            try {
                Intent dismiss = new Intent(OverlayTriggers.ACTION_DISMISS_OVERLAY);
                dismiss.setPackage(getPackageName());
                sendBroadcast(dismiss);
            } catch (Exception ignored) {}
            return;
        }
        // 2026-07-14 — Keyboard: edge Back cancels (hardware Back is Enter). Avoid synth Back→ENT.
        // Was: always synth KEYCODE_BACK. Reversal: drop branch; edge also submits.
        if (currentScreenState == STATE_WIFI_KEYBOARD) {
            clickFeedback();
            if (keyboardPurpose == KEYBOARD_SOULSEEK_MSG && keyboardComposeFromContextPm) {
                restoreSettingsAfterSoulseekAccount();
            } else if (keyboardReturnState == STATE_SETTINGS && keyboardReturnSettingsSubKey != null) {
                restoreSettingsAfterSoulseekAccount();
            } else {
                changeScreen(keyboardReturnState);
            }
            return;
        }
        long now = android.os.SystemClock.uptimeMillis();
        dispatchKeyEvent(new KeyEvent(now, now, KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_BACK, 0));
        dispatchKeyEvent(new KeyEvent(now, now, KeyEvent.ACTION_UP, KeyEvent.KEYCODE_BACK, 0));
    }

    /**
     * 2026-07-14 — A5 bottom-edge swipe up → Solar home menu.
     * Layman: flick up from the bottom to jump to the main list.
     */
    private void handleA5EdgeHome() {
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            dismissThemedContextMenu();
        }
        if (shouldRouteKeysToGlobalChipOverlay()) {
            try {
                Intent dismiss = new Intent(OverlayTriggers.ACTION_DISMISS_OVERLAY);
                dismiss.setPackage(getPackageName());
                sendBroadcast(dismiss);
            } catch (Exception ignored) {}
        }
        changeScreen(STATE_MENU);
    }

    /**
     * 2026-07-14 — A5 hold-still (or future top-edge) → in-app context quick menu.
     * Skip on Now Playing so album scrub/hold is not stolen (HOLD_SCRUB_MS ~500).
     */
    private void handleA5EdgeOpenContext() {
        if (currentScreenState == STATE_PLAYER) return;
        if (themedContextMenu != null && themedContextMenu.isShowing()) return;
        if (shouldRouteKeysToGlobalChipOverlay()) return;
        showThemedContextMenu();
    }

    private void dismissThemedContextMenu() {
        dismissThemedContextMenu(true);
    }

    /**
     * @param recordUsbPromptDismissed when closing the USB enable prompt without turning storage on,
     *        suppress re-prompt until cable disconnect.
     */
    private void dismissThemedContextMenu(boolean recordUsbPromptDismissed) {
        dismissThemedContextMenu(recordUsbPromptDismissed, menuTransitionsEnabled, null);
    }

    /** Back chip / root dismiss — animate modal out before restoring focus. */
    private void dismissContextMenuAnimated() {
        dismissThemedContextMenu(true, true, null);
    }

    private void dismissThemedContextMenu(final boolean recordUsbPromptDismissed,
            final boolean animated, final Runnable onComplete) {
        if (otaSystemReplaceInProgress) return;
        final boolean closingUsbEnablePrompt = isUsbEnablePromptTierActive() || usbEnablePromptSession;
        flushContextQueueMoveIfDirty();
        cancelPendingContextWifiRefresh();
        cancelPendingContextBluetoothRefresh();
        cancelWifiContextScanFollowUps();
        contextMenuTierStack.clear();
        contextMenuInVolumeSlider = false;
        contextMenuVolumeOnly = false;
        contextMenuBlockingHint = false;
        contextMenuInQueueTier = false;
        contextMenuQuickOnly = false;
        contextQueueEditPlaylist = false;
        playlistEditEntry = null;
        playlistEditTracks.clear();
        clearContextQueueMoveSession();
        contextMenuVolumeReturnTier = null;
        contextMenuVolumeOnly = false;
        contextMenuOpenedAtMs = 0;
        contextTierConfirmOpen = false;
        volumeHandler.removeCallbacks(hideVolumeContextTask);
        updateNetworkRescanLoop();
        if (themedContextMenu != null) {
            if (animated) {
                themedContextMenu.dismissAnimated(new Runnable() {
                    @Override
                    public void run() {
                        finishThemedContextMenuDismiss(recordUsbPromptDismissed, closingUsbEnablePrompt,
                                onComplete);
                    }
                });
                return;
            }
            themedContextMenu.dismiss();
        }
        finishThemedContextMenuDismiss(recordUsbPromptDismissed, closingUsbEnablePrompt, onComplete);
    }

    private void finishThemedContextMenuDismiss(boolean recordUsbPromptDismissed,
            boolean closingUsbEnablePrompt, Runnable onComplete) {
        syncUsbReclaimForContextMenu(false);
        if (closingUsbEnablePrompt && recordUsbPromptDismissed) {
            onUsbStorageEnableDialogDismissed("context_menu_close");
        }
        usbEnablePromptSession = false;
        if (closingUsbEnablePrompt) {
            // Keep usbPromptBackHandledOnDown until KEY_UP swallows residual Back.
        } else {
            usbPromptBackHandledOnDown = false;
        }
        restoreFocusAfterContextMenuDismiss();
        updateVideoStatusBarPolicy();
        if (onComplete != null) onComplete.run();
    }

    private boolean isNetworkRescanActive() {
        if (currentScreenState == STATE_WIFI || currentScreenState == STATE_BLUETOOTH) return true;
        boolean ctxWifi = isWifiTierMounted() && !contextTierConfirmOpen
                && (isWifiContextExpanded() || wifiContextPendingEnable || wifiContextPendingDisable);
        boolean ctxBt = isBtTierMounted() && !contextTierConfirmOpen
                && (isBluetoothContextExpanded() || btContextPendingEnable || btContextPendingDisable);
        boolean active = ctxWifi || ctxBt;
        // #region agent log
        if (DebugAgentLog.ENABLED && themedContextMenu != null && themedContextMenu.isShowing()) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("ctxWifi", ctxWifi);
                d.put("ctxBt", ctxBt);
                d.put("tierTop", contextMenuTopTier());
                d.put("submenuOpen", themedContextMenu.isSubmenuTierOpen());
                d.put("volSlider", contextMenuInVolumeSlider);
                d.put("active", active);
                DebugAgentLog.log(this, "MainActivity.isNetworkRescanActive", "rescan gate", "H2", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        return active;
    }

    private void updateNetworkRescanLoop() {
        networkRescanHandler.removeCallbacks(networkRescanTick);
        if (isNetworkRescanActive()) {
            networkRescanHandler.postDelayed(networkRescanTick, NETWORK_RESCAN_INTERVAL_MS);
        }
    }

    private void applySettingsRowFocusability(LinearLayout layout) {
        if (layout == null) return;
        layout.setFocusable(true);
        layout.setClickable(true);
        layout.setFocusableInTouchMode(true);
        layout.setDescendantFocusability(android.view.ViewGroup.FOCUS_BLOCK_DESCENDANTS);
    }

    private boolean isViewDescendantOf(View view, View ancestor) {
        if (view == null || ancestor == null) return false;
        View p = view;
        while (p != null) {
            if (p == ancestor) return true;
            if (!(p.getParent() instanceof View)) return false;
            p = (View) p.getParent();
        }
        return false;
    }

    /** Wheel up/down in settings lists — walks {@link #containerSettingsItems} rows directly. */
    private boolean moveSettingsListFocus(int delta) {
        // 2026-07-15 — Home editor strip owns the wheel while moving.
        if (homeEditorMoveFrom >= 0 && SettingsScreens.HOME.equals(settingsSubScreenKey)) {
            stepHomeEditorMove(delta);
            return true;
        }
        // #region agent log
        if (isConversationThreadActive()) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("delta", delta);
                d.put("settingsItems", containerSettingsItems != null
                        ? containerSettingsItems.getChildCount() : -1);
                View foc = getCurrentFocus();
                d.put("focusClass", foc != null ? foc.getClass().getSimpleName() : "null");
                d.put("listSel", listConversationThread.getSelectedItemPosition());
                d.put("listHasFocus", listConversationThread.hasFocus());
                DebugAgentLog.log(this, "MainActivity.moveSettingsListFocus",
                        "wheel during conversation", "H3-H5", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        if (containerSettingsItems == null || delta == 0) return false;
        View focused = getCurrentFocus();
        int currentIdx = -1;
        for (int i = 0; i < containerSettingsItems.getChildCount(); i++) {
            View row = containerSettingsItems.getChildAt(i);
            if (row == focused || isViewDescendantOf(focused, row)) {
                currentIdx = i;
                break;
            }
        }
        if (currentIdx < 0) {
            for (int i = 0; i < containerSettingsItems.getChildCount(); i++) {
                View row = containerSettingsItems.getChildAt(i);
                if (row == null || row.getVisibility() != View.VISIBLE || !row.isEnabled()
                        || !row.isFocusable()) {
                    continue;
                }
                if (row.requestFocus()) {
                    // 2026-07-11 — Edge-only ensure; was requestChildFocus.
                    if (settingsScrollView instanceof ScrollView) {
                        FocusScrollHelper.ensureChildVisible((ScrollView) settingsScrollView, row);
                    }
                    lastSettingsFocusIndex = i;
                    return true;
                }
            }
            return false;
        }
        // 2026-07-17 — Flywheel may pass |delta|>1; skip that many focusable rows in one pass.
        int step = delta < 0 ? -1 : 1;
        int need = Math.max(1, Math.abs(delta));
        int landed = -1;
        View landedView = null;
        for (int i = currentIdx + step; i >= 0 && i < containerSettingsItems.getChildCount(); i += step) {
            View next = containerSettingsItems.getChildAt(i);
            if (next == null || next.getVisibility() != View.VISIBLE || !next.isEnabled()
                    || !next.isFocusable()) {
                continue;
            }
            need--;
            landed = i;
            landedView = next;
            if (need <= 0) break;
        }
        if (landedView != null && landedView.requestFocus()) {
            if (SettingsScreens.HOME.equals(settingsSubScreenKey)) {
                homeScreenEditorFocusIndex = landed;
            }
            lastSettingsFocusIndex = landed;
            Object tag = landedView.getTag();
            if (tag instanceof String && currentScreenState == STATE_SETTINGS) {
                // 2026-07-19 — Was sync updateSettingsPreview (StatFs/icons every notch).
                scheduleSettingsPreviewUpdate((String) tag);
            }
            if (settingsScrollView instanceof ScrollView) {
                FocusScrollHelper.ensureChildVisible((ScrollView) settingsScrollView, landedView);
            }
            return true;
        }
        if (isInfiniteScroll && !wheelPhysics.suppressWrapAround()
                && containerSettingsItems.getChildCount() > 0) {
            int wrapStart = delta < 0 ? containerSettingsItems.getChildCount() - 1 : 0;
            int wrapStep = delta < 0 ? -1 : 1;
            for (int i = wrapStart; i >= 0 && i < containerSettingsItems.getChildCount(); i += wrapStep) {
                View next = containerSettingsItems.getChildAt(i);
                if (next == null || next.getVisibility() != View.VISIBLE || !next.isEnabled()
                        || !next.isFocusable()) {
                    continue;
                }
                if (!next.requestFocus()) continue;
                // 2026-07-11 — Edge-only; was requestChildFocus.
                if (SettingsScreens.HOME.equals(settingsSubScreenKey)) {
                    homeScreenEditorFocusIndex = i;
                }
                lastSettingsFocusIndex = i;
                Object tag = next.getTag();
                // 2026-07-19 — Defer preview (was sync when flywheel cool).
                if (tag instanceof String && currentScreenState == STATE_SETTINGS) {
                    scheduleSettingsPreviewUpdate((String) tag);
                }
                if (settingsScrollView instanceof ScrollView) {
                    FocusScrollHelper.ensureChildVisible((ScrollView) settingsScrollView, next);
                }
                return true;
            }
        }
        if (settingsScrollView instanceof android.widget.ScrollView) {
            Y1ScrollIndicators.edgeGlowAtLimit((android.widget.ScrollView) settingsScrollView, delta);
        }
        return false;
    }

    /** True when wheel/OK input should work on the current list without re-seeding focus. */
    private boolean isFocusValidForCurrentScreen() {
        View focused = getCurrentFocus();
        if (focused == null || !focused.isShown() || !focused.isFocusable()) return false;
        switch (currentScreenState) {
            case STATE_MENU:
                // Index-driven highlight — wheel may move focus before View.requestFocus post runs.
                return layoutMainMenu != null && layoutMainMenu.getVisibility() == View.VISIBLE
                        && containerHomeMenuItems != null
                        && focusedHomeMenuIndex >= 0
                        && focusedHomeMenuIndex < containerHomeMenuItems.getChildCount();
            case STATE_BROWSER:
            case STATE_PODCASTS:
            case STATE_DEEZER:
            case STATE_APPS:
            case STATE_MORE:
            case STATE_USB_STORAGE:
            case STATE_NAVIDROME:
            case STATE_PLEX:
            case STATE_JELLYFIN:
                // 2026-07-14 — Browse ScrollView focus wins before ListView early-return (Deezer etc.).
                if (focused != null && containerBrowserItems != null
                        && isViewDescendantOf(focused, containerBrowserItems)) {
                    return true;
                }
                if (layoutBrowserMode == null || layoutBrowserMode.getVisibility() != View.VISIBLE) {
                    return false;
                }
                if (listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE) {
                    if (listVirtualSongs.hasFocus()) return true;
                    if (focused != null && isViewDescendantOf(focused, listVirtualSongs)) return true;
                    int sel = listVirtualSongs.getSelectedItemPosition();
                    return sel >= 0 && listVirtualSongs.getAdapter() != null
                            && sel < listVirtualSongs.getCount();
                }
                return isViewDescendantOf(focused, layoutBrowserMode);
            case STATE_SOULSEEK:
                // 2026-07-14 — Get Music ScrollView rows beat Reach ListView early-return.
                // Layman: highlight on Type Search… / recent is already “valid”; don’t snap back to Back.
                // Was: listReachBrowse VISIBLE + empty selection returned false → every wheel reseeded Back→TypeSearch.
                // Tech: leftover VISIBLE listReachBrowse short-circuited before layoutBrowserMode check.
                // Reversal: restore list-first branches (breaks Get Music when listReachBrowse stays visible).
                if (focused != null && containerBrowserItems != null
                        && isViewDescendantOf(focused, containerBrowserItems)) {
                    return true;
                }
                if (listConversationThread != null && listConversationThread.getVisibility() == View.VISIBLE) {
                    if (listConversationThread.hasFocus()) return true;
                    if (focused != null && isViewDescendantOf(focused, listConversationThread)) return true;
                    int sel = listConversationThread.getSelectedItemPosition();
                    return sel >= 0 && listConversationThread.getAdapter() != null
                            && sel < listConversationThread.getCount();
                }
                if (listReachBrowse != null && listReachBrowse.getVisibility() == View.VISIBLE) {
                    if (listReachBrowse.hasFocus()) return true;
                    if (focused != null && isViewDescendantOf(focused, listReachBrowse)) return true;
                    int sel = listReachBrowse.getSelectedItemPosition();
                    return sel >= 0 && listReachBrowse.getAdapter() != null
                            && sel < listReachBrowse.getCount();
                }
                // ponytail: recognise back button as valid focus on Soulseek/Reach screens
                if (btnConversationBack != null && focused == btnConversationBack) return true;
                // 2026-07-11 — Get Music / Reach search / action sheets use browser ScrollView.
                // Was: return false → every wheel tick reseeded to first row (unreachable results).
                // Reversal: drop layoutBrowserMode check if search moves to listReachBrowse only.
                if (layoutBrowserMode != null && layoutBrowserMode.getVisibility() == View.VISIBLE
                        && focused != null && isViewDescendantOf(focused, layoutBrowserMode)) {
                    return true;
                }
                return false;
            case STATE_WIFI:
                if (focused != null && focused.isShown() && focused.isFocusable()) {
                    if (btnScanWifi != null && focused == btnScanWifi) return true;
                    if (containerWifiItems != null && isViewDescendantOf(focused, containerWifiItems)) return true;
                }
                return false;
            case STATE_BLUETOOTH:
                if (focused != null && focused.isShown() && focused.isFocusable()) {
                    if (btnScanBt != null && focused == btnScanBt) return true;
                    if (containerBtItems != null && isViewDescendantOf(focused, containerBtItems)) return true;
                }
                return false;
            case STATE_PLAYER:
                if (focused != null && focused.isShown() && focused.isFocusable()) {
                    if (playerProgressTrack != null && focused == playerProgressTrack) return true;
                    if (layoutPlayerMode != null && focused == layoutPlayerMode) return true;
                }
                return false;
            default:
                if (MediaSuiteHost.isMediaListBrowseState(currentScreenState)) {
                    if (layoutBrowserMode == null || layoutBrowserMode.getVisibility() != View.VISIBLE) {
                        return false;
                    }
                    if (listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE) {
                        if (listVirtualSongs.hasFocus()) return true;
                        if (focused != null && isViewDescendantOf(focused, listVirtualSongs)) return true;
                        int sel = listVirtualSongs.getSelectedItemPosition();
                        return sel >= 0 && listVirtualSongs.getAdapter() != null
                                && sel < listVirtualSongs.getCount();
                    }
                    return isViewDescendantOf(focused, layoutBrowserMode);
                }
                return true;
        }
    }

    private void scrollBrowserRowIntoView(View row, ViewGroup parent) {
        if (row == null || parent != containerBrowserItems || scrollViewBrowser == null) return;
        if (scrollViewBrowser instanceof android.widget.ScrollView) {
            FocusScrollHelper.ensureChildVisible((android.widget.ScrollView) scrollViewBrowser, row);
        }
    }

    /**
     * 2026-07-14 — True for Get Music / Deezer / Soulseek / browse ScrollView menus (not virtual ListView).
     * Layman: screens that paint rows in the browser scroll strip, not the fast song list.
     * Tech: containerBrowserItems + scrollViewBrowser; excludes STATE_SETTINGS Reach ListView.
     * Reversal: inline the state list at call sites again.
     */
    private boolean isBrowserScrollMenuScreen() {
        if (listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE) {
            return false;
        }
        return currentScreenState == STATE_BROWSER
                || currentScreenState == STATE_PODCASTS
                || currentScreenState == STATE_SOULSEEK
                || currentScreenState == STATE_DEEZER
                || currentScreenState == STATE_APPS
                || currentScreenState == STATE_MORE
                || currentScreenState == STATE_NAVIDROME
                || currentScreenState == STATE_PLEX
                || currentScreenState == STATE_JELLYFIN
                || MediaSuiteHost.isMediaListBrowseState(currentScreenState);
    }

    /**
     * 2026-07-14 — Wheel/DPAD before View hierarchy eats keys (same idea as Reach ListView).
     * Layman: dial / face L-R move the blue highlight on Get Music before Android steals the press.
     * Was: only Reach settings had pre-super intercept → DPAD never reached onKeyDown browse walk.
     * Now: containerBrowserItems index walk (descendant-aware) owns the key.
     * Reversal: drop call from dispatchKeyEvent; rely on onKeyDown after super again.
     */
    private boolean handleBrowserScrollWheelKeyDown(int keyCode, KeyEvent event) {
        if (event == null || event.getAction() != KeyEvent.ACTION_DOWN) return false;
        if (!Y1InputKeys.isWheelKey(keyCode)) return false;
        if (!isBrowserScrollMenuScreen()) return false;
        if (isThemeListActive()) return false;
        if (currentScreenState == STATE_BROWSER && isPlaylistMoveActive()) return false;
        // 2026-07-14 — If highlight is already on a browse row, never reseed to Back.
        // Layman: scrolling past Type Search… must not jump back to the top each click.
        // Tech: listReachBrowse / listVirtualSongs early “invalid” used to force ensure→child0.
        View focNow = getCurrentFocus();
        boolean inBrowseRows = focNow != null && containerBrowserItems != null
                && isViewDescendantOf(focNow, containerBrowserItems);
        boolean focusValidBefore = inBrowseRows || isFocusValidForCurrentScreen();
        if (!focusValidBefore) ensureBrowserListFocus();
        // 2026-07-19 — Coalesce browser ScrollView wheel like home/settings (≥80 ms paint floor).
        boolean moved = applyWheelAccelFocus(keyCode, event, new WheelFocusMover() {
            @Override
            public boolean move(int delta) {
                return moveBrowserScrollFocus(delta);
            }
        }, true);
        // #region agent log
        if (event.getRepeatCount() == 0) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("runId", "post-fix");
                d.put("keyCode", keyCode);
                d.put("delta", Y1InputKeys.isWheelUp(keyCode) ? -1 : 1);
                d.put("moved", moved);
                d.put("screen", currentScreenState);
                d.put("soulseekUi", soulseekUiMode);
                d.put("getMusic", getMusicFromEntryPoint);
                d.put("focusValidBefore", focusValidBefore);
                d.put("inBrowseRows", inBrowseRows);
                // Activity has no isInTouchMode — ask decor / focused view.
                View decor = getWindow() != null ? getWindow().getDecorView() : null;
                d.put("touchMode", decor != null && decor.isInTouchMode());
                d.put("children", containerBrowserItems != null
                        ? containerBrowserItems.getChildCount() : -1);
                // H-EMPTY / H-TOUCH: dump focusable siblings so we know if Type Search has nowhere to go.
                StringBuilder kids = new StringBuilder();
                if (containerBrowserItems != null) {
                    int n = Math.min(containerBrowserItems.getChildCount(), 8);
                    for (int i = 0; i < n; i++) {
                        View c = containerBrowserItems.getChildAt(i);
                        if (c == null) continue;
                        if (i > 0) kids.append('|');
                        kids.append(i).append(':')
                                .append(c.getClass().getSimpleName())
                                .append(c.isFocusable() ? 'F' : '-')
                                .append(c.isFocusableInTouchMode() ? 'T' : '-')
                                .append(c.isEnabled() ? 'E' : 'x');
                        if (c instanceof android.widget.TextView) {
                            CharSequence t = ((android.widget.TextView) c).getText();
                            if (t != null && t.length() > 0) {
                                String s = String.valueOf(t);
                                if (s.length() > 24) s = s.substring(0, 24);
                                kids.append('{').append(s).append('}');
                            }
                        }
                    }
                }
                d.put("kids", kids.toString());
                View foc = getCurrentFocus();
                d.put("focusText", foc instanceof android.widget.TextView
                        ? String.valueOf(((android.widget.TextView) foc).getText()) : "");
                d.put("focusClass", foc != null ? foc.getClass().getSimpleName() : "null");
                d.put("focusFitm", foc != null && foc.isFocusableInTouchMode());
                DebugF0e28cLog.log(this, "MainActivity.handleBrowserScrollWheelKeyDown",
                        "browse pre-super wheel", "H-C,H-E,H-TOUCH,H-EMPTY", d);
                // Session 701426 — correlate wheel move with live-refresh focus loss.
                Debug701426Log.log(this, "MainActivity.handleBrowserScrollWheelKeyDown",
                        "wheel on browse results", "D", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        if (moved) clickFeedback();
        // Always consume: otherwise DPAD UP/DOWN is swallowed by ScrollView with no highlight move.
        return true;
    }

    /**
     * 2026-07-14 — Move highlight among {@link #containerBrowserItems} like settings lists.
     * Layman: jump to the next real menu line, skipping section titles; nested row insides stick together.
     * Tech: resolve focused descendant → row index → next focusable sibling (not focusSearch).
     * Was: only walked immediate parent LinearLayout children — nested Get Music rows trapped focus.
     * Reversal: restore parent.indexOfChild(getCurrentFocus()) sibling walk in onKeyDown.
     */
    private boolean moveBrowserScrollFocus(int delta) {
        if (containerBrowserItems == null || delta == 0) return false;
        View focused = getCurrentFocus();
        int currentIdx = -1;
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View row = containerBrowserItems.getChildAt(i);
            if (row == focused || isViewDescendantOf(focused, row)) {
                currentIdx = i;
                break;
            }
        }
        if (currentIdx < 0) {
            for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
                View row = containerBrowserItems.getChildAt(i);
                if (row == null || row.getVisibility() != View.VISIBLE || !row.isEnabled()
                        || !row.isFocusable()) {
                    continue;
                }
                if (row.requestFocus()) {
                    scrollBrowserRowIntoView(row, containerBrowserItems);
                    return true;
                }
            }
            return false;
        }
        int step = delta < 0 ? -1 : 1;
        for (int i = currentIdx + step; i >= 0 && i < containerBrowserItems.getChildCount();
                i += step) {
            View next = containerBrowserItems.getChildAt(i);
            if (next == null || next.getVisibility() != View.VISIBLE || !next.isEnabled()
                    || !next.isFocusable()) {
                continue;
            }
            boolean got = next.requestFocus();
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("runId", "pre-fix");
                d.put("from", currentIdx);
                d.put("to", i);
                d.put("delta", delta);
                d.put("gotFocus", got);
                d.put("touchMode", next.isInTouchMode());
                d.put("nextClass", next.getClass().getSimpleName());
                d.put("nextFocusable", next.isFocusable());
                d.put("nextFitm", next.isFocusableInTouchMode());
                d.put("nextEnabled", next.isEnabled());
                d.put("nextBlockDesc", next instanceof ViewGroup
                        ? ((ViewGroup) next).getDescendantFocusability() : -1);
                CharSequence label = null;
                if (next instanceof android.widget.TextView) {
                    label = ((android.widget.TextView) next).getText();
                } else if (next instanceof ViewGroup && ((ViewGroup) next).getChildCount() > 0
                        && ((ViewGroup) next).getChildAt(0) instanceof android.widget.TextView) {
                    label = ((android.widget.TextView) ((ViewGroup) next).getChildAt(0)).getText();
                }
                d.put("nextLabel", label != null ? String.valueOf(label) : "");
                View after = getCurrentFocus();
                d.put("afterText", after instanceof android.widget.TextView
                        ? String.valueOf(((android.widget.TextView) after).getText()) : "");
                DebugF0e28cLog.log(this, "MainActivity.moveBrowserScrollFocus",
                        "try focus next row", "H-NEST,H-TOUCH", d);
            } catch (Exception ignored) {}
            // #endregion
            if (!got) continue;
            scrollBrowserRowIntoView(next, containerBrowserItems);
            return true;
        }
        if (scrollViewBrowser instanceof android.widget.ScrollView) {
            Y1ScrollIndicators.edgeGlowAtLimit((android.widget.ScrollView) scrollViewBrowser, delta);
        }
        return false;
    }

    private void ensureBrowserListFocus() {
        if (listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE
                && listVirtualSongs.getAdapter() != null && listVirtualSongs.getCount() > 0) {
            int pos = virtualSongListPosition();
            if (pos < 0) pos = listVirtualSongs.getSelectedItemPosition();
            if (pos < 0) pos = 0;
            if (pos >= listVirtualSongs.getCount()) pos = listVirtualSongs.getCount() - 1;
            final int target = pos;
            FocusScrollHelper.ensureListPositionVisible(listVirtualSongs, target);
            listVirtualSongs.requestFocus();
            listVirtualSongs.post(new Runnable() {
                @Override
                public void run() {
                    if (listVirtualSongs == null) return;
                    int childIdx = target - listVirtualSongs.getFirstVisiblePosition();
                    if (childIdx >= 0 && childIdx < listVirtualSongs.getChildCount()) {
                        View v = listVirtualSongs.getChildAt(childIdx);
                        if (v != null && v.isFocusable()) v.requestFocus();
                    }
                }
            });
            return;
        }
        if (containerBrowserItems == null) return;
        // #region agent log
        View focBeforeEnsure = getCurrentFocus();
        // #endregion
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View row = containerBrowserItems.getChildAt(i);
            if (row != null && row.getVisibility() == View.VISIBLE && row.isFocusable() && row.isEnabled()) {
                row.requestFocus();
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("runId", "pre-fix");
                    d.put("reseedIdx", i);
                    d.put("children", containerBrowserItems.getChildCount());
                    d.put("beforeText", focBeforeEnsure instanceof android.widget.TextView
                            ? String.valueOf(((android.widget.TextView) focBeforeEnsure).getText()) : "");
                    d.put("beforeTag", focBeforeEnsure != null && focBeforeEnsure.getTag() != null
                            ? focBeforeEnsure.getTag().getClass().getSimpleName() : "null");
                    d.put("afterText", row instanceof android.widget.TextView
                            ? String.valueOf(((android.widget.TextView) row).getText()) : "");
                    d.put("afterTag", row.getTag() != null
                            ? row.getTag().getClass().getSimpleName() : "null");
                    d.put("getMusic", getMusicFromEntryPoint);
                    d.put("soulseekUi", soulseekUiMode);
                    d.put("searching", getMusicSearchInProgress || soulseekSearchInProgress);
                    Debug701426Log.log(this, "MainActivity.ensureBrowserListFocus",
                            "reseeded browse focus to first focusable", "D", d);
                } catch (Exception ignored) {}
                // #endregion
                return;
            }
        }
    }

    private void ensureSoulseekListFocus() {
        if (listConversationThread != null && listConversationThread.getVisibility() == View.VISIBLE
                && listConversationThread.getAdapter() != null && listConversationThread.getCount() > 0) {
            int pos = listConversationThread.getSelectedItemPosition();
            if (pos < 0) pos = 0;
            if (pos >= listConversationThread.getCount()) pos = listConversationThread.getCount() - 1;
            final int target = pos;
            FocusScrollHelper.ensureListPositionVisible(listConversationThread, target);
            listConversationThread.requestFocus();
            listConversationThread.post(new Runnable() {
                @Override
                public void run() {
                    if (listConversationThread == null) return;
                    int childIdx = target - listConversationThread.getFirstVisiblePosition();
                    if (childIdx >= 0 && childIdx < listConversationThread.getChildCount()) {
                        View v = listConversationThread.getChildAt(childIdx);
                        if (v != null && v.isFocusable()) v.requestFocus();
                    }
                }
            });
            return;
        }
        if (listReachBrowse != null && listReachBrowse.getVisibility() == View.VISIBLE
                && listReachBrowse.getAdapter() != null && listReachBrowse.getCount() > 0) {
            int pos = listReachBrowse.getSelectedItemPosition();
            if (pos < 0) pos = 0;
            if (pos >= listReachBrowse.getCount()) pos = listReachBrowse.getCount() - 1;
            final int target = pos;
            FocusScrollHelper.ensureListPositionVisible(listReachBrowse, target);
            listReachBrowse.requestFocus();
            listReachBrowse.post(new Runnable() {
                @Override
                public void run() {
                    if (listReachBrowse == null) return;
                    int childIdx = target - listReachBrowse.getFirstVisiblePosition();
                    if (childIdx >= 0 && childIdx < listReachBrowse.getChildCount()) {
                        View v = listReachBrowse.getChildAt(childIdx);
                        if (v != null && v.isFocusable()) v.requestFocus();
                    }
                }
            });
            return;
        }
        // 2026-07-11 — Get Music / Reach search ScrollView: same as browser states.
        // Was: no fallthrough → dismiss left focus nowhere / first-row trap.
        ensureBrowserListFocus();
    }

    private void restoreFocusAfterContextMenuDismiss() {
        new Handler().post(new Runnable() {
            @Override
            public void run() {
                if (contextMenuNavPending) {
                    contextMenuNavPending = false;
                    return;
                }
                if (isFocusValidForCurrentScreen()) return;
                switch (currentScreenState) {
                    case STATE_MENU:
                        requestFirstHomeMenuFocus();
                        break;
                    case STATE_SETTINGS:
                        if (containerSettingsItems != null && containerSettingsItems.getChildCount() > 0) {
                            containerSettingsItems.getChildAt(0).requestFocus();
                        }
                        break;
                    case STATE_BROWSER:
                    case STATE_PODCASTS:
                    case STATE_APPS:
                    case STATE_MORE:
                    case STATE_USB_STORAGE:
                        ensureBrowserListFocus();
                        break;
                    case STATE_SOULSEEK:
                        ensureSoulseekListFocus();
                        break;
                    case STATE_WIFI:
                        if (containerWifiItems != null && containerWifiItems.getChildCount() > 0) {
                            containerWifiItems.getChildAt(0).requestFocus();
                        } else if (btnScanWifi != null) {
                            btnScanWifi.requestFocus();
                        }
                        break;
                    case STATE_BLUETOOTH:
                        if (containerBtItems != null && containerBtItems.getChildCount() > 0) {
                            containerBtItems.getChildAt(0).requestFocus();
                        } else if (btnScanBt != null) {
                            btnScanBt.requestFocus();
                        }
                        break;
                    case STATE_PLAYER:
                        if (playerProgressTrack != null) {
                            playerProgressTrack.requestFocus();
                        } else if (layoutPlayerMode != null) {
                            layoutPlayerMode.requestFocus();
                        }
                        break;
                    default:
                        if (MediaSuiteHost.isMediaListBrowseState(currentScreenState)) {
                            ensureBrowserListFocus();
                        }
                        break;
                }
            }
        });
    }

    private ThemedContextMenu.QuickItem[] buildContextQuickBar() {
        boolean hasQueue = contextQuickBarShowsQueue();
        int queueSize = hasQueue ? playback.unifiedQueue().size() : 0;
        // 2026-07-06 — FM: 1 station → Now Playing chip; 2+ → Queue chip with station list.
        boolean fmActive = playback.isFmActive();
        boolean singleTrack =
                (fmActive && queueSize <= 1) || (!fmActive && hasQueue && queueSize == 1);
        int endIcon = !hasQueue ? R.drawable.ic_music
                : (singleTrack ? R.drawable.ic_music : R.drawable.ic_queue);
        String endLabel = !hasQueue ? getString(R.string.home_menu_music)
                : (singleTrack ? getString(R.string.home_menu_now_playing)
                : getString(R.string.context_quick_queue));
        // #region agent log
        try {
            JSONObject d = new JSONObject();
            d.put("hasQueue", hasQueue);
            d.put("queueSize", queueSize);
            d.put("singleTrack", singleTrack);
            d.put("endLabel", endLabel);
            QueueDebugLog.log("MainActivity.buildContextQuickBar", "quick bar built", "H6", d);
        } catch (Exception ignored) {}
        // #endregion
        // 2026-07-18 — Quick-bar volume chip uses 0–100 display; ear at Hearing Safety cap.
        int volMax = MediaVolumeControl.getDisplayMaxVolume(this);
        int volCur = MediaVolumeControl.getDisplayVolume(this, AudioManager.STREAM_MUSIC);
        boolean volEar = HearingSafetyVolume.shouldShowEarAtDisplayMax(this) && volCur >= volMax;
        int volIcon = volEar ? R.drawable.ic_headphone
                : ThemedContextMenu.volumeIconResForLevel(volCur, volMax);
        int brightIcon = ThemedContextMenu.brightnessIconResForLevel(currentSystemBrightness, 255);
        boolean rooted = DeviceFeatures.hasRootAccess();
        // 2026-07-14 — A5 has no dedicated hard volume; show vol/sleep chips like Y1.
        // Was: isY1() only (A5 chips vanished). Now: showsOverlayVolumeLockChips().
        // Reversal: boolean y1 = DeviceFeatures.isY1();
        boolean showVolSleep = DeviceFeatures.showsOverlayVolumeLockChips();
        // 2026-07-15 — Sleep/Zzz rightmost after Volume (was Lock at index 1).
        return new ThemedContextMenu.QuickItem[] {
            new ThemedContextMenu.QuickItem(null, R.drawable.ic_home, getString(R.string.context_go_to_home), true),
            new ThemedContextMenu.QuickItem(null, R.drawable.ic_wifi, getString(R.string.context_tier_wifi), true),
            new ThemedContextMenu.QuickItem(null, R.drawable.ic_bluetooth, getString(R.string.home_menu_bluetooth), true),
            new ThemedContextMenu.QuickItem(null, R.drawable.ic_power, getString(R.string.context_quick_power), rooted),
            new ThemedContextMenu.QuickItem(null, endIcon, endLabel, true),
            new ThemedContextMenu.QuickItem(null, brightIcon, getString(R.string.context_quick_brightness), true),
            new ThemedContextMenu.QuickItem(null, volIcon, getString(R.string.context_quick_volume), showVolSleep),
            new ThemedContextMenu.QuickItem(null, R.drawable.ic_zzz, getString(R.string.context_action_sleep), showVolSleep)
        };
    }

