    // --- Inactivity auto-shutdown ---

    /**
     * Reset the inactivity timer — call on any user interaction.
     * 2026-07-15 — Also drives {@link InputPriorityGate} (background work waits 3s idle).
     */
    private void resetInactivityTimer() {
        lastUserInteractionMs = System.currentTimeMillis();
    }

    /** True while keys/touch are active (within {@link InputPriorityGate#IDLE_MS}). */
    private boolean isInputPriorityBusy() {
        return InputPriorityGate.shouldDefer(System.currentTimeMillis(), lastUserInteractionMs);
    }

    /** Ms until background work may run (0 = now). */
    private long msUntilInputIdle() {
        return InputPriorityGate.msUntilAllowed(System.currentTimeMillis(), lastUserInteractionMs);
    }

    /**
     * 2026-07-15 — Post work only after input has been idle; re-check when fired.
     * Layman: heavy jobs wait until you stop touching the player for 3 seconds.
     * Use for optional UI rebuilds / scans — never for PM popups or key handling.
     */
    private void postWhenInputIdle(final Handler handler, final Runnable work) {
        if (handler == null || work == null) return;
        final Runnable gate = new Runnable() {
            @Override
            public void run() {
                long wait = msUntilInputIdle();
                if (wait > 0L) {
                    handler.postDelayed(this, wait);
                    return;
                }
                work.run();
            }
        };
        long wait = msUntilInputIdle();
        if (wait > 0L) {
            handler.postDelayed(gate, wait);
        } else {
            handler.post(gate);
        }
    }

    /** Start the periodic inactivity check loop. */
    private void startInactivityMonitor() {
        inactivityHandler.removeCallbacks(inactivityCheckRunnable);
        resetInactivityTimer();
        inactivityHandler.postDelayed(inactivityCheckRunnable, INACTIVITY_CHECK_INTERVAL_MS);
    }

    /** Stop the inactivity monitor (e.g. on destroy). */
    private void stopInactivityMonitor() {
        inactivityHandler.removeCallbacks(inactivityCheckRunnable);
    }

    /**
     * Called every 60 seconds. If the device has been idle for 30 minutes
     * and no media is playing, disable Wi-Fi and power off.
     */
    private void checkInactivityShutdown() {
        int minutes = inactivityShutdownMinutes();
        if (minutes <= 0) return;

        // Don't shut down if media is playing
        boolean playing = false;
        try { playing = mediaPlayer != null && mediaPlayer.isPlaying(); } catch (Exception ignored) {}
        if (playing) {
            // Media is playing — reset timer so shutdown won't happen immediately after playback stops
            resetInactivityTimer();
            return;
        }

        // Don't shut down if USB storage mode is active
        if (currentScreenState == STATE_USB_STORAGE) return;

        long idleMs = System.currentTimeMillis() - lastUserInteractionMs;
        if (idleMs >= InactivityShutdownConfig.shutdownDelayMs(minutes)) {
            performInactivityShutdown();
        }
    }

    private void migrateInactivityShutdownPrefs() {
        if (prefs == null) return;
        if (prefs.contains(InactivityShutdownConfig.PREF_MINUTES)) {
            int min = prefs.getInt(InactivityShutdownConfig.PREF_MINUTES,
                    InactivityShutdownConfig.defaultMinutes());
            inactivityShutdownIndex = InactivityShutdownConfig.indexForMinutes(min);
            return;
        }
        if (!prefs.getBoolean(InactivityShutdownConfig.LEGACY_PREF_ENABLED, true)) {
            inactivityShutdownIndex = 0;
            prefs.edit().putInt(InactivityShutdownConfig.PREF_MINUTES, 0).commit();
        } else {
            inactivityShutdownIndex = InactivityShutdownConfig.indexForMinutes(
                    InactivityShutdownConfig.defaultMinutes());
            prefs.edit().putInt(InactivityShutdownConfig.PREF_MINUTES,
                    InactivityShutdownConfig.defaultMinutes()).commit();
        }
    }

    private int inactivityShutdownMinutes() {
        return InactivityShutdownConfig.minutesAtIndex(inactivityShutdownIndex);
    }

    private String inactivityShutdownStateText() {
        int minutes = inactivityShutdownMinutes();
        if (minutes <= 0) return getString(R.string.common_off);
        if (minutes >= 60 && minutes % 60 == 0) {
            return getString(R.string.common_timeout_min, minutes / 60);
        }
        return getString(R.string.common_timeout_min, minutes);
    }

    /** Disable Wi-Fi and power off the device. */
    private void performInactivityShutdown() {
        // Disable Wi-Fi first
        try {
            android.net.wifi.WifiManager wm =
                    (android.net.wifi.WifiManager) getSystemService(Context.WIFI_SERVICE);
            if (wm != null && wm.isWifiEnabled()) {
                wm.setWifiEnabled(false);
            }
        } catch (Exception ignored) {}

        // Brief delay then power off
        inactivityHandler.postDelayed(new Runnable() {
            @Override
            public void run() {
                performDeviceShutdown();
            }
        }, 1000);
    }

    /** Power quick chip — shut down or switch to Rockbox without leaving the context modal first. */
