    /** 2026-07-06 — Arm static handoff so MediaBtnReceiver works after MainActivity LMK. */
    void beginExternalInputHandoff() {
        beginExternalInputHandoff(null);
    }

    /**
     * 2026-07-06 — Resolve MODE_JJ / MODE_FM / MODE_ANDROID from target package when known.
     * Layman: pick the right key translation table before leaving Solar.
     * Technical: defaults to MODE_ANDROID when target is null or Solar/Rockbox.
     */
    void beginExternalInputHandoff(String targetPackage) {
        int mode = ExternalInputHandoff.MODE_ANDROID;
        if (targetPackage != null && targetPackage.length() > 0) {
            int resolved = ExternalInputHandoff.resolveModeForForegroundPackage(targetPackage);
            if (resolved != ExternalInputHandoff.MODE_OFF) {
                mode = resolved;
            }
        }
        ExternalInputHandoff.setDpadMode(mode);
        ExternalInputHandoff.armFastInjector(this);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("mode", ExternalInputHandoff.getDpadMode());
            d.put("screen", currentScreenState);
            DebugSessionLog.log("MainActivity.beginExternalInputHandoff",
                    "external input handoff enabled", "H-DPAD", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    /** 2026-07-06 — Solar HOME focus — clear static handoff (single writer in ExternalInputHandoff). */
    private void endExternalInputHandoff() {
        if (ExternalInputHandoff.getDpadMode() == ExternalInputHandoff.MODE_OFF) return;
        ExternalInputHandoff.forceDisarmForSolarFocus();
        // #region agent log
        try {
            DebugSessionLog.log("MainActivity.endExternalInputHandoff",
                    "external input handoff disabled", "H-DPAD", null);
        } catch (Exception ignored) {}
        // #endregion
    }

    private boolean shouldRouteExternalInputHandoff() {
        return ExternalInputHandoff.getDpadMode() != ExternalInputHandoff.MODE_OFF
                && !hasWindowFocus()
                && isScreenInteractive();
    }

    boolean handleExternalInputHandoffMediaButton(Context context, KeyEvent event) {
        if (event == null || !shouldRouteExternalInputHandoff()) return false;
        int keyCode = event.getKeyCode();
        if (!ExternalInputHandoff.isMediaNavigationKey(keyCode)) return false;
        int dpadCode = ExternalInputHandoff.mediaToDpad(
                keyCode, event.getRepeatCount(), ExternalInputHandoff.getDpadMode());
        if (dpadCode <= 0) return false;
        if (event.getAction() == KeyEvent.ACTION_UP) {
            ExternalInputHandoff.injectClick(context != null ? context : this, dpadCode);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("mediaCode", keyCode);
                d.put("dpadCode", dpadCode);
                d.put("repeat", event.getRepeatCount());
                DebugSessionLog.log("MainActivity.handleExternalInputHandoffMediaButton",
                        "injected dpad", "H-DPAD", d);
            } catch (Exception ignored) {}
            // #endregion
        }
        return true;
    }

    /** User declined USB storage — stop in-app intercept; recovery agent re-homes if SystemUI sticks. */
    private boolean isUsbLockContextMenuActive() {
        return isUsbMassStorageUiLocked() && themedContextMenu != null && themedContextMenu.isShowing();
    }

    private void syncUsbReclaimForContextMenu(boolean menuOpen) {
        if (usbFocusHelper == null) return;
        // Suspend HOME/suppressor while USB enable prompt or mass-storage lock menu is up.
        boolean usbContextMenu = isUsbMassStorageUiLocked()
                || isUsbEnablePromptTierActive() || usbEnablePromptSession;
        if (!usbContextMenu) return;
        usbFocusHelper.setReclaimSuspended(menuOpen);
    }

    private boolean isUsbEnablePromptTierActive() {
        return contextMenuTierStack.contains("usb_storage") && !isUsbMassStorageActive();
    }

    private boolean isUsbEnablePromptShowing() {
        return themedContextMenu != null && themedContextMenu.isShowing() && isUsbEnablePromptTierActive();
    }

    /**
     * 2026-07-16 — Block USB enable UI only while setup/library faces are actively covering home.
     * Layman: no USB Connection sheet over “Getting things ready…” or a mid-scan library.
     * Tech: first-ready / lib-scan overlay owners; not permanent prep/rockbox flags.
     */
    private boolean isHeavyWorkBlockingUsbPrompt() {
        if (firstReadyOverlayActive) return true;
        if ((blockingOverlayOwners & OVERLAY_FIRST_READY) != 0) return true;
        if (libraryScanRunning) return true;
        // Full-screen loading only when it is the first-ready or lib-scan owner (not brief toasts).
        if (layoutLoadingOverlay != null
                && layoutLoadingOverlay.getVisibility() == View.VISIBLE
                && (blockingOverlayOwners & (OVERLAY_FIRST_READY | OVERLAY_LIB_SCAN)) != 0) {
            return true;
        }
        return false;
    }

    /**
     * 2026-07-16 — Once home list is painted without first-ready face, mark UI ready so USB
     * receivers that check {@link FirstSessionReadyGate#isHomeReadyForUsbPrompt} can proceed.
     */
    private void ensureUiReadyForUsbIfHomeVisible() {
        if (FirstSessionReadyGate.isUiReadyComplete(this)) return;
        if (firstReadyOverlayActive) return;
        if (currentScreenState != STATE_MENU) return;
        if (layoutMainMenu == null || layoutMainMenu.getVisibility() != View.VISIBLE) return;
        if (homeMenuEntries == null || homeMenuEntries.isEmpty()) return;
        FirstSessionReadyGate.markUiReadyComplete(this);
    }

    /** Package-visible: receiver asks whether enable UI must wait (active setup face only). */
    boolean shouldDeferUsbConnectPromptNow() {
        return isHeavyWorkBlockingUsbPrompt();
    }

    private void deferUsbConnectPrompt() {
        usbConnectPendingAfterLibraryScan = true;
    }

    /**
     * Package-visible for {@link UsbStorageOverlayReceiver} while setup/library still running.
     * Layman: remember the cable so we can ask after home is ready — without locking the session.
     */
    void deferUsbConnectPromptForSetup() {
        if (usbDialogDismissedThisConnection || usbMassStorageLocked) return;
        if (UsbHostSessionPolicy.hasUserDismissedThisSession(this)) return;
        deferUsbConnectPrompt();
    }

    /** Show USB enable prompt after library/overlay work finishes (if still connected). */
    private void flushDeferredUsbConnectPromptIfNeeded() {
        ensureUiReadyForUsbIfHomeVisible();
        if (!usbConnectPendingAfterLibraryScan) return;
        if (isHeavyWorkBlockingUsbPrompt()) return;
        if (usbDialogDismissedThisConnection || usbMassStorageLocked) {
            usbConnectPendingAfterLibraryScan = false;
            return;
        }
        if (UsbHostSessionPolicy.hasUserDismissedThisSession(this)) {
            usbConnectPendingAfterLibraryScan = false;
            return;
        }
        usbConnectPendingAfterLibraryScan = false;
        // 2026-07-16 — Deferred during setup: session may still be unevaluated; force one eval.
        // Was: routeUsbHostInterceptUi early-out when hasPromptEvaluatedThisSession from stale mark.
        if (UsbHostSessionPolicy.hasPromptEvaluatedThisSession(this)
                && !usbDialogShownThisConnection
                && !isUsbEnablePromptShowing()) {
            // Stale evaluated without paint — clear process-local flags only by re-routing show.
            usbDialogShownThisConnection = false;
        }
        // Prefer direct show when host is still connected (one clear path).
        if (usbFocusHelper != null && usbFocusHelper.isHostConnected()
                && !isUsbAutoConnectEnabled()
                && shouldOfferUsbConnectPrompt()) {
            showUsbMassStorageDialog();
            return;
        }
        routeUsbHostInterceptUi(true);
    }

    /** Enable dialog vs mass-storage lock screen — one evaluation per host connect event (2026-07-06). */
    private void routeUsbHostInterceptUi(final boolean fromConnectEvent) {
        ensureUiReadyForUsbIfHomeVisible();
        // 2026-07-14 — Idle BEFORE any getprop/sysfs snapshot (Y1 GC_FOR_ALLOC while prompt up).
        // Was: usbSnapshot + debug I/O ran on every USB_STATE before early returns.
        // 2026-07-16 — If session was marked evaluated but UI never painted, allow one more show.
        if (fromConnectEvent
                && UsbHostSessionPolicy.hasPromptEvaluatedThisSession(this)
                && !usbDialogShownThisConnection
                && !usbDialogDismissedThisConnection
                && !isUsbEnablePromptShowing()
                && !UsbHostSessionPolicy.hasUserDismissedThisSession(this)) {
            // Fall through to ensure path — do not idle-skip.
        } else if (usbEnablePromptSession || isUsbEnablePromptShowing()
                || usbDialogShownThisConnection || usbDialogDismissedThisConnection
                || UsbHostSessionPolicy.hasUserDismissedThisSession(this)
                || UsbHostSessionPolicy.hasPromptEvaluatedThisSession(this)) {
            if (fromConnectEvent && !isUsbMassStorageActive()) {
                // #region agent log
                try {
                    org.json.JSONObject d2 = new org.json.JSONObject();
                    d2.put("fromConnectEvent", fromConnectEvent);
                    d2.put("usbDialogShown", usbDialogShownThisConnection);
                    d2.put("idleSkip", true);
                    Debug02fc83Log.log(MainActivity.this, "MainActivity.routeUsbHostInterceptUi",
                            "idle skip", "H6", d2);
                } catch (Exception ignored) {}
                // #endregion
                return;
            }
            if (!isUsbMassStorageActive()) {
                return;
            }
        }
        // #region agent log
        try {
            org.json.JSONObject d2 = new org.json.JSONObject();
            d2.put("fromConnectEvent", fromConnectEvent);
            d2.put("usbDialogShown", usbDialogShownThisConnection);
            d2.put("usbDialogDismissed", usbDialogDismissedThisConnection);
            d2.put("sessionEvaluated",
                    UsbHostSessionPolicy.hasPromptEvaluatedThisSession(MainActivity.this));
            d2.put("sessionDismissed",
                    UsbHostSessionPolicy.hasUserDismissedThisSession(MainActivity.this));
            d2.put("umsWatchdog", usbFocusHelper != null && usbFocusHelper.isUmsWatchdogActive());
            d2.put("enablePromptShowing", isUsbEnablePromptShowing());
            Debug02fc83Log.log(MainActivity.this, "MainActivity.routeUsbHostInterceptUi",
                    "entry", "H1,H4", d2);
            if (Debug705932Log.ENABLED) {
                org.json.JSONObject d = Debug705932Log.usbSnapshot();
                d.put("fromConnectEvent", fromConnectEvent);
                d.put("dismissed", usbDialogDismissedThisConnection);
                Debug705932Log.log("MainActivity.routeUsbHostInterceptUi", "entry", "H1,H4", d);
            }
        } catch (Exception ignored) {}
        // #endregion
        if (UsbHostSessionPolicy.hasUserDismissedThisSession(this)) {
            if (usbFocusHelper != null) {
                usbFocusHelper.setInterceptPaused(true);
            }
            return;
        }
        // 2026-07-06 — Resume/focus paths must not re-open enable prompt; connect event evaluates once.
        if (!fromConnectEvent && (usbFocusHelper == null
                || !usbFocusHelper.isMassStorageInterceptActive())) {
            return;
        }
        // 2026-07-16 — Allow connect path when evaluated was set without painting the sheet.
        boolean staleEvaluatedNoPaint = UsbHostSessionPolicy.hasPromptEvaluatedThisSession(this)
                && !usbDialogShownThisConnection
                && !usbDialogDismissedThisConnection
                && !isUsbEnablePromptShowing();
        if (fromConnectEvent && !UsbHostSessionPolicy.shouldEvaluatePromptThisSession(this)
                && !staleEvaluatedNoPaint
                && !isUsbMassStorageActive()) {
            return;
        }
        if (isHeavyWorkBlockingUsbPrompt()) {
            deferUsbConnectPrompt();
            return;
        }
        if (usbDialogDismissedThisConnection
                || (usbFocusHelper != null && usbFocusHelper.isUserDeclinedHostSession())) {
            if (usbFocusHelper != null) {
                usbFocusHelper.setInterceptPaused(true);
            }
            return;
        }
        if (isUsbEnablePromptShowing()) {
            return;
        }
        if (isUsbLockContextMenuActive()) {
            return;
        }
        // 2026-07-10 — Solar STATE_USB_STORAGE owns lock UI (July-2 monlith restore).
        // Was: companion chip modal race with MainActivity.
        if (isUsbMassStorageActive() || currentScreenState == STATE_USB_STORAGE) {
            if (UsbMassStorageController.isMassStorageExported()
                    || UsbMassStorageController.isKernelMassStorageMode()
                    || currentScreenState == STATE_USB_STORAGE
                    || usbMassStorageLocked) {
                enterUsbMassStorageLock();
            } else {
                clearStaleUsbMassStorageLockIfNeeded();
            }
            return;
        }
        if (!fromConnectEvent) {
            long now = System.currentTimeMillis();
            if (now - lastUsbRouteUiMs < USB_ROUTE_MIN_MS) {
                return;
            }
            lastUsbRouteUiMs = now;
        }
        if (fromConnectEvent) {
            lastUmsProbeMs = 0L;
        }
        refreshUsbMassStorageExportedAsync(new Runnable() {
            @Override
            public void run() {
                if (usbDialogDismissedThisConnection) {
                    if (usbFocusHelper != null) {
                        usbFocusHelper.setInterceptPaused(true);
                    }
                    return;
                }
                if (isUsbEnablePromptShowing()) {
                    return;
                }
                String branch;
                if (isUsbMassStorageActive()) {
                    branch = "enterLock";
                    enterUsbMassStorageLock();
                    if (usbFocusHelper != null) {
                        usbFocusHelper.setMassStorageInterceptActive(true);
                    }
                } else if (fromConnectEvent) {
                    branch = "ensureFromConnect";
                    ensureUsbHostInterceptUi(true);
                    if (usbFocusHelper != null) {
                        usbFocusHelper.setMassStorageInterceptActive(false);
                    }
                } else if (usbFocusHelper != null) {
                    branch = "ensureFocusIntercept";
                    usbFocusHelper.setMassStorageInterceptActive(false);
                    ensureUsbHostInterceptUi(false);
                } else {
                    branch = "noop";
                }
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("branch", branch);
                    d.put("fromConnectEvent", fromConnectEvent);
                    d.put("enablePromptShowing", isUsbEnablePromptShowing());
                    d.put("dismissed", usbDialogDismissedThisConnection);
                    d.put("umsActive", isUsbMassStorageActive());
                    d.put("screen", currentScreenState);
                    d.put("hasWindowFocus", hasWindowFocus());
                    DebugSessionLog.log("MainActivity.routeUsbHostInterceptUi", "asyncDone", "H3-H5", d);
                } catch (Exception ignored) {}
                // #endregion
            }
        });
    }

    /**
     * True while user is in USB storage mode (July-2 sticky flags + real LUN export).
     * Layman: after Turn on, stays "active" until cable unplug even while kernel is still binding.
     * 2026-07-16 — Also treat armed user session as active so host eject cannot unlock menus early.
     */
    private boolean isUsbMassStorageActive() {
        if (usbMassStorageLocked || currentScreenState == STATE_USB_STORAGE) return true;
        if (UsbMassStorageController.isUserSessionActive()) return true;
        // Prefer async cache for navigation hot path; live probe only when cache says maybe-on.
        if (cachedUmsExported) return true;
        // TTL-cached kernel/LUN probe (750ms) — safe after UMS unplug storm.
        return UsbMassStorageController.isMassStorageExported();
    }

    /** Solar USB storage lock UI — block navigation while eject screen / UMS active. */
    private boolean isUsbMassStorageUiLocked() {
        return isUsbMassStorageActive();
    }

    /**
     * 2026-07-18 — Drop eject-screen / lock flags so menus work again.
     * Layman: leave the "USB storage is on" wall when the cable or charge is gone.
     * Tech: same session flag clear as confirmed USB_STATE disconnect.
     * Reversal: inline these clears only in {@code onUsbStateChanged(false)}.
     */
    private void clearUsbStorageUsageBlocks(String reason) {
        usbDisconnectAtMs = System.currentTimeMillis();
        usbDialogShownThisConnection = false;
        usbDialogDismissedThisConnection = false;
        usbConnectPendingAfterLibraryScan = false;
        usbEnablePromptSession = false;
        usbMassStorageLocked = false;
        cachedUmsExported = false;
        lastUmsProbeMs = 0L;
        settingsBrowseFullWidth = false;
        ThemeManager.setBlockSdcardThemeAssets(false);
        UsbMassStorageController.clearUserSession();
        int dest = usbReturnScreen;
        usbReturnScreen = STATE_MENU;
        if (usbFocusHelper != null) {
            usbFocusHelper.setMassStorageInterceptActive(false);
        }
        if (prefs != null) {
            prefs.edit().remove("usb_manual_disable").apply();
        }
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            dismissThemedContextMenu(false);
        }
        if (currentScreenState == STATE_USB_STORAGE) {
            applyScreenChange(dest);
        }
        if (usbFocusHelper != null) {
            usbFocusHelper.bringToFrontLightPublic();
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("reason", reason != null ? reason : "");
            d.put("destScreen", dest);
            d.put("currentScreen", currentScreenState);
            DebugSessionLog.log("MainActivity.clearUsbStorageUsageBlocks", "unlocked", "H4", d);
            Debug0f5debLog.log(this, "MainActivity.clearUsbStorageUsageBlocks",
                    "USB usage blocks cleared", "H1,H3,H4", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    /**
     * 2026-07-18 — Battery left charging/full: assume USB host cable is gone.
     * Layman: charge icon off → unlock disk-mode blocks even if USB_STATE was missed.
     * Tech: UI clear + session reset + {@link UsbMassStorageController#teardownAfterConfirmedUnplug}.
     * Reversal: no-op on charge-loss; rely only on USB_STATE disconnect.
     */
    private void onChargingLostClearUsbStorageBlocks() {
        boolean blocked = isUsbMassStorageUiLocked()
                || usbEnablePromptSession
                || UsbMassStorageController.isUserSessionActive()
                || UsbMassStorageController.isKernelMassStorageMode()
                || cachedUmsExported;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("blocked", blocked);
            d.put("uiLocked", isUsbMassStorageUiLocked());
            d.put("userSession", UsbMassStorageController.isUserSessionActive());
            d.put("kernelUms", UsbMassStorageController.isKernelMassStorageMode());
            Debug0f5debLog.log(this, "MainActivity.onChargingLostClearUsbStorageBlocks",
                    blocked ? "will clear USB blocks" : "no USB blocks — skip", "H1,H3", d);
        } catch (Exception ignored) {}
        // #endregion
        if (!blocked) return;
        UsbStorageOverlayReceiver.dismissGlobalOverlayIfActive(this);
        UsbStorageConcierge.clearOnUsbDisconnect();
        UsbHostSessionPolicy.onUsbHostDisconnected(getApplicationContext());
        clearUsbStorageUsageBlocks("charge_lost");
        final Context app = getApplicationContext();
        new Thread(new Runnable() {
            @Override
            public void run() {
                UsbMassStorageController.teardownAfterConfirmedUnplug(app);
            }
        }, "UsbChargeLostUmsOff").start();
    }

    private boolean isSystemUsbMassStorageExported() {
        return cachedUmsExported;
    }

    private void loadEqPresetsAsync() {
        eqPresetNames.add(getString(R.string.eq_normal_default));
        new Thread(new Runnable() {
            @Override
            public void run() {
                final java.util.ArrayList<String> names = new java.util.ArrayList<String>();
                try {
                    MediaPlayer dummyMp = new MediaPlayer();
                    Equalizer dummyEq = new Equalizer(0, dummyMp.getAudioSessionId());
                    short presets = dummyEq.getNumberOfPresets();
                    for (short i = 0; i < presets; i++) {
                        names.add(dummyEq.getPresetName(i));
                    }
                    dummyEq.release();
                    dummyMp.release();
                } catch (Exception e) {
                    names.clear();
                    names.add(getString(R.string.eq_normal_default));
                }
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (!names.isEmpty()) {
                            eqPresetNames.clear();
                            eqPresetNames.addAll(names);
                            if (currentEqPresetIndex >= eqPresetNames.size()) {
                                currentEqPresetIndex = 0;
                            }
                        }
                    }
                });
            }
        }, "EqPresets").start();
    }

    /** Force a fresh UMS probe (e.g. right after toggling mass storage). */
    private void refreshUsbMassStorageExportedAsyncForced(final Runnable after) {
        lastUmsProbeMs = 0L;
        refreshUsbMassStorageExportedAsync(after);
    }

    private void refreshUsbMassStorageExportedAsync(final Runnable after) {
        final long now = System.currentTimeMillis();
        if (now - lastUmsProbeMs < UMS_PROBE_MIN_MS) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("skipped", true);
                d.put("sinceLastMs", now - lastUmsProbeMs);
                DebugSessionLog.log("MainActivity.refreshUmsExported", "throttled", "H4", d);
            } catch (Exception ignored) {}
            // #endregion
            if (after != null) {
                runOnUiThread(after);
            }
            return;
        }
        lastUmsProbeMs = now;
        new Thread(new Runnable() {
            @Override
            public void run() {
                final boolean exported = querySystemUsbMassStorageExported();
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        cachedUmsExported = exported;
                        if (exported) {
                            ThemeManager.setBlockSdcardThemeAssets(true, MainActivity.this);
                        } else if (!usbMassStorageLocked) {
                            ThemeManager.setBlockSdcardThemeAssets(false);
                        }
                        // #region agent log
                        try {
                            org.json.JSONObject d = new org.json.JSONObject();
                            d.put("exported", exported);
                            d.put("locked", usbMassStorageLocked);
                            DebugSessionLog.log("MainActivity.refreshUmsExported", "cached", "H-UMS", d);
                        } catch (Exception ignored) {}
                        // #endregion
                        if (after != null) after.run();
                    }
                });
            }
        }).start();
    }

    /**
     * Replace SystemUI UsbStorageActivity with Solar's enable dialog or mass-storage lock screen.
     *
     * @param fromConnectEvent true on first USB_STATE host connect; false on focus intercept.
     */
    /** Auto-connect USB storage when a PC/host cable is attached (Settings → Connections → USB). */
    private boolean isUsbAutoConnectEnabled() {
        return prefs != null && prefs.getBoolean("usb_auto_connect", false)
                && !prefs.getBoolean("usb_manual_disable", false);
    }

    private void ensureUsbHostInterceptUi(boolean fromConnectEvent) {
        if (isHeavyWorkBlockingUsbPrompt()) {
            deferUsbConnectPrompt();
            return;
        }
        if (usbDialogDismissedThisConnection) {
            return;
        }
        if (usbFocusHelper == null || !usbFocusHelper.isHostConnected()) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "noHost");
                d.put("fromConnectEvent", fromConnectEvent);
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "skip", "H4", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        }

        if (isUsbMassStorageActive()) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "umsActive");
                d.put("screen", currentScreenState);
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "enterLock", "H3-H5", d);
            } catch (Exception ignored) {}
            // #endregion
            enterUsbMassStorageLock();
            return;
        }

        if (isUsbAutoConnectEnabled()) {
            if (!UsbStorageSessionFlags.shouldOfferUsbConnectPromptAfterBootSettle(this)) {
                return;
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "autoConnect");
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "autoEnable", "H3", d);
            } catch (Exception ignored) {}
            // #endregion
            enableUsbMassStorageAutoConnect();
            return;
        }

        if (!shouldOfferUsbConnectPrompt()) {
            return;
        }

        // July-2 monlith: Solar themed context menu owns the enable prompt (not companion).
        // 2026-07-16 — Do not mark shown/evaluated until showUsbMassStorageDialog paints
        // (defer path must leave session open for post-setup flush).
        if (fromConnectEvent) {
            if (usbDialogShownThisConnection) {
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("reason", "dialogAlreadyShown");
                    DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "skip", "H3", d);
                } catch (Exception ignored) {}
                // #endregion
                return;
            }
        } else if (!fromConnectEvent && usbDialogShownThisConnection && !isUsbMassStorageActive()) {
            // One offer per connect — focus intercept must not re-open the enable dialog.
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "alreadyShownThisConnection");
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "skip", "H-USB-SPAM", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        } else if (themedContextMenu != null && themedContextMenu.isShowing()
                && contextMenuTierStack.contains("usb_storage")) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "dialogVisible");
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "skip", "H3", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        } else if (usbMassStorageLocked && currentScreenState == STATE_USB_STORAGE) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "onUsbStorageScreen");
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "skip", "H3", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        } else if (!fromConnectEvent && usbDialogDismissedThisConnection) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("reason", "userDismissed");
                DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "skip", "H3", d);
            } catch (Exception ignored) {}
            // #endregion
            return;
        }

        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("reason", "showDialog");
            d.put("fromConnectEvent", fromConnectEvent);
            d.put("usbDialogShown", usbDialogShownThisConnection);
            d.put("screen", currentScreenState);
            DebugSessionLog.log("MainActivity.ensureUsbHostInterceptUi", "showDialog", "H3", d);
        } catch (Exception ignored) {}
        // #endregion
        android.util.Log.d("UsbFocus", "ensureUsbHostInterceptUi: showUsbMassStorageDialog");
        showUsbMassStorageDialog();
    }

    /**
     * True only when kernel is mass_storage AND a LUN is bound (PC can see a disk).
     * 2026-07-10 — Was: any non-empty lun/file → true even on MTP with stale sysfs → false lock.
     * Now: {@link UsbMassStorageController#isMassStorageExported()} only.
     */
    private boolean querySystemUsbMassStorageExported() {
        return UsbMassStorageController.isMassStorageExported();
    }

    /**
     * Clear sticky USB lock when LUN is not exported and user is not mid-enable.
     * Layman: fake "USB storage in use" goes away; real Turn on screen stays until Turn Off.
     */
    private void clearStaleUsbMassStorageLockIfNeeded() {
        if (!usbMassStorageLocked && !cachedUmsExported
                && currentScreenState != STATE_USB_STORAGE) {
            return;
        }
        if (UsbMassStorageController.isMassStorageExported()) return;
        // 2026-07-16 — User armed Turn on / auto-connect: keep eject UI until confirmed unplug.
        // Layman: PC eject of the disk must not free the menus while the cable is still in.
        if (UsbMassStorageController.isUserSessionActive()) {
            return;
        }
        // User intentionally on eject screen (Turn on just pressed / lock painted) — keep it.
        if (currentScreenState == STATE_USB_STORAGE && usbMassStorageLocked) {
            return;
        }
        // Kernel mass_storage without LUN still blocks SD — tear down and unlock.
        // 2026-07-15 — Skip when user turned UMS on this session (bind may still be racing).
        if (UsbMassStorageController.isKernelMassStorageMode()
                && !UsbMassStorageController.isUserSessionActive()) {
            final Context app = getApplicationContext();
            new Thread(new Runnable() {
                @Override
                public void run() {
                    UsbMassStorageController.disable(app);
                }
            }, "UsbStaleUmsClear").start();
        }
        onExternalUsbStorageUnlock();
        UsbStorageOverlayReceiver.dismissGlobalOverlayIfActive(this);
    }

    /**
     * Mass-storage lock: Solar STATE_USB_STORAGE eject screen (July-2 monlith).
     * Layman: stays until cable unplug — no companion overlay, no menu browsing.
     * 2026-07-16 — Always re-stop media and dismiss context menus so Turn on cannot leave playback running.
     */
    private void enterUsbMassStorageLock() {
        // #region agent log
        try {
            org.json.JSONObject d = Debug266f21Log.usbSnapshot();
            d.put("fg", ExternalInputHandoff.getForegroundPackageName(this));
            d.put("hasWindowFocus", hasWindowFocus());
            d.put("cachedUmsExported", cachedUmsExported);
            d.put("kernelUms", UsbMassStorageController.isKernelMassStorageMode());
            d.put("lunExported", UsbMassStorageController.isMassStorageExported());
            Debug266f21Log.log(this, "MainActivity.enterUsbMassStorageLock", "lock enter", "H4,H5", d);
        } catch (Exception ignored) {}
        // #endregion
        // Drop any companion USB shell that might still be up from older builds.
        UsbStorageOverlayReceiver.dismissCompanionShell(this);
        cancelLibraryScanGracefully("usb_storage_lock");
        boolean alreadyOnScreen = currentScreenState == STATE_USB_STORAGE;
        boolean firstEnter = !usbMassStorageLocked;
        usbMassStorageLocked = true;
        usbEnablePromptSession = false;
        usbDialogShownThisConnection = true;
        // Enable prompt must never sit over the eject screen.
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            dismissThemedContextMenu(false);
        }
        if (firstEnter) {
            if (currentScreenState != STATE_USB_STORAGE) {
                usbReturnScreen = currentScreenState;
            }
        }
        // Always suspend media on every lock paint (Turn on, re-entry, auto-connect).
        suspendBackgroundForUsbStorage();
        applyUsbStorageScreenLayout();
        if (usbFocusHelper != null) {
            usbFocusHelper.setMassStorageInterceptActive(true);
        }
        if (!alreadyOnScreen) {
            applyScreenChange(STATE_USB_STORAGE);
        } else {
            buildUsbStorageUI();
        }
        // Optimistic while enable is in flight; probe will correct on refresh.
        if (UsbMassStorageController.isMassStorageExported()
                || UsbMassStorageController.isUserSessionActive()) {
            cachedUmsExported = true;
        }
        SystemUiUsbSuppressor.dismissNow(this);
    }

    private void applyUsbStorageScreenLayout() {
        settingsBrowseFullWidth = true;
        if (settingsPreviewPane != null) {
            settingsPreviewPane.setVisibility(View.GONE);
        }
        if (podcastPreviewPane != null) {
            podcastPreviewPane.setVisibility(View.GONE);
        }
        applyFullWidthMenusLayout();
    }

    private void scheduleUsbStorageFocus() {
        View root = findViewById(android.R.id.content);
        if (root == null) return;
        root.post(new Runnable() {
            @Override
            public void run() {
                if (currentScreenState != STATE_USB_STORAGE) return;
                if (themedContextMenu != null && themedContextMenu.isShowing()) return;
                refocusUsbStorageButton();
            }
        });
    }

    private void refocusUsbStorageButton() {
        if (containerBrowserItems == null) return;
        for (int i = containerBrowserItems.getChildCount() - 1; i >= 0; i--) {
            View child = containerBrowserItems.getChildAt(i);
            if (child != null && child.getVisibility() == View.VISIBLE
                    && child.isFocusable() && child.isEnabled()) {
                child.requestFocus();
                scrollBrowserRowIntoView(child, containerBrowserItems);
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("focused", child.hasFocus());
                    d.put("tag", child.getTag() != null ? child.getTag().toString() : "");
                    d.put("hasWindowFocus", hasWindowFocus());
                    DebugSessionLog.log("MainActivity.refocusUsbStorageButton", "focus", "H-USB-FOCUS", d);
                } catch (Exception ignored) {}
                // #endregion
                return;
            }
        }
    }

    private void suspendBackgroundForUsbStorage() {
        ThemeManager.prepareThemeForUsbStorage(this);
        try {
            applyThemeToMainMenu();
            if (currentScreenState == STATE_USB_STORAGE) {
                buildUsbStorageUI();
            }
        } catch (Exception ignored) {}
        teardownSoulseekSession();
        teardownDeezerSession();
        cancelReachDownloadIfAny(false);
        stopActivePlaybackForUsbStorage();
        if (isServerRunning) {
            toggleWebServer();
        }
    }

    /**
     * Hard-stop players when USB mass-storage lock engages — queue metadata stays for later.
     * 2026-07-16 — Was: pause only; music kept decoding while SD was exported to the PC.
     * Layman: turning on USB storage silences everything until the cable is out.
     */
    private void stopActivePlaybackForUsbStorage() {
        try {
            if (mediaSuite != null) {
                mediaSuite.stopVideoAndYoutubeStream();
            }
        } catch (Exception ignored) {}
        try {
            if (playback.isPodcastActive() && podcastIjkPlayer != null) {
                podcastIjkPlayer.pause();
                try {
                    podcastIjkPlayer.seekTo(0);
                } catch (Exception ignored) {}
            }
        } catch (Exception ignored) {}
        try {
            if (isMusicIjkActive() && musicIjkPlayer != null) {
                musicIjkPlayer.pause();
            }
        } catch (Exception ignored) {}
        try {
            if (mediaPlayer != null) {
                if (mediaPlayer.isPlaying()) {
                    mediaPlayer.stop();
                }
                mediaPlayer.reset();
            }
        } catch (Exception ignored) {}
        try {
            if (mediaSuite != null && playback.isRadioActive()) {
                mediaSuite.toggleRadioPlayPause();
            }
        } catch (Exception ignored) {}
        try {
            if (mediaSuite != null && playback.isFmActive()) {
                // Best-effort: leave FM shell without leaving UMS lock.
                mediaSuite.leaveFmNowPlayingToShell();
            }
        } catch (Exception ignored) {}
        isPausedByHand = true;
        try {
            updatePlayerUI();
        } catch (Exception ignored) {}
        try {
            syncNowPlayingHomeVisibility();
        } catch (Exception ignored) {}
    }

    private void clearArtistOwnAlbumCache() {
        artistOwnAlbumCacheKey = "";
    }

    /** True when the artist is primary on at least one album in the library. */
    private boolean artistHasOwnAlbum(String artist) {
        if (artist == null || artist.trim().isEmpty()) return false;
        String normalized = artist.trim();
        String cacheKey = ArtistNames.matchKey(normalized);
        if (cacheKey.equals(artistOwnAlbumCacheKey)) return artistOwnAlbumCacheValue;
        boolean owns = ArtistBrowsePolicy.hasOwnAlbum(normalized, policyTracksFromLibrary(), libraryBrowsePrefs);
        artistOwnAlbumCacheKey = cacheKey;
        artistOwnAlbumCacheValue = owns;
        return owns;
    }

    private void openArtistBrowse(String artist) {
        virtualQueryArtist = artist.trim();
        if (ArtistBrowsePolicy.shouldSkipAlbumPicker(virtualQueryArtist, libraryBrowsePrefs,
                policyTracksFromLibrary())) {
            currentBrowserMode = BROWSER_VIRTUAL_SONGS;
            virtualQueryType = "ARTIST";
            virtualQueryValue = virtualQueryArtist;
            virtualQueryArtist = "";
            buildVirtualSongs();
            return;
        }
        currentBrowserMode = BROWSER_ARTIST_ALBUMS;
        buildArtistAlbums();
    }

    private void showPlaylistMoveStripUi() {
        if (playlistMovePickIndex < 0 || playlistMovePickIndex >= virtualSongList.size()) return;
        playlistMoveFrom = playlistMovePickIndex;
        listVirtualSongs.setVisibility(View.GONE);
        listVirtualSongs.setAlpha(1f);
        int rowW = y1ActiveRowWidthPx();
        int rowH = y1LibraryRowHeightPx;
        playlistMoveRowBgSel = ThemeManager.getItemRowBackgroundScaled(
                getResources(), true, rowW, rowH);
        playlistMoveRowBgNorm = ThemeManager.getItemRowBackgroundScaled(
                getResources(), false, rowW, rowH);
        android.view.ViewGroup browserParent = (android.view.ViewGroup) scrollViewBrowser.getParent();
        if (playlistMoveOverlay == null) {
            playlistMoveOverlay = new FrameLayout(this);
            browserParent.addView(playlistMoveOverlay, new android.view.ViewGroup.LayoutParams(
                    android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                    android.view.ViewGroup.LayoutParams.MATCH_PARENT));
        }
        playlistMoveOverlay.setVisibility(View.VISIBLE);
        playlistMoveOverlay.setAlpha(1f);
        playlistMoveOverlay.removeAllViews();
        playlistMoveScroll = new ScrollView(this);
        playlistMoveScroll.setVerticalScrollBarEnabled(false);
        playlistMoveScroll.setFillViewport(true);
        playlistMoveScroll.setAlpha(1f);
        FrameLayout scrollHost = new FrameLayout(this);
        playlistMoveScroll.addView(scrollHost, new ScrollView.LayoutParams(
                ScrollView.LayoutParams.MATCH_PARENT, ScrollView.LayoutParams.MATCH_PARENT));
        LinearLayout host = new LinearLayout(this);
        host.setOrientation(LinearLayout.VERTICAL);
        FrameLayout.LayoutParams hostLp = new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.WRAP_CONTENT);
        hostLp.gravity = Gravity.TOP;
        scrollHost.addView(host, hostLp);
        playlistMoveRibbon = new LibraryMoveRibbon(host, playlistMoveScroll, createPlaylistMoveBinder(), this);
        playlistMoveOverlay.addView(playlistMoveScroll, new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT));
        playlistMoveRibbon.enter(playlistMoveFrom, playlistMoveEnterBrowseSlot, playlistMoveEnterPadTop);
        // 2026-07-15 — Touch drag on mover (wheel/OK-hold paths unchanged).
        attachPlaylistMoveTouchDrag();
    }

    /**
     * 2026-07-15 — Drag the lifted playlist ribbon strip with a finger (Spotify-queue feel).
     * Was: wheel/OK only. Reversal: remove MoveRibbonTouch.attachActiveDrag call.
     */
    private void attachPlaylistMoveTouchDrag() {
        if (playlistMoveRibbon == null || !MoveRibbonTouch.touchReorderEnabled()) return;
        final View mover = playlistMoveRibbon.moverRowForTouch();
        if (mover == null) return;
        final int slotH = y1LibraryRowHeightPx + 2;
        MoveRibbonTouch.attachActiveDrag(mover, slotH, new MoveRibbonTouch.Callbacks() {
            @Override
            public void onLift() {}

            @Override
            public void onStep(int delta) {
                if (delta == 0 || !isPlaylistMoveActive()) return;
                handlePlaylistMoveWheel(delta);
            }

            @Override
            public void onConfirm() {
                if (isPlaylistMoveActive()) confirmPlaylistMove();
            }
        });
    }

    private void hidePlaylistMoveStripUi() {
        hidePlaylistMoveStripUi(true);
    }

    private void hidePlaylistMoveStripUi(boolean showList) {
        playlistMoveTutorialShowing = false;
        if (playlistMoveOverlay != null) {
            playlistMoveOverlay.animate().cancel();
            playlistMoveOverlay.setAlpha(1f);
            playlistMoveOverlay.setVisibility(View.GONE);
        }
        if (listVirtualSongs != null && showList) {
            listVirtualSongs.setVisibility(View.VISIBLE);
        }
        if (playlistMoveRibbon != null) playlistMoveRibbon.teardown();
        playlistMoveRibbon = null;
        playlistMoveScroll = null;
        playlistMoveTitleCache = null;
        playlistMoveSubCache = null;
        playlistMoveRowBgSel = null;
        playlistMoveRowBgNorm = null;
    }

    private static final int PLAYLIST_CONFIRM_SHOW_MS = 120;
    private static final int PLAYLIST_CONFIRM_HOLD_MS = 450;

    private void confirmPlaylistMove() {
        if (playlistMoveRibbon != null && playlistMoveRibbon.isAnimating()) return;
        final int placed = playlistMoveFrom;
        final int browseSlot = QueueBrowseWindow.browseViewportSlot(
                placed, virtualSongList.size(), PlaylistMoveWindow.VISIBLE_ROWS);
        Runnable afterCheck = new Runnable() {
            @Override
            public void run() {
                if (playlistMoveRibbon != null) {
                    playlistMoveRibbon.animateConfirmHandoff(placed, browseSlot, new Runnable() {
                        @Override
                        public void run() {
                            finishPlaylistMoveConfirm(placed, browseSlot);
                        }
                    });
                } else {
                    finishPlaylistMoveConfirm(placed, browseSlot);
                }
            }
        };
        if (playlistMoveRibbon != null && placed >= 0) {
            playlistMoveRibbon.flashConfirm(placed, afterCheck);
        } else {
            afterCheck.run();
        }
    }

    /** Crossfade ribbon → list at browse slot; avoids flash from notify + overlay swap. */
    private void finishPlaylistMoveConfirm(final int placed, final int browseSlot) {
        flushPlaylistMoveIfDirty();
        playlistListFocusIndex = placed;
        playlistMoveFrom = -1;
        playlistMovePickIndex = -1;
        playlistMoveSnapshot = null;
        playlistMoveWheelFilter.reset();

        if (listVirtualSongs != null && listVirtualSongs.getAdapter() != null) {
            listVirtualSongs.setVisibility(View.VISIBLE);
            listVirtualSongs.setAlpha(0f);
            ((android.widget.BaseAdapter) listVirtualSongs.getAdapter()).notifyDataSetChanged();
            scrollPlaylistListToViewportSlot(placed, browseSlot, playlistListRowHeightPx());
        }

        Runnable revealList = new Runnable() {
            @Override
            public void run() {
                hidePlaylistMoveStripUi(false);
                if (listVirtualSongs != null) {
                    listVirtualSongs.animate().cancel();
                    listVirtualSongs.animate()
                            .alpha(1f)
                            .setDuration(LibraryMoveRibbon.ENTER_MS)
                            .start();
                    listVirtualSongs.post(new Runnable() {
                        @Override
                        public void run() {
                            focusPlaylistListRow(placed);
                            flashPlaylistRowConfirm(placed);
                            pulsePlaylistRowTicker(placed);
                        }
                    });
                }
            }
        };

        if (playlistMoveOverlay != null && playlistMoveOverlay.getVisibility() == View.VISIBLE) {
            playlistMoveOverlay.animate().cancel();
            playlistMoveOverlay.animate()
                    .alpha(0f)
                    .setDuration(LibraryMoveRibbon.ENTER_MS)
                    .withEndAction(revealList)
                    .start();
        } else {
            revealList.run();
        }
    }

    private void flashPlaylistRowConfirm(int index) {
        if (listVirtualSongs == null) return;
        int childIdx = index - listVirtualSongs.getFirstVisiblePosition();
        if (childIdx < 0 || childIdx >= listVirtualSongs.getChildCount()) return;
        View row = listVirtualSongs.getChildAt(childIdx);
        if (!(row instanceof FrameLayout)) return;
        android.widget.ImageView confirm = (android.widget.ImageView)
                ((FrameLayout) row).findViewWithTag(MoveRibbonRows.TAG_CONFIRM);
        if (confirm == null) return;
        confirm.animate().cancel();
        confirm.setAlpha(0f);
        confirm.setVisibility(View.VISIBLE);
        confirm.animate().alpha(1f).setDuration(PLAYLIST_CONFIRM_SHOW_MS).start();
        confirm.postDelayed(new Runnable() {
            @Override
            public void run() {
                confirm.animate()
                        .alpha(0f)
                        .setDuration(PLAYLIST_CONFIRM_SHOW_MS)
                        .setListener(new android.animation.AnimatorListenerAdapter() {
                            @Override
                            public void onAnimationEnd(android.animation.Animator animation) {
                                confirm.animate().setListener(null);
                                confirm.setVisibility(View.GONE);
                                confirm.setAlpha(1f);
                            }
                        })
                        .start();
            }
        }, PLAYLIST_CONFIRM_HOLD_MS);
    }

    /** Soft timetable pulse on the placed row — matches Wi-Fi tier ticker feedback. */
    private void pulsePlaylistRowTicker(int index) {
        if (listVirtualSongs == null) return;
        int childIdx = index - listVirtualSongs.getFirstVisiblePosition();
        if (childIdx < 0 || childIdx >= listVirtualSongs.getChildCount()) return;
        final View row = listVirtualSongs.getChildAt(childIdx);
        if (row == null) return;
        row.animate().cancel();
        row.setTranslationY(0f);
        row.animate()
                .alpha(0.48f)
                .setDuration(70)
                .withEndAction(new Runnable() {
                    @Override
                    public void run() {
                        row.animate()
                                .alpha(1f)
                                .setDuration(LibraryMoveRibbon.ENTER_MS)
                                .start();
                    }
                })
                .start();
    }

    private int virtualSongListPosition() {
        if (listVirtualSongs == null) return -1;
        View focused = listVirtualSongs.getFocusedChild();
        int pos = -1;
        if (focused != null) {
            pos = listVirtualSongs.getPositionForView(focused);
        }
        if (pos < 0) pos = listVirtualSongs.getSelectedItemPosition();
        if (pos >= 0 && isVirtualPlaylistView()) playlistListFocusIndex = pos;
        return pos;
    }

    /** Wheel tick during playlist move — burst filter + sustained-scroll stride up to 2×. */
    private boolean handlePlaylistMoveWheel(int delta) {
        if (delta == 0) return false;
        if (playlistMoveRibbon != null && playlistMoveRibbon.isAnimating()) return true;
        int stride = playlistMoveWheelFilter.acceptStride(delta);
        if (stride <= 0) return true;
        int size = virtualSongList.size();
        int newIdx = playlistMoveFrom;
        for (int s = 0; s < stride; s++) {
            int step = QueueMoveWindow.nextMoveIndex(newIdx, delta, size);
            if (step == newIdx) break;
            newIdx = step;
        }
        if (newIdx != playlistMoveFrom) {
            applyPlaylistMove(playlistMoveFrom, newIdx);
            clickFeedback();
        }
        return true;
    }

    private void applyPlaylistMove(int from, int to) {
        if (from == to || from < 0 || to < 0
                || from >= virtualSongList.size() || to >= virtualSongList.size()) return;
        if (playlistMoveRibbon != null && playlistMoveRibbon.isAnimating()) return;
        applyPlaylistMoveData(from, to);
        if (playlistMoveRibbon != null) {
            playlistMoveRibbon.onMoveIndexChanged(to, to - from);
        }
    }

    private void applyPlaylistMoveData(int from, int to) {
        File moved = virtualSongList.remove(from);
        virtualSongList.add(to, moved);
        if (playlistMoveTitleCache != null && playlistMoveSubCache != null
                && from < playlistMoveTitleCache.size() && from < playlistMoveSubCache.size()) {
            String title = playlistMoveTitleCache.remove(from);
            String sub = playlistMoveSubCache.remove(from);
            playlistMoveTitleCache.add(to, title);
            playlistMoveSubCache.add(to, sub);
            int lo = Math.min(from, to);
            int hi = Math.max(from, to);
            for (int i = lo; i <= hi; i++) {
                renumberPlaylistMoveCacheTitle(i);
            }
        }
        playlistMoveFrom = to;
        playlistListFocusIndex = to;
        playlistMoveDirty = true;
    }

    private void renumberPlaylistMoveCacheTitle(int index) {
        if (playlistMoveTitleCache == null || index < 0 || index >= playlistMoveTitleCache.size()) return;
        String old = playlistMoveTitleCache.get(index);
        int dot = old.indexOf('·');
        String name = dot >= 0 && dot + 1 < old.length()
                ? old.substring(dot + 1).trim() : old;
        playlistMoveTitleCache.set(index, String.format(Locale.US, "%02d · %s", index + 1, name));
    }

    private void flushPlaylistMoveIfDirty() {
        if (!playlistMoveDirty) return;
        playlistMoveDirty = false;
        if (playlistViewEntry == null || playlistViewEntry.sourceFile == null) return;
        try {
            PlaylistManager.saveM3u(
                    PlaylistManager.fromTracks(playlistViewEntry.name, virtualSongList),
                    playlistViewEntry.sourceFile);
            playlistViewEntry.tracks.clear();
            playlistViewEntry.tracks.addAll(virtualSongList);
            if (libraryPlaylists != null) {
                for (PlaylistManager.Entry e : libraryPlaylists) {
                    if (playlistViewEntry.name.equals(e.name)) {
                        e.tracks.clear();
                        e.tracks.addAll(virtualSongList);
                        break;
                    }
                }
            }
        } catch (Exception e) {
            Toast.makeText(this, getString(R.string.library_playlist_save_failed), Toast.LENGTH_SHORT).show();
        }
    }

    private void cancelPlaylistMove() {
        if (playlistMoveFrom < 0) return;
        if (playlistMoveRibbon != null && playlistMoveRibbon.isAnimating()) return;
        final int home = playlistMovePickIndex >= 0 ? playlistMovePickIndex : playlistListFocusIndex;
        if (playlistMoveSnapshot != null) {
            virtualSongList.clear();
            virtualSongList.addAll(playlistMoveSnapshot);
        }
        playlistMoveDirty = false;
        playlistMoveFrom = -1;
        playlistMovePickIndex = -1;
        playlistMoveSnapshot = null;
        playlistMoveWheelFilter.reset();
        hidePlaylistMoveStripUi();
        playlistListFocusIndex = Math.max(0, home);
        refreshPlaylistSongList(playlistListFocusIndex);
    }

    private void resetPlaylistMoveState() {
        if (playlistMoveFrom >= 0 && playlistMoveSnapshot != null) {
            virtualSongList.clear();
            virtualSongList.addAll(playlistMoveSnapshot);
        }
        playlistMoveFrom = -1;
        playlistMovePickIndex = -1;
        playlistMoveSnapshot = null;
        playlistMoveDirty = false;
        playlistMoveWheelFilter.reset();
        hidePlaylistMoveStripUi();
        playlistViewEntry = null;
    }

    private void refreshPlaylistSongList() {
        refreshPlaylistSongList(playlistListFocusIndex);
    }

    /** After move confirm/cancel, {@code focusIndex} is the row to keep selected (queue-editor parity). */
    private void refreshPlaylistSongList(int focusIndex) {
        if (listVirtualSongs == null || listVirtualSongs.getAdapter() == null) return;
        if (focusIndex >= 0) {
            playlistListFocusIndex = focusIndex;
        }
        final int focusIdx = focusIndex >= 0 ? focusIndex : playlistListFocusIndex;
        android.widget.BaseAdapter adapter = (android.widget.BaseAdapter) listVirtualSongs.getAdapter();
        adapter.notifyDataSetChanged();
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                restorePlaylistListScrollAfterMove(focusIdx);
            }
        });
    }

    /**
     * Browse-mode scroll + focus — same slot rules as queue viewer after move confirm/cancel.
     */
    private void restorePlaylistListScrollAfterMove(final int focusIdx) {
        if (listVirtualSongs == null) return;
        int target = Math.max(0, focusIdx);
        int count = virtualSongList.size();
        if (count <= 0) return;
        if (target >= count) target = count - 1;
        final int focusTarget = target;
        playlistListFocusIndex = focusTarget;
        int browseSlot = QueueBrowseWindow.browseViewportSlot(
                focusTarget, count, PlaylistMoveWindow.VISIBLE_ROWS);
        int rowH = playlistListRowHeightPx();
        scrollPlaylistListToViewportSlot(focusTarget, browseSlot, rowH);
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                scrollPlaylistListToViewportSlot(focusTarget, browseSlot, rowH);
                focusPlaylistListRow(focusTarget);
            }
        });
    }

    private int playlistListRowHeightPx() {
        int rowH = y1LibraryRowHeightPx + 2;
        if (listVirtualSongs != null && listVirtualSongs.getChildCount() > 0) {
            View row = listVirtualSongs.getChildAt(0);
            if (row != null && row.getHeight() > 0) rowH = row.getHeight();
        }
        return rowH;
    }

    private void scrollPlaylistListToViewportSlot(int index, int browseSlot, int rowH) {
        if (listVirtualSongs == null) return;
        listVirtualSongs.setSelection(index);
        listVirtualSongs.setSelectionFromTop(index, browseSlot * rowH);
    }

    private void focusPlaylistListRow(int index) {
        if (listVirtualSongs == null) return;
        listVirtualSongs.requestFocus();
        int childIdx = index - listVirtualSongs.getFirstVisiblePosition();
        if (childIdx >= 0 && childIdx < listVirtualSongs.getChildCount()) {
            View v = listVirtualSongs.getChildAt(childIdx);
            if (v != null && v.isFocusable()) {
                v.requestFocus();
                return;
            }
        }
        FocusScrollHelper.focusListPosition(listVirtualSongs, index);
    }

    private boolean isPlaylistViewNowPlayingSlot(int idx) {
        if (!playback.isMusicActive() || virtualQueryValue == null) return false;
        String activePl = playback.musicActivePlaylistName();
        if (activePl == null || !activePl.equals(virtualQueryValue)) return false;
        if (idx < 0 || idx >= virtualSongList.size()) return false;
        File cur = playback.musicPlaylist().isEmpty() ? null : playback.musicPlaylist().get(playback.musicIndex());
        return cur != null && cur.equals(virtualSongList.get(idx));
    }

    private void refreshContextQueueTierIfOpen() {
        if (themedContextMenu == null || !themedContextMenu.isShowing()) return;
        if (!contextMenuInQueueTier && !"queue".equals(contextMenuTopTier())) {
            return;
        }
        if (themedContextMenu.isQueueMode()) {
            ThemedContextMenu.QueueRowSpec[] specs = buildContextQueueRowSpecs();
            if (specs.length != themedContextMenu.queueRowCount()) {
                rebuildContextQueueTier(true);
                return;
            }
            themedContextMenu.ensureQueueListVisible();
            themedContextMenu.refreshQueueRowTitles(specs);
            themedContextMenu.refreshQueuePlayingState(specs);
            int np = playback.unifiedQueue().index();
            if (np >= 0 && np < specs.length && specs[np].nowPlaying) {
                SolarAdbTest.queuePlaybackState(specs[np].playing);
            }
            return;
        }
        if (contextQueueEditPlaylist) pushContextPlaylistEditTier();
        else rebuildContextQueueTier(true);
    }

    private ThemedContextMenu.QueueRowSpec[] buildContextQueueRowSpecs() {
        if (contextQueueEditPlaylist) {
            ThemedContextMenu.QueueRowSpec[] rows =
                    new ThemedContextMenu.QueueRowSpec[playlistEditTracks.size()];
            for (int i = 0; i < playlistEditTracks.size(); i++) {
                File f = playlistEditTracks.get(i);
                String line = musicTrackLabel(f);
                int dot = line.indexOf(" · ");
                String title = dot > 0 ? line.substring(0, dot) : line;
                String sub = dot > 0 ? line.substring(dot + 3) : "";
                rows[i] = new ThemedContextMenu.QueueRowSpec(title, sub, false, false);
            }
            return rows;
        }
        return buildQueueRowSpecsFast(playback.unifiedQueue());
    }

    private ThemedContextMenu.QueueRowSpec[] buildQueueRowSpecs() {
        PlayQueue q = playback.unifiedQueue();
        int size = q.size();
        if (size >= QUEUE_SPEC_FULL_METADATA_MAX) return buildQueueRowSpecsFast(q);
        boolean playing = false;
        try { playing = mediaPlayer != null && mediaPlayer.isPlaying(); } catch (Exception ignored) {}
        ThemedContextMenu.QueueRowSpec[] rows = new ThemedContextMenu.QueueRowSpec[size];
        for (int i = 0; i < size; i++) {
            PlayQueue.QueueItem item = q.items().get(i);
            rows[i] = new ThemedContextMenu.QueueRowSpec(
                    queueItemTitle(item), queueItemSubtitle(item),
                    i == q.index(), playing && i == q.index());
        }
        return rows;
    }

    /** Large queue — filename labels only; avoids scanning the whole library per row. */
    private ThemedContextMenu.QueueRowSpec[] buildQueueRowSpecsFast(PlayQueue q) {
        boolean playing = false;
        try { playing = mediaPlayer != null && mediaPlayer.isPlaying(); } catch (Exception ignored) {}
        int size = q.size();
        int np = q.index();
        ThemedContextMenu.QueueRowSpec[] rows = new ThemedContextMenu.QueueRowSpec[size];
        for (int i = 0; i < size; i++) {
            PlayQueue.QueueItem item = q.items().get(i);
            rows[i] = new ThemedContextMenu.QueueRowSpec(
                    queueItemTitleFast(item), queueItemSubtitleFast(item),
                    i == np, playing && i == np);
        }
        return rows;
    }

    private String queueItemTitleFast(PlayQueue.QueueItem item) {
        if (item == null) return "";
        if (item.kind == PlayQueue.ItemKind.MUSIC_FILE && item.file != null) {
            String n = item.file.getName();
            int dot = n.lastIndexOf('.');
            String base = dot > 0 ? n.substring(0, dot) : n;
            return maybePrefixReachDownloadProgress(item, base);
        }
        return queueItemTitle(item);
    }

    private String queueItemSubtitleFast(PlayQueue.QueueItem item) {
        if (item == null) return "";
        if (item.kind == PlayQueue.ItemKind.MUSIC_FILE) return getString(R.string.home_menu_music);
        return queueItemSubtitle(item);
    }

    private String wifiCapabilitiesForSsid(String ssid) {
        if (ssid == null || ssid.isEmpty()) return "";
        ScanResult cached = wifiScanCacheBySsid.get(ssid);
        if (cached != null) {
            return cached.capabilities != null ? cached.capabilities : "";
        }
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            java.util.List<ScanResult> results = wm != null ? wm.getScanResults() : null;
            if (results == null) return "";
            for (ScanResult result : results) {
                if (ssid.equals(result.SSID)) return result.capabilities != null ? result.capabilities : "";
            }
        } catch (Exception e) {
            SolarLog.w("MainActivity", "wifiCapabilitiesForSsid: " + e.getMessage());
        }
        return "";
    }

    private String wifiStateTextForSsid(String ssid, String capabilities) {
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            WifiInfo info = wm != null ? wm.getConnectionInfo() : null;
            String connected = info != null && info.getSSID() != null ? info.getSSID().replace("\"", "") : "";
            if (ssid != null && ssid.equals(connected)) return "ON";
        } catch (Exception ignored) {}
        return "";
    }

    private BluetoothDevice bluetoothDeviceByAddress(String addr) {
        if (addr == null || addr.isEmpty()) return null;
        try {
            BluetoothAdapter adapter = BluetoothAdapter.getDefaultAdapter();
            if (adapter == null) return null;
            return adapter.getRemoteDevice(addr);
        } catch (Exception ignored) {
            return null;
        }
    }

    private String bluetoothStateText(BluetoothDevice device) {
        return bluetoothDeviceStateText(device);
    }

