    private void persistPlaybackQueue() {
        // ponytail: failed mount-time restore leaves memory empty while play_queue.json still has items — never wipe disk.
        if (!playback.hasAnyQueue()
                && PlayQueueStore.hasPersistedQueue(getApplicationContext())) {
            return;
        }
        int seek = -1;
        boolean playing = false;
        try {
            seek = activeAudioPositionMs();
            playing = isActiveAudioPlaying();
        } catch (Exception ignored) {}
        AsyncPlayQueueWriter.bumpEpoch();
        AsyncPlayQueueWriter.scheduleSave(getApplicationContext(), playback.unifiedQueue(),
                seek, playing);
        syncNowPlayingHomeVisibility();
    }

    /** Coalesce rapid queue edits (context-menu move) into one disk write. */
    private void persistPlaybackQueueDebounced() {
        persistPlaybackQueue();
    }

    private void restorePlaybackQueue() {
        PlayQueue q = new PlayQueue();
        if (!PlayQueueStore.restore(getApplicationContext(), q) || q.isEmpty()) return;
        playback.restoreQueueState(q.items(), q.index());
        syncNowPlayingHomeVisibility();
        refreshRestoredQueuePreview();
        refreshContextQueueTierIfOpen();
    }

    /** Bind home/player labels from restored queue without starting playback. */
    private void refreshRestoredQueuePreview() {
        if (!playback.hasAnyQueue()) return;
        PlayQueue.QueueItem cur = playback.currentItem();
        if (cur == null) return;
        String title = "";
        String artist = "";
        if (cur.kind == PlayQueue.ItemKind.PODCAST_EPISODE && cur.episode != null) {
            title = cur.episode.title != null ? cur.episode.title : "";
            artist = cur.podcastShowTitle != null ? cur.podcastShowTitle : "";
        } else if (cur.kind == PlayQueue.ItemKind.NAVIDROME_STREAM
                || cur.kind == PlayQueue.ItemKind.PLEX_STREAM
                || cur.kind == PlayQueue.ItemKind.JELLYFIN_STREAM) {
            title = cur.navidromeTitle != null ? cur.navidromeTitle : "";
            artist = cur.navidromeArtist != null ? cur.navidromeArtist : "";
        } else if (cur.file != null) {
            if (cur.kind == PlayQueue.ItemKind.REACH_STREAM) {
                title = cur.reachMeta != null && !cur.reachMeta.isEmpty()
                        ? cur.reachMeta : cur.file.getName();
                artist = cur.reachPeerUsername != null ? cur.reachPeerUsername : "";
            } else if (cur.kind == PlayQueue.ItemKind.DEEZER_STREAM) {
                String meta = cur.deezerMeta != null ? cur.deezerMeta.trim() : "";
                if (meta.isEmpty()) {
                    title = cur.file.getName();
                } else {
                    int dash = meta.indexOf(" - ");
                    if (dash > 0) {
                        artist = meta.substring(0, dash).trim();
                        title = meta.substring(dash + 3).trim();
                    } else {
                        title = meta;
                    }
                }
            } else {
                SongItem si = findSongItem(cur.file);
                title = si != null && si.title != null ? si.title : cur.file.getName();
                artist = si != null && si.artist != null ? si.artist : "";
            }
        }
        if (title.isEmpty()) title = "Unknown";
        if (tvPlayerTitle != null) tvPlayerTitle.setText(title);
        if (tvPlayerArtist != null) {
            tvPlayerArtist.setText(artist.isEmpty()
                    ? getString(R.string.reach_loading_track) : artist);
        }
        updateMusicTrackCountUi();
        refreshNowPlayingPreview();
    }

    private boolean deferStreamTrackNotReady() {
        return startupMountRetryAttempt < STARTUP_MOUNT_RETRY_MAX
                || PlayQueueStore.countMissingPaths(getApplicationContext()) > 0;
    }

    private void retryRestorePlaybackQueueAfterMount() {
        PlayQueue q = new PlayQueue();
        if (!PlayQueueStore.restore(getApplicationContext(), q) || q.isEmpty()) return;
        int before = playback.unifiedQueue().size();
        if (!playback.hasAnyQueue()) {
            playback.restoreQueueState(q.items(), q.index());
        } else if (q.size() > playback.unifiedQueue().size()) {
            playback.restoreQueueState(q.items(), q.index());
        }
        syncNowPlayingHomeVisibility();
        if (playback.unifiedQueue().size() != before) {
            refreshRestoredQueuePreview();
            // #region agent log
            try {
                JSONObject d = new JSONObject();
                d.put("before", before);
                d.put("after", playback.unifiedQueue().size());
                d.put("fromDisk", q.size());
                QueueDebugLog.log("MainActivity.retryRestorePlaybackQueueAfterMount", "mount retry restore", "H1", d);
            } catch (Exception ignored) {}
            // #endregion
            refreshContextQueueTierIfOpen();
        }
    }

    private void scheduleStartupMountRetry() {
        if (PlayQueueStore.countMissingPaths(getApplicationContext()) <= 0) return;
        startupMountRetryAttempt = 0;
        startupMountHandler.removeCallbacks(startupMountRetryRunnable);
        startupMountHandler.postDelayed(startupMountRetryRunnable, STARTUP_MOUNT_RETRY_INTERVAL_MS);
    }

    /**
     * Context “Clear Queue” — wipe queue metadata and hard-stop every audio/video engine.
     * 2026-07-18 — Was mediaPlayer-only; YouTube Music IJK / podcasts / radio kept playing
     * with an empty queue (unstoppable background audio). Reversal: restore MP-only stop.
     * Layman: clear queue means silence — nothing keeps humming in the background.
     * Technical: same teardown as mediaStopNonFmPlayback + internet radio + FM session,
     * then PlayQueueStore + playback.clearQueue.
     */
    private void clearPlaybackQueue() {
        // Growing stream / Reach transfer handoff must finish before engines drop.
        finalizeReachStreamHandoff();
        try {
            cancelReachDownloadIfAny(false);
        } catch (Exception ignored) {}
        try {
            saveCurrentPodcastResume();
        } catch (Exception ignored) {}
        // Podcast download + IJK (releases podcastIjkPlayer).
        try {
            stopPodcastDownloadFully();
        } catch (Exception ignored) {}
        // YouTube video/audio resolve, music IJK, MediaPlayer, FM chip session.
        try {
            stopCompetingAudioEngines();
        } catch (Exception ignored) {}
        // Internet radio (not covered by stopCompetingAudioEngines).
        try {
            if (mediaSuite != null && mediaSuite.internetRadioPlayer() != null) {
                mediaSuite.internetRadioPlayer().stop();
            }
        } catch (Exception ignored) {}
        // Belt-and-suspenders if stopCompeting skipped MP (already idle).
        try {
            if (mediaPlayer != null) {
                if (mediaPlayer.isPlaying()) mediaPlayer.stop();
                mediaPlayer.reset();
            }
        } catch (Exception ignored) {}
        isPausedByHand = false;
        playerPendingSeekMs = -1;
        PlayQueueStore.clear(getApplicationContext());
        playback.clearQueue();
        lastAlbumArtBytes = null;
        // Drop any in-flight NP track-change throbber left from skip/prepare.
        try {
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_TRACK_CHANGE);
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_SEEK_BUFFER);
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_MEDIA_BUFFER);
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_DOWNLOAD);
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_YOUTUBE_RESOLVE);
        } catch (Exception ignored) {}
        syncNowPlayingHomeVisibility();
        refreshContextQuickBarIfShowing();
        updatePlayerUI();
    }

    private void addClearQueueContextActionIfNeeded() {
        if (!playback.hasAnyQueue()) return;
        addContextAction(getString(R.string.context_clear_queue), new Runnable() {
            @Override
            public void run() {
                clearPlaybackQueue();
            }
        });
    }

    private boolean handlePlayPauseKeyDown(KeyEvent event) {
        if (currentScreenState == STATE_WIFI_KEYBOARD) return false;
        if (event.getRepeatCount() == 0) {
            globalPpKeyDownAt = System.currentTimeMillis();
            globalPpLongFlowHandled = false;
            clockHandler.removeCallbacks(globalPpFlowHoldRunnable);
            if (isFlowEnabled() && currentScreenState != STATE_FLOW) {
                clockHandler.postDelayed(globalPpFlowHoldRunnable, FLOW_LAUNCH_HOLD_MS);
                // 2026-07-18 — NP: keep holding Play/Pause for Flow tip while finger is down.
                showNpLiveHoldHintForFlow();
                // 2026-07-18 — Throbber from hold start until Flow paints (or abort).
                armFlowHoldThrobber();
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("contextMenu", themedContextMenu != null && themedContextMenu.isShowing());
                d.put("queueTier", contextMenuInQueueTier);
                d.put("queueMoveFrom", contextQueueMoveFrom);
                d.put("np", currentScreenState == STATE_PLAYER);
                DebugAgentLog.log(this, "MainActivity.handlePlayPauseKeyDown",
                        "pp key down armed", "H6-H7", d);
            } catch (Exception ignored) {}
            // #endregion
            return true;
        }
        triggerGlobalPpFlowHoldIfEligible();
        return true;
    }

    /** Play/Pause long-hold — A–Z jump on song lists; else open Flow from home/library/NP. */
    private void triggerGlobalPpFlowHoldIfEligible() {
        if (globalPpLongFlowHandled || currentScreenState == STATE_FLOW) return;
        if (globalPpKeyDownAt <= 0) return;
        if (System.currentTimeMillis() - globalPpKeyDownAt < FLOW_LAUNCH_HOLD_MS) return;
        // 2026-07-19 — Never open Flow while Stem/Mix assign owns the library.
        if (mixAssignMode || stemPickMode || StemOrMixSession.isActive()) {
            clearFlowHoldThrobber();
            return;
        }
        // 2026-07-15 — Song lists: long PP jumps to next letter only when list is title-sorted.
        if (currentScreenState == STATE_BROWSER && currentBrowserMode == BROWSER_VIRTUAL_SONGS
                && listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE
                && isFastScrollLetterEligible()) {
            int current = listVirtualSongs.getSelectedItemPosition();
            if (current < 0) current = 0;
            int target = wheelSectionIndex.jumpTarget(current, 1);
            if (target >= 0 && target != current) {
                listVirtualSongs.setSelection(target);
                String letter = wheelSectionIndex.letterAtPosition(target);
                if (letter != null) showFastScrollLetter(letter);
            }
            globalPpLongFlowHandled = true;
            clearFlowHoldThrobber();
            clickFeedback();
            return;
        }
        if (!isFlowEnabled()) {
            clearFlowHoldThrobber();
            return;
        }
        if (currentScreenState == STATE_PLAYER) {
            hideNpLiveHoldHint();
            markFlowHoldHintDone();
            returnToFlowFromNowPlaying();
        } else if (isNpToFlowHandoffEligible()) {
            hideNpLiveHoldHint();
            markFlowHoldHintDone();
            enterFlowFromNowPlaying(null, currentScreenState);
        } else {
            hideNpLiveHoldHint();
            openFlow(FlowLaunchRequest.picker(currentScreenState));
        }
        globalPpLongFlowHandled = true;
        clickFeedback();
    }

