    /**
     * 2026-07-15 — Dismiss in-app + WM overlay shells when going to sleep.
     * Layman: close quick menu / USB prompt so sleep never leaves a stuck sheet on wake.
     * Was: performScreenSleep only dismissed ThemedContextMenu; SCREEN_OFF left menus up.
     * Reversal: call dismissThemedContextMenu() alone without overlay/USB session dismiss.
     */
    private void dismissOverlaysAndUsbPromptForScreenSleep(String reason) {
        boolean usbPrompt = isUsbEnablePromptShowing() || usbEnablePromptSession
                || isUsbEnablePromptTierActive();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("reason", reason != null ? reason : "");
            d.put("usbPrompt", usbPrompt);
            d.put("menuShowing", themedContextMenu != null && themedContextMenu.isShowing());
            android.util.Log.i("SolarDebugD74b0d",
                    "{\"sessionId\":\"d74b0d\",\"runId\":\"post-fix\",\"hypothesisId\":\"E\","
                            + "\"location\":\"MainActivity.dismissOverlaysAndUsbPromptForScreenSleep\","
                            + "\"message\":\"sleep dismiss\",\"data\":" + d.toString()
                            + ",\"timestamp\":" + System.currentTimeMillis() + "}");
        } catch (Exception ignored) {}
        // #endregion
        dismissThemedContextMenu();
        UsbStorageOverlayReceiver.dismissCompanionShell(this);
        if (usbPrompt) {
            // Sleep while USB connect prompt is up = user dismissed this plug session.
            UsbHostSessionPolicy.markUserDismissed(getApplicationContext());
        }
    }

    /** Screen off — root power key only (Y1); shared by hold-center and context menu. */
    /**
     * 2026-07-15 — Sleep from in-app quick bar / holds — shared PowerActions path.
     * Was: local trySuScreenOff. Now: PowerActions.screenSleep (A5 + Y1/Y2).
     * Reversal: restore trySuScreenOff body below and call it here.
     */
    private void performScreenSleep(boolean feedback) {
        if (currentScreenState == MediaSuiteHost.STATE_VIDEO_PLAYER
                && !com.solar.launcher.video.VideoSettings.getSleepDuringPlayback(this)) {
            if (feedback) clickFeedback();
            return;
        }
        if (feedback) clickFeedback();
        // 2026-07-15 — Dismiss before keyevent so sleep is not race-dependent on SCREEN_OFF alone.
        dismissOverlaysAndUsbPromptForScreenSleep("performScreenSleep");
        PowerActions.screenSleep(this);
    }

    private boolean isScreenInteractive() {
        try {
            PowerManager pm = (PowerManager) getSystemService(Context.POWER_SERVICE);
            if (android.os.Build.VERSION.SDK_INT >= 20) return pm.isInteractive();
            return pm.isScreenOn();
        } catch (Exception e) {
            return true;
        }
    }

    private void restartCurrentPodcast() {
        PodcastResumeStore.clear(getApplicationContext(), podcastResumeKey);
        podcastPendingResumeMs = 0;
        try {
            if (podcastIjkPlayer != null) {
                podcastIjkPlayer.seekTo(0);
                if (!podcastIjkPlayer.isPlaying()) {
                    podcastIjkPlayer.start();
                    applyPlaybackSpeed();
                }
                isPausedByHand = false;
            }
        } catch (Exception ignored) {}
        refreshPodcastTimeUi();
        updatePlayerUI();
    }

    private void markCurrentPodcastPlayed() {
        // 2026-07-15 — Persist played + clear resume.
        PodcastPlayedStore.markPlayed(getApplicationContext(), podcastResumeKey);
        PodcastResumeStore.clear(getApplicationContext(), podcastResumeKey);
        podcastPendingResumeMs = 0;
        Toast.makeText(this, getString(R.string.context_action_mark_played), Toast.LENGTH_SHORT).show();
    }

    /** 2026-07-15 — Seek relative for podcast/audiobook long-form listening. */
    private void skipActiveAudioByMs(int deltaMs) {
        int pos = activeAudioPositionMs();
        int dur = activeAudioDurationMs();
        int next = pos + deltaMs;
        if (next < 0) next = 0;
        if (dur > 0 && next > dur) next = dur;
        seekActiveAudio(next);
        if (playback.isPodcastActive()) refreshPodcastTimeUi();
        updatePlayerUI();
    }

    private final com.solar.launcher.playback.SleepTimer sleepTimer = new com.solar.launcher.playback.SleepTimer();

    private void ensureSleepTimerWired() {
        sleepTimer.setListener(new com.solar.launcher.playback.SleepTimer.Listener() {
            @Override
            public void onSleepFire(boolean endOfEpisodeOnly) {
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        pauseActiveAudio();
                        isPausedByHand = true;
                        updatePlayerUI();
                        Toast.makeText(MainActivity.this, R.string.sleep_timer_fired, Toast.LENGTH_SHORT).show();
                    }
                });
            }
        });
    }

    private void cycleSleepTimer() {
        ensureSleepTimerWired();
        int m = sleepTimer.getMode();
        if (m == com.solar.launcher.playback.SleepTimer.OFF) {
            sleepTimer.arm(com.solar.launcher.playback.SleepTimer.MIN_15);
        } else if (m == com.solar.launcher.playback.SleepTimer.MIN_15) {
            sleepTimer.arm(com.solar.launcher.playback.SleepTimer.MIN_30);
        } else if (m == com.solar.launcher.playback.SleepTimer.MIN_30) {
            sleepTimer.arm(com.solar.launcher.playback.SleepTimer.MIN_45);
        } else if (m == com.solar.launcher.playback.SleepTimer.MIN_45) {
            sleepTimer.arm(com.solar.launcher.playback.SleepTimer.END_OF_EPISODE);
        } else {
            sleepTimer.cancel();
        }
        Toast.makeText(this, getString(R.string.sleep_timer_set, sleepTimer.label()), Toast.LENGTH_SHORT).show();
    }

    /** 2026-07-15 — True when current music queue item lives under Audiobooks/. */
    private boolean isAudiobookPlaybackActive() {
        if (!playback.isMusicActive() || playback.musicPlaylist().isEmpty()) return false;
        File f = playback.musicPlaylist().get(playback.musicIndex());
        return com.solar.launcher.audiobook.AudiobookLibrary.isUnderAudiobookRoot(f);
    }

    private java.util.List<com.solar.launcher.audiobook.Mp4ChapterParser.Chapter> audiobookChapters
            = new java.util.ArrayList<com.solar.launcher.audiobook.Mp4ChapterParser.Chapter>();
    private int audiobookChapterIndex;

    /** 2026-07-15 — Load embedded or multi-file chapters for the current audiobook track. */
    private void refreshAudiobookChaptersForTrack(File track) {
        audiobookChapters.clear();
        audiobookChapterIndex = 0;
        if (track == null || !com.solar.launcher.audiobook.AudiobookLibrary.isUnderAudiobookRoot(track)) {
            return;
        }
        audiobookChapters.addAll(com.solar.launcher.audiobook.AudiobookLibrary.resolveChapters(track));
    }

    private void showAudiobookChapterPicker() {
        if (audiobookChapters.isEmpty() && !playback.musicPlaylist().isEmpty()) {
            refreshAudiobookChaptersForTrack(playback.musicPlaylist().get(playback.musicIndex()));
        }
        if (audiobookChapters.isEmpty()) {
            Toast.makeText(this, R.string.audiobook_no_chapters, Toast.LENGTH_SHORT).show();
            return;
        }
        // 2026-07-15 — Rebuild context sheet as a chapter list (same show path as hold menu).
        contextMenuLabels.clear();
        contextMenuIconKeys.clear();
        contextMenuStateTexts.clear();
        contextMenuHeaders.clear();
        contextMenuActions.clear();
        contextMenuKeepOpen.clear();
        for (int i = 0; i < audiobookChapters.size(); i++) {
            final int idx = i;
            final com.solar.launcher.audiobook.Mp4ChapterParser.Chapter ch = audiobookChapters.get(i);
            addContextAction(ch.title, new Runnable() {
                @Override
                public void run() {
                    seekAudiobookChapter(idx);
                }
            });
        }
        if (themedContextMenu == null) return;
        String[] labels = contextMenuLabels.toArray(new String[contextMenuLabels.size()]);
        String[] iconKeys = contextMenuIconKeys.toArray(new String[contextMenuIconKeys.size()]);
        String[] stateTexts = contextMenuStateTexts.toArray(new String[contextMenuStateTexts.size()]);
        boolean[] headers = new boolean[contextMenuHeaders.size()];
        for (int i = 0; i < headers.length; i++) headers[i] = contextMenuHeaders.get(i);
        ViewGroup root = (ViewGroup) findViewById(android.R.id.content);
        int margin = (int) (10 * getResources().getDisplayMetrics().density);
        int panelW = screenWidthPx > margin * 2 ? screenWidthPx - margin * 2 : y1ActiveRowWidthPx();
        themedContextMenu.show(root, getString(R.string.audiobook_chapters), null, labels, iconKeys,
                stateTexts, headers, createContextMenuListListener(), y1RowHeightPx, panelW,
                false, false, null, null);
        themedContextMenu.focusOptionsList();
    }

    private void seekAudiobookChapter(int index) {
        if (index < 0 || index >= audiobookChapters.size()) return;
        audiobookChapterIndex = index;
        long start = audiobookChapters.get(index).startMs;
        // Multi-file mode stores file index in startMs when no embedded chapters.
        File track = playback.musicPlaylist().isEmpty() ? null
                : playback.musicPlaylist().get(playback.musicIndex());
        if (track != null && track.isFile()
                && (track.getName().toLowerCase(Locale.US).endsWith(".m4b")
                || track.getName().toLowerCase(Locale.US).endsWith(".m4a"))) {
            seekActiveAudio((int) start);
        } else {
            // Sibling files: startMs is index into book folder — play that file if present.
            if (track != null && track.getParentFile() != null) {
                java.util.List<File> files = com.solar.launcher.audiobook.AudiobookLibrary
                        .chaptersForBook(track.getParentFile());
                if (index < files.size()) {
                    int qi = playback.musicPlaylist().indexOf(files.get(index));
                    if (qi >= 0) {
                        playback.setMusicIndex(qi);
                        isPausedByHand = false;
                        prepareMusicTrack(qi);
                        return;
                    }
                }
            }
            seekActiveAudio(0);
        }
        updatePlayerUI();
    }

    private void seekAudiobookChapterRelative(int delta) {
        if (audiobookChapters.isEmpty() && !playback.musicPlaylist().isEmpty()) {
            refreshAudiobookChaptersForTrack(playback.musicPlaylist().get(playback.musicIndex()));
        }
        if (audiobookChapters.size() < 2) {
            if (delta > 0) nextTrack();
            else { /* prev handled by caller */ }
            return;
        }
        int next = audiobookChapterIndex + delta;
        if (next < 0) next = 0;
        if (next >= audiobookChapters.size()) next = audiobookChapters.size() - 1;
        seekAudiobookChapter(next);
    }

    private void playCurrentFolderAll() {
        File targetFolder = browserFocusedFolder();
        if (targetFolder == null) targetFolder = currentFolder;
        if (targetFolder == null) return;
        List<File> list = new ArrayList<File>();
        File[] files = targetFolder.listFiles();
        if (files != null) {
            for (File f : files) {
                if (isAudioFile(f)) list.add(f);
            }
        }
        if (!list.isEmpty()) playTrackList(list, 0);
    }

    private void appendTrackToMusicQueue(File track) {
        if (track == null || !track.isFile()) return;
        List<File> one = new ArrayList<File>();
        one.add(track);
        playback.appendToMusicQueue(one);
        persistPlaybackQueue();
        suppressListClickUntil = System.currentTimeMillis() + 400;
        Toast.makeText(this, getString(R.string.toast_added_to_queue), Toast.LENGTH_SHORT).show();
    }

    private void queueReachTrackAfterCurrent(File track, String meta) {
        queueReachTrackAfterCurrent(track, meta, null);
    }

    private void queueReachTrackAfterCurrent(File track, String meta, String peer) {
        if (track == null || !track.isFile()) return;
        playback.queueReachAfterCurrent(track, meta != null ? meta : track.getName(), peer);
        if (peer != null && !peer.isEmpty()) {
            ReachTrackProvenance.record(prefs, track.getAbsolutePath(), peer);
        }
        persistPlaybackQueue();
        refreshContextQueueTierIfOpen();
        refreshReachProgressUi();
        suppressListClickUntil = System.currentTimeMillis() + 400;
        Toast.makeText(this, getString(R.string.toast_added_to_queue), Toast.LENGTH_SHORT).show();
    }

    private int virtualListFocusPosition() {
        if (listVirtualSongs == null) return -1;
        View focused = listVirtualSongs.getFocusedChild();
        if (focused != null) {
            int pos = listVirtualSongs.getPositionForView(focused);
            if (pos >= 0) return pos;
        }
        return listVirtualSongs.getSelectedItemPosition();
    }

    private File virtualFocusedAudioFile() {
        if (listVirtualSongs == null) return null;
        int pos = virtualListFocusPosition();
        if (pos >= 0 && pos < virtualSongList.size()) return virtualSongList.get(pos);
        return null;
    }

    private File podcastSavedFileFocus() {
        View c = getCurrentFocus();
        if (c != null && c.getTag() instanceof File) {
            File f = (File) c.getTag();
            if (f.isFile()) return f;
        }
        return null;
    }

    private void deleteSavedPodcastFile(File file) {
        if (file == null) return;
        PodcastResumeStore.clear(getApplicationContext(), PodcastResumeStore.keyForFile(file));
        if (file.delete()) {
            Toast.makeText(this, getString(R.string.podcasts_deleted_saved), Toast.LENGTH_SHORT).show();
            if (podcastSavedShowFolder != null && !podcastSavedShowFolder.isEmpty()) {
                buildPodcastSavedEpisodesUI(podcastSavedShowFolder);
            } else {
                buildPodcastSavedShowsUI();
            }
        } else {
            Toast.makeText(this, getString(R.string.podcasts_delete_failed), Toast.LENGTH_SHORT).show();
        }
    }

    private void addContextWifiToggle() {
        if (currentScreenState == STATE_WIFI_KEYBOARD) return;
        addContextAction(wifiContextToggleLabel(), null, null, new Runnable() {
            @Override
            public void run() {
                toggleWifiFromContextMenu();
            }
        });
    }

    private String wifiContextToggleLabel() {
        if (SolarSilentWifi.isUiHidden()) {
            return getString(R.string.context_wifi_off);
        }
        if (wifiContextPendingDisable) {
            return getString(R.string.context_wifi_off);
        }
        if (wifiContextPendingEnable) {
            return getString(R.string.context_wifi_on);
        }
        WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm == null) return getString(R.string.context_wifi_off);
        int state = wm.getWifiState();
        if (state == WifiManager.WIFI_STATE_ENABLING && !wifiContextPendingDisable) {
            return getString(R.string.context_wifi_on);
        }
        if (state == WifiManager.WIFI_STATE_DISABLING && !wifiContextPendingEnable) {
            return getString(R.string.context_wifi_busy);
        }
        return getString(isWifiPowerOn() ? R.string.context_wifi_on : R.string.context_wifi_off);
    }

    /** True when Wi-Fi tier should list networks (not while user is turning Wi-Fi off). */
    private boolean isWifiContextExpanded() {
        if (SolarSilentWifi.isUiHidden()) return false;
        if (wifiContextPendingDisable) return false;
        if (wifiContextPendingEnable) return true;
        WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm != null) {
            int state = wm.getWifiState();
            if (state == WifiManager.WIFI_STATE_ENABLING && !wifiContextPendingDisable) {
                return true;
            }
        }
        return isWifiPowerOn();
    }

    private boolean isWifiContextToggleLabel(String label) {
        if (label == null || label.isEmpty()) return false;
        return label.equals(getString(R.string.context_wifi_on))
                || label.equals(getString(R.string.context_wifi_off))
                || label.equals(getString(R.string.context_wifi_busy));
    }

    /**
     * User-visible Wi‑Fi power. Silent background wake reports false so menus look Off.
     */
    private boolean isWifiPowerOn() {
        if (SolarSilentWifi.isUiHidden()) return false;
        WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        return wm != null && wm.isWifiEnabled();
    }

    private String wifiPowerStateText() {
        if (SolarSilentWifi.isUiHidden()) return stateOnOff(false);
        WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm == null) return stateOnOff(false);
        int state = wm.getWifiState();
        if (state == WifiManager.WIFI_STATE_ENABLING || state == WifiManager.WIFI_STATE_DISABLING) {
            return "Wait...";
        }
        return stateOnOff(wm.isWifiEnabled());
    }

    private boolean podcastStreamingNeedsWifi() {
        if (!playback.isPodcastActive()) return false;
        if (podcastDownloadInProgress) return true;
        if (!podcastPartialPlaybackStarted) return false;
        if (podcastGrowingCacheFinal != null && podcastGrowingCacheFinal.isFile()) return false;
        if (podcastGrowingCacheFile != null && podcastDownloadBytesTotal > 0
                && podcastGrowingCacheFile.length() >= podcastDownloadBytesTotal) {
            return false;
        }
        return true;
    }

    private boolean wifiDisableNeedsWarning() {
        return WifiOffPolicy.disableNeedsWarning(
                isWifiPowerOn(),
                soulseekSharePolicy.announceShares(),
                hasActiveReachDownload(),
                reachPartialPlaybackStarted && reachDownloadInProgress(),
                podcastStreamingNeedsWifi());
    }

    /** Block sleep Wi-Fi off while media, Reach, uploads, or PC transfer server are active. */
    private boolean wifiSleepBlockedByActiveUse() {
        if (wifiDisableNeedsWarning()) return true;
        if (shouldKeepSoulseekAwakeForTransfers()) return true;
        if (isMediaPlayingNeedsWifi()) return true;
        if (isServerRunning) return true;
        return false;
    }

    private boolean isMediaPlayingNeedsWifi() {
        try {
            if (mediaPlayer != null && mediaPlayer.isPlaying()) return true;
        } catch (Exception ignored) {}
        if (playback.isPodcastActive() && podcastIjkPlayer != null) {
            try {
                if (podcastIjkPlayer.isPlaying()) return true;
            } catch (Exception ignored) {}
        }
        if (reachPartialPlaybackStarted) return true;
        return false;
    }

    private void applyWifiPowerState(boolean enable) {
        final WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm == null) return;
        // Any user toggle claims the radio — silent NTP/diag will not turn it back off.
        SolarSilentWifi.onUserWifiIntent();
        if (enable) {
            wifiDisabledBySleepPolicy = false;
            if (prefs != null) {
                prefs.edit().putBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, false).commit();
            }
            wifiContextPendingDisable = false;
            wifiContextPendingEnable = true;
            Toast.makeText(this, getString(R.string.toast_wifi_turning_on), Toast.LENGTH_SHORT).show();
            wm.setWifiEnabled(true);
            if (themedContextMenu != null && themedContextMenu.isShowing()) {
                contextTierConfirmOpen = false;
                cancelPendingContextWifiRefresh();
                ensureContextWifiListVisibleAfterEnable();
            }
        } else {
            wifiDisabledBySleepPolicy = false;
            if (prefs != null) {
                prefs.edit().putBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, false).commit();
            }
            wifiContextPendingEnable = false;
            wifiContextPendingDisable = true;
            cancelWifiContextScanFollowUps();
            // User-facing: "Disconnecting…" only — light diag flush then radio off.
            SolarDiagnosticReporter.runBeforeWifiDisable(this, true, new Runnable() {
                @Override
                public void run() {
                    try {
                        wm.setWifiEnabled(false);
                    } catch (Exception ignored) {}
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            if (themedContextMenu != null && themedContextMenu.isShowing()
                                    && isContextTierActive("wifi")) {
                                contextTierConfirmOpen = false;
                                cancelPendingContextWifiRefresh();
                                refreshContextWifiTierImmediate(true, true);
                            }
                        }
                    });
                }
            });
        }
    }

    private void toggleWifiFromContextMenu() {
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("wifiOn", isWifiPowerOn());
            d.put("expanded", isWifiContextExpanded());
            d.put("tierTop", contextMenuTopTier());
            d.put("needsWarning", wifiDisableNeedsWarning());
            DebugAgentLog.log(this, "MainActivity.toggleWifiFromContextMenu", "toggle", "H6-H7", d);
        } catch (Exception ignored) {}
        // #endregion
        if (!isWifiPowerOn()) {
            applyWifiPowerState(true);
            refreshContextWifiTierImmediate(false, true);
            return;
        }
        if (!wifiDisableNeedsWarning()) {
            applyWifiPowerState(false);
            refreshContextWifiTierImmediate(false, true);
            return;
        }
        showContextTierConfirm(
                getString(R.string.wifi_off_warning_title),
                getString(R.string.wifi_off_warning_message),
                getString(R.string.wifi_off_confirm),
                getString(R.string.common_cancel),
                new Runnable() {
                    @Override
                    public void run() {
                        applyWifiPowerState(false);
                        refreshContextWifiTierImmediate(false, true);
                    }
                },
                null);
    }

    /**
     * Confirm dialog inside an open context tier — keeps quick bar + tier stack (unlike showThemedConfirm).
     */
    private void showContextTierConfirm(String title, String message, String confirmLabel, String cancelLabel,
            final Runnable onConfirm, final Runnable onCancel) {
        if (themedContextMenu == null) return;
        contextTierConfirmOpen = true;
        cancelPendingContextWifiRefresh();
        java.util.ArrayList<String> labels = new java.util.ArrayList<String>();
        java.util.ArrayList<String> states = new java.util.ArrayList<String>();
        java.util.ArrayList<Boolean> headers = new java.util.ArrayList<Boolean>();
        java.util.ArrayList<Runnable> actions = new java.util.ArrayList<Runnable>();
        labels.add(message != null ? message : "");
        states.add(null);
        headers.add(Boolean.TRUE);
        actions.add(null);
        labels.add(confirmLabel);
        states.add(null);
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override public void run() {
                contextTierConfirmOpen = false;
                if (onConfirm != null) onConfirm.run();
                if (themedContextMenu != null && themedContextMenu.isShowing()
                        && isContextTierActive("wifi") && !isWifiPowerOn()) {
                    refreshContextWifiTierImmediate(true, true);
                }
            }
        });
        labels.add(cancelLabel);
        states.add(null);
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override public void run() {
                contextTierConfirmOpen = false;
                if (onCancel != null) onCancel.run();
                if (themedContextMenu != null && themedContextMenu.isShowing()
                        && "wifi".equals(contextMenuTopTier())) {
                    refreshContextWifiTierImmediate(false, true);
                }
            }
        });
        showContextMenuTierInPlace(title, labels, states, headers, actions, true);
        themedContextMenu.focusSubmenuList();
        themedContextMenu.requestOverlayFocus();
    }

