    private static final long ROCKBOX_SWITCH_POLL_MS = 400L;
    private static final long ROCKBOX_SWITCH_TIMEOUT_MS = 10_000L;

    private void launchRockboxSwitch() {
        // 2026-07-08 — Canonical PowerActions path (helper single-fire); keep please-wait + poll.
        launchAlternateHomeSwitch(LauncherDefault.TARGET_ROCKBOX);
    }

    /** 2026-07-06 — Install JJ when online, then switch HOME without reboot. */
    private void launchJjSwitch() {
        launchAlternateHomeSwitch(LauncherDefault.TARGET_JJ);
    }

    /** 2026-07-08 — Switch to Stock (Innioasis) HOME without reboot. */
    private void launchStockSwitch() {
        launchAlternateHomeSwitch(LauncherDefault.TARGET_STOCK);
    }

    /**
     * 2026-07-08 — Please-wait + poll wrapping PowerActions (was: local script race with helper).
     * Layman: show a short waiting screen while the home app changes, then close it when it lands.
     * Technical: PowerActions owns helper/script; here we only arm handoff after fg probe succeeds.
     * Reversal: restore inline LauncherSwitch.switchTo* on this thread.
     */
    private void launchAlternateHomeSwitch(final String target) {
        if (LauncherDefault.TARGET_JJ.equals(target)) {
            if (!JjLauncherAvailability.isOfferVisible(this)) {
                Toast.makeText(this, getString(R.string.dialog_jj_unavailable), Toast.LENGTH_SHORT).show();
                return;
            }
            showPleaseWaitOverlay(getString(R.string.dialog_jj_rebooting));
            PowerActions.switchToJj(this);
        } else if (LauncherDefault.TARGET_ROCKBOX.equals(target)) {
            if (!LauncherSwitch.isRockboxInstalled(this)) {
                Toast.makeText(this, getString(R.string.dialog_rockbox_unavailable), Toast.LENGTH_SHORT).show();
                return;
            }
            showPleaseWaitOverlay(getString(R.string.dialog_rockbox_rebooting));
            PowerActions.switchToRockbox(this);
        } else if (LauncherDefault.TARGET_STOCK.equals(target)) {
            if (!LauncherSwitch.isStockOfferVisible(this)) {
                Toast.makeText(this, getString(R.string.dialog_stock_unavailable), Toast.LENGTH_SHORT).show();
                return;
            }
            showPleaseWaitOverlay(getString(R.string.dialog_stock_rebooting));
            PowerActions.switchToStock(this);
        } else {
            return;
        }
        isIntentionalFocusLoss = true;
        final long switchStart = System.currentTimeMillis();
        // Poll on UI thread — PowerActions already started the switch off-thread.
        pollAlternateHomeSwitchCompletion(target, switchStart, 0);
    }

    /** Poll until alternate HOME owns the screen, then drop overlay or time out. */
    private void pollAlternateHomeSwitchCompletion(final String target, final long switchStartMs,
            final int attempt) {
        boolean fg;
        if (LauncherDefault.TARGET_JJ.equals(target)) {
            fg = LauncherSwitch.isJjForeground(this);
        } else if (LauncherDefault.TARGET_STOCK.equals(target)) {
            fg = LauncherSwitch.isStockForeground(this);
        } else {
            fg = LauncherSwitch.isRockboxForeground(this);
        }
        if (fg) {
            dismissRockboxSwitchOverlayIfNeeded();
            // 2026-07-06 — JJ/Rockbox/Stock now foreground: reclaim MEDIA_BUTTON before wheel (H2).
            if (LauncherDefault.TARGET_JJ.equals(target)
                    || LauncherDefault.TARGET_STOCK.equals(target)) {
                MediaButtonRegistrar.ensureRegistered(this);
                ExternalInputHandoff.armJjShim(this);
                RockboxForegroundMonitor.ensureStarted(this);
                if (LauncherDefault.TARGET_JJ.equals(target)) {
                    beginExternalInputHandoff(LauncherDefault.JJ_PACKAGE);
                } else {
                    beginExternalInputHandoff(LauncherSwitch.stockPackageForDevice(this));
                }
            } else if (LauncherDefault.TARGET_ROCKBOX.equals(target)) {
                MediaButtonRegistrar.ensureRegistered(this);
                ExternalInputHandoff.armForForegroundPackage(this);
                RockboxForegroundMonitor.ensureStarted(this);
            }
            if (!LauncherPreference.isSolarHome(this)) {
                finish();
            }
            return;
        }
        long elapsed = System.currentTimeMillis() - switchStartMs;
        if (elapsed >= ROCKBOX_SWITCH_TIMEOUT_MS) {
            dismissRockboxSwitchOverlayIfNeeded();
            isIntentionalFocusLoss = false;
            int msg = LauncherDefault.TARGET_JJ.equals(target)
                    ? R.string.dialog_jj_failed
                    : (LauncherDefault.TARGET_STOCK.equals(target)
                            ? R.string.dialog_stock_failed
                            : R.string.dialog_rockbox_failed);
            Toast.makeText(this, getString(msg), Toast.LENGTH_SHORT).show();
            RockboxRestartGrace.arm(getApplicationContext());
            return;
        }
        new Handler().postDelayed(new Runnable() {
            @Override
            public void run() {
                pollAlternateHomeSwitchCompletion(target, switchStartMs, attempt + 1);
            }
        }, ROCKBOX_SWITCH_POLL_MS);
    }

    /** Poll until Rockbox owns the screen, then drop overlay or time out. */
    private void pollRockboxSwitchCompletion(final long switchStartMs, final int attempt) {
        pollAlternateHomeSwitchCompletion(LauncherDefault.TARGET_ROCKBOX, switchStartMs, attempt);
    }

    private boolean isSoulseekSharingRejectionMessage(String text) {
        if (text == null || text.isEmpty()) return false;
        String lower = text.toLowerCase(Locale.US);
        return lower.contains("not sharing") || lower.contains("not shared")
                || lower.contains("upload denied") || lower.contains("share")
                || lower.contains("files");
    }

    private void showReachDownloadMessageInterstitial(final String peer, final String messageText) {
        dismissThemedContextMenu();
        String body = messageText != null ? messageText : "";
        if (isSoulseekSharingRejectionMessage(body)
                || isSoulseekSharingRejectionMessage(soulseekDownloadFailureReason)) {
            body = body + "\n\n" + getString(R.string.soulseek_sharing_reciprocity_hint);
        }
        final SoulseekClient.Result active = soulseekActiveDownload;
        final int pendingAction = soulseekPendingAction;
        String[] labels = active != null
                ? new String[] {
                    getString(R.string.soulseek_pm_open_conversation),
                    getString(R.string.soulseek_pm_dismiss),
                    getString(R.string.soulseek_pm_retry_download)
                }
                : new String[] {
                    getString(R.string.soulseek_pm_open_conversation),
                    getString(R.string.soulseek_pm_dismiss)
                };
        ViewGroup root = (ViewGroup) findViewById(android.R.id.content);
        int margin = (int) (10 * getResources().getDisplayMetrics().density);
        int panelW = screenWidthPx > margin * 2 ? screenWidthPx - margin * 2 : y1ActiveRowWidthPx();
        themedContextMenu.show(root, peer, body, labels, null, null,
                new boolean[labels.length],
                new ThemedContextMenu.Listener() {
                    @Override
                    public void onSelected(final int index) {
                        suppressListClickUntil = System.currentTimeMillis() + CONTEXT_MENU_CLICK_SUPPRESS_MS;
                        dismissThemedContextMenu();
                        if (index == 0) {
                            clickFeedback();
                            soulseekMessagePeer = peer;
                            buildSoulseekConversationUI(peer);
                        } else if (index == 2 && active != null) {
                            clickFeedback();
                            startSoulseekTransfer(active, pendingAction > 0
                                    ? pendingAction : SOULSEEK_ACTION_PLAY);
                        }
                    }
                }, y1RowHeightPx, panelW, false, true);
        clickFeedback();
    }

    private void watchSoulseekPeer(final String username) {
        if (username == null || username.trim().isEmpty()) return;
        final String key = username.trim().toLowerCase(Locale.US);
        synchronized (soulseekPeerWatchInFlight) {
            if (soulseekPeerWatchInFlight.contains(key)) {
                return;
            }
            soulseekPeerWatchInFlight.add(key);
        }
        ReachDbExecutor.run(new Runnable() {
            @Override
            public void run() {
                ReachDatabase.PeerCacheEntry cached =
                        ReachDatabase.getInstance(MainActivity.this).getPeerCacheSync(key);
                if (cached != null && cached.isFresh()) {
                    if (cached.country != null && !cached.country.isEmpty()) {
                        soulseekPeerCountry.put(key, cached.country);
                    }
                    soulseekPeerSharedFiles.put(key, cached.files);
                    synchronized (soulseekPeerWatchInFlight) {
                        soulseekPeerWatchInFlight.remove(key);
                    }
                    return;
                }
                SoulseekUserDirectory.watch(ensureSoulseekClient(), username,
                        new SoulseekUserDirectory.Callback() {
                    @Override
                    public void onUserInfo(SoulseekUserDirectory.UserInfo info) {
                        synchronized (soulseekPeerWatchInFlight) {
                            soulseekPeerWatchInFlight.remove(key);
                        }
                        if (info == null) return;
                        soulseekPeerSharedFiles.put(key, info.files);
                        if (info.country != null && !info.country.isEmpty()) {
                            soulseekPeerCountry.put(key, info.country);
                        }
                        ReachDatabase.getInstance(MainActivity.this).putPeerCache(
                                username, info.country, info.files, info.isOnline());
                        runOnUiThread(new Runnable() {
                            @Override
                            public void run() {
                                refreshSoulseekPeerCountryUi(username);
                            }
                        });
                    }

                    @Override
                    public void onError(String reason) {
                        synchronized (soulseekPeerWatchInFlight) {
                            soulseekPeerWatchInFlight.remove(key);
                        }
                    }
                });
            }
        });
    }

    private String soulseekPeerCountryCode(String username) {
        if (username == null) return null;
        if (SolarDeveloperAccounts.isVirtualPeer(username)) return null;
        return soulseekPeerCountry.get(username.trim().toLowerCase(Locale.US));
    }

    private void applySoulseekCountryFlag(android.widget.TextView tv, String country) {
        if (tv == null) return;
        android.graphics.drawable.Drawable flag = SoulseekCountryFlags.loadFlagDrawable(this, country);
        if (flag != null) {
            int pad = (int) (4 * getResources().getDisplayMetrics().density);
            flag.setBounds(0, 0, flag.getIntrinsicWidth(), flag.getIntrinsicHeight());
            tv.setCompoundDrawables(flag, null, null, null);
            tv.setCompoundDrawablePadding(pad);
        } else {
            tv.setCompoundDrawables(null, null, null, null);
        }
    }

    private void refreshSoulseekPeerCountryUi(String username) {
        if (username == null) return;
        String cc = soulseekPeerCountryCode(username);
        if (currentScreenState == STATE_SOULSEEK && soulseekUiMode == SOULSEEK_UI_RESULTS) {
            refreshSoulseekResultRowsForPeer(username);
        }
    }

    private void refreshSoulseekResultRowsForPeer(String username) {
        if (containerBrowserItems == null || username == null) return;
        String key = username.trim().toLowerCase(Locale.US);
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View child = containerBrowserItems.getChildAt(i);
            if (child instanceof Button) {
                Object tag = child.getTag();
                if (tag instanceof SoulseekClient.Result) {
                    SoulseekClient.Result r = (SoulseekClient.Result) tag;
                    if (r.username != null && r.username.toLowerCase(Locale.US).equals(key)) {
                        applySoulseekCountryFlag((Button) child, soulseekPeerCountryCode(r.username));
                    }
                }
            }
        }
    }

