    private void buildInternetCountrySettingsUI() {
        if (mediaSuite == null) return;
        setSettingsSubScreen(SettingsScreens.RADIO_INTERNET_COUNTRY);
        updateStatusBarTitle();
        containerSettingsItems.removeAllViews();

        Button btnBack = createListButton(getString(R.string.common_cancel_back));
        styleSecondaryLabel(btnBack);
        btnBack.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                drillSettingsBack(new Runnable() {
                    @Override
                    public void run() {
                        buildRadioSettingsUI();
                    }
                });
            }
        });
        containerSettingsItems.addView(btnBack);

        final LinearLayout loading = createSettingsRow("radio.country.loading",
                R.string.radio_net_loading_countries, false);
        TextView loadingState = loading.findViewWithTag("inline_state") instanceof TextView
                ? (TextView) loading.findViewWithTag("inline_state") : null;
        if (loadingState != null) loadingState.setText(getString(R.string.common_wait));
        loading.setEnabled(false);
        containerSettingsItems.addView(loading);

        new Thread(new Runnable() {
            @Override
            public void run() {
                final List<com.solar.launcher.radio.net.RadioBrowserClient.Country> countries =
                        new ArrayList<com.solar.launcher.radio.net.RadioBrowserClient.Country>();
                String err = null;
                try {
                    countries.addAll(new com.solar.launcher.radio.net.RadioBrowserClient(
                            MainActivity.this).listCountries());
                } catch (Exception e) {
                    err = e.getMessage();
                }
                final String fErr = err;
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (!SettingsScreens.RADIO_INTERNET_COUNTRY.equals(settingsSubScreenKey)) return;
                        containerSettingsItems.removeView(loading);
                        if (fErr != null) {
                            Button errRow = createListButton(getString(R.string.radio_net_load_error, fErr));
                            errRow.setEnabled(false);
                            containerSettingsItems.addView(errRow);
                            return;
                        }
                        final String current = mediaSuite.internetCountryLabel();
                        for (final com.solar.launcher.radio.net.RadioBrowserClient.Country c : countries) {
                            final String iso = c.isoCode;
                            LinearLayout row = createSettingsRow("radio.country." + iso,
                                    c.name + " (" + c.stationcount + ")", false, true);
                            TextView stateView = row.findViewWithTag("inline_state") instanceof TextView
                                    ? (TextView) row.findViewWithTag("inline_state") : null;
                            if (stateView != null) {
                                stateView.setText(iso.equalsIgnoreCase(current)
                                        ? getString(R.string.common_on) : "");
                            }
                            row.setOnClickListener(new View.OnClickListener() {
                                @Override
                                public void onClick(View v) {
                                    clickFeedback();
                                    mediaSuite.applyInternetCountry(iso);
                                    buildInternetCountrySettingsUI();
                                }
                            });
                            containerSettingsItems.addView(row);
                        }
                        if (containerSettingsItems.getChildCount() > 1) {
                            containerSettingsItems.getChildAt(1).requestFocus();
                        }
                    }
                });
            }
        }).start();
    }

    private boolean handleRadioSettingsBack() {
        if (SettingsScreens.RADIO_FM_BAND.equals(settingsSubScreenKey)
                || SettingsScreens.RADIO_INTERNET_COUNTRY.equals(settingsSubScreenKey)) {
            drillSettingsBack(new Runnable() {
                @Override
                public void run() {
                    buildRadioSettingsUI();
                }
            });
            return true;
        }
        if (SettingsScreens.RADIO.equals(settingsSubScreenKey)) {
            if (SettingsScreens.MEDIA.equals(settingsParentKey)) {
                drillSettingsBack(new Runnable() {
                    @Override
                    public void run() {
                        buildMediaSettingsUI();
                    }
                });
            } else {
                drillSettingsBack(new Runnable() {
                    @Override
                    public void run() {
                        buildSettingsUI();
                    }
                });
            }
            return true;
        }
        if (SettingsScreens.VIDEO.equals(settingsSubScreenKey)) {
            if (SettingsScreens.MEDIA.equals(settingsParentKey)) {
                drillSettingsBack(new Runnable() {
                    @Override
                    public void run() {
                        buildMediaSettingsUI();
                    }
                });
            } else {
                drillSettingsBack(new Runnable() {
                    @Override
                    public void run() {
                        buildSettingsUI();
                    }
                });
            }
            return true;
        }
        return false;
    }

    /** Reach master on and Soulseek service enabled. */
    private boolean soulseekActive() {
        return soulseekReachEnabled && soulseekEnabled;
    }

    /**
     * 2026-07-15 — Package hook for {@link SessionLifecycle}: keep Reach client for PM popups.
     * Layman: Session leave code asks "is chat still allowed to run?"
     */
    boolean soulseekActiveForSession() {
        return soulseekActive();
    }

    /** Reach master on and Deezer service enabled. */
    private boolean deezerActive() {
        return soulseekReachEnabled && deezerEnabled;
    }

    private void syncReachConnectivityFlags() {
        ConnectivityHelper.setReachEnabled(soulseekActive());
        ConnectivityHelper.setDeezerEnabled(deezerActive());
    }

    /**
     * Full Soulseek backend stop: no client, share scan, policy timer, NAT peer state, or
     * diag PM session. Safe to call when already off (idempotent). Energy / heat path.
     */
    private void stopSoulseekBackgroundWork() {
        soulseekPolicyDebounceHandler.removeCallbacks(soulseekPolicyDebounceRunnable);
        soulseekShareRescanPending = false;
        soulseekSearchInProgress = false;
        getMusicReachDone = true;
        if (soulseekClient != null) {
            try {
                soulseekClient.cancelSearch();
            } catch (Exception ignored) {}
            soulseekClient.shutdown();
            soulseekClient = null;
        }
        soulseekSharePolicy.setReachMasterEnabled(false);
        ConnectivityHelper.setReachEnabled(false);
        ConnectivityHelper.setReachLoginOk(false);
        ReachPeerConnectivity.reset();
        SolarDiagSessionManager.shutdown();
        syncReachConnectivityFlags();
        syncStatusBarSearchThrobber();
    }

    /** Tear down live Soulseek / Deezer work when a service is turned off. */
    private void applyReachServiceState() {
        syncReachConnectivityFlags();
        if (!soulseekActive()) {
            stopSoulseekBackgroundWork();
        } else {
            scheduleSoulseekSharePolicyRefresh();
        }
        if (!deezerActive()) {
            if (deezerScreen != null) deezerScreen.cancelSearch();
            ConnectivityHelper.setDeezerLoginOk(false);
        }
        if (soulseekActive()) {
            updateSoulseekSharePolicy();
        }
        buildHomeMenu();
    }

    private java.util.Map<String, Integer> shareDurationCache() {
        java.util.Map<String, Integer> cached = cachedShareDurations;
        if (cached != null) return cached;
        // 2026-07-16 — Full path→duration map is heap-heavy on Y1; skip rebuild under pressure.
        // Reversal: always load durationSecByPath().
        if (LowMemoryGate.shouldDeferHeavyWork(this)) {
            return java.util.Collections.emptyMap();
        }
        cached = MusicLibraryStore.getInstance(getApplicationContext()).durationSecByPath();
        cachedShareDurations = cached;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("count", cached != null ? cached.size() : 0);
            DebugSessionLog.log("MainActivity.shareDurationCache", "loaded", "H-CRASH1", d);
        } catch (Exception ignored) {}
        // #endregion
        return cached;
    }

    private void invalidateShareDurationCache() {
        cachedShareDurations = null;
    }

