    /** Fetches donators.xml when online — read-only thank-you names. 2026-07-05 */
    private void buildDonorsListUI() {
        setSettingsAboutFullWidth(true);
        setSettingsSubScreen(SettingsScreens.DONORS_LIST);
        updateStatusBarTitle();
        updateScreenBackground(STATE_SETTINGS);
        containerSettingsItems.removeAllViews();

        final int gen = ++donorsListLoadGen;
        Button loading = createListButton(getString(R.string.donors_loading));
        loading.setEnabled(false);
        containerSettingsItems.addView(loading);

        if (!ConnectivityHelper.isOnline(this)) {
            containerSettingsItems.removeAllViews();
            addSettingsInfoParagraph(getString(R.string.donors_load_failed));
            return;
        }

        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    final java.util.List<SolarDonatorsClient.Donator> donors =
                            SolarDonatorsClient.fetchDonators(SolarDonatorsClient.DEFAULT_DONATORS_URL);
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            if (gen != donorsListLoadGen) return;
                            if (!SettingsScreens.DONORS_LIST.equals(settingsSubScreenKey)) return;
                            renderDonorsListUI(donors);
                        }
                    });
                } catch (Exception e) {
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            if (gen != donorsListLoadGen) return;
                            if (!SettingsScreens.DONORS_LIST.equals(settingsSubScreenKey)) return;
                            containerSettingsItems.removeAllViews();
                            addSettingsInfoParagraph(getString(R.string.donors_load_failed));
                        }
                    });
                }
            }
        }).start();
    }

    /** Bind donor names after async fetch — rows are display-only. 2026-07-05 */
    private void renderDonorsListUI(java.util.List<SolarDonatorsClient.Donator> donors) {
        containerSettingsItems.removeAllViews();
        if (donors == null || donors.isEmpty()) {
            addSettingsInfoParagraph(getString(R.string.donors_empty));
            return;
        }
        for (SolarDonatorsClient.Donator donor : donors) {
            if (donor == null || donor.name == null || donor.name.trim().isEmpty()) continue;
            Button row = createListButton(donor.listLabel());
            row.setEnabled(false);
            row.setFocusable(false);
            containerSettingsItems.addView(row);
        }
    }

    private void buildAboutUI() {
        setSettingsAboutFullWidth(true);
        setSettingsSubScreen(SettingsScreens.ABOUT);
        updateStatusBarTitle();
        updateScreenBackground(STATE_SETTINGS);
        containerSettingsItems.removeAllViews();

        float density = getResources().getDisplayMetrics().density;
        int hPad = (int) (12 * density);
        int logoSize = (int) (96 * density);
        int rowW = settingsAboutFullWidth && screenWidthPx > 0
                ? screenWidthPx : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());

        LinearLayout content = new LinearLayout(this);
        content.setOrientation(LinearLayout.VERTICAL);
        content.setGravity(Gravity.CENTER_HORIZONTAL);
        content.setPadding(hPad, hPad, hPad, hPad);
        content.setFocusable(false);

        ImageView logo = new ImageView(this);
        Bitmap appIcon = loadAssetBitmap("logo/square_full_logo_colour.png");
        if (appIcon != null) {
            logo.setImageBitmap(appIcon);
            logo.setScaleType(ImageView.ScaleType.FIT_CENTER);
        }
        content.addView(logo, new LinearLayout.LayoutParams(logoSize, logoSize));

        TextView tvVersion = new TextView(this);
        tvVersion.setFocusable(false);
        tvVersion.setGravity(Gravity.CENTER);
        tvVersion.setSingleLine(true);
        tvVersion.setText(getString(R.string.about_version, AppVersion.displayLabel(this)));
        tvVersion.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        tvVersion.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size) * 1.1f);
        ThemeManager.applyThemedTextStyle(tvVersion, ThemeManager.getTextColorPrimary());
        LinearLayout.LayoutParams verLp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT);
        verLp.topMargin = hPad / 2;
        content.addView(tvVersion, verLp);

        TextView attribution = new TextView(this);
        attribution.setFocusable(false);
        attribution.setGravity(Gravity.CENTER);
        attribution.setText(buildAboutAttributionLine());
        attribution.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size));
        ThemeManager.applyThemedTextStyle(attribution, ThemeManager.getTextColorPrimary());
        LinearLayout.LayoutParams attrLp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT);
        attrLp.topMargin = hPad / 2;
        content.addView(attribution, attrLp);

        containerSettingsItems.addView(content, new LinearLayout.LayoutParams(
                rowW, LinearLayout.LayoutParams.WRAP_CONTENT));

        LinearLayout btnContact = createSettingsRow(RowKeys.CONTACT_DEVELOPER,
                R.string.settings_contact_developer, true);
        btnContact.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                openSolarDevelopmentThread();
            }
        });
        if (isDevSupportExperimentEnabled()) {
            containerSettingsItems.addView(btnContact);
        }

        LinearLayout btnDebug = createSettingsRow(RowKeys.DEBUG, R.string.settings_sub_debug, true);
        btnDebug.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                buildDebugUI();
            }
        });
        containerSettingsItems.addView(btnDebug);

        if (BuildConfig.FEATURE_OTA_UPDATE) {
            final Button otaProbe = createListButton(getString(R.string.update_checking));
            otaProbe.setEnabled(false);
            containerSettingsItems.addView(otaProbe);
            probeAboutOtaAvailability(otaProbe);
            otaProbe.requestFocus();
        } else if (containerSettingsItems.getChildCount() > 0) {
            containerSettingsItems.getChildAt(0).requestFocus();
        }
    }

    private boolean isDevSupportExperimentEnabled() {
        return SolarDeveloperAccounts.isExperimentEnabled(prefs);
    }

    private boolean canOpenDeveloperSupport() {
        return hasInternetConnection() && soulseekActive();
    }

    /** Standard PM thread to aggregated Solar Development peer — ships hidden diagnostics on open. */
    private void openSolarDevelopmentThread() {
        if (!isDevSupportExperimentEnabled()) return;
        if (!canOpenDeveloperSupport()) {
            Toast.makeText(this, R.string.settings_report_unreachable, Toast.LENGTH_LONG).show();
            return;
        }
        buildSoulseekConversationUI(SolarDeveloperAccounts.VIRTUAL_PEER);
    }

    /** Other Y1 Users / Find User — SolarDev profile stats under Solar Development label. */
    private void openSolarDevelopmentProfile() {
        if (!isDevSupportExperimentEnabled()) return;
        if (!canOpenDeveloperSupport()) {
            Toast.makeText(this, R.string.settings_report_unreachable, Toast.LENGTH_LONG).show();
            return;
        }
        showSoulseekConversationPanel(false);
        setSettingsSubScreen(SettingsScreens.SOULSEEK_FIND_REACH);
        updateStatusBarTitle();
        applyReachBrowseLayoutMode();
        containerSettingsItems.removeAllViews();
        Button loadingBack = createListButton(getString(R.string.soulseek_back_settings));
        loadingBack.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                buildSoulseekSettingsUI();
            }
        });
        containerSettingsItems.addView(loadingBack);
        Button loading = createListButton(getString(R.string.soulseek_searching));
        loading.setEnabled(false);
        containerSettingsItems.addView(loading);
        final int gen = ++soulseekReachUserActionsGen;
        SoulseekClient client = ensureSoulseekClient();
        if (client == null) {
            containerSettingsItems.removeAllViews();
            containerSettingsItems.addView(loadingBack);
            addSettingsInfoParagraph(getString(R.string.soulseek_reach_users_failed, "Offline"));
            return;
        }
        SoulseekUserDirectory.watch(client, SolarDeveloperAccounts.SOLAR_DEV,
                new SoulseekUserDirectory.Callback() {
            @Override
            public void onUserInfo(final SoulseekUserDirectory.UserInfo info) {
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (gen != soulseekReachUserActionsGen) return;
                        populateSolarDevelopmentActionsPanel(info, new Runnable() {
                            @Override
                            public void run() {
                                buildSoulseekSettingsUI();
                            }
                        });
                    }
                });
            }

            @Override
            public void onError(final String reason) {
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (gen != soulseekReachUserActionsGen) return;
                        populateSolarDevelopmentActionsPanel(null, new Runnable() {
                            @Override
                            public void run() {
                                buildSoulseekSettingsUI();
                            }
                        });
                    }
                });
            }
        });
    }

    /** Solar Development user panel — SolarDev stats, no country flag, no wire username. */
    private void populateSolarDevelopmentActionsPanel(final SoulseekUserDirectory.UserInfo info,
            final Runnable onBack) {
        containerSettingsItems.removeAllViews();
        Button btnBack = createListButton(getString(R.string.soulseek_back_settings));
        btnBack.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                onBack.run();
            }
        });
        containerSettingsItems.addView(btnBack);

        final String displayName = getString(R.string.solar_development_display_name);
        String status = info != null && info.isOnline()
                ? getString(R.string.soulseek_user_online) : getString(R.string.soulseek_user_offline);
        String filesLine = info != null && info.files > 0
                ? getString(R.string.soulseek_peer_files, info.files)
                : getString(R.string.soulseek_user_no_files);
        TextView tv = new TextView(this);
        tv.setText(getString(R.string.soulseek_reach_status_line, displayName, status, filesLine));
        tv.setTypeface(ThemeManager.getCustomFont());
        containerSettingsItems.addView(tv);

        if (info != null && info.username != null) {
            soulseekPeerSharedFiles.put(info.username.toLowerCase(Locale.US), info.files);
        }

        Button btnMsg = createListButton(getString(R.string.soulseek_compose_message));
        btnMsg.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                openSolarDevelopmentThread();
            }
        });
        containerSettingsItems.addView(btnMsg);

        if (containerSettingsItems.getChildCount() > 1) {
            containerSettingsItems.getChildAt(1).requestFocus();
        }
    }

    private void probeAboutOtaAvailability(final Button placeholder) {
        if (!ConnectivityHelper.isOnline(this)) {
            replaceAboutOtaPlaceholder(placeholder, null, true);
            return;
        }
        final String updatesUrl = OTA_UPDATES_URL != null && !OTA_UPDATES_URL.trim().isEmpty()
                ? OTA_UPDATES_URL.trim() : SolarUpdateClient.DEFAULT_UPDATES_URL;
        new Thread(new Runnable() {
            @Override
            public void run() {
                boolean ok = false;
                int releaseCount = 0;
                try {
                    List<SolarUpdateClient.ReleaseInfo> fetched =
                            SolarUpdateClient.fetchUpdates(updatesUrl);
                    releaseCount = fetched.size();
                    ok = releaseCount > 0;
                } catch (Exception ignored) {}
                final boolean reachable = ok;
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (!SettingsScreens.ABOUT.equals(settingsSubScreenKey)) return;
                        if (reachable) {
                            Button updateBtn = createListButton(getString(R.string.about_update_button));
                            updateBtn.setOnClickListener(new View.OnClickListener() {
                                @Override
                                public void onClick(View v) {
                                    clickFeedback();
                                    buildUpdateSettingsUI();
                                }
                            });
                            replaceAboutOtaPlaceholder(placeholder, updateBtn, false);
                        } else {
                            replaceAboutOtaPlaceholder(placeholder, null, true);
                        }
                    }
                });
            }
        }, "AboutOtaProbe").start();
    }

