    private void registerArtistCategory(java.util.HashMap<String, String> artistByKey, String raw) {
        if (raw == null) return;
        String trimmed = raw.trim();
        if (trimmed.isEmpty() || "Unknown Artist".equalsIgnoreCase(trimmed)) return;
        String display = trimmed;
        String key = ArtistNames.matchKey(display);
        String existing = artistByKey.get(key);
        if (existing == null) {
            artistByKey.put(key, display);
        } else {
            artistByKey.put(key, ArtistNames.preferCanonical(existing, display));
        }
    }

    private void registerAlbumCategory(java.util.HashMap<String, String> albumByKey, String raw) {
        if (raw == null) return;
        String trimmed = raw.trim();
        if (trimmed.isEmpty() || "Unknown Album".equalsIgnoreCase(trimmed)) return;
        String key = AlbumNames.matchKey(trimmed);
        String existing = albumByKey.get(key);
        if (existing == null) {
            albumByKey.put(key, trimmed);
        } else if (!existing.equals(trimmed)) {
            java.util.HashMap<String, Integer> counts = new java.util.HashMap<String, Integer>();
            counts.put(existing, 1);
            counts.put(trimmed, 1);
            albumByKey.put(key, AlbumNames.chooseCanonical(counts));
        }
    }

    /** Primary artist for album when browsed via a guest/feature credit. */
    private String albumOwnerArtistForBrowse(String album, String browsedArtist) {
        return ArtistBrowsePolicy.albumOwnerForBrowse(album, browsedArtist,
                policyTracksFromLibrary(), libraryBrowsePrefs);
    }

    private String albumBrowseSubtitle(String album) {
        String owner = ArtistBrowsePolicy.albumBrowseSubtitle(album, virtualQueryArtist,
                policyTracksFromLibrary(), libraryBrowsePrefs);
        if (owner == null || owner.trim().isEmpty()) return "";
        if (ArtistNames.equals(owner, virtualQueryArtist)) return "";
        return getString(R.string.library_album_by_artist, owner);
    }
    private char getInitialChar(String text) {
        if (text == null || text.isEmpty()) return '#';
        String clean = text.replace("📁 ", "").replace("👤 ", "")
                .replace("💿 ", "").replace("🎵 ", "").trim().toUpperCase();
        if (clean.isEmpty()) return '#';
        return clean.charAt(0);
    }

    /** 2026-07-06: JJ fast A–Z jump — 3+ wheel steps in 50ms scrolls by first letter. */
    private boolean handleLibraryListFastScroll(int keyCode) {
        if (listVirtualSongs == null || currentScrollIndexList.isEmpty()) return false;
        int wheelKey = Y1InputKeys.isWheelDown(keyCode) ? 22 : (Y1InputKeys.isWheelUp(keyCode) ? 21 : keyCode);
        if (wheelKey != 21 && wheelKey != 22) return false;

        long now = System.currentTimeMillis();
        if (now - lastWheelTime < 40 && wheelFastCount < 2) {
            lastWheelTime = now;
            return true;
        }
        boolean isFastScroll = false;
        if (now - lastWheelTime < 50) {
            wheelFastCount++;
            if (wheelFastCount >= 3) isFastScroll = true;
        } else {
            wheelFastCount = 0;
        }
        lastWheelTime = now;
        if (!isFastScroll) return false;

        int currentPos = listVirtualSongs.getSelectedItemPosition();
        if (currentPos < 0) currentPos = 0;
        char currentChar = getInitialChar(currentScrollIndexList.get(
                Math.min(currentPos, currentScrollIndexList.size() - 1)));
        int targetPos = currentPos;
        if (wheelKey == 22) {
            for (int i = currentPos + 1; i < currentScrollIndexList.size(); i++) {
                if (getInitialChar(currentScrollIndexList.get(i)) != currentChar) {
                    targetPos = i;
                    break;
                }
            }
        } else if (wheelKey == 21) {
            char targetChar = currentChar;
            boolean foundPrevChar = false;
            for (int i = currentPos - 1; i >= 0; i--) {
                char c = getInitialChar(currentScrollIndexList.get(i));
                if (!foundPrevChar && c != currentChar) {
                    foundPrevChar = true;
                    targetChar = c;
                }
                if (foundPrevChar && c != targetChar) {
                    targetPos = i + 1;
                    break;
                }
                if (i == 0) targetPos = 0;
            }
        }
        FocusScrollHelper.ensureListPositionVisible(listVirtualSongs, targetPos);
        clickFeedback();
        return true;
    }

    private void applyListWraparoundIfNeeded(int keyCode) {
        if (!listWraparound || listVirtualSongs == null || currentScrollIndexList.isEmpty()) return;
        int count = currentScrollIndexList.size();
        if (count < 2) return;
        int pos = listVirtualSongs.getSelectedItemPosition();
        if (Y1InputKeys.isWheelUp(keyCode) && pos <= 0) {
            FocusScrollHelper.ensureListPositionVisible(listVirtualSongs, count - 1);
        } else if (Y1InputKeys.isWheelDown(keyCode) && pos >= count - 1) {
            FocusScrollHelper.ensureListPositionVisible(listVirtualSongs, 0);
        }
    }

    private void saveAudiobookBookmarkIfNeeded() {
        if (mediaPlayer == null || !playback.isMusicActive() || playback.musicPlaylist().isEmpty()) return;
        File track = playback.musicPlaylist().get(playback.musicIndex());
        if (!com.solar.launcher.audiobook.AudiobookBookmarks.isAudiobookTrack(track)) return;
        try {
            int pos = mediaPlayer.getCurrentPosition();
            com.solar.launcher.audiobook.AudiobookBookmarks.save(
                    this, track, pos, playback.musicIndex());
        } catch (Exception ignored) {}
    }

    private boolean isLocalMusicFavoriteTarget(File audio) {
        if (audio == null || !audio.isFile()) return false;
        PlayQueue.QueueItem item = playback.currentItem();
        if (item != null && (item.kind == PlayQueue.ItemKind.REACH_STREAM
                || item.kind == PlayQueue.ItemKind.DEEZER_STREAM)) {
            return false;
        }
        return !isReachTempFile(audio) && !DeezerCache.isTempFile(streamAppCacheRoot(), audio);
    }

    private void addAlbumFavoriteContextActions(final String albumName, final String artistFilter) {
        if (albumName == null || albumName.trim().isEmpty()) return;
        final java.util.List<File> tracks = collectTracksForQuery(
                artistFilter != null ? "ARTIST_ALBUM" : "ALBUM", albumName, artistFilter);
        if (tracks.isEmpty()) return;
        boolean anyUnfav = false;
        for (File f : tracks) {
            if (!isMusicFavorite(f)) {
                anyUnfav = true;
                break;
            }
        }
        final boolean add = anyUnfav;
        addContextAction(getString(add ? R.string.context_add_album_to_favorites
                : R.string.context_remove_album_from_favorites), new Runnable() {
            @Override public void run() { toggleAlbumFavorites(tracks, add); }
        });
    }

    private void toggleAlbumFavorites(java.util.List<File> tracks, boolean favorite) {
        if (tracks == null) return;
        for (File f : tracks) {
            if (f == null) continue;
            String path = f.getAbsolutePath();
            MusicLibraryStore.getInstance(this).setFavorite(path, favorite);
            if (favorite) favoritePaths.add(path);
            else favoritePaths.remove(path);
        }
        if (currentBrowserMode == BROWSER_FAVORITES) buildVirtualSongsForFavorites();
    }

    private void toggleMusicFavorite(File audio) {
        if (audio == null) return;
        String path = audio.getAbsolutePath();
        boolean on = !favoritePaths.contains(path);
        MusicLibraryStore.getInstance(this).setFavorite(path, on);
        if (on) favoritePaths.add(path);
        else favoritePaths.remove(path);
        // Favorites browse needs row drop; elsewhere LED/check only. 2026-07-19
        if (currentBrowserMode == BROWSER_FAVORITES) {
            buildVirtualSongsForFavorites();
        } else if (listVirtualSongs != null
                && listVirtualSongs.getAdapter() instanceof android.widget.BaseAdapter) {
            ((android.widget.BaseAdapter) listVirtualSongs.getAdapter()).notifyDataSetChanged();
        }
    }

    private boolean isMusicFavorite(File audio) {
        return audio != null && favoritePaths.contains(audio.getAbsolutePath());
    }

    private void confirmDeleteSongFromDevice(final File audio) {
        if (audio == null || !audio.isFile()) return;
        showThemedConfirm(getString(R.string.context_delete_song),
                getString(R.string.context_delete_song_confirm),
                getString(R.string.context_delete_song),
                getString(R.string.common_cancel_back), new Runnable() {
            @Override public void run() {
                String path = audio.getAbsolutePath();
                if (audio.delete()) {
                    favoritePaths.remove(path);
                    MusicLibraryStore.getInstance(MainActivity.this).setFavorite(path, false);
                    pruneDeletedLibraryTracks(java.util.Collections.singletonList(path));
                }
            }
        });
    }

    private void confirmDeleteAlbumFromDevice(final String album, final String artistFilter) {
        if (album == null || album.trim().isEmpty()) return;
        showThemedConfirm(getString(R.string.context_delete_album),
                getString(R.string.context_delete_album_confirm),
                getString(R.string.context_delete_album),
                getString(R.string.common_cancel_back), new Runnable() {
            @Override public void run() {
                java.util.ArrayList<File> doomed = new java.util.ArrayList<File>();
                synchronized (customLibrary) {
                    for (SongItem song : customLibrary) {
                        if (!AlbumNames.equals(song.album, album)) continue;
                        if (artistFilter != null && !ArtistParser.containsArtist(song.artist, artistFilter)) continue;
                        if (song.file != null) doomed.add(song.file);
                    }
                }
                java.util.ArrayList<String> paths = new java.util.ArrayList<String>();
                for (File f : doomed) {
                    String path = f.getAbsolutePath();
                    f.delete();
                    favoritePaths.remove(path);
                    MusicLibraryStore.getInstance(MainActivity.this).setFavorite(path, false);
                    paths.add(path);
                }
                pruneDeletedLibraryTracks(paths);
            }
        });
    }

    /**
     * Drop deleted paths from RAM + SQLite without a full card walk.
     * Was: startLibraryScan(false) after every delete. Reversal: that call.
     * 2026-07-19
     */
    private void pruneDeletedLibraryTracks(java.util.List<String> paths) {
        if (paths == null || paths.isEmpty()) return;
        MusicLibraryStore store = MusicLibraryStore.getInstance(getApplicationContext());
        java.util.HashSet<String> doomed = new java.util.HashSet<String>(paths);
        synchronized (customLibrary) {
            for (int i = customLibrary.size() - 1; i >= 0; i--) {
                SongItem s = customLibrary.get(i);
                if (s != null && s.file != null && doomed.contains(s.file.getAbsolutePath())) {
                    customLibrary.remove(i);
                }
            }
        }
        for (String p : paths) {
            store.deletePath(p);
        }
        invalidateSongPathIndex();
        clearArtCacheReadyStamp();
        clearArtistOwnAlbumCache();
        refreshLibraryCategoryIndex();
        if (flowScreenHost != null) {
            flowScreenHost.invalidateCatalogCache();
        }
        refreshLibraryBrowseIfVisible();
        if (currentScreenState == STATE_BROWSER) {
            refreshBrowserAfterLibraryScan();
        }
    }
    // 💡 [추가] 아티스트/앨범 리스트 전용 10개 돌려막기 어댑터!
    private class CategoryListAdapter extends android.widget.BaseAdapter {
        private List<String> items;
        private String type;
        private String browseArtist;

        public CategoryListAdapter(List<String> items, String type, String browseArtist) {
            this.items = items;
            this.type = type;
            this.browseArtist = browseArtist;
        }

        @Override public int getCount() { return items.size(); }
        @Override public Object getItem(int position) { return items.get(position); }
        @Override public long getItemId(int position) { return position; }

        @Override
        public View getView(final int position, View convertView, android.view.ViewGroup parent) {
            final String name = items.get(position);
            final boolean artistAlbumBrowse = "ARTIST_ALBUM".equals(type) && browseArtist != null;

            if (artistAlbumBrowse) {
                final String subtitle = albumBrowseSubtitle(name);
                final int rowKind = Y1_ROW_ITEM;
                final int rowW = y1ActiveRowWidthPx();
                FrameLayout row;
                if (convertView instanceof FrameLayout && "artist_album_row".equals(convertView.getTag())) {
                    row = (FrameLayout) convertView;
                } else {
                    row = MoveRibbonRows.createLibraryMoveRow(MainActivity.this, y1LibraryRowHeightPx);
                    row.setTag("artist_album_row");
                    row.setFocusable(true);
                    row.setSoundEffectsEnabled(false);
                }
                applyLibraryListRowParams(row, y1LibraryRowHeightPx + 2);
                final String titleText = "💿 " + name;
                row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                    @Override
                    public void onFocusChange(View v, boolean hasFocus) {
                        MoveRibbonRows.bindLibraryMoveRow(MainActivity.this, row, titleText, subtitle,
                                false, hasFocus, false, false, rowW, y1LibraryRowHeightPx);
                        if (hasFocus) showFastScrollLetter(name);
                    }
                });
                // 2026-07-14 — A5: focus-then-confirm on artist→album MoveRibbon (was one-tap).
                A5FocusConfirm.setOnClickListener(row, new View.OnClickListener() {
                    @Override
                    public void onClick(View v) {
                        clickFeedback();
                        virtualQueryType = "ARTIST_ALBUM";
                        virtualQueryValue = name;
                        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
                        buildVirtualSongs();
                    }
                });
                attachA5RowLongPress(row);
                MoveRibbonRows.bindLibraryMoveRow(MainActivity.this, row, titleText, subtitle,
                        false, row.hasFocus(), false, false, rowW, y1LibraryRowHeightPx);
                return row;
            }

            final Button btn;

            if (convertView != null && convertView instanceof Button) {
                btn = (Button) convertView;
            } else {
                btn = createListButton("");
            }
            applyLibraryListRowParams(btn, y1RowHeightPx);

            String prefix = "👤 ";
            if ("ALBUM".equals(type) || "ARTIST_ALBUM".equals(type)) prefix = "💿 ";
            else if ("GENRE".equals(type)) prefix = "🎸 ";
            else if ("YEAR".equals(type)) prefix = "📅 ";
            btn.setText(prefix + name);

            final int rowKind = Y1_ROW_ITEM;
            final int rowW = y1ActiveRowWidthPx();
            btn.setBackground(getY1RowBackground(false, rowW, rowKind));
            ThemeManager.applyThemedTextStyle(btn, y1RowTextColorNormal(rowKind));
            btn.setSelected(false);
            btn.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    btn.setBackground(getY1RowBackground(hasFocus, rowW, rowKind));
                    ThemeManager.applyThemedTextStyle(btn, hasFocus
                            ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                    btn.setSelected(hasFocus);
                    if (hasFocus) showFastScrollLetter(name);
                }
            });

            btn.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    clickFeedback();
                    // 2026-07-15 — Audiobook Authors/Books stay in audiobookLibrary (not music browse).
                    if (isAudiobookLibraryMode) {
                        virtualQueryType = type;
                        virtualQueryValue = name;
                        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
                        buildAudiobookVirtualSongs();
                        return;
                    }
                    if ("ARTIST".equals(type)) {
                        openArtistBrowse(name);
                    } else if ("ARTIST_ALBUM".equals(type)) {
                        virtualQueryType = "ARTIST_ALBUM";
                        virtualQueryValue = name;
                        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
                        buildVirtualSongs();
                    } else {
                        virtualQueryType = type;
                        virtualQueryValue = name;
                        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
                        buildVirtualSongs();
                    }
                }
            });

            return btn;
        }
    }

    private void buildArtistAlbums() {
        if (isCustomScanning) {
            showLoadingPopup();
            currentBrowserMode = BROWSER_ROOT;
            buildFileBrowserUI();
            return;
        }
        scrollViewBrowser.setVisibility(View.GONE);
        listVirtualSongs.setVisibility(View.VISIBLE);
        browserStatusTitle = getString(R.string.status_path, virtualQueryArtist);
        updateStatusBarTitle();
        updateLibraryBreadcrumb();

        if (ArtistBrowsePolicy.shouldSkipAlbumPicker(virtualQueryArtist, libraryBrowsePrefs,
                policyTracksFromLibrary())) {
            virtualQueryType = "ARTIST";
            virtualQueryValue = virtualQueryArtist;
            virtualQueryArtist = "";
            currentBrowserMode = BROWSER_VIRTUAL_SONGS;
            buildVirtualSongs();
            return;
        }
        java.util.LinkedHashMap<String, String> albumsByKey = new java.util.LinkedHashMap<>();
        for (SongItem song : customLibrary) {
            if (!ArtistParser.containsArtist(song.artist, virtualQueryArtist)) continue;
            if (song.album == null || song.album.trim().isEmpty()) continue;
            String key = AlbumNames.matchKey(song.album);
            if (!albumsByKey.containsKey(key)) albumsByKey.put(key, song.album);
        }
        List<String> categories = new ArrayList<>(albumsByKey.values());
        java.util.Collections.sort(categories);
        currentScrollIndexList.clear();
        currentScrollIndexList.addAll(categories);
        CategoryListAdapter adapter = new CategoryListAdapter(categories, "ARTIST_ALBUM", virtualQueryArtist);
        listVirtualSongs.setAdapter(adapter);
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                if (listVirtualSongs.getChildCount() > 0) listVirtualSongs.getChildAt(0).requestFocus();
            }
        });
    }

    private void buildPlaylistsUI() {
        deezerPlaylistView = null;
        if (scrollViewBrowser != null) scrollViewBrowser.setVisibility(View.VISIBLE);
        if (listVirtualSongs != null) listVirtualSongs.setVisibility(View.GONE);
        containerBrowserItems.removeAllViews();
        browserStatusTitle = getString(R.string.status_library_playlists);
        updateStatusBarTitle();
        updateLibraryBreadcrumb();

        Button back = createListButton(getString(R.string.common_back));
        back.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                currentBrowserMode = BROWSER_ROOT;
                buildFileBrowserUI();
            }
        });
        containerBrowserItems.addView(back);

        // Local M3U playlists first — distinct from Deezer cloud browsing below.
        libraryPlaylists = PlaylistManager.scan(rootFolder);
        createBrowserSectionHeader(getString(R.string.library_playlists_local_section));

        Button newPlaylist = createListButton(getString(R.string.library_new_playlist));
        newPlaylist.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                pendingPlaylistTracks = null;
                openPlaylistNameKeyboard(true);
            }
        });
        containerBrowserItems.addView(newPlaylist);

        if (libraryPlaylists.isEmpty()) {
            Button empty = createListButton(getString(R.string.library_playlists_empty));
            empty.setEnabled(false);
            containerBrowserItems.addView(empty);
        } else {
            for (final PlaylistManager.Entry pl : libraryPlaylists) {
                Button b = createListButton("📋 " + pl.name + " (" + pl.tracks.size() + ")");
                b.setTag(pl);
                b.setOnClickListener(new View.OnClickListener() {
                    @Override
                    public void onClick(View v) {
                        clickFeedback();
                        virtualQueryType = "PLAYLIST";
                        virtualQueryValue = pl.name;
                        buildVirtualSongsFromPlaylist(pl);
                    }
                });
                containerBrowserItems.addView(b);
            }
        }

        Button saveQueue = createListButton(getString(R.string.library_save_queue_m3u));
        saveQueue.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                saveMusicQueueAsM3u();
            }
        });
        containerBrowserItems.addView(saveQueue);

        if (deezerActive() && DeezerAccount.hasArl(prefs)) {
            createBrowserSectionHeader(getString(R.string.deezer_playlists_section), "deezer_pl_section");
            Button loading = createListButton(getString(R.string.deezer_playlists_loading));
            loading.setEnabled(false);
            loading.setTag("deezer_pl_loading");
            containerBrowserItems.addView(loading);
            loadDeezerPlaylistsAsync();
        } else if (deezerActive()) {
            createBrowserSectionHeader(getString(R.string.deezer_playlists_section), "deezer_pl_section");
            Button unavailable = createListButton(getString(R.string.deezer_playlists_unavailable));
            unavailable.setEnabled(false);
            containerBrowserItems.addView(unavailable);
        }

        // Default focus: first local action (new playlist, or first saved list).
        int focusIdx = libraryPlaylists.isEmpty() ? 2 : 3;
        if (focusIdx < containerBrowserItems.getChildCount()) {
            containerBrowserItems.getChildAt(focusIdx).requestFocus();
        }
    }

    /** Index inside containerBrowserItems for inserting Deezer cloud playlist rows. */
    private int deezerPlaylistInsertIndex() {
        View loading = containerBrowserItems.findViewWithTag("deezer_pl_loading");
        if (loading != null) return containerBrowserItems.indexOfChild(loading);
        View header = containerBrowserItems.findViewWithTag("deezer_pl_section");
        if (header != null) return containerBrowserItems.indexOfChild(header) + 1;
        return containerBrowserItems.getChildCount();
    }

    private void loadDeezerPlaylistsAsync() {
        deezerPlaylistsLoadGen++;
        final int gen = deezerPlaylistsLoadGen;
        new Thread(new Runnable() {
            @Override public void run() {
                List<DeezerPlaylist> found = new ArrayList<DeezerPlaylist>();
                String err = null;
                try {
                    DeezerClient c = new DeezerClient(prefs);
                    if (!c.isSessionValid()) c.initSession();
                    long userId = DeezerAccount.loadUserId(prefs);
                    if (userId <= 0) throw new IOException("No user id");
                    DeezerSearch search = new DeezerSearch(c);
                    found = search.listUserPlaylists(userId);
                } catch (Exception e) {
                    err = e.getMessage();
                }
                final List<DeezerPlaylist> ff = found;
                final String ferr = err;
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (gen != deezerPlaylistsLoadGen) return;
                        if (currentBrowserMode != BROWSER_PLAYLISTS) return;
                        deezerPlaylistsCache.clear();
                        deezerPlaylistsCache.addAll(ff);
                        View loading = containerBrowserItems.findViewWithTag("deezer_pl_loading");
                        int insertAt = deezerPlaylistInsertIndex();
                        if (loading != null) {
                            insertAt = containerBrowserItems.indexOfChild(loading);
                            containerBrowserItems.removeView(loading);
                        }
                        if (ff.isEmpty()) {
                            Button empty = createListButton(ferr != null
                                    ? getString(R.string.deezer_playlist_save_failed, ferr)
                                    : getString(R.string.deezer_playlists_empty));
                            empty.setEnabled(false);
                            containerBrowserItems.addView(empty, insertAt);
                        } else {
                            for (final DeezerPlaylist pl : ff) {
                                Button b = createListButton("♫ " + pl.title + " ("
                                        + getString(R.string.deezer_playlist_tracks, pl.trackCount) + ")");
                                b.setTag(pl);
                                b.setOnClickListener(new View.OnClickListener() {
                                    @Override public void onClick(View v) {
                                        clickFeedback();
                                        openDeezerPlaylistBrowse(pl);
                                    }
                                });
                                containerBrowserItems.addView(b, insertAt);
                                insertAt++;
                            }
                        }
                    }
                });
            }
        }, "DeezerPlaylists").start();
    }

    private void openDeezerPlaylistBrowse(final DeezerPlaylist pl) {
        if (pl == null) return;
        deezerPlaylistView = pl;
        currentBrowserMode = BROWSER_DEEZER_PLAYLIST;
        deezerPlaylistTracks.clear();
        containerBrowserItems.removeAllViews();
        browserStatusTitle = pl.title;
        updateStatusBarTitle();
        updateLibraryBreadcrumb();

        Button back = createListButton(getString(R.string.common_back));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                currentBrowserMode = BROWSER_PLAYLISTS;
                deezerPlaylistView = null;
                buildPlaylistsUI();
            }
        });
        containerBrowserItems.addView(back);

        Button loading = createListButton(getString(R.string.get_music_loading_container));
        loading.setEnabled(false);
        containerBrowserItems.addView(loading);

        new Thread(new Runnable() {
            @Override public void run() {
                List<DeezerResult> tracks = new ArrayList<DeezerResult>();
                String err = null;
                try {
                    DeezerClient c = new DeezerClient(prefs);
                    if (!c.isSessionValid()) c.initSession();
                    tracks = new DeezerSearch(c).listPlaylistTracks(pl.id);
                } catch (Exception e) {
                    err = e.getMessage();
                }
                final List<DeezerResult> tt = tracks;
                final String ferr = err;
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (deezerPlaylistView == null || deezerPlaylistView.id != pl.id) return;
                        deezerPlaylistTracks.clear();
                        deezerPlaylistTracks.addAll(tt);
                        buildDeezerPlaylistDetailUI(ferr);
                    }
                });
            }
        }, "DeezerPlTracks").start();
    }

    private void buildDeezerPlaylistDetailUI(String loadError) {
        if (deezerPlaylistView == null) return;
        containerBrowserItems.removeAllViews();

        Button back = createListButton(getString(R.string.common_back));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                currentBrowserMode = BROWSER_PLAYLISTS;
                deezerPlaylistView = null;
                buildPlaylistsUI();
            }
        });
        containerBrowserItems.addView(back);

        if (loadError != null && loadError.length() > 0) {
            Button err = createListButton(getString(R.string.deezer_playlist_save_failed, loadError));
            err.setEnabled(false);
            containerBrowserItems.addView(err);
            return;
        }
        if (deezerPlaylistTracks.isEmpty()) {
            Button empty = createListButton(getString(R.string.get_music_empty_results));
            empty.setEnabled(false);
            containerBrowserItems.addView(empty);
            return;
        }

        Button play = createListButton(getString(R.string.deezer_playlist_play));
        play.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                playDeezerPlaylistFromIndex(new ArrayList<DeezerResult>(deezerPlaylistTracks), 0);
            }
        });
        containerBrowserItems.addView(play);

        Button save = createListButton(getString(R.string.deezer_playlist_save));
        save.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                saveDeezerPlaylistToDevice(deezerPlaylistView,
                        new ArrayList<DeezerResult>(deezerPlaylistTracks));
            }
        });
        containerBrowserItems.addView(save);

        for (int i = 0; i < deezerPlaylistTracks.size(); i++) {
            final DeezerResult tr = deezerPlaylistTracks.get(i);
            final int idx = i;
            String sub = GetMusicSearch.formatDeezerSubtitle(tr);
            View row = createGetMusicListRow(tr.title, sub, new View.OnClickListener() {
                @Override public void onClick(View v) {
                    clickFeedback();
                    playDeezerPlaylistFromIndex(new ArrayList<DeezerResult>(deezerPlaylistTracks), idx);
                }
            });
            row.setTag(tr);
            containerBrowserItems.addView(row);
        }
        if (containerBrowserItems.getChildCount() > 1) containerBrowserItems.getChildAt(1).requestFocus();
    }

    private void saveDeezerPlaylistToDevice(final DeezerPlaylist playlist,
            final List<DeezerResult> tracks) {
        if (playlist == null || tracks == null || tracks.isEmpty()) return;
        if (!requireInternet(R.string.deezer_wifi_required)) return;
        deezerPlaylistSaveGen++;
        final int gen = deezerPlaylistSaveGen;
        Button progress = createListButton(getString(R.string.deezer_playlist_saving, 0, tracks.size()));
        progress.setEnabled(false);
        progress.setTag("deezer_save_progress");
        if (currentBrowserMode == BROWSER_DEEZER_PLAYLIST) {
            containerBrowserItems.removeAllViews();
            containerBrowserItems.addView(progress);
        }
        DeezerPlaylistSaver.save(prefs, rootFolder, playlist, tracks, new DeezerPlaylistSaver.Listener() {
            @Override public void onProgress(int done, int total, String trackTitle) {
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (gen != deezerPlaylistSaveGen) return;
                        progress.setText(getString(R.string.deezer_playlist_saving, done + 1, total));
                    }
                });
            }
            @Override public void onComplete(File m3uFile, List<File> saved) {
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (gen != deezerPlaylistSaveGen) return;
                        scanMediaLibraryAsync();
                        Toast.makeText(MainActivity.this, getString(R.string.deezer_playlist_saved),
                                Toast.LENGTH_SHORT).show();
                        currentBrowserMode = BROWSER_PLAYLISTS;
                        deezerPlaylistView = null;
                        buildPlaylistsUI();
                    }
                });
            }
            @Override public void onError(String message) {
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (gen != deezerPlaylistSaveGen) return;
                        showGlobalContextAlert(playlist.title,
                                getString(R.string.deezer_playlist_save_failed, message));
                        buildDeezerPlaylistDetailUI("");
                    }
                });
            }
        });
    }

    private void playDeezerPlaylistFromIndex(List<DeezerResult> tracks, int startIndex) {
        if (tracks == null || tracks.isEmpty()) return;
        if (!requireInternet(R.string.deezer_wifi_required)) return;
        if (!GetMusicSources.deezerConfiguredForGetMusic(prefs, deezerActive())) {
            Toast.makeText(this, getString(R.string.deezer_not_configured), Toast.LENGTH_LONG).show();
            return;
        }
        int idx = Math.max(0, Math.min(startIndex, tracks.size() - 1));
        deezerPlaylistPlayback = new ArrayList<DeezerResult>(tracks);
        deezerPlaylistPlaybackIndex = idx;
        saveCurrentPodcastResume();
        stopPodcastDownloadFully();
        finalizeReachStreamHandoff();
        // 2026-07-15 — Kill YouTube Music IJK / video before playlist transfer starts.
        stopCompetingAudioEngines();
        playback.clearQueue();
        try {
            if (mediaPlayer != null) mediaPlayer.reset();
        } catch (Exception ignored) {}
        playerReturnScreen = currentScreenState;
        startDeezerPlaylistTransferAt(idx, DeezerScreen.ACTION_PLAY);
    }

    private void startDeezerPlaylistTransferAt(final int index, final int action) {
        if (deezerPlaylistPlayback == null || index < 0 || index >= deezerPlaylistPlayback.size()) return;
        final DeezerResult r = deezerPlaylistPlayback.get(index);
        deezerPlaylistPlaybackIndex = index;
        if (deezerScreen == null) deezerScreen = new DeezerScreen(deezerHost);
        deezerScreen.startTransfer(r, action);
    }

    private void advanceDeezerPlaylistIfNeeded() {
        if (deezerPlaylistPlayback == null || deezerPlaylistPlaybackIndex < 0) return;
        int next = deezerPlaylistPlaybackIndex + 1;
        if (next >= deezerPlaylistPlayback.size()) {
            deezerPlaylistPlayback = null;
            deezerPlaylistPlaybackIndex = -1;
            return;
        }
        deezerPlaylistPlaybackIndex = next;
        startDeezerPlaylistTransferAt(next, DeezerScreen.ACTION_PLAY);
    }

    private void buildVirtualSongsFromPlaylist(final PlaylistManager.Entry pl) {
        resetPlaylistMoveState();
        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
        scrollViewBrowser.setVisibility(View.GONE);
        listVirtualSongs.setVisibility(View.VISIBLE);
        virtualQueryType = "PLAYLIST";
        virtualQueryValue = pl.name;
        playlistViewEntry = pl;
        browserStatusTitle = getString(R.string.status_path, pl.name);
        updateStatusBarTitle();
        updateLibraryBreadcrumb();
        virtualSongList.clear();
        virtualSongList.addAll(pl.tracks);
        currentScrollIndexList.clear();
        final List<SongItem> targetSongs = new ArrayList<SongItem>();
        for (File f : pl.tracks) {
            SongItem si = findSongItem(f);
            if (si != null) {
                targetSongs.add(si);
                currentScrollIndexList.add(si.title);
            } else {
                targetSongs.add(new SongItem(f, f.getName(), "", "", ""));
                currentScrollIndexList.add(f.getName());
            }
        }
        setSongListAdapter(targetSongs, true);
        playlistListFocusIndex = 0;
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                focusPlaylistListRow(0);
            }
        });
    }

    private SongItem findSongItem(File f) {
        if (f == null) return null;
        ensureSongPathIndex();
        SongItem cached = songPathIndex.get(f.getAbsolutePath());
        if (cached != null) return cached;
        for (SongItem s : customLibrary) {
            if (f.equals(s.file)) return s;
        }
        return null;
    }

    private void ensureSongPathIndex() {
        if (songPathIndex != null) return;
        songPathIndex = new java.util.HashMap<String, SongItem>();
        java.util.ArrayList<SongItem> snap = new java.util.ArrayList<SongItem>(customLibrary);
        for (SongItem s : snap) {
            if (s.file != null) songPathIndex.put(s.file.getAbsolutePath(), s);
        }
    }

    private void patchLibraryMetadataForPath(String path, String title, String artist, String album) {
        if (path == null) return;
        for (SongItem song : customLibrary) {
            if (song.file != null && path.equals(song.file.getAbsolutePath())) {
                if (title != null && !title.trim().isEmpty()) song.title = title.trim();
                if (artist != null && !artist.trim().isEmpty()) song.artist = artist.trim();
                if (album != null && !album.trim().isEmpty()) song.album = album.trim();
                if (song.file.isFile()) {
                    MusicLibraryStore.getInstance(getApplicationContext()).upsert(
                            song.file, song.title, song.artist, song.album, song.genre,
                            song.albumArtist, "", song.trackNumber);
                }
                invalidateSongPathIndex();
                if (currentScreenState == STATE_BROWSER && currentBrowserMode == BROWSER_VIRTUAL_SONGS) {
                    buildVirtualSongs();
                }
                return;
            }
        }
    }

    /** Wi‑Fi auto-fetch when tags or album art are missing (runs even if embedded art exists). */
    private void maybeAutoFetchTrackInfo(final File track, final AudioTags.Info tags,
            final String safeFileName, final boolean hasDeezerMeta) {
        if (!isAutoFetchEnabled || hasDeezerMeta || track == null || tags == null) return;
        final boolean needsMeta = !AudioTags.hasValidTags(tags)
                || tags.album.isEmpty() || "Unknown Album".equalsIgnoreCase(tags.album.trim());
        final boolean needsArt = tags.embeddedArt == null || tags.embeddedArt.length == 0;
        if (!needsMeta && !needsArt) return;
        android.net.wifi.WifiManager wm = (android.net.wifi.WifiManager)
                getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm == null || !wm.isWifiEnabled() || wm.getConnectionInfo().getNetworkId() == -1) return;

        String searchQuery;
        if (AudioTags.hasValidTags(tags)) {
            searchQuery = tags.artist + " " + tags.title;
        } else {
            searchQuery = safeFileName.replace("-", " ").replace("_", " ");
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("file", track.getName());
            d.put("needsMeta", needsMeta);
            d.put("needsArt", needsArt);
            d.put("query", searchQuery);
            DebugAgentLog.log(this, "MainActivity.maybeAutoFetchTrackInfo", "auto-fetch", "H-C", d);
        } catch (Exception ignored) {}
        // #endregion
        fetchTrackInfoFromInternet(track, searchQuery, AudioTags.hasValidTags(tags),
                tags.title, tags.artist);
    }

    private void invalidateSongPathIndex() {
        songPathIndex = null;
        cachedPolicyTracks = null;
        flowLibraryRowsCache.invalidate();
        libraryCategoryIndex.invalidate();
        libraryRamCache.invalidate();
    }

    /** 2026-07-06: Rebuild category index after library bind. */
    private void refreshLibraryCategoryIndex() {
        libraryCategoryIndex.rebuild(libraryScanGen, flowLibraryRows());
        refreshLibraryRamCache();
    }

    /**
     * 2026-07-18 — Rebuild Tier-0 artist/album RAM indexes (+ segment mode) after hydrate.
     * Layman: remember who/what albums exist so Artists opens without re-reading every file.
     * Technical: NavRow list from customLibrary; LibraryMemoryBudget picks FULL vs SEGMENTED.
     */
    private void refreshLibraryRamCache() {
        java.util.ArrayList<com.solar.launcher.library.LibraryRamCache.NavRow> rows =
                new java.util.ArrayList<com.solar.launcher.library.LibraryRamCache.NavRow>();
        synchronized (customLibrary) {
            for (SongItem s : customLibrary) {
                if (s == null) continue;
                String path = s.file != null ? s.file.getAbsolutePath() : "";
                rows.add(new com.solar.launcher.library.LibraryRamCache.NavRow(
                        path, s.artist, s.album));
            }
        }
        libraryRamCache.rebuild(libraryScanGen, rows);
    }

    private List<FlowCatalog.SongRow> flowLibraryRows() {
        return flowLibraryRowsCache.rows(customLibrary, libraryScanGen);
    }

    private List<LibrarySearch.SearchRow> flowLibrarySearchRows() {
        return flowLibraryRowsCache.searchRows(customLibrary, libraryScanGen);
    }


    private boolean isPodcastMediaFile(File f) {
        if (f == null) return false;
        String p = f.getAbsolutePath();
        // 2026-07-15 — Podcasts may live on any browsable volume.
        for (File root : PodcastLibrary.getPodcastRootsSafe()) {
            if (root == null) continue;
            String rootPath = root.getAbsolutePath();
            if (p.equals(rootPath) || p.startsWith(rootPath + File.separator)) return true;
        }
        return false;
    }

    private boolean isMusicBrowseContextFile(File f) {
        return f != null && f.isFile() && isAudioFile(f) && !isPodcastMediaFile(f)
                && !isReachTempFile(f) && !DeezerCache.isTempFile(streamAppCacheRoot(), f);
    }

    private SongItem resolveSongMetadata(File f) {
        SongItem si = findSongItem(f);
        if (si != null) return si;
        if (!isMusicBrowseContextFile(f)) return null;
        AudioTags.Info tags = AudioTags.read(f, prefs);
        String title = tags.title;
        String artist = tags.artist;
        String album = tags.album;
        String genre = tags.genre != null && !tags.genre.isEmpty() ? tags.genre : "Unknown Genre";
        if (artist.isEmpty()) artist = "Unknown Artist";
        if (album.isEmpty()) album = "Unknown Album";
        return new SongItem(f, title, artist, album, genre, tags.albumArtist, tags.trackNumber, tags.year);
    }

    private boolean isOnSameMusicListing(String type, String value, String artistForAlbum) {
        if (currentScreenState != STATE_BROWSER || currentBrowserMode != BROWSER_VIRTUAL_SONGS) return false;
        if (type == null || !type.equals(virtualQueryType)) return false;
        if (value == null || !value.equals(virtualQueryValue)) return false;
        if ("ARTIST_ALBUM".equals(type)) {
            return ArtistParser.containsArtist(artistForAlbum, virtualQueryArtist)
                    && value != null && value.equals(virtualQueryValue);
        }
        if ("ARTIST".equals(type) && value != null) {
            return value.equals(virtualQueryValue);
        }
        return true;
    }

    private void openMusicArtistListing(final String artist) {
        if (artist == null || artist.trim().isEmpty()) return;
        changeScreen(STATE_BROWSER);
        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
        virtualQueryType = "ARTIST";
        virtualQueryValue = ArtistNames.normalizeDisplay(artist);
        virtualQueryArtist = "";
        buildVirtualSongs();
    }

    private void openMusicAlbumListing(final String artist, final String album) {
        if (album == null || album.trim().isEmpty()) return;
        changeScreen(STATE_BROWSER);
        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
        if (artist != null && !artist.trim().isEmpty() && !"Unknown Artist".equals(artist)) {
            virtualQueryType = "ARTIST_ALBUM";
            virtualQueryValue = album;
            virtualQueryArtist = artist;
        } else {
            virtualQueryType = "ALBUM";
            virtualQueryValue = album;
            virtualQueryArtist = "";
        }
        buildVirtualSongs();
    }

    private void openMusicGenreListing(final String genre) {
        if (genre == null || genre.trim().isEmpty() || "Unknown Genre".equals(genre)) return;
        changeScreen(STATE_BROWSER);
        currentBrowserMode = BROWSER_VIRTUAL_SONGS;
        virtualQueryType = "GENRE";
        virtualQueryValue = genre;
        virtualQueryArtist = "";
        buildVirtualSongs();
    }

    private void openMusicPlaylistListing(final String name) {
        if (name == null || name.trim().isEmpty()) return;
        java.util.List<PlaylistManager.Entry> lists = libraryPlaylists;
        if (lists == null || lists.isEmpty()) lists = PlaylistManager.scan(rootFolder);
        for (PlaylistManager.Entry pl : lists) {
            if (name.equals(pl.name)) {
                changeScreen(STATE_BROWSER);
                currentBrowserMode = BROWSER_VIRTUAL_SONGS;
                buildVirtualSongsFromPlaylist(pl);
                return;
            }
        }
    }

    /** Focused local track for context menus — NP, song lists, folders, favorites. */
    private File focusedMusicTrackForContext() {
        if (currentScreenState == STATE_FLOW && flowScreenHost != null && flowScreenHost.isFlipped()) {
            FlowScreenHost.FlowBackRow row = flowScreenHost.getSelectedBackRow();
            if (row != null && row.track != null && row.track.isFile()) return row.track;
        }
        if (currentScreenState == STATE_PLAYER && playback.isMusicActive()) {
            java.util.List<File> q = playback.musicPlaylist();
            int i = playback.musicIndex();
            if (i >= 0 && i < q.size()) return q.get(i);
        }
        if (currentScreenState == STATE_BROWSER) {
            // 2026-07-15 — Favorites share the virtual song list UI under BROWSER_FAVORITES.
            if (currentBrowserMode == BROWSER_VIRTUAL_SONGS
                    || currentBrowserMode == BROWSER_FAVORITES) {
                return virtualFocusedAudioFile();
            }
            if (currentBrowserMode == BROWSER_FOLDER && !isPickingBackground) return browserFocusedAudioFile();
        }
        return null;
    }

    private static final int FIND_LIKE_SUGGESTIONS_MAX = 10;

    private void addMusicBrowseContextActions(File trackFile, String playlistNameIfAny) {
        if (!isMusicBrowseContextFile(trackFile)) return;
        final SongItem si = resolveSongMetadata(trackFile);
        if (si == null) return;

        java.util.List<String> creditedArtists = ArtistParser.splitArtists(si.artist);
        if (creditedArtists.isEmpty() && si.artist != null && !si.artist.trim().isEmpty()
                && !"Unknown Artist".equals(si.artist)) {
            creditedArtists = java.util.Collections.singletonList(si.artist.trim());
        }
        for (final String artistName : creditedArtists) {
            if (!isOnSameMusicListing("ARTIST", artistName, null)) {
                addContextAction(getString(R.string.context_browse_artist, artistName), new Runnable() {
                    @Override
                    public void run() {
                        openMusicArtistListing(artistName);
                    }
                });
            }
        }
        if (si.album != null && !si.album.trim().isEmpty() && !"Unknown Album".equals(si.album)) {
            final String listingType = !creditedArtists.isEmpty() ? "ARTIST_ALBUM" : "ALBUM";
            final String albumArtist = creditedArtists.isEmpty() ? si.artist
                    : ArtistParser.primaryArtist(si.artist);
            if (!isOnSameMusicListing(listingType, si.album, albumArtist)) {
                addContextAction(getString(R.string.context_browse_album, si.album), new Runnable() {
                    @Override
                    public void run() {
                        openMusicAlbumListing(albumArtist, si.album);
                    }
                });
            }
            // 2026-07-15 — Track menus open album Flow scrolled to this cover (not from NP — that uses handoff).
            // Was: track context had browse/playlist only. Reversal: drop addFlowAlbumFromTrackContextAction call.
            if (currentScreenState != STATE_PLAYER && currentScreenState != STATE_FLOW) {
                addFlowAlbumFromTrackContextAction(si);
            }
        }
        if (si.genre != null && !si.genre.trim().isEmpty() && !"Unknown Genre".equals(si.genre)
                && !isOnSameMusicListing("GENRE", si.genre, null)) {
            addContextAction(getString(R.string.context_browse_genre, si.genre), new Runnable() {
                @Override
                public void run() {
                    openMusicGenreListing(si.genre);
                }
            });
        }
        if (deezerPlaylistActionsAvailable()) {
            addContextAction(getString(R.string.context_add_to_local_playlist), new Runnable() {
                @Override public void run() {
                    openAddToPlaylistFlow(java.util.Collections.singletonList(trackFile));
                }
            });
        } else {
            addContextAction(getString(R.string.context_action_add_to_playlist), new Runnable() {
                @Override
                public void run() {
                    openAddToPlaylistFlow(java.util.Collections.singletonList(trackFile));
                }
            });
        }
        if (playlistNameIfAny != null && !playlistNameIfAny.isEmpty()
                && !isOnSameMusicListing("PLAYLIST", playlistNameIfAny, null)) {
            addContextAction(getString(R.string.context_browse_playlist, playlistNameIfAny), new Runnable() {
                @Override
                public void run() {
                    openMusicPlaylistListing(playlistNameIfAny);
                }
            });
        }
        // 2026-07-19 — Stem Player / Mix / Instrumental / Acapella (opt-in or local solo cache).
        if (com.solar.launcher.stem.StemFeatures.showCloudStemMenus(prefs)) {
            addContextAction(getString(R.string.context_action_stem_player), new Runnable() {
                @Override
                public void run() {
                    enterStemPickBrowse();
                }
            });
        }
        File cacheDir = getCacheDir();
        final File instrLocal = com.solar.launcher.stem.LalalClient.findReadySoloFile(
                this, trackFile, com.solar.launcher.stem.SoloMode.INSTRUMENTAL, cacheDir);
        final File acapLocal = com.solar.launcher.stem.LalalClient.findReadySoloFile(
                this, trackFile, com.solar.launcher.stem.SoloMode.ACAPELLA, cacheDir);
        if (com.solar.launcher.stem.StemFeatures.showSoloMenu(prefs, instrLocal != null)) {
            final File srcInstr = trackFile;
            addContextAction(getString(R.string.context_action_play_instrumental), new Runnable() {
                @Override
                public void run() {
                    playSoloStemMode(srcInstr, com.solar.launcher.stem.SoloMode.INSTRUMENTAL);
                }
            });
        }
        if (com.solar.launcher.stem.StemFeatures.showSoloMenu(prefs, acapLocal != null)) {
            final File srcAcap = trackFile;
            addContextAction(getString(R.string.context_action_play_acapella), new Runnable() {
                @Override
                public void run() {
                    playSoloStemMode(srcAcap, com.solar.launcher.stem.SoloMode.ACAPELLA);
                }
            });
        }
        // 2026-07-19 — Start Mix with this song in slot 1 (opt-in).
        if (trackFile != null && trackFile.isFile()
                && com.solar.launcher.stem.StemFeatures.showCloudStemMenus(prefs)) {
            final File mixSeed = trackFile;
            addContextAction(getString(R.string.context_action_start_mix), new Runnable() {
                @Override
                public void run() {
                    enterMixAssignBrowse(-1, mixSeed);
                }
            });
        }
        boolean playerOffline = currentScreenState == STATE_PLAYER
                && !ConnectivityHelper.isOnline(this);
        boolean reachSearch = !playerOffline
                && (ConnectivityHelper.isReachPeerOk()
                || ReachPeerConnectivity.state() != ReachPeerConnectivity.State.UNAVAILABLE);
        boolean deezerSearch = !playerOffline && deezerActive() && ConnectivityHelper.isDeezerLoginOk();
        if (reachSearch || deezerSearch) {
            List<String> findLike = SoulseekSearchSuggestions.suggestionsFromId3(
                    si.title, si.artist, si.album, si.genre);
            java.util.LinkedHashSet<String> interestTerms = new java.util.LinkedHashSet<String>();
            interestTerms.addAll(findLike);
            if (si.genre != null && !si.genre.trim().isEmpty()) {
                interestTerms.add(si.genre.trim());
            }
            String primaryArtist = si.artist != null && !si.artist.trim().isEmpty()
                    ? ArtistParser.primaryArtist(si.artist) : null;
            if (primaryArtist != null && !primaryArtist.trim().isEmpty()) {
                interestTerms.add(primaryArtist.trim());
            }
            if (!findLike.isEmpty()) {
                addContextSectionHeader(getString(R.string.context_find_like_this));
                int shown = 0;
                for (final String q : findLike) {
                    if (shown >= FIND_LIKE_SUGGESTIONS_MAX) break;
                    addContextAction(q, new Runnable() {
                        @Override
                        public void run() {
                            launchMusicSearchFromSuggestion(q, true);
                        }
                    });
                    shown++;
                }
            }
            if (reachSearch && !interestTerms.isEmpty()) {
                addContextSectionHeader(getString(R.string.context_add_to_interests));
                int shown = 0;
                for (final String term : interestTerms) {
                    if (shown >= FIND_LIKE_SUGGESTIONS_MAX) break;
                    final String t = term;
                    addContextAction(getString(R.string.context_like_interest, t), new Runnable() {
                        @Override
                        public void run() {
                            addReachInterestFromTerm(t, true);
                        }
                    });
                    addContextAction(getString(R.string.context_dislike_interest, t), new Runnable() {
                        @Override
                        public void run() {
                            addReachInterestFromTerm(t, false);
                        }
                    });
                    shown++;
                }
            }
        }
    }

    /** Collect library files matching a virtual browse query (artist/album/etc.). */
    private java.util.List<File> collectTracksForQuery(String type, String value, String artistForAlbum) {
        java.util.ArrayList<File> out = new java.util.ArrayList<File>();
        if (type == null || value == null) return out;
        for (SongItem song : customLibrary) {
            boolean match = false;
            if ("ALL".equals(type)) match = true;
            else if ("ARTIST".equals(type) && ArtistParser.containsArtist(song.artist, value)) match = true;
            else if ("ALBUM".equals(type) && AlbumNames.equals(song.album, value)) match = true;
            else if ("GENRE".equals(type) && song.genre.equals(value)) match = true;
            else if ("ARTIST_ALBUM".equals(type)
                    && ArtistParser.containsArtist(song.artist, artistForAlbum)
                    && AlbumNames.equals(song.album, value)) match = true;
            if (match && song.file != null && song.file.isFile()) out.add(song.file);
        }
        return out;
    }

    /** Focused category row on artist/album browse lists. */
    private String focusedCategoryName() {
        if (listVirtualSongs == null) return null;
        android.widget.ListAdapter ad = listVirtualSongs.getAdapter();
        if (!(ad instanceof CategoryListAdapter)) return null;
        int pos = virtualListFocusPosition();
        if (pos < 0 || pos >= ad.getCount()) return null;
        Object item = ad.getItem(pos);
        return item != null ? item.toString() : null;
    }

    private void openPlaylistNameKeyboard(boolean createOnly) {
        dismissThemedContextMenu();
        playlistKeyboardCreateOnly = createOnly;
        keyboardPurpose = KEYBOARD_PLAYLIST_NAME;
        keyboardReturnState = STATE_BROWSER;
        keyboardPrefill = "";
        changeScreen(STATE_WIFI_KEYBOARD);
    }

    private void finishPlaylistNameEntry() {
        final String name = typedPassword != null ? typedPassword.trim() : "";
        if (name.isEmpty()) {
            Toast.makeText(this, getString(R.string.library_playlist_name_empty), Toast.LENGTH_SHORT).show();
            return;
        }
        final boolean createOnly = playlistKeyboardCreateOnly;
        final java.util.List<File> tracks = pendingPlaylistTracks;
        try {
            PlaylistManager.Entry created = PlaylistManager.createPlaylist(
                    rootFolder, name, createOnly ? null : tracks);
            libraryPlaylists = PlaylistManager.scan(rootFolder);
            if (createOnly) {
                Toast.makeText(this, getString(R.string.library_playlist_created, created.name),
                        Toast.LENGTH_SHORT).show();
            } else {
                int count = tracks != null ? tracks.size() : 0;
                Toast.makeText(this, getString(R.string.library_playlist_added, count, created.name),
                        Toast.LENGTH_SHORT).show();
            }
        } catch (Exception e) {
            Toast.makeText(this, getString(R.string.library_playlist_save_failed), Toast.LENGTH_SHORT).show();
        }
        pendingPlaylistTracks = null;
        playlistKeyboardCreateOnly = false;
        changeScreen(STATE_BROWSER);
    }

    private void finishBtPairingPinEntry() {
        clickFeedback();
        String pin = typedPassword != null ? typedPassword.trim() : "0000";
        BluetoothAudioRepair.savePairingPin(this, targetBtPairingAddress, pin);
        changeScreen(keyboardReturnState != STATE_WIFI_KEYBOARD ? keyboardReturnState : STATE_SETTINGS);
        refreshSettingsPreview(RowKeys.BLUETOOTH_PAIRING_PIN);
        if (targetBtPairingAddress != null && !targetBtPairingAddress.isEmpty()) {
            BluetoothDevice dev = BluetoothAudioRepair.deviceForAddress(targetBtPairingAddress);
            if (dev != null) {
                BluetoothAudioRepair.requestRepair(this, dev);
            }
        }
    }

    private PlaylistManager.Entry focusedLocalPlaylistEntry() {
        View c = getCurrentFocus();
        while (c != null) {
            if (c.getTag() instanceof PlaylistManager.Entry) {
                return (PlaylistManager.Entry) c.getTag();
            }
            Object p = c.getParent();
            c = p instanceof View ? (View) p : null;
        }
        return null;
    }

