    /**
     * 2026-07-15 — Save audio-if-needed then open local playlist picker (YouTube).
     * Layman: uses the audio file under Music/YouTube so playlist rows stay music tracks.
     * Reversal: remove helper + context menu call sites.
     */
    private void openAddYouTubeTrackToLocalPlaylistFlow(final YouTubeVideo video) {
        if (video == null || video.id == null || video.id.isEmpty()) return;
        File existing = YouTubeSavePaths.findSavedAudio(this, video);
        if (existing != null && existing.length() > 1024L) {
            openAddToPlaylistFlow(java.util.Collections.singletonList(existing));
            return;
        }
        if (!requireInternet(R.string.toast_internet_required)) return;
        Toast.makeText(this, getString(R.string.get_music_loading_container), Toast.LENGTH_SHORT).show();
        setBlockingLoading(true);
        setLoadingOverlayText(getString(R.string.youtube_save_resolving));
        YouTubeDownloader.saveAudio(this, video, new YouTubeDownloader.Callback() {
            @Override
            public void onProgress(String phase, int percent, long doneBytes, long totalBytes) {
                setBlockingLoading(true);
                if ("resolve".equals(phase)) {
                    setLoadingOverlayText(getString(R.string.youtube_save_resolving));
                    return;
                }
                if (percent >= 0) {
                    setLoadingOverlayText(getString(R.string.youtube_save_progress_pct, percent));
                } else if (doneBytes > 0L) {
                    setLoadingOverlayText(getString(R.string.youtube_save_progress_bytes,
                            formatYoutubeSaveBytes(doneBytes)));
                } else {
                    setLoadingOverlayText(getString(R.string.youtube_save_progress_pct, 0));
                }
            }
            @Override public void onComplete(File savedFile) {
                setBlockingLoading(false);
                if (savedFile != null && savedFile.exists() && savedFile.length() > 1024L) {
                    openAddToPlaylistFlow(java.util.Collections.singletonList(savedFile));
                } else {
                    Toast.makeText(MainActivity.this, R.string.youtube_save_done, Toast.LENGTH_SHORT).show();
                }
            }
            @Override public void onError(String message) {
                setBlockingLoading(false);
                Toast.makeText(MainActivity.this,
                        getString(R.string.youtube_save_failed,
                                message != null ? message : "error"),
                        Toast.LENGTH_LONG).show();
            }
        });
    }

    /**
     * Expected on-disk path for a single Navidrome/Plex/Jellyfin track (mirrors *Downloader).
     * Layman: Artist/Album/Title.ext under the service folder on media storage.
     */
    private File localRemoteTrackFile(String serviceRoot, String artist, String album,
            String title, String suffix) {
        if (serviceRoot == null || serviceRoot.isEmpty()) return null;
        String artistDir = safeRemoteMediaName(artist);
        String albumName = album != null && album.length() > 0 ? album : title;
        String albumDir = safeRemoteMediaName(albumName);
        String ext = suffix != null && suffix.length() > 0 ? suffix : "mp3";
        File dir = new File(new File(new File(DeviceFeatures.getNewMediaRoot(this), serviceRoot),
                artistDir), albumDir);
        return new File(dir, safeRemoteMediaName(title) + "." + ext.toLowerCase(java.util.Locale.US));
    }

    private static String safeRemoteMediaName(String raw) {
        if (raw == null || raw.trim().isEmpty()) return "Unknown";
        return raw.trim().replaceAll("[\\\\/:*?\"<>|]", "_");
    }

    private void openAddToDeezerPlaylistFlow(final DeezerResult track) {
        if (track == null || !deezerPlaylistActionsAvailable()) return;
        pendingDeezerPlaylistTrack = track;
        deezerPlaylistPickGen++;
        final int gen = deezerPlaylistPickGen;
        if (!deezerPlaylistsCache.isEmpty()) {
            showAddToDeezerPlaylistPickerTier(deezerPlaylistsCache);
            return;
        }
        Toast.makeText(this, getString(R.string.deezer_playlists_loading), Toast.LENGTH_SHORT).show();
        new Thread(new Runnable() {
            @Override public void run() {
                java.util.List<DeezerPlaylist> found = new java.util.ArrayList<DeezerPlaylist>();
                String err = null;
                try {
                    DeezerClient c = new DeezerClient(prefs);
                    if (!c.isSessionValid()) c.initSession();
                    long userId = DeezerAccount.loadUserId(prefs);
                    found = new DeezerSearch(c).listUserPlaylists(userId);
                } catch (Exception e) {
                    err = e.getMessage();
                }
                final java.util.List<DeezerPlaylist> ff = found;
                final String ferr = err;
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (gen != deezerPlaylistPickGen) return;
                        if (ff.isEmpty()) {
                            Toast.makeText(MainActivity.this,
                                    getString(R.string.deezer_playlist_save_failed,
                                            ferr != null ? ferr : ""),
                                    Toast.LENGTH_LONG).show();
                            pendingDeezerPlaylistTrack = null;
                            return;
                        }
                        deezerPlaylistsCache.clear();
                        deezerPlaylistsCache.addAll(ff);
                        showAddToDeezerPlaylistPickerTier(ff);
                    }
                });
            }
        }, "DeezerPlPick").start();
    }

    private void showAddToDeezerPlaylistPickerTier(final java.util.List<DeezerPlaylist> lists) {
        if (themedContextMenu == null || !themedContextMenu.isShowing()) {
            showThemedContextMenu();
        }
        pushContextMenuTier("deezer_pl_pick");
        java.util.ArrayList<String> labels = new java.util.ArrayList<String>();
        java.util.ArrayList<String> states = new java.util.ArrayList<String>();
        java.util.ArrayList<Boolean> headers = new java.util.ArrayList<Boolean>();
        java.util.ArrayList<Runnable> actions = new java.util.ArrayList<Runnable>();
        labels.add(getString(R.string.context_add_to_deezer_playlist_title));
        states.add("");
        headers.add(Boolean.TRUE);
        actions.add(null);
        for (final DeezerPlaylist pl : lists) {
            labels.add(pl.title);
            states.add("");
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override public void run() {
                    final DeezerResult track = pendingDeezerPlaylistTrack;
                    if (track == null || pl == null) return;
                    new Thread(new Runnable() {
                        @Override public void run() {
                            String err = null;
                            try {
                                DeezerClient c = new DeezerClient(prefs);
                                if (!c.isSessionValid()) c.initSession();
                                c.addTrackToPlaylist(pl.id, track.id);
                            } catch (Exception e) {
                                err = e.getMessage();
                            }
                            final String ferr = err;
                            runOnUiThread(new Runnable() {
                                @Override public void run() {
                                    pendingDeezerPlaylistTrack = null;
                                    dismissThemedContextMenu();
                                    if (ferr != null) {
                                        Toast.makeText(MainActivity.this,
                                                getString(R.string.deezer_playlist_save_failed, ferr),
                                                Toast.LENGTH_LONG).show();
                                    } else {
                                        Toast.makeText(MainActivity.this,
                                                getString(R.string.deezer_playlist_track_added, pl.title),
                                                Toast.LENGTH_SHORT).show();
                                    }
                                }
                            });
                        }
                    }, "DeezerPlAdd").start();
                }
            });
        }
        showContextMenuTierInPlace(getString(R.string.context_add_to_deezer_playlist_title),
                labels, states, headers, actions, true);
        themedContextMenu.focusSubmenuList();
        themedContextMenu.requestOverlayFocus();
    }

    private void openAddToPlaylistFlow(java.util.List<File> tracks) {
        if (tracks == null || tracks.isEmpty()) {
            Toast.makeText(this, getString(R.string.library_queue_empty), Toast.LENGTH_SHORT).show();
            return;
        }
        pendingPlaylistTracks = new java.util.ArrayList<File>(tracks);
        java.util.List<PlaylistManager.Entry> lists = PlaylistManager.scan(rootFolder);
        libraryPlaylists = lists;
        if (lists.isEmpty()) {
            openPlaylistNameKeyboard(false);
            return;
        }
        showAddToPlaylistPickerTier(lists);
    }

    private void showAddToPlaylistPickerTier(final java.util.List<PlaylistManager.Entry> lists) {
        if (themedContextMenu == null || !themedContextMenu.isShowing()) {
            showThemedContextMenu();
        }
        pushContextMenuTier("playlist_pick");
        java.util.ArrayList<String> labels = new java.util.ArrayList<String>();
        java.util.ArrayList<String> states = new java.util.ArrayList<String>();
        java.util.ArrayList<Boolean> headers = new java.util.ArrayList<Boolean>();
        java.util.ArrayList<Runnable> actions = new java.util.ArrayList<Runnable>();
        labels.add(getString(R.string.context_add_to_playlist_title));
        states.add("");
        headers.add(Boolean.TRUE);
        actions.add(null);
        for (final PlaylistManager.Entry pl : lists) {
            labels.add(pl.name);
            states.add("");
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override public void run() {
                    try {
                        PlaylistManager.appendTracks(pl.sourceFile, rootFolder, pendingPlaylistTracks);
                        libraryPlaylists = PlaylistManager.scan(rootFolder);
                        int count = pendingPlaylistTracks != null ? pendingPlaylistTracks.size() : 0;
                        Toast.makeText(MainActivity.this,
                                getString(R.string.library_playlist_added, count, pl.name),
                                Toast.LENGTH_SHORT).show();
                        pendingPlaylistTracks = null;
                        dismissThemedContextMenu();
                    } catch (Exception e) {
                        Toast.makeText(MainActivity.this,
                                getString(R.string.library_playlist_save_failed),
                                Toast.LENGTH_SHORT).show();
                    }
                }
            });
        }
        labels.add(getString(R.string.context_playlist_new));
        states.add("");
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override public void run() {
                openPlaylistNameKeyboard(false);
            }
        });
        showContextMenuTierInPlace(getString(R.string.context_add_to_playlist_title),
                labels, states, headers, actions, true);
        themedContextMenu.focusSubmenuList();
        themedContextMenu.requestOverlayFocus();
    }

    private void saveMusicQueueAsM3u() {
        if (playback.musicPlaylist().isEmpty()) {
            Toast.makeText(this, getString(R.string.library_queue_empty), Toast.LENGTH_SHORT).show();
            return;
        }
        try {
            File dir = PlaylistManager.playlistsDir(rootFolder);
            if (!dir.exists()) dir.mkdirs();
            String name = "Queue " + System.currentTimeMillis();
            File dest = new File(dir, name.replace(' ', '_') + ".m3u");
            java.util.List<PlayQueue.QueueItem> musicItems = collectMusicQueueItemsForPlaylist();
            PlaylistManager.saveM3u(PlaylistManager.fromTracks(name, playback.musicPlaylist()), dest);
            materializePlaylistStreamTracksAsync(dest, musicItems);
            Toast.makeText(this, getString(R.string.library_playlist_saved, dest.getName()), Toast.LENGTH_SHORT).show();
            if (currentBrowserMode == BROWSER_PLAYLISTS) buildPlaylistsUI();
        } catch (Exception e) {
            toastStreamDownloadWarning(getString(R.string.library_playlist_save_failed));
        }
    }

