    private boolean isWifiNetworkSaved(String ssid) {
        if (ssid == null) return false;
        return WifiConnector.findSavedNetId(wifiManagerConfiguredNetworks(), ssid) >= 0;
    }

    /** Wi-Fi settings context menu only — re-randomizes MTK NVRAM MAC via su. */
    private void refreshWifiMacAddress() {
        Toast.makeText(this, getString(R.string.toast_wifi_mac_refreshing), Toast.LENGTH_SHORT).show();
        WifiMacRandomizer.refreshManual(this, new WifiMacRandomizer.Callback() {
            @Override
            public void onComplete(boolean success, String macFormatted) {
                if (success) {
                    Toast.makeText(MainActivity.this,
                            getString(R.string.toast_wifi_mac_refreshed, macFormatted),
                            Toast.LENGTH_LONG).show();
                    if (currentScreenState == STATE_WIFI) startWifiScan();
                } else {
                    Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_mac_failed),
                            Toast.LENGTH_LONG).show();
                }
            }
        });
    }

    private void forgetWifiNetwork(String ssid) {
        if (ssid == null) return;
        WifiConnector.forget(this, ssid, new WifiConnector.Callback() {
            @Override
            public void onComplete(boolean success) {
                if (success) {
                    Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_forgotten, ssid),
                            Toast.LENGTH_SHORT).show();
                    if (currentScreenState == STATE_WIFI) startWifiScan();
                    scheduleContextWifiRefresh(false);
                } else {
                    Toast.makeText(MainActivity.this, getString(R.string.toast_wifi_forget_failed),
                            Toast.LENGTH_SHORT).show();
                }
            }
        });
    }

    private void forgetBluetoothDevice(final BluetoothDevice device) {
        if (device == null) return;
        try {
            if (device.getBondState() != BluetoothDevice.BOND_BONDED) return;
            Method removeBond = device.getClass().getMethod("removeBond");
            removeBond.invoke(device);
            Toast.makeText(this, getString(R.string.toast_bt_forgotten,
                    device.getName() != null ? device.getName() : device.getAddress()),
                    Toast.LENGTH_SHORT).show();
            if (currentScreenState == STATE_BLUETOOTH) startBluetoothScan();
        } catch (Exception e) {
            Toast.makeText(this, getString(R.string.toast_bt_forget_failed), Toast.LENGTH_SHORT).show();
        }
    }

    private String musicTrackLabel(File f) {
        if (f == null) return "";
        SongItem si = findSongItem(f);
        if (si != null) return si.title + " · " + si.artist;
        String n = f.getName();
        int dot = n.lastIndexOf('.');
        return dot > 0 ? n.substring(0, dot) : n;
    }

    // 💡 4. 자체 DB에서 노래를 뽑아 '재활용 엔진'에 밀어넣는 함수
    /**
     * 2026-07-18 — Songs list: placeholder + REASON_LIBRARY_LOAD, bind after first frame.
     * Was: filter/sort entire customLibrary on OK stack. Reversal: buildVirtualSongsNow() inline.
     */
    private void buildVirtualSongs() {
        if (isCustomScanning) {
            showLoadingPopup();
            currentBrowserMode = BROWSER_ROOT;
            buildFileBrowserUI();
            return;
        }
        if (!"PLAYLIST".equals(virtualQueryType)) {
            resetPlaylistMoveState();
        }
        scrollViewBrowser.setVisibility(View.GONE);
        listVirtualSongs.setVisibility(View.VISIBLE);
        if ("ALL".equals(virtualQueryType)) {
            browserStatusTitle = getString(R.string.status_library_all_songs);
        } else if ("RECENT".equals(virtualQueryType)) {
            browserStatusTitle = getString(R.string.browser_recently_added);
        } else if ("HAS_STEMS".equals(virtualQueryType)) {
            browserStatusTitle = stemPickMode
                    ? getString(R.string.stem_pick_status, stemMashupMarks.size())
                    : getString(R.string.status_has_stems);
        } else {
            browserStatusTitle = getString(R.string.status_path, virtualQueryValue);
        }
        updateStatusBarTitle();
        updateLibraryBreadcrumb();
        // Has Stems: off-thread invert index — never O(n) trackStemsReady on UI. 2026-07-19
        if ("HAS_STEMS".equals(virtualQueryType)) {
            startHasStemsBrowseAsync();
            return;
        }
        // Loading placeholder adapter (disabled until bind finishes).
        java.util.List<SongItem> placeholder = new ArrayList<SongItem>();
        listVirtualSongs.setAdapter(new SongListAdapter(placeholder, false));
        // Show a single loading row via category-style empty — SongListAdapter empty is blank;
        // use status throbber + disable list until filled.
        listVirtualSongs.setEnabled(false);
        UiBusy.beginAutoEnd(UiBusy.REASON_LIBRARY_LOAD, 12000L);
        final int gen = libraryScanGen;
        listVirtualSongs.postOnAnimation(new Runnable() {
            @Override
            public void run() {
                try {
                    if (libraryScanGen != gen) return;
                    buildVirtualSongsNow();
                } finally {
                    UiBusy.end(UiBusy.REASON_LIBRARY_LOAD);
                    if (listVirtualSongs != null) listVirtualSongs.setEnabled(true);
                }
            }
        });
    }

    /**
     * Placeholder then background Has Stems index — keeps wheel responsive.
     * 2026-07-19
     */
    private void startHasStemsBrowseAsync() {
        scrollViewBrowser.setVisibility(View.VISIBLE);
        listVirtualSongs.setVisibility(View.GONE);
        containerBrowserItems.removeAllViews();
        Button loading = createListButton(getString(R.string.has_stems_loading));
        loading.setEnabled(false);
        containerBrowserItems.addView(loading);
        UiBusy.beginAutoEnd(UiBusy.REASON_LIBRARY_LOAD, 15000L);
        final int gen = ++hasStemsBrowseGen;
        final android.content.Context app = getApplicationContext();
        final File appCache = getCacheDir();
        new Thread(new Runnable() {
            @Override
            public void run() {
                java.util.ArrayList<SongItem> snap = new java.util.ArrayList<SongItem>();
                java.util.ArrayList<File> files = new java.util.ArrayList<File>();
                synchronized (customLibrary) {
                    for (SongItem s : customLibrary) {
                        if (s == null || s.file == null) continue;
                        snap.add(s);
                        files.add(s.file);
                    }
                }
                java.util.HashSet<String> ready =
                        com.solar.launcher.stem.LalalClient.indexReadyOriginatingPaths(
                                app, files, appCache);
                final java.util.ArrayList<SongItem> matched = new java.util.ArrayList<SongItem>();
                for (int i = 0; i < snap.size(); i++) {
                    SongItem s = snap.get(i);
                    if (s == null || s.file == null) continue;
                    String path = s.file.getAbsolutePath();
                    if (s.hasStemsBit == 1 || ready.contains(path)) {
                        s.hasStemsBit = 1;
                        matched.add(s);
                    } else if (s.hasStemsBit < 0) {
                        s.hasStemsBit = 0;
                    }
                }
                sortSongItems(matched, false);
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        UiBusy.end(UiBusy.REASON_LIBRARY_LOAD);
                        if (hasStemsBrowseGen != gen) return;
                        if (!"HAS_STEMS".equals(virtualQueryType)
                                || currentBrowserMode != BROWSER_VIRTUAL_SONGS) {
                            return;
                        }
                        bindHasStemsBrowseResults(matched);
                    }
                });
            }
        }, "HasStemsIndex").start();
    }

    /** Bind Has Stems list after background index. 2026-07-19 */
    private void bindHasStemsBrowseResults(java.util.List<SongItem> targetSongs) {
        virtualSongList.clear();
        currentScrollIndexList.clear();
        if (targetSongs == null || targetSongs.isEmpty()) {
            scrollViewBrowser.setVisibility(View.VISIBLE);
            listVirtualSongs.setVisibility(View.GONE);
            containerBrowserItems.removeAllViews();
            Button hint = createListButton(getString(R.string.has_stems_empty));
            hint.setEnabled(false);
            containerBrowserItems.addView(hint);
            return;
        }
        for (SongItem s : targetSongs) {
            virtualSongList.add(s.file);
            currentScrollIndexList.add(s.title);
        }
        scrollViewBrowser.setVisibility(View.GONE);
        listVirtualSongs.setVisibility(View.VISIBLE);
        listVirtualSongs.setEnabled(true);
        setSongListAdapter(targetSongs, false);
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                if (listVirtualSongs.getChildCount() > 0) {
                    listVirtualSongs.getChildAt(0).requestFocus();
                }
            }
        });
    }

    /** 2026-07-15/18 — Filter/sort/bind virtual songs (post-frame). */
    private void buildVirtualSongsNow() {
        virtualSongList.clear();
        currentScrollIndexList.clear();
        final List<SongItem> targetSongs = new ArrayList<>();
        // HAS_STEMS uses startHasStemsBrowseAsync — never sync probe here. 2026-07-19
        if ("HAS_STEMS".equals(virtualQueryType)) {
            startHasStemsBrowseAsync();
            return;
        }
        for (SongItem song : customLibrary) {
            boolean match = false;
            // RECENT mirrors ALL content — full library, then date-sorted below.
            if (virtualQueryType.equals("ALL") || virtualQueryType.equals("RECENT")) match = true;
            else if (virtualQueryType.equals("ARTIST")
                    && ArtistParser.containsArtist(song.artist, virtualQueryValue)) match = true;
            else if (virtualQueryType.equals("ALBUM") && AlbumNames.equals(song.album, virtualQueryValue)) match = true;
            else if (virtualQueryType.equals("GENRE") && song.genre.equals(virtualQueryValue)) match = true;
            else if (virtualQueryType.equals("YEAR") && song.year > 0
                    && virtualQueryValue.equals(String.valueOf(song.year))) match = true;
            else if (virtualQueryType.equals("ARTIST_ALBUM")
                    && ArtistParser.containsArtist(song.artist, virtualQueryArtist)
                    && AlbumNames.equals(song.album, virtualQueryValue)) match = true;
            if (match) targetSongs.add(song);
        }
        boolean isAlbumContext = "ALBUM".equals(virtualQueryType) || "ARTIST_ALBUM".equals(virtualQueryType);
        // 2026-07-15 — Recently Added forces Date added; All Songs keeps user's lib_song_sort.
        if ("RECENT".equals(virtualQueryType)) {
            sortSongItems(targetSongs, false, LibraryBrowsePrefs.SONG_SORT_DATE);
        } else {
            sortSongItems(targetSongs, isAlbumContext);
        }
        for (SongItem s : targetSongs) {
            virtualSongList.add(s.file);
            currentScrollIndexList.add(s.title);
        }
        setSongListAdapter(targetSongs, false);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("queryType", virtualQueryType);
            d.put("count", targetSongs.size());
            DebugLibraryMenuLog.log("MainActivity.buildVirtualSongs", "adapter set ok", "H4", d);
        } catch (Exception ignored) {}
        // #endregion
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                if (listVirtualSongs.getChildCount() > 0) {
                    listVirtualSongs.getChildAt(0).requestFocus();
                }
            }
        });
    }

    private void buildFolderBrowserUI() {
        folderBrowserEntries.clear();
        currentScrollIndexList.clear();
        String pathLabel = cleanPathLabel(currentFolder.getAbsolutePath());
        browserStatusTitle = isPickingApk
                ? getString(R.string.status_apk_install)
                : getString(R.string.status_path, pathLabel);
        updateStatusBarTitle();
        updateLibraryBreadcrumb();
        File[] files = currentFolder.listFiles();

        final File storageRoot = getStorageRoot();
        boolean showUp = isPickingBackground || isPickingApk
                ? !currentFolder.getAbsolutePath().equals(storageRoot.getAbsolutePath())
                : !currentFolder.getAbsolutePath().equals(rootFolder.getAbsolutePath());

        if (files == null || files.length == 0) {
            if (scrollViewBrowser != null) scrollViewBrowser.setVisibility(View.VISIBLE);
            if (listVirtualSongs != null) listVirtualSongs.setVisibility(View.GONE);
            containerBrowserItems.removeAllViews();
            if (showUp) {
                Button btnUp = createListButton(getString(R.string.browser_up));
                btnUp.setOnClickListener(new View.OnClickListener() {
                    @Override
                    public void onClick(View v) {
                        clickFeedback();
                        final File parent = currentFolder.getParentFile();
                        drillBrowserBack(new Runnable() {
                            @Override
                            public void run() {
                                if (parent != null) currentFolder = parent;
                                buildFileBrowserUI();
                            }
                        });
                    }
                });
                containerBrowserItems.addView(btnUp);
            }
            Button btnEmpty = createListButton(
                    files == null ? "⚠️ USB Disconnect Required (Tap to go back)" : "📂 Empty Folder (Tap to go back)");
            btnEmpty.setTextColor(0xFFFF5555);
            btnEmpty.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    clickFeedback();
                    if (isPickingApk) {
                        if (currentFolder.getAbsolutePath().equals(getStorageRoot().getAbsolutePath())) {
                            isPickingApk = false;
                            changeScreen(STATE_APPS);
                        } else {
                            File parent = currentFolder.getParentFile();
                            if (parent != null) currentFolder = parent;
                            buildFileBrowserUI();
                        }
                    } else if (isPickingBackground) {
                        if (currentFolder.getAbsolutePath().equals(getStorageRoot().getAbsolutePath())) {
                            isPickingBackground = false;
                            changeScreen(STATE_SETTINGS);
                        } else {
                            File parent = currentFolder.getParentFile();
                            if (parent != null) currentFolder = parent;
                            buildFileBrowserUI();
                        }
                    } else if (currentFolder.getAbsolutePath().equals(rootFolder.getAbsolutePath())) {
                        isPickingBackground = false;
                        changeScreen(STATE_MENU);
                    } else {
                        currentFolder = currentFolder.getParentFile();
                        buildFileBrowserUI();
                    }
                }
            });
            containerBrowserItems.addView(btnEmpty);
            return;
        }

        List<File> folders = new ArrayList<File>();
        List<File> audioFiles = new ArrayList<File>();
        List<File> apkFiles = new ArrayList<File>();
        List<File> imageFiles = new ArrayList<File>();

        for (File f : files) {
            if (f.isDirectory()) folders.add(f);
            else if (isPickingBackground && isImageFile(f)) imageFiles.add(f);
            else if (isPickingApk && isApkFile(f)) apkFiles.add(f);
            else if (!isPickingBackground && !isPickingApk && isAudioFile(f)) audioFiles.add(f);
            else if (!isPickingBackground && !isPickingApk && isApkFile(f)) apkFiles.add(f);
        }
        java.util.Comparator<File> fileSorter = new java.util.Comparator<File>() {
            @Override
            public int compare(File f1, File f2) {
                return f1.getName().compareToIgnoreCase(f2.getName());
            }
        };
        java.util.Collections.sort(folders, fileSorter);
        java.util.Collections.sort(audioFiles, fileSorter);
        java.util.Collections.sort(apkFiles, fileSorter);
        java.util.Collections.sort(imageFiles, fileSorter);

        if (showUp) {
            folderBrowserEntries.add(FolderBrowserEntry.up(getString(R.string.browser_up)));
            currentScrollIndexList.add(getString(R.string.browser_up));
        }
        appendOtherStorageVolumeEntries();
        for (File folder : folders) {
            folderBrowserEntries.add(FolderBrowserEntry.folder(folder));
            currentScrollIndexList.add(folder.getName());
        }
        if (isPickingBackground) {
            for (File img : imageFiles) {
                folderBrowserEntries.add(FolderBrowserEntry.image(img));
                currentScrollIndexList.add(img.getName());
            }
        } else {
            for (File apk : apkFiles) {
                folderBrowserEntries.add(FolderBrowserEntry.apk(apk));
                currentScrollIndexList.add(apk.getName());
            }
            for (File audio : audioFiles) {
                folderBrowserEntries.add(FolderBrowserEntry.audio(audio));
                currentScrollIndexList.add(audio.getName());
            }
        }

        scrollViewBrowser.setVisibility(View.GONE);
        listVirtualSongs.setVisibility(View.VISIBLE);
        clearVirtualSongListHeaders();
        listVirtualSongs.setAdapter(new FolderBrowserAdapter());
        listVirtualSongs.post(new Runnable() {
            @Override
            public void run() {
                if (listVirtualSongs.getChildCount() > 0) {
                    listVirtualSongs.getChildAt(0).requestFocus();
                }
            }
        });
    }

    /** At a volume root, list the other storage (MicroSD ↔ Internal) as a jump row. */
    private void appendOtherStorageVolumeEntries() {
        // 2026-07-15 — Was Y2-only; now any family with multiple browsable roots.
        if (!com.solar.launcher.DeviceFeatures.isStorageVolumeRoot(currentFolder)) {
            return;
        }
        java.util.List<File> browsable = com.solar.launcher.DeviceFeatures.getBrowsableStorageRoots();
        if (browsable == null || browsable.size() < 2) return;
        for (File root : browsable) {
            if (root.equals(currentFolder)) continue;
            String label = com.solar.launcher.DeviceFeatures.storageRootLabel(this, root);
            folderBrowserEntries.add(FolderBrowserEntry.storageVolume(root, label));
            currentScrollIndexList.add(label);
        }
    }

