    /**
     * 2026-07-15 — YouTube Audio: open music Now Playing with a local file.
     * 2026-07-16 — Play-cache files stay only while queued; replaced by playTrackList purge.
     * Layman: play the buffered track like any song. Technical: playTrackList singleton → STATE_PLAYER.
     * Reversal: remove call site.
     */
    public void mediaPlayAudioFileInNowPlaying(File file) {
        if (file == null || !file.isFile()) return;
        playTrackList(java.util.Collections.singletonList(file), 0, null);
    }

    private void startYouTubeSave(final YouTubeVideo video, final boolean audioOnly) {
        if (video == null) return;
        java.io.File existing = audioOnly
                ? YouTubeSavePaths.findSavedAudio(this, video)
                : YouTubeSavePaths.findSavedVideo(this, video);
        if (existing != null && existing.length() > 1024L) {
            Toast.makeText(this, R.string.youtube_already_saved, Toast.LENGTH_SHORT).show();
            return;
        }
        // 2026-07-15 — Immediate overlay during resolve (was blank until download started).
        setBlockingLoading(true);
        setLoadingOverlayText(getString(R.string.youtube_save_resolving));
        YouTubeDownloader.Callback cb = new YouTubeDownloader.Callback() {
            @Override
            public void onProgress(String phase, int percent, long doneBytes, long totalBytes) {
                setBlockingLoading(true);
                if ("resolve".equals(phase)) {
                    setLoadingOverlayText(getString(R.string.youtube_save_resolving));
                    return;
                }
                if (percent >= 0) {
                    setLoadingOverlayText(getString(R.string.youtube_save_progress_pct, percent));
                } else if (doneBytes > 0L) {
                    setLoadingOverlayText(getString(R.string.youtube_save_progress_bytes,
                            formatYoutubeSaveBytes(doneBytes)));
                } else {
                    setLoadingOverlayText(getString(R.string.youtube_save_progress_pct, 0));
                }
            }
            @Override public void onComplete(java.io.File savedFile) {
                setBlockingLoading(false);
                Toast.makeText(MainActivity.this, R.string.youtube_save_done, Toast.LENGTH_SHORT).show();
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("audioOnly", audioOnly);
                    d.put("name", savedFile != null ? savedFile.getName() : "");
                    d.put("ext", savedFile != null && savedFile.getName().contains(".")
                            ? savedFile.getName().substring(savedFile.getName().lastIndexOf('.') + 1) : "");
                    d.put("len", savedFile != null ? savedFile.length() : 0L);
                    com.solar.launcher.debug.Debug2241b1Log.log(
                            "MainActivity.startYouTubeSave", "save complete", "YT1", "post-fix", d);
                } catch (Exception ignored) {}
                // #endregion
                // 2026-07-15 — Force full walk; scan(false) can hit SQLite mtime fast-path and miss new file.
                if (audioOnly) {
                    startLibraryScan(true);
                }
            }
            @Override public void onError(String message) {
                setBlockingLoading(false);
                Toast.makeText(MainActivity.this,
                        getString(R.string.youtube_save_failed,
                                message != null ? message : "error"),
                        Toast.LENGTH_LONG).show();
            }
        };
        if (audioOnly) {
            YouTubeDownloader.saveAudio(this, video, cb);
        } else {
            YouTubeDownloader.saveVideo(this, video, cb);
        }
    }

    /** 2026-07-15 — Human size for Save overlay when Content-Length missing. */
    private static String formatYoutubeSaveBytes(long bytes) {
        if (bytes < 1024L) return bytes + " B";
        if (bytes < 1024L * 1024L) return (bytes / 1024L) + " KB";
        return (bytes / (1024L * 1024L)) + " MB";
    }

    private void fetchPodcastShows(final String query) {
        fetchPodcastShows(query, getPodcastStorefront(), null, null);
    }

    private void fetchPodcastShows(final String query, final String country,
            final Integer genreId, final String displayLabel) {
        if (query == null || query.trim().isEmpty()) return;
        if (!requireInternet(R.string.podcasts_wifi_required_search)) return;
        podcastLastQuery = displayLabel != null && displayLabel.length() > 0
                ? displayLabel : query.trim();
        if (tvBrowserPath != null) {
            if (displayLabel == null && genreId == null) {
                tvBrowserPath.setText(getString(R.string.path_podcasts_search_query, podcastLastQuery));
            } else {
                tvBrowserPath.setText(getString(R.string.path_podcasts_results, podcastLastQuery));
            }
        }
        podcastShows.clear();
        cancelPodcastEpisodeProbe();
        podcastSearchLoading = true;
        syncStatusBarSearchThrobber();
        buildPodcastShowsShell();
        final int gen = podcastUiGen;
        final String searchTerm = query.trim();
        final String searchCountry = country;
        final Integer searchGenre = genreId;
        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    final List<OpenRssClient.Podcast> raw = OpenRssClient.searchPodcasts(
                            searchTerm, searchCountry, searchGenre, 20);
                    final List<OpenRssClient.Podcast> deezerOnly =
                            new java.util.ArrayList<OpenRssClient.Podcast>();
                    if (deezerActive() && ConnectivityHelper.isDeezerLoginOk()) {
                        try {
                            DeezerSearch dz = new DeezerSearch(new DeezerClient(prefs));
                            List<DeezerSearch.DeezerPodcastShow> dzShows =
                                    dz.searchPodcasts(searchTerm);
                            for (DeezerSearch.DeezerPodcastShow s : dzShows) {
                                OpenRssClient.Podcast p = DeezerPodcast.toPodcast(s);
                                if (p != null) deezerOnly.add(p);
                            }
                        } catch (Exception ignored) {}
                    }
                    if (raw.isEmpty() && deezerOnly.isEmpty()) {
                        runOnUiThreadSafe(new Runnable() {
                            @Override
                            public void run() {
                                if (gen != podcastUiGen || !isPodcastUiActive()) return;
                                podcastSearchLoading = false;
                                syncStatusBarSearchThrobber();
                                removePodcastProbeStatusRow();
                                Toast.makeText(MainActivity.this, getString(R.string.podcasts_no_results),
                                        Toast.LENGTH_SHORT).show();
                                buildPodcastSearchUI();
                            }
                        });
                        return;
                    }
                    OpenRssClient.probePodcastsPlayable(raw, new OpenRssClient.PodcastProbeCallback() {
                        @Override
                        public void onProbed(final OpenRssClient.Podcast podcast, final boolean playable) {
                            if (!playable || podcast == null) return;
                            runOnUiThreadSafe(new Runnable() {
                                @Override
                                public void run() {
                                    if (gen != podcastUiGen || !isPodcastUiActive()) return;
                                    final String focusKey = captureBrowserFocusKey();
                                    final int scrollY = scrollViewBrowser instanceof android.widget.ScrollView
                                            ? ((android.widget.ScrollView) scrollViewBrowser).getScrollY() : -1;
                                    podcastShows.add(podcast);
                                    appendPodcastShowRow(podcast);
                                    restoreBrowserFocusKey(focusKey, scrollY);
                                }
                            });
                        }

                        @Override
                        public void onComplete(final int playableCount, final int totalCount) {
                            runOnUiThreadSafe(new Runnable() {
                                @Override
                                public void run() {
                                    if (gen != podcastUiGen || !isPodcastUiActive()) return;
                                    podcastSearchLoading = false;
                                    syncStatusBarSearchThrobber();
                                    removePodcastProbeStatusRow();
                                    final String focusKey = captureBrowserFocusKey();
                                    final int scrollY = scrollViewBrowser instanceof android.widget.ScrollView
                                            ? ((android.widget.ScrollView) scrollViewBrowser).getScrollY() : -1;
                                    for (OpenRssClient.Podcast dp : deezerOnly) {
                                        podcastShows.add(dp);
                                        appendPodcastShowRow(dp);
                                    }
                                    restoreBrowserFocusKey(focusKey, scrollY);
                                    int hidden = totalCount - playableCount;
                                    if (hidden > 0) {
                                        Toast.makeText(MainActivity.this,
                                                getString(R.string.podcasts_filtered_unavailable, hidden),
                                                Toast.LENGTH_SHORT).show();
                                    }
                                    if (playableCount == 0 && deezerOnly.isEmpty()) {
                                        Toast.makeText(MainActivity.this, getString(R.string.podcasts_no_results),
                                                Toast.LENGTH_SHORT).show();
                                        buildPodcastSearchUI();
                                    }
                                }
                            });
                        }
                    });
                } catch (final Throwable e) {
                    runOnUiThreadSafe(new Runnable() {
                        @Override
                        public void run() {
                            podcastSearchLoading = false;
                            syncStatusBarSearchThrobber();
                            if (gen != podcastUiGen || !isPodcastUiActive()) return;
                            removePodcastProbeStatusRow();
                            Toast.makeText(MainActivity.this, getString(R.string.podcasts_search_failed),
                                    Toast.LENGTH_LONG).show();
                            buildPodcastSearchUI();
                        }
                    });
                }
            }
        }).start();
    }

