    private final SoulseekClient.Listener soulseekListener = new SoulseekClient.Listener() {
        @Override
        public void onStatus(final String message) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    long now = android.os.SystemClock.uptimeMillis();
                    if (now - soulseekLastStatusUiMs < 200) return;
                    soulseekLastStatusUiMs = now;
                    if (soulseekUiMode == SOULSEEK_UI_DOWNLOAD && soulseekActiveDownload != null) {
                        return;
                    }
                    if (!isSoulseekUiActive()) return;
                    if (message != null && message.startsWith("Widening")
                            && soulseekSearchStatusRow != null
                            && soulseekUiMode == SOULSEEK_UI_RESULTS) {
                        soulseekSearchStatusRow.setText(getString(R.string.soulseek_widening_search));
                    }
                    if (tvBrowserPath != null) tvBrowserPath.setText(getString(R.string.path_soulseek, message));
                }
            });
        }

        @Override
        public void onDownloadPhase(final String phase, final String detail) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    if (soulseekUiMode != SOULSEEK_UI_DOWNLOAD || soulseekActiveDownload == null) return;
                    long now = android.os.SystemClock.uptimeMillis();
                    if (now - soulseekLastStatusUiMs < 200) return;
                    soulseekLastStatusUiMs = now;
                    soulseekDownloadPhase = phase != null ? phase : "";
                    soulseekDownloadPhaseDetail = detail != null ? detail : "";
                    updateSoulseekDownloadStatusUi();
                }
            });
        }

        @Override
        public void onConnected(final int listenPort) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    ConnectivityHelper.setReachLoginOk(true);
                    buildHomeMenu();
                    registerReachDirectoryPresence();
                    requestSoulseekShareRescan();
                    soulseekListenPort = listenPort;
                    if (isSoulseekUiActive() && tvBrowserPath != null && soulseekUiMode == SOULSEEK_UI_SEARCH) {
                        SoulseekAccount account = SoulseekAccount.load(prefs);
                        tvBrowserPath.setText(getString(R.string.path_soulseek, SoulseekAccount.displayLabel(account)
                                + " · " + getString(R.string.soulseek_connected_port, listenPort)));
                    }
                    if (!prefs.getBoolean("soulseek_port_warn_shown", false)) {
                        prefs.edit().putBoolean("soulseek_port_warn_shown", true).commit();
                        Toast.makeText(MainActivity.this, getString(R.string.soulseek_port_warning, listenPort),
                                Toast.LENGTH_LONG).show();
                    }
                    SoulseekClient client = soulseekClient;
                    if (client != null) {
                        ensureInnioasisRoomJoined();
                        SolarDevelopmentBootstrap.onSoulseekConnected(
                                MainActivity.this, prefs, client);
                    }
                }
            });
        }

        @Override
        public void onLoginFailed(final String reason) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    ConnectivityHelper.setReachLoginOk(false);
                    buildHomeMenu();
                    if (isTransientReachError(reason)) return;
                    Toast.makeText(MainActivity.this,
                            getString(R.string.soulseek_login_failed_check_account,
                                    humanizeSoulseekError(reason)),
                            Toast.LENGTH_LONG).show();
                }
            });
        }

        @Override
        public void onSearchResult(final SoulseekClient.Result result) {
            if (soulseekClient != null && soulseekClient.isPeerDenied(result.username)) return;
            if (soulseekHideHighBitrate && result.isOverBitrateThreshold()) return;
            // 2026-07-15 — Drop late packets when user left results (Hallmark: no off-screen work).
            // Layman: no country lookups or list rebuilds if you're not looking at search.
            if (librarySearchReachActive && currentBrowserMode == BROWSER_LIBRARY_SEARCH) {
                String label = formatLibrarySearchReachLabel(result);
                synchronized (librarySearchReachRows) {
                    if (librarySearchReachRows.size() < LibrarySearch.PAGE_SIZE
                            && label != null && !label.isEmpty()
                            && !librarySearchReachRows.contains(label)) {
                        librarySearchReachRows.add(label);
                    }
                }
                runOnUiThreadSafe(new Runnable() {
                    @Override public void run() {
                        if (!librarySearchReachActive || currentBrowserMode != BROWSER_LIBRARY_SEARCH) {
                            return;
                        }
                        // 2026-07-15 — Don't rebuild library search under every Reach packet while typing.
                        if (isInputPriorityBusy()) {
                            soulseekUiHandler.removeCallbacks(librarySearchReachIdleRebuild);
                            soulseekUiHandler.postDelayed(librarySearchReachIdleRebuild,
                                    Math.max(200L, msUntilInputIdle()));
                            return;
                        }
                        buildLibrarySearchUI();
                    }
                });
                return;
            }
            if (!isSoulseekSearchResultsScreenActive()) {
                return;
            }
            // Peer country only while results are on screen (username “polling”).
            watchSoulseekPeer(result.username);
            synchronized (soulseekPendingUi) {
                soulseekPendingUi.add(result);
                if (!soulseekUiFlushScheduled) {
                    soulseekUiFlushScheduled = true;
                    long delay = soulseekPendingUi.size() > 16 ? SOULSEEK_UI_FLUSH_MS_HEAVY : SOULSEEK_UI_FLUSH_MS;
                    soulseekUiHandler.postDelayed(soulseekUiFlushRunnable, delay);
                }
            }
        }

        @Override
        public void onSearchFinished(final int token, final int count) {
            runOnUiThreadSafe(new Runnable() {
                @Override
                public void run() {
                    if (librarySearchReachActive && currentBrowserMode == BROWSER_LIBRARY_SEARCH) {
                        librarySearchReachSearching = false;
                        librarySearchReachActive = false;
                        syncStatusBarSearchThrobber();
                        buildLibrarySearchUI();
                        return;
                    }
                    soulseekUiHandler.removeCallbacks(soulseekUiFlushRunnable);
                    flushSoulseekResultsUi(true);
                    if (getMusicReachSearchActive()) {
                        final int gen = getMusicSearchGen;
                        if (soulseekClient != null) {
                            for (SoulseekClient.Result r : soulseekClient.getResultsSnapshot()) {
                                if (soulseekClient.isPeerDenied(r.username)) continue;
                                if (soulseekHideHighBitrate && r.isOverBitrateThreshold()) continue;
                                mergeGetMusicReachResult(r);
                            }
                        }
                        List<SoulseekClient.Result> reachSort = new ArrayList<SoulseekClient.Result>();
                        for (MusicSearchEntry e : getMusicEntries) {
                            if (e.reach != null) reachSort.add(e.reach);
                        }
                        sortSoulseekResultsByQuality(reachSort, soulseekLastQuery,
                                SoulseekDownloadHistory.loadPeerSet(prefs));
                        List<MusicSearchEntry> kept = new ArrayList<MusicSearchEntry>();
                        for (MusicSearchEntry e : getMusicEntries) {
                            if (e.source != MusicSearchEntry.Source.REACH) kept.add(e);
                        }
                        getMusicEntries.clear();
                        getMusicEntries.addAll(kept);
                        for (SoulseekClient.Result r : reachSort) {
                            getMusicEntries.add(MusicSearchEntry.reach(r));
                        }
                        getMusicReachDone = true;
                        finishGetMusicSearch(gen);
                        if (isSoulseekUiActive() && soulseekUiMode == SOULSEEK_UI_RESULTS) {
                            buildGetMusicResultsUI();
                        }
                        return;
                    }
                    mergeSoulseekResultsFromSnapshot();
                    if (soulseekFocusedResultRow != null
                            && soulseekFocusedResultRow.getTag() instanceof SoulseekClient.Result) {
                        soulseekPendingFocusKey = soulseekResultKey(
                                (SoulseekClient.Result) soulseekFocusedResultRow.getTag());
                    } else {
                        soulseekPendingFocusKey = null;
                    }
                    final List<SoulseekClient.Result> toSort =
                            new ArrayList<SoulseekClient.Result>(soulseekResults);
                    new Thread(new Runnable() {
                        @Override
                        public void run() {
                            sortSoulseekResultsByQuality(toSort, soulseekLastQuery,
                                    SoulseekDownloadHistory.loadPeerSet(prefs));
                            runOnUiThreadSafe(new Runnable() {
                                @Override
                                public void run() {
                                    soulseekSearchInProgress = false;
                                    syncStatusBarSearchThrobber();
                                    soulseekResults.clear();
                                    soulseekResultKeys.clear();
                                    for (SoulseekClient.Result r : toSort) {
                                        soulseekResultKeys.add(soulseekResultKey(r));
                                    }
                                    soulseekResults.addAll(toSort);
                                    soulseekResultsVisibleCount = Math.min(SOULSEEK_PAGE_SIZE, soulseekResults.size());
                                    if (!isSoulseekUiActive()) return;
                                    if (soulseekUiMode == SOULSEEK_UI_DOWNLOAD) {
                                        if (!soulseekDownloadUiFailed && tvBrowserPath != null) {
                                            tvBrowserPath.setText(getString(
                                                    R.string.path_soulseek_search_done_download,
                                                    soulseekLastQuery, toSort.size()));
                                        }
                                        if (toSort.isEmpty()) {
                                            Toast.makeText(MainActivity.this,
                                                    getString(R.string.soulseek_no_results),
                                                    Toast.LENGTH_SHORT).show();
                                        } else if (soulseekAutoDownloadPending && !soulseekDownloadUiFailed
                                                && soulseekActiveDownload == null) {
                                            soulseekAutoDownloadPending = false;
                                            startSoulseekTransfer(soulseekResults.get(0), SOULSEEK_ACTION_PLAY);
                                        }
                                        return;
                                    }
                                    if (soulseekUiMode == SOULSEEK_UI_ACTION) {
                                        return;
                                    }
                                    buildSoulseekResultsUI();
                                    finalizeSoulseekSearch(toSort.size());
                                    scheduleSoulseekSharePolicyRefresh();
                                    if (toSort.isEmpty()) {
                                        Toast.makeText(MainActivity.this,
                                                getString(R.string.soulseek_no_results),
                                                Toast.LENGTH_SHORT).show();
                                    } else if (soulseekAutoDownloadPending) {
                                        soulseekAutoDownloadPending = false;
                                        startSoulseekTransfer(soulseekResults.get(0), SOULSEEK_ACTION_PLAY);
                                    }
                                }
                            });
                        }
                    }, "SoulseekSort").start();
                }
            });
        }

        @Override
        public void onDownloadProgress(final String filename, final long done, final long total) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    if (soulseekActiveDownload == null) return;
                    long now = android.os.SystemClock.uptimeMillis();
                    // 2026-07-15 — Coarser progress UI while user is interacting off download/NP.
                    long minGap = 150L;
                    if (isInputPriorityBusy()
                            && soulseekUiMode != SOULSEEK_UI_DOWNLOAD
                            && currentScreenState != STATE_PLAYER) {
                        minGap = 800L;
                    }
                    if (now - soulseekLastProgressUiMs < minGap && total > 0 && done < total) return;
                    soulseekLastProgressUiMs = now;
                    if (done > 0) {
                        soulseekDownloadStalled = false;
                        soulseekUiHandler.removeCallbacks(soulseekStallWatchRunnable);
                        showSoulseekTryAnotherRow(false);
                    }
                    int pct = total > 0 ? (int) (done * 100 / total) : 0;
                    if (total > 0) reachGrowingTotalBytes = total;
                    updateSoulseekDownloadProgress(pct, done, total);
                    if (reachPartialPlaybackStarted && currentScreenState == STATE_PLAYER) {
                        updateReachPlayerBufferUi(pct, done, total);
                    }
                }
            });
        }

        @Override
        public void onDownloadPartialReady(final File partialFile, final long done, final long total) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    if (soulseekActiveDownload == null || partialFile == null) return;
                    final int action = soulseekPendingAction;
                    int pct = total > 0 ? (int) (done * 100 / total) : 0;
                    if (total > 0) reachGrowingTotalBytes = total;
                    updateSoulseekDownloadProgress(pct, done, total);
                    if (action == SOULSEEK_ACTION_PLAY && !reachPartialPlaybackStarted) {
                        reachPartialPlaybackStarted = true;
                        reachGrowingCacheFile = partialFile;
                        reachGrowingPreparedBytes = partialFile.length();
                        stopSoulseekDownloadUiRunnables();
                        startReachPlayFromPartial(partialFile);
                    } else if (action == SOULSEEK_ACTION_PLAY && reachPartialPlaybackStarted) {
                        reachGrowingCacheFile = partialFile;
                        updateReachGrowingDurationUi();
                        tryReachId3FromPartial(partialFile);
                    } else if (action == SOULSEEK_ACTION_QUEUE && reachQueuePartialFile == null) {
                        reachQueuePartialFile = partialFile;
                        String meta = soulseekActiveDownload != null
                                ? soulseekActiveDownload.title() : partialFile.getName();
                        String peer = soulseekActiveDownload != null
                                ? soulseekActiveDownload.username : null;
                        queueReachTrackAfterCurrent(partialFile, meta, peer);
                    }
                }
            });
        }

        @Override
        public void onDownloadComplete(final File file) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    try {
                        handleSoulseekDownloadCompleteOnUi(file);
                    } catch (Throwable t) {
                        android.util.Log.w("Solar", "Reach download complete UI", t);
                        clearSoulseekBackgroundSaveState();
                        stopSoulseekDownloadUiRunnables();
                        soulseekActiveDownload = null;
                        soulseekPendingAction = 0;
                    }
                }
            });
        }

        @Override
        public void onError(final String message) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    try {
                        handleSoulseekDownloadErrorOnUi(message);
                    } catch (Throwable t) {
                        android.util.Log.w("Solar", "Reach download error UI", t);
                        clearSoulseekBackgroundSaveState();
                        stopSoulseekDownloadUiRunnables();
                        soulseekActiveDownload = null;
                        soulseekPendingAction = 0;
                    }
                }
            });
        }
    };

    private final Runnable soulseekUiFlushRunnable = new Runnable() {
        @Override
        public void run() {
            // 2026-07-15 — Batching search rows rebuilds the list; wait out typing.
            if (isInputPriorityBusy()) {
                soulseekUiHandler.postDelayed(this, Math.max(200L, msUntilInputIdle()));
                return;
            }
            flushSoulseekResultsUi(false);
        }
    };

    private static String soulseekResultKey(SoulseekClient.Result result) {
        return result.username.toLowerCase(Locale.US) + "\0" + result.filename;
    }

    private static void sortSoulseekResultsByQuality(List<SoulseekClient.Result> list,
            String query, java.util.Set<String> historyPeers) {
        Collections.sort(list, new Comparator<SoulseekClient.Result>() {
            @Override
            public int compare(SoulseekClient.Result a, SoulseekClient.Result b) {
                return SoulseekClient.Result.compareByDownloadReliability(a, b, query, historyPeers);
            }
        });
    }

    private int soulseekRankInsertIndex(SoulseekClient.Result r) {
        java.util.Set<String> history = SoulseekDownloadHistory.loadPeerSet(prefs);
        for (int i = 0; i < soulseekResults.size(); i++) {
            if (SoulseekClient.Result.compareByDownloadReliability(
                    r, soulseekResults.get(i), soulseekLastQuery, history) < 0) return i;
        }
        return soulseekResults.size();
    }

    private void addSoulseekResultToList(SoulseekClient.Result r) {
        if (soulseekSearchInProgress) {
            soulseekResults.add(r);
        } else {
            soulseekResults.add(soulseekRankInsertIndex(r), r);
        }
    }

    private boolean requestSoulseekFocusByKey(String key) {
        if (key == null || containerBrowserItems == null) return false;
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View v = containerBrowserItems.getChildAt(i);
            if (v.getTag() instanceof SoulseekClient.Result) {
                SoulseekClient.Result r = (SoulseekClient.Result) v.getTag();
                if (key.equals(soulseekResultKey(r))) {
                    v.requestFocus();
                    return true;
                }
            }
        }
        return false;
    }

    private static String formatSoulseekSize(long bytes) {
        if (bytes <= 0) return "?";
        if (bytes >= 1024L * 1024L) {
            return String.format(Locale.US, "%.1f MB", bytes / (1024.0 * 1024.0));
        }
        return String.format(Locale.US, "%.0f KB", bytes / 1024.0);
    }

    private static String formatSoulseekBitrate(int kbps) {
        if (kbps <= 0) return "";
        return kbps + " kbps · ";
    }

    private static String formatSoulseekSpeed(long bytesPerSec) {
        if (bytesPerSec <= 0) return "";
        if (bytesPerSec >= 1024 * 1024) {
            return String.format(Locale.US, "%.1f MB/s", bytesPerSec / (1024.0 * 1024.0));
        }
        return String.format(Locale.US, "%.0f KB/s", bytesPerSec / 1024.0);
    }

    private void flushSoulseekResultsUi(boolean force) {
        soulseekUiFlushScheduled = false;
        List<SoulseekClient.Result> batch;
        synchronized (soulseekPendingUi) {
            if (soulseekPendingUi.isEmpty()) return;
            int take = force ? soulseekPendingUi.size()
                    : Math.min(SOULSEEK_ROWS_PER_FLUSH, soulseekPendingUi.size());
            batch = new ArrayList<SoulseekClient.Result>(soulseekPendingUi.subList(0, take));
            soulseekPendingUi.subList(0, take).clear();
        }
        if (!isSoulseekUiActive()) return;

        if (getMusicReachSearchActive()) {
            flushGetMusicReachBatch(batch);
            synchronized (soulseekPendingUi) {
                if (!soulseekPendingUi.isEmpty()) {
                    soulseekUiFlushScheduled = true;
                    long delay = soulseekPendingUi.size() > 16 ? SOULSEEK_UI_FLUSH_MS_HEAVY : SOULSEEK_UI_FLUSH_MS;
                    soulseekUiHandler.postDelayed(soulseekUiFlushRunnable, delay);
                }
            }
            return;
        }

        for (SoulseekClient.Result r : batch) {
            if (soulseekClient != null && soulseekClient.isPeerDenied(r.username)) continue;
            if (!soulseekResultKeys.add(soulseekResultKey(r))) continue;
            addSoulseekResultToList(r);
        }
        if (soulseekSearchInProgress) {
            appendSoulseekResultRowsInner();
        } else {
            refreshSoulseekVisibleResults(true);
        }
        updateSoulseekPathCount(force);
        synchronized (soulseekPendingUi) {
            if (!soulseekPendingUi.isEmpty()) {
                soulseekUiFlushScheduled = true;
                long delay = soulseekPendingUi.size() > 16 ? SOULSEEK_UI_FLUSH_MS_HEAVY : SOULSEEK_UI_FLUSH_MS;
                soulseekUiHandler.postDelayed(soulseekUiFlushRunnable, delay);
            }
        }
    }

    private void mergeSoulseekResultsFromSnapshot() {
        if (soulseekClient == null) return;
        for (SoulseekClient.Result r : soulseekClient.getResultsSnapshot()) {
            if (!soulseekResultAllowed(r)) continue;
            if (!soulseekResultKeys.add(soulseekResultKey(r))) continue;
            addSoulseekResultToList(r);
        }
    }

    private int soulseekVisibleCap() {
        if (soulseekSearchInProgress) return SOULSEEK_PAGE_SIZE;
        return soulseekResultsVisibleCount;
    }

    private int soulseekRankedResultCount() {
        int n = 0;
        for (SoulseekClient.Result r : soulseekResults) {
            if (soulseekClient != null && soulseekClient.isPeerDenied(r.username)) continue;
            if (soulseekSearchInProgress && r.isLikelySlowDownload()) continue;
            n++;
        }
        return n;
    }

    private void rebuildSoulseekOrganizedEntries() {
        soulseekOrganizedEntries.clear();
        List<SoulseekClient.Result> filtered = new ArrayList<SoulseekClient.Result>();
        for (SoulseekClient.Result r : soulseekResults) {
            if (!soulseekResultAllowed(r)) continue;
            filtered.add(r);
        }
        soulseekOrganizedEntries.addAll(GetMusicSearch.organizeReachResults(filtered));
    }

    private boolean soulseekUseOrganizedDisplay() {
        return !soulseekSearchInProgress && !soulseekOrganizedEntries.isEmpty();
    }

    private List<MusicSearchEntry> soulseekResultsForDisplay() {
        if (soulseekBrowseContainer != null) return soulseekBrowseContainer.children;
        if (soulseekUseOrganizedDisplay()) return soulseekOrganizedEntries;
        return null;
    }

    private int soulseekDisplayResultCount() {
        List<MusicSearchEntry> display = soulseekResultsForDisplay();
        if (display != null) return display.size();
        return soulseekRankedResultCount();
    }

    private void appendSoulseekResultRowsInner() {
        if (!isSoulseekUiActive() || soulseekUiMode != SOULSEEK_UI_RESULTS) return;
        int cap = soulseekVisibleCap();
        int insertAt = soulseekResultInsertIndex();
        int added = 0;
        List<MusicSearchEntry> organized = soulseekResultsForDisplay();
        if (organized != null) {
            while (soulseekResultUiCount < organized.size() && soulseekResultUiCount < cap) {
                MusicSearchEntry e = organized.get(soulseekResultUiCount);
                View row = e.isContainer()
                        ? makeSoulseekContainerRow(e) : makeSoulseekResultButton(e.reach);
                containerBrowserItems.addView(row, insertAt + added);
                soulseekResultUiCount++;
                added++;
            }
        } else {
            int rankedIndex = 0;
            for (SoulseekClient.Result r : soulseekResults) {
                if (soulseekClient != null && soulseekClient.isPeerDenied(r.username)) continue;
                if (soulseekSearchInProgress && r.isLikelySlowDownload()) continue;
                if (rankedIndex < soulseekResultUiCount) {
                    rankedIndex++;
                    continue;
                }
                if (soulseekResultUiCount >= cap) break;
                containerBrowserItems.addView(makeSoulseekResultButton(r), insertAt + added);
                soulseekResultUiCount++;
                rankedIndex++;
                added++;
            }
        }
        if (soulseekSearchStatusRow != null && soulseekResultUiCount > 0) {
            containerBrowserItems.removeView(soulseekSearchStatusRow);
            soulseekSearchStatusRow = null;
        }
        updateSoulseekMoreRow(soulseekDisplayResultCount());
    }

    /** Rebuild visible result rows from ranked soulseekResults — not arrival order. */
    private void refreshSoulseekVisibleResults(boolean fullRebuild) {
        if (!isSoulseekUiActive() || soulseekUiMode != SOULSEEK_UI_RESULTS) return;
        // 2026-07-15 — Keep wheel focus while results stream in.
        final String focusKey = captureBrowserFocusKey();
        final int scrollBefore = scrollViewBrowser instanceof android.widget.ScrollView
                ? ((android.widget.ScrollView) scrollViewBrowser).getScrollY() : -1;
        if (!fullRebuild) {
            // Append only — never requestFocus (keeps A5 wheel / face L/R responsive).
            appendSoulseekResultRowsInner();
            syncStatusBarSearchThrobber();
            return;
        }
        java.util.ArrayList<View> toRemove = new java.util.ArrayList<View>();
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View v = containerBrowserItems.getChildAt(i);
            if (v.getTag() instanceof SoulseekClient.Result
                    || v.getTag() instanceof MusicSearchEntry) toRemove.add(v);
        }
        for (View v : toRemove) containerBrowserItems.removeView(v);
        soulseekResultUiCount = 0;
        appendSoulseekResultRowsInner();
        restoreBrowserFocusKey(focusKey, scrollBefore);
        syncStatusBarSearchThrobber();
    }

    private int soulseekResultInsertIndex() {
        if (soulseekMoreRow != null && soulseekMoreRow.getParent() == containerBrowserItems) {
            return containerBrowserItems.indexOfChild(soulseekMoreRow);
        }
        return containerBrowserItems.getChildCount();
    }

    private void updateReachBrowserHint(int hintResId) {
        if (tvBrowserPath != null) tvBrowserPath.setText(getString(hintResId));
    }

    private boolean getMusicReachSearchActive() {
        return isGetMusicUnifiedUi()
                && (getMusicMode == GetMusicSources.MODE_UNIFIED
                || getMusicMode == GetMusicSources.MODE_REACH_ONLY)
                && GetMusicSources.reachSearchInGetMusic(prefs, soulseekActive());
    }

    private boolean getMusicDeezerSearchActive() {
        return isGetMusicUnifiedUi()
                && (getMusicMode == GetMusicSources.MODE_UNIFIED
                || getMusicMode == GetMusicSources.MODE_DEEZER_ONLY)
                && GetMusicSources.deezerSearchInGetMusic(prefs, deezerActive());
    }

    private void maybeFinishGetMusicSearch(int gen) {
        if (gen != getMusicSearchGen) return;
        if (!getMusicDeezerDone) return;
        if (!getMusicNavidromeDone) return;
        if (!getMusicPlexDone) return;
        if (!getMusicJellyfinDone) return;
        if (getMusicReachSearchActive() && !getMusicReachDone) return;
        finishGetMusicSearch(gen);
    }

    private boolean isGetMusicUnifiedUi() {
        return getMusicFromEntryPoint;
    }

    private String getMusicStatusTitle() {
        return getString(R.string.get_music_status_title);
    }

    private String getMusicSourcesSubtitle() {
        return getString(GetMusicSources.activeSourceSubtitleRes(
                prefs, soulseekActive(), deezerActive()));
    }

    private boolean getMusicHasBothSearchSources() {
        return GetMusicSources.activeSourceSubtitle(prefs, soulseekActive(), deezerActive())
                == GetMusicSources.SUBTITLE_BOTH;
    }

    private void updateReachBrowserHintForGetMusic() {
        if (tvBrowserPath != null) {
            tvBrowserPath.setText(getMusicSourcesSubtitle());
        }
    }

    private View createGetMusicListRow(String title, String subtitle, final View.OnClickListener click) {
        final int rowKind = Y1_ROW_ITEM;
        final LinearLayout row = new LinearLayout(this);
        row.setOrientation(LinearLayout.VERTICAL);
        // 2026-07-14 — Block descendant focus so the row shell takes highlight (settings-row parity).
        // Layman: blue bar sits on the whole track line, not stuck on Search again forever.
        // Was: default AFTER_DESCENDANTS → requestFocus failed (TextViews not focusable) →
        // wheel could not leave Search again onto albums/tracks.
        // Reversal: drop BLOCK_DESCENDANTS / focusableInTouchMode; return to Button-only rows.
        row.setDescendantFocusability(ViewGroup.FOCUS_BLOCK_DESCENDANTS);
        row.setFocusable(true);
        row.setFocusableInTouchMode(true);
        row.setClickable(true);
        row.setSoundEffectsEnabled(false);
        int hPad = (int) (10 * getResources().getDisplayMetrics().density);
        row.setPadding(hPad, 4, hPad, 4);
        int rowW = listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx();
        row.setBackground(getY1RowBackground(false, rowW, rowKind));
        A5FocusConfirm.setOnClickListener(row, click);
        attachA5RowLongPress(row);

        final TextView tvTitle = new TextView(this);
        tvTitle.setFocusable(false);
        tvTitle.setClickable(false);
        tvTitle.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        tvTitle.setText(title != null ? title : "");
        ThemeManager.applyThemedTextStyle(tvTitle, y1RowTextColorNormal(rowKind));
        tvTitle.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                getResources().getDimension(R.dimen.y1_menu_text_size));
        enableMarquee(tvTitle);
        row.addView(tvTitle, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT));

        if (subtitle != null && subtitle.length() > 0) {
            TextView tvSub = new TextView(this);
            tvSub.setFocusable(false);
            tvSub.setClickable(false);
            tvSub.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
            tvSub.setText(subtitle);
            ThemeManager.applyThemedTextStyle(tvSub, ThemeManager.getTextColorSecondary());
            tvSub.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX,
                    getResources().getDimension(R.dimen.y1_menu_text_size) * 0.85f);
            enableMarquee(tvSub);
            row.addView(tvSub, new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT));

            row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    int w = row.getWidth() > 0 ? row.getWidth()
                            : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());
                    row.setBackground(getY1RowBackground(hasFocus, w, rowKind));
                    ThemeManager.applyThemedTextStyle(tvTitle, hasFocus
                            ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                    ThemeManager.applyThemedTextStyle(tvSub, hasFocus
                            ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                    tvTitle.setSelected(hasFocus);
                    tvSub.setSelected(hasFocus);
                    if (hasFocus) showFastScrollLetter(title);
                }
            });
        } else {
            row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    int w = row.getWidth() > 0 ? row.getWidth()
                            : (listRowWidthPx > 0 ? listRowWidthPx : y1ActiveRowWidthPx());
                    row.setBackground(getY1RowBackground(hasFocus, w, rowKind));
                    ThemeManager.applyThemedTextStyle(tvTitle, hasFocus
                            ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
                    tvTitle.setSelected(hasFocus);
                    if (hasFocus) showFastScrollLetter(title);
                }
            });
        }

        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT);
        lp.setMargins(0, 1, 0, 1);
        row.setLayoutParams(lp);
        return row;
    }

    private void fetchGetMusicResults(final String query) {
        if (query == null || query.trim().isEmpty()) return;
        if (!requireInternet(R.string.toast_internet_required)) return;
        soulseekLastQuery = query.trim();
        GetMusicSearchHistory.remember(prefs, soulseekLastQuery);
        getMusicSearchGen++;
        final int gen = getMusicSearchGen;
        getMusicSearchInProgress = true;
        syncStatusBarSearchThrobber();
        getMusicDeezerDone = false;
        getMusicDeezerTracksReady = false;
        getMusicDeezerArtistsFetched = false;
        getMusicReachDone = false;
        getMusicDeezerError = null;
        getMusicResultsVisibleCount = GET_MUSIC_PAGE_SIZE;
        getMusicEntries.clear();
        getMusicTopLevelEntries.clear();
        getMusicBrowseContainer = null;
        getMusicDeezerResults.clear();
        getMusicDeezerArtists.clear();
        getMusicReachKeys.clear();
        getMusicDeezerDedupeKeys.clear();
        getMusicNavidromeEntries.clear();
        getMusicNavidromeDone = !NavidromePrefs.isConfigured(prefs);
        getMusicPlexEntries.clear();
        // 2026-07-14: Skip Get Music merge unless Debug experiment is On.
        getMusicPlexDone = !(com.solar.launcher.plex.PlexExperiment.isEnabled(prefs)
                && com.solar.launcher.plex.PlexPrefs.isConfigured(prefs));
        getMusicJellyfinEntries.clear();
        getMusicJellyfinDone = !(com.solar.launcher.jellyfin.JellyfinExperiment.isEnabled(prefs)
                && com.solar.launcher.jellyfin.JellyfinPrefs.isConfigured(prefs));
        getMusicEntryUiCount = 0;
        soulseekResults.clear();
        soulseekResultKeys.clear();
        soulseekOrganizedEntries.clear();
        soulseekBrowseContainer = null;
        synchronized (soulseekPendingUi) {
            soulseekPendingUi.clear();
        }
        soulseekUiHandler.removeCallbacks(soulseekUiFlushRunnable);
        soulseekUiFlushScheduled = false;
        buildGetMusicResultsShell();

        final boolean wantDeezer = getMusicDeezerSearchActive();
        final boolean wantReachSearch = getMusicReachSearchActive();

        if (wantDeezer) {
            if (GetMusicSources.deezerConfiguredForGetMusic(prefs, deezerActive())
                    && !ConnectivityHelper.isDeezerLoginOk()) {
                refreshDeezerSessionFromPrefs(false);
            }
            new Thread(new Runnable() {
                @Override public void run() {
                    String errorMsg = null;
                    try {
                        DeezerClient c = new DeezerClient(prefs);
                        if (GetMusicSources.deezerConfiguredForGetMusic(prefs, deezerActive())) {
                            try {
                                if (c.initSession()) ConnectivityHelper.setDeezerLoginOk(true);
                            } catch (Exception ignored) {}
                        }
                        final DeezerSearch search = new DeezerSearch(c);
                        Thread tracksThread = new Thread(new Runnable() {
                            @Override public void run() {
                                List<DeezerResult> foundTracks = new ArrayList<DeezerResult>();
                                String err = null;
                                try {
                                    foundTracks = search.searchTracks(soulseekLastQuery);
                                } catch (Exception e) {
                                    err = e.getMessage() != null ? e.getMessage() : "Error";
                                }
                                final List<DeezerResult> ff = foundTracks;
                                final String trackErr = err;
                                runOnUiThread(new Runnable() {
                                    @Override public void run() {
                                        if (gen != getMusicSearchGen) return;
                                        applyGetMusicDeezerTracksUi(gen, ff, trackErr);
                                        maybeCompleteGetMusicDeezerSearch(gen);
                                    }
                                });
                            }
                        }, "GetMusicDzTracks");
                        Thread artistsThread = new Thread(new Runnable() {
                            @Override public void run() {
                                List<DeezerSearch.DeezerArtist> foundArtists =
                                        new ArrayList<DeezerSearch.DeezerArtist>();
                                String err = null;
                                try {
                                    foundArtists = search.searchArtists(soulseekLastQuery);
                                } catch (Exception e) {
                                    err = e.getMessage() != null ? e.getMessage() : "Error";
                                }
                                final List<DeezerSearch.DeezerArtist> fa = foundArtists;
                                final String artistErr = err;
                                runOnUiThread(new Runnable() {
                                    @Override public void run() {
                                        if (gen != getMusicSearchGen) return;
                                        getMusicDeezerArtists.clear();
                                        getMusicDeezerArtists.addAll(fa);
                                        getMusicDeezerArtistsFetched = true;
                                        if (artistErr != null) getMusicDeezerError = artistErr;
                                        if (getMusicDeezerTracksReady) {
                                            refreshGetMusicResultsVisible(true);
                                        }
                                        maybeCompleteGetMusicDeezerSearch(gen);
                                    }
                                });
                            }
                        }, "GetMusicDzArtists");
                        tracksThread.start();
                        artistsThread.start();
                    } catch (Exception e) {
                        errorMsg = e.getMessage() != null ? e.getMessage() : "Error";
                        final String err = errorMsg;
                        runOnUiThread(new Runnable() {
                            @Override public void run() {
                                if (gen != getMusicSearchGen) return;
                                applyGetMusicDeezerTracksUi(gen, new ArrayList<DeezerResult>(), err);
                                getMusicDeezerArtists.clear();
                                getMusicDeezerArtistsFetched = true;
                                maybeCompleteGetMusicDeezerSearch(gen);
                            }
                        });
                    }
                }
            }, "GetMusicDeezer").start();
        } else {
            getMusicDeezerDone = true;
            getMusicDeezerTracksReady = true;
            getMusicDeezerArtistsFetched = true;
        }

        if (wantReachSearch) {
            SoulseekClient reachClient = null;
            if (requireReachPeerConnectivity()) {
                reachClient = ensureSoulseekClient();
            }
            if (reachClient != null) {
                soulseekSearchInProgress = true;
                updateGetMusicSearchStatusRow();
                reachClient.search(soulseekLastQuery);
            } else {
                getMusicReachDone = true;
                maybeFinishGetMusicSearch(gen);
            }
        } else {
            getMusicReachDone = true;
            if (getMusicDeezerDone && getMusicNavidromeDone && getMusicPlexDone && getMusicJellyfinDone) maybeFinishGetMusicSearch(gen);
        }

        if (NavidromePrefs.isConfigured(prefs) && requireInternet(R.string.navidrome_wifi_required)) {
            NavidromeClient.getInstance().search(soulseekLastQuery,
                    new NavidromeClient.Callback<com.solar.launcher.navidrome.NavidromeSearchResult>() {
                @Override public void onSuccess(com.solar.launcher.navidrome.NavidromeSearchResult result) {
                    if (gen != getMusicSearchGen) return;
                    getMusicNavidromeEntries.clear();
                    if (result != null) {
                        for (com.solar.launcher.navidrome.NavidromeSong s : result.songs) {
                            getMusicNavidromeEntries.add(MusicSearchEntry.navidrome(s));
                        }
                        for (com.solar.launcher.navidrome.NavidromeAlbum al : result.albums) {
                            java.util.List<MusicSearchEntry> tracks = new java.util.ArrayList<MusicSearchEntry>();
                            getMusicNavidromeEntries.add(MusicSearchEntry.navidromeAlbum(al, tracks));
                        }
                    }
                    getMusicNavidromeDone = true;
                    maybeFinishGetMusicSearch(gen);
                }
                @Override public void onError(String message) {
                    if (gen != getMusicSearchGen) return;
                    getMusicNavidromeDone = true;
                    maybeFinishGetMusicSearch(gen);
                }
            });
        }
        if (com.solar.launcher.plex.PlexExperiment.isEnabled(prefs)
                && com.solar.launcher.plex.PlexPrefs.isConfigured(prefs)
                && requireInternet(R.string.plex_wifi_required)) {
            com.solar.launcher.plex.PlexClient.getInstance().search(soulseekLastQuery,
                    new com.solar.launcher.plex.PlexClient.Callback<com.solar.launcher.plex.PlexSearchResult>() {
                @Override public void onSuccess(com.solar.launcher.plex.PlexSearchResult result) {
                    if (gen != getMusicSearchGen) return;
                    getMusicPlexEntries.clear();
                    if (result != null) {
                        for (com.solar.launcher.plex.PlexSong s : result.songs) {
                            getMusicPlexEntries.add(MusicSearchEntry.plex(s));
                        }
                        for (com.solar.launcher.plex.PlexAlbum al : result.albums) {
                            java.util.List<MusicSearchEntry> tracks = new java.util.ArrayList<MusicSearchEntry>();
                            getMusicPlexEntries.add(MusicSearchEntry.plexAlbum(al, tracks));
                        }
                    }
                    getMusicPlexDone = true;
                    maybeFinishGetMusicSearch(gen);
                }
                @Override public void onError(String message) {
                    if (gen != getMusicSearchGen) return;
                    getMusicPlexDone = true;
                    maybeFinishGetMusicSearch(gen);
                }
            });
        }
        if (com.solar.launcher.jellyfin.JellyfinExperiment.isEnabled(prefs)
                && com.solar.launcher.jellyfin.JellyfinPrefs.isConfigured(prefs)
                && requireInternet(R.string.jellyfin_wifi_required)) {
            com.solar.launcher.jellyfin.JellyfinClient.getInstance().search(soulseekLastQuery,
                    new com.solar.launcher.jellyfin.JellyfinClient.Callback<
                            com.solar.launcher.jellyfin.JellyfinSearchResult>() {
                @Override public void onSuccess(com.solar.launcher.jellyfin.JellyfinSearchResult result) {
                    if (gen != getMusicSearchGen) return;
                    getMusicJellyfinEntries.clear();
                    if (result != null) {
                        for (com.solar.launcher.jellyfin.JellyfinSong s : result.songs) {
                            getMusicJellyfinEntries.add(MusicSearchEntry.jellyfin(s));
                        }
                        for (com.solar.launcher.jellyfin.JellyfinAlbum al : result.albums) {
                            java.util.List<MusicSearchEntry> tracks = new java.util.ArrayList<MusicSearchEntry>();
                            getMusicJellyfinEntries.add(MusicSearchEntry.jellyfinAlbum(al, tracks));
                        }
                    }
                    getMusicJellyfinDone = true;
                    maybeFinishGetMusicSearch(gen);
                }
                @Override public void onError(String message) {
                    if (gen != getMusicSearchGen) return;
                    getMusicJellyfinDone = true;
                    maybeFinishGetMusicSearch(gen);
                }
            });
        }
    }

    private void finishGetMusicSearch(int gen) {
        if (gen != getMusicSearchGen) return;
        getMusicSearchInProgress = false;
        soulseekSearchInProgress = false;
        syncStatusBarSearchThrobber();
        getMusicTopLevelEntries.clear();
        java.util.List<MusicSearchEntry> mergedReach = new java.util.ArrayList<MusicSearchEntry>(getMusicEntries);
        mergedReach.addAll(getMusicNavidromeEntries);
        mergedReach.addAll(getMusicPlexEntries);
        mergedReach.addAll(getMusicJellyfinEntries);
        getMusicTopLevelEntries.addAll(
                organizeGetMusicResults(getMusicDeezerArtists, mergedReach));
        getMusicBrowseContainer = null;
        getMusicEntryUiCount = 0;
        refreshGetMusicResultsVisible(true);
        if (getMusicSearchStatusRow != null && getMusicResultsForDisplay().isEmpty()) {
            getMusicSearchStatusRow.setText(getString(
                    getMusicHasBothSearchSources()
                            ? R.string.get_music_empty_unified : R.string.get_music_empty_results));
        }
        if (tvBrowserPath != null) {
            tvBrowserPath.setText(getString(R.string.get_music_path_results, soulseekLastQuery));
        }
    }

    private List<MusicSearchEntry> getMusicResultsForDisplay() {
        if (getMusicBrowseContainer != null) return getMusicBrowseContainer.children;
        if (!getMusicSearchInProgress && !getMusicTopLevelEntries.isEmpty()) {
            return getMusicTopLevelEntries;
        }
        return organizeGetMusicResults(getMusicDeezerArtists, mergedGetMusicFlat());
    }

    private java.util.List<MusicSearchEntry> mergedGetMusicFlat() {
        java.util.List<MusicSearchEntry> merged = new java.util.ArrayList<MusicSearchEntry>(getMusicEntries);
        merged.addAll(getMusicNavidromeEntries);
        merged.addAll(getMusicPlexEntries);
        merged.addAll(getMusicJellyfinEntries);
        return merged;
    }

    /** Deezer-first when both sources are active; round-robin within each catalog. */
    private List<MusicSearchEntry> organizeGetMusicResults(
            List<DeezerSearch.DeezerArtist> artists, List<MusicSearchEntry> flat) {
        if (getMusicHasBothSearchSources()) {
            return GetMusicSearch.organizeUnifiedDeezerFirst(artists, flat);
        }
        return GetMusicSearch.organizeWithContainers(artists, flat);
    }

    private void removeDeezerEntriesFromGetMusic() {
        java.util.Iterator<MusicSearchEntry> it = getMusicEntries.iterator();
        while (it.hasNext()) {
            if (it.next().source == MusicSearchEntry.Source.DEEZER) it.remove();
        }
    }

    /** Apply Deezer track hits as soon as the API returns — before artist search finishes. */
    private void applyGetMusicDeezerTracksUi(final int gen, List<DeezerResult> tracks, String err) {
        if (gen != getMusicSearchGen) return;
        removeDeezerEntriesFromGetMusic();
        getMusicDeezerResults.clear();
        if (tracks != null) getMusicDeezerResults.addAll(tracks);
        getMusicDeezerDedupeKeys = GetMusicSearch.deezerDedupeKeys(getMusicDeezerResults);
        for (DeezerResult r : getMusicDeezerResults) {
            getMusicEntries.add(MusicSearchEntry.deezer(r));
        }
        getMusicDeezerTracksReady = true;
        if (err != null) getMusicDeezerError = err;
        updateGetMusicSearchStatusRow();
        refreshGetMusicResultsVisible(true);
    }

    private void maybeCompleteGetMusicDeezerSearch(int gen) {
        if (gen != getMusicSearchGen || getMusicDeezerDone) return;
        if (!getMusicDeezerTracksReady || !getMusicDeezerArtistsFetched) return;
        getMusicDeezerDone = true;
        updateGetMusicSearchStatusRow();
        refreshGetMusicResultsVisible(true);
        maybeFinishGetMusicSearch(gen);
    }

    private void refreshGetMusicResultsVisible(boolean fullRebuild) {
        if (!isSoulseekUiActive() || soulseekUiMode != SOULSEEK_UI_RESULTS || !isGetMusicUnifiedUi()) return;
        // 2026-07-15 — Preserve focus/scroll while Get Music results stream in.
        final String focusKey = captureBrowserFocusKey();
        final int scrollBefore = scrollViewBrowser instanceof android.widget.ScrollView
                ? ((android.widget.ScrollView) scrollViewBrowser).getScrollY() : -1;
        if (!fullRebuild) {
            // Append only — do not restore focus (user may be wheeling through rows).
            appendGetMusicResultRowsInner();
            syncStatusBarSearchThrobber();
            return;
        }
        java.util.ArrayList<View> toRemove = new java.util.ArrayList<View>();
        for (int i = 0; i < containerBrowserItems.getChildCount(); i++) {
            View v = containerBrowserItems.getChildAt(i);
            if (v.getTag() instanceof MusicSearchEntry) toRemove.add(v);
        }
        for (View v : toRemove) containerBrowserItems.removeView(v);
        getMusicEntryUiCount = 0;
        appendGetMusicResultRowsInner();
        restoreBrowserFocusKey(focusKey, scrollBefore);
        syncStatusBarSearchThrobber();
    }

    /** 2026-07-15 — Stable-ish debug id for a Get Music row (not for UI). */
    private static String musicSearchEntryDebugKey(MusicSearchEntry e) {
        if (e == null) return "";
        if (e.reach != null) return "r:" + GetMusicSearch.reachResultKey(e.reach);
        if (e.deezer != null) return "d:" + e.deezer.id;
        if (e.kind != null) return e.kind.name() + ":" + e.containerLabel;
        return String.valueOf(e.source);
    }

    private void openGetMusicContainer(final MusicSearchEntry container) {
        if (container == null || !container.isContainer()) return;
        if (container.needsLazyLoad()) {
            beginGetMusicLazyContainerLoad(container);
            return;
        }
        getMusicBrowseContainer = container;
        getMusicEntryUiCount = 0;
        getMusicResultsVisibleCount = GET_MUSIC_PAGE_SIZE;
        containerBrowserItems.removeAllViews();

        Button back = createListButton(getString(R.string.get_music_back_containers));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                getMusicBrowseContainer = null;
                getMusicEntryUiCount = 0;
                buildGetMusicResultsUI();
            }
        });
        containerBrowserItems.addView(back);

        String pathLabel;
        if (container.kind == MusicSearchEntry.RowKind.DEEZER_ARTIST) {
            pathLabel = getString(R.string.get_music_artist_row, container.containerLabel);
        } else if (container.kind == MusicSearchEntry.RowKind.DEEZER_ALBUM) {
            pathLabel = GetMusicSearch.formatDeezerReleaseLabel(
                    container.deezerRecordType, container.containerLabel);
        } else {
            pathLabel = getString(R.string.get_music_folder_row, container.containerLabel);
        }
        if (tvBrowserPath != null) {
            tvBrowserPath.setText(getString(R.string.get_music_path_container, pathLabel));
        }
        appendGetMusicResultRowsInner();
        if (containerBrowserItems.getChildCount() > 0) containerBrowserItems.getChildAt(0).requestFocus();
    }

    private void beginGetMusicLazyContainerLoad(final MusicSearchEntry container) {
        getMusicContainerLoadGen++;
        final int gen = getMusicContainerLoadGen;
        getMusicBrowseContainer = container;
        getMusicEntryUiCount = 0;
        containerBrowserItems.removeAllViews();

        Button back = createListButton(getString(R.string.get_music_back_containers));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                getMusicBrowseContainer = null;
                getMusicEntryUiCount = 0;
                buildGetMusicResultsUI();
            }
        });
        containerBrowserItems.addView(back);

        Button loading = createListButton(getString(R.string.get_music_loading_container));
        loading.setEnabled(false);
        containerBrowserItems.addView(loading);
        if (tvBrowserPath != null) {
            tvBrowserPath.setText(getString(R.string.get_music_path_container,
                    container.containerLabel));
        }

        new Thread(new Runnable() {
            @Override public void run() {
                List<MusicSearchEntry> children = new ArrayList<MusicSearchEntry>();
                try {
                    DeezerClient c = new DeezerClient(prefs);
                    DeezerSearch search = new DeezerSearch(c);
                    if (container.kind == MusicSearchEntry.RowKind.DEEZER_ARTIST) {
                        List<DeezerSearch.DeezerAlbum> albums =
                                search.listArtistAlbums(container.deezerContainerId);
                        java.util.Collections.sort(albums, new java.util.Comparator<DeezerSearch.DeezerAlbum>() {
                            @Override
                            public int compare(DeezerSearch.DeezerAlbum a, DeezerSearch.DeezerAlbum b) {
                                int ta = recordTypeOrder(a.recordType);
                                int tb = recordTypeOrder(b.recordType);
                                if (ta != tb) return ta - tb;
                                return a.title.compareToIgnoreCase(b.title);
                            }
                        });
                        for (DeezerSearch.DeezerAlbum a : albums) {
                            if (a == null || a.id <= 0) continue;
                            children.add(MusicSearchEntry.deezerAlbumBrowse(
                                    a.id, a.title, a.recordType, null));
                        }
                    } else if (container.kind == MusicSearchEntry.RowKind.DEEZER_ALBUM) {
                        List<DeezerResult> tracks =
                                search.listAlbumTracks(container.deezerContainerId);
                        for (DeezerResult t : tracks) {
                            if (t == null) continue;
                            children.add(MusicSearchEntry.deezer(t));
                        }
                    }
                } catch (Exception ignored) {}
                final List<MusicSearchEntry> loaded = children;
                runOnUiThread(new Runnable() {
                    @Override public void run() {
                        if (gen != getMusicContainerLoadGen) return;
                        getMusicBrowseContainer = MusicSearchEntry.withChildren(container, loaded);
                        getMusicEntryUiCount = 0;
                        getMusicResultsVisibleCount = GET_MUSIC_PAGE_SIZE;
                        containerBrowserItems.removeAllViews();
                        containerBrowserItems.addView(backFromLazyContainerButton());
                        if (loaded.isEmpty()) {
                            Button empty = createListButton(getString(R.string.get_music_empty_results));
                            empty.setEnabled(false);
                            containerBrowserItems.addView(empty);
                        } else {
                            appendGetMusicResultRowsInner();
                        }
                        if (containerBrowserItems.getChildCount() > 0) {
                            containerBrowserItems.getChildAt(0).requestFocus();
                        }
                    }
                });
            }
        }, "GetMusicBrowse").start();
    }

    private static int recordTypeOrder(String recordType) {
        if (recordType == null) return 0;
        String t = recordType.toLowerCase(java.util.Locale.US);
        if ("album".equals(t)) return 0;
        if ("ep".equals(t)) return 1;
        if ("single".equals(t)) return 2;
        return 3;
    }

    private Button backFromLazyContainerButton() {
        Button back = createListButton(getString(R.string.get_music_back_containers));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                getMusicBrowseContainer = null;
                getMusicEntryUiCount = 0;
                buildGetMusicResultsUI();
            }
        });
        return back;
    }

    private void buildGetMusicResultsShell() {
        soulseekUiMode = SOULSEEK_UI_RESULTS;
        getMusicEntryUiCount = 0;
        getMusicSearchStatusRow = null;
        getMusicMoreRow = null;
        prepareSoulseekBrowserChrome();
        browserStatusTitle = getMusicStatusTitle();
        updateStatusBarTitle();
        if (tvBrowserPath != null) {
            tvBrowserPath.setText(getString(R.string.get_music_path_searching, soulseekLastQuery));
        }
        updateReachBrowserHintForGetMusic();
        containerBrowserItems.removeAllViews();

        Button back = createListButton(getString(R.string.get_music_back_search));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                cancelGetMusicSearch();
                buildSoulseekSearchUI();
            }
        });
        containerBrowserItems.addView(back);

        getMusicSearchStatusRow = createListButton(getString(R.string.get_music_searching));
        getMusicSearchStatusRow.setEnabled(false);
        containerBrowserItems.addView(getMusicSearchStatusRow);
        updateGetMusicSearchStatusRow();
        if (containerBrowserItems.getChildCount() > 0) containerBrowserItems.getChildAt(0).requestFocus();
    }

    private void updateGetMusicSearchStatusRow() {
        if (getMusicSearchStatusRow == null) return;
        if (getMusicDeezerError != null && getMusicDeezerDone) {
            getMusicSearchStatusRow.setText(getString(R.string.get_music_deezer_error, getMusicDeezerError));
            return;
        }
        boolean wantReach = getMusicReachSearchActive();
        boolean wantDeezer = getMusicDeezerSearchActive();
        if (!getMusicDeezerDone && wantDeezer && wantReach) {
            getMusicSearchStatusRow.setText(getString(R.string.get_music_searching_both));
        } else if (!getMusicDeezerDone && wantDeezer) {
            getMusicSearchStatusRow.setText(getString(R.string.get_music_searching_deezer));
        } else if (wantReach && soulseekSearchInProgress) {
            getMusicSearchStatusRow.setText(getString(R.string.get_music_searching_soulseek));
        } else if (getMusicSearchInProgress) {
            getMusicSearchStatusRow.setText(getString(R.string.get_music_searching));
        }
    }

    private void buildGetMusicResultsUI() {
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("screen", currentScreenState);
            d.put("browserVis", layoutBrowserMode != null ? layoutBrowserMode.getVisibility() : -1);
            d.put("playerVis", layoutPlayerMode != null ? layoutPlayerMode.getVisibility() : -1);
            com.solar.launcher.DebugSessionLog.log("MainActivity.buildGetMusicResultsUI", "rebuild results", "H-D", d);
        } catch (Exception ignored) {}
        // #endregion
        soulseekUiMode = SOULSEEK_UI_RESULTS;
        getMusicEntryUiCount = 0;
        getMusicSearchStatusRow = null;
        getMusicMoreRow = null;
        prepareSoulseekBrowserChrome();
        browserStatusTitle = getMusicStatusTitle();
        updateStatusBarTitle();
        if (tvBrowserPath != null) {
            tvBrowserPath.setText(getString(R.string.get_music_path_results, soulseekLastQuery));
        }
        containerBrowserItems.removeAllViews();

        Button back = createListButton(getString(R.string.get_music_back_search));
        back.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                buildSoulseekSearchUI();
            }
        });
        containerBrowserItems.addView(back);

        Button searchAgain = createListButton(getString(R.string.get_music_search_again));
        searchAgain.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                openGetMusicSearchKeyboard();
            }
        });
        containerBrowserItems.addView(searchAgain);

        if (getMusicEntries.isEmpty()) {
            Button empty = createListButton(getString(
                    getMusicHasBothSearchSources()
                            ? R.string.get_music_empty_unified : R.string.get_music_empty_results));
            empty.setEnabled(false);
            containerBrowserItems.addView(empty);
        } else {
            getMusicTopLevelEntries.clear();
            getMusicTopLevelEntries.addAll(
                    organizeGetMusicResults(getMusicDeezerArtists, getMusicEntries));
            getMusicBrowseContainer = null;
            updateReachBrowserHint(R.string.get_music_hint_results);
            appendGetMusicResultRowsInner();
        }
        if (containerBrowserItems.getChildCount() > 0) {
            // #region agent log
            try {
                View foc = getCurrentFocus();
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("runId", "pre-fix");
                d.put("children", containerBrowserItems.getChildCount());
                d.put("entries", getMusicEntries.size());
                d.put("forcingChild0", true);
                d.put("focusBefore", foc instanceof android.widget.TextView
                        ? String.valueOf(((android.widget.TextView) foc).getText()) : "");
                Debug701426Log.log(this, "MainActivity.buildGetMusicResultsUI",
                        "full UI rebuild forcing Back focus", "C", d);
            } catch (Exception ignored) {}
            // #endregion
            containerBrowserItems.getChildAt(0).requestFocus();
        }
    }

    private void cancelGetMusicSearch() {
        getMusicSearchGen++;
        getMusicSearchInProgress = false;
        soulseekSearchInProgress = false;
        if (soulseekClient != null) soulseekClient.cancelSearch();
        if (deezerScreen != null) deezerScreen.cancelSearch();
    }

    private int getMusicVisibleCap() {
        if (getMusicSearchInProgress) return GET_MUSIC_PAGE_SIZE;
        return getMusicResultsVisibleCount;
    }

    private void appendGetMusicResultRowsInner() {
        if (!isSoulseekUiActive() || soulseekUiMode != SOULSEEK_UI_RESULTS || !isGetMusicUnifiedUi()) return;
        final List<MusicSearchEntry> display = getMusicResultsForDisplay();
        int cap = getMusicVisibleCap();
        int insertAt = getMusicResultInsertIndex();
        int added = 0;
        while (getMusicEntryUiCount < display.size() && getMusicEntryUiCount < cap) {
            final MusicSearchEntry e = display.get(getMusicEntryUiCount);
            View row = makeGetMusicResultRow(e);
            containerBrowserItems.addView(row, insertAt + added);
            getMusicEntryUiCount++;
            added++;
        }
        if (getMusicSearchStatusRow != null && getMusicEntryUiCount > 0) {
            containerBrowserItems.removeView(getMusicSearchStatusRow);
            getMusicSearchStatusRow = null;
        }
        updateGetMusicMoreRow(display.size());
    }

    private int getMusicResultInsertIndex() {
        if (getMusicMoreRow != null && getMusicMoreRow.getParent() == containerBrowserItems) {
            return containerBrowserItems.indexOfChild(getMusicMoreRow);
        }
        return containerBrowserItems.getChildCount();
    }

    private void updateGetMusicMoreRow() {
        updateGetMusicMoreRow(getMusicResultsForDisplay().size());
    }

    private void updateGetMusicMoreRow(int total) {
        if (!isSoulseekUiActive() || !isGetMusicUnifiedUi()) return;
        if (getMusicMoreRow != null && getMusicMoreRow.getParent() == containerBrowserItems) {
            containerBrowserItems.removeView(getMusicMoreRow);
            getMusicMoreRow = null;
        }
        if (getMusicEntryUiCount >= total || getMusicEntryUiCount >= getMusicVisibleCap()) {
            if (!getMusicSearchInProgress && getMusicEntryUiCount < total) {
                getMusicMoreRow = createListButton(getString(R.string.deezer_show_more, total - getMusicEntryUiCount));
                getMusicMoreRow.setOnClickListener(new View.OnClickListener() {
                    @Override public void onClick(View v) {
                        clickFeedback();
                        getMusicResultsVisibleCount += GET_MUSIC_PAGE_SIZE;
                        appendGetMusicResultRowsInner();
                    }
                });
                containerBrowserItems.addView(getMusicMoreRow);
            }
        }
    }

    private View makeGetMusicResultRow(final MusicSearchEntry e) {
        String title;
        String subtitle;
        if (e.isContainer()) {
            if (e.kind == MusicSearchEntry.RowKind.DEEZER_ARTIST) {
                title = getString(R.string.get_music_artist_row, e.containerLabel);
                subtitle = getString(R.string.get_music_artist_browse_hint);
            } else if (e.kind == MusicSearchEntry.RowKind.DEEZER_ALBUM) {
                title = GetMusicSearch.formatDeezerReleaseLabel(e.deezerRecordType, e.containerLabel);
                subtitle = e.children.isEmpty()
                        ? getString(R.string.get_music_album_browse_hint)
                        : getString(R.string.get_music_container_tracks, e.children.size());
            } else if (e.kind == MusicSearchEntry.RowKind.NAVIDROME_ALBUM
                    || e.kind == MusicSearchEntry.RowKind.PLEX_ALBUM
                    || e.kind == MusicSearchEntry.RowKind.JELLYFIN_ALBUM) {
                title = e.containerLabel != null ? e.containerLabel : "";
                subtitle = e.source == MusicSearchEntry.Source.PLEX
                        ? getString(R.string.get_music_source_plex)
                        : (e.source == MusicSearchEntry.Source.JELLYFIN
                        ? getString(R.string.get_music_source_jellyfin)
                        : getString(R.string.get_music_source_navidrome));
            } else {
                title = getString(R.string.get_music_folder_row, e.containerLabel);
                subtitle = getString(R.string.get_music_container_tracks, e.children.size());
            }
        } else if (e.source == MusicSearchEntry.Source.DEEZER && e.deezer != null) {
            title = e.deezer.title;
            subtitle = GetMusicSearch.formatDeezerSubtitle(e.deezer);
            String dur = DeezerClient.formatDuration(e.deezer.durationSec);
            if (!dur.isEmpty()) subtitle = subtitle.isEmpty() ? dur : subtitle + " · " + dur;
        } else if (e.reach != null) {
            title = GetMusicSearch.formatReachTitle(e.reach);
            subtitle = getString(R.string.get_music_from_user, e.reach.username);
            watchSoulseekPeer(e.reach.username);
        } else if (e.source == MusicSearchEntry.Source.NAVIDROME && e.navidromeSong != null) {
            title = e.navidromeSong.title != null ? e.navidromeSong.title : "";
            subtitle = getString(R.string.get_music_source_navidrome);
            if (e.navidromeSong.artist != null && !e.navidromeSong.artist.isEmpty()) {
                subtitle = e.navidromeSong.artist + " · " + subtitle;
            }
        } else if (e.source == MusicSearchEntry.Source.PLEX && e.plexSong != null) {
            title = e.plexSong.title != null ? e.plexSong.title : "";
            subtitle = getString(R.string.get_music_source_plex);
            if (e.plexSong.artist != null && !e.plexSong.artist.isEmpty()) {
                subtitle = e.plexSong.artist + " · " + subtitle;
            }
        } else if (e.source == MusicSearchEntry.Source.JELLYFIN && e.jellyfinSong != null) {
            title = e.jellyfinSong.title != null ? e.jellyfinSong.title : "";
            subtitle = getString(R.string.get_music_source_jellyfin);
            if (e.jellyfinSong.artist != null && !e.jellyfinSong.artist.isEmpty()) {
                subtitle = e.jellyfinSong.artist + " · " + subtitle;
            }
        } else {
            title = "";
            subtitle = "";
        }
        View.OnClickListener click = new View.OnClickListener() {
            @Override public void onClick(View v) {
                clickFeedback();
                if (!requireInternet(R.string.toast_internet_required)) return;
                if (e.isContainer()) openGetMusicContainer(e);
                else buildGetMusicActionUI(e);
            }
        };
        View row = createGetMusicListRow(title, subtitle, click);
        row.setTag(e);
        return row;
    }

    private void buildGetMusicActionUI(final MusicSearchEntry e) {
        getMusicActionEntry = e;
        if (e.source == MusicSearchEntry.Source.DEEZER && e.deezer != null) {
            getMusicEmbeddedInDeezer = true;
            if (deezerScreen != null) deezerScreen.buildActionUi(e.deezer);
            soulseekUiMode = SOULSEEK_UI_ACTION;
            return;
        }
        if (e.source == MusicSearchEntry.Source.NAVIDROME && e.navidromeSong != null) {
            if (!requireInternet(R.string.navidrome_wifi_required)) return;
            playNavidromeSongs(java.util.Collections.singletonList(e.navidromeSong), 0);
            return;
        }
        if (e.source == MusicSearchEntry.Source.PLEX && e.plexSong != null) {
            if (!requireInternet(R.string.plex_wifi_required)) return;
            playPlexSongs(java.util.Collections.singletonList(e.plexSong), 0);
            return;
        }
        if (e.source == MusicSearchEntry.Source.JELLYFIN && e.jellyfinSong != null) {
            if (!requireInternet(R.string.jellyfin_wifi_required)) return;
            playJellyfinSongs(java.util.Collections.singletonList(e.jellyfinSong), 0);
            return;
        }
        if (e.reach != null) {
            buildSoulseekActionUI(e.reach);
        }
    }

    private void mergeGetMusicReachResult(SoulseekClient.Result r) {
        if (!isGetMusicUnifiedUi()) return;
        String key = GetMusicSearch.reachResultKey(r);
        if (!getMusicReachKeys.add(key)) return;
        if (GetMusicSearch.reachMatchesDeezer(r, getMusicDeezerDedupeKeys)) return;
        getMusicEntries.add(MusicSearchEntry.reach(r));
    }

    private void flushGetMusicReachBatch(List<SoulseekClient.Result> batch) {
        if (!isGetMusicUnifiedUi() || batch == null) return;
        java.util.Set<String> history = SoulseekDownloadHistory.loadPeerSet(prefs);
        List<SoulseekClient.Result> reachOnly = new ArrayList<SoulseekClient.Result>();
        for (SoulseekClient.Result r : batch) {
            if (soulseekClient != null && soulseekClient.isPeerDenied(r.username)) continue;
            if (soulseekHideHighBitrate && r.isOverBitrateThreshold()) continue;
            reachOnly.add(r);
        }
        sortSoulseekResultsByQuality(reachOnly, soulseekLastQuery, history);
        for (SoulseekClient.Result r : reachOnly) {
            mergeGetMusicReachResult(r);
        }
        // ponytail: hold Reach rows until Deezer tracks land so catalog hits paint first.
        if (getMusicDeezerSearchActive() && !getMusicDeezerTracksReady) return;
        if (getMusicSearchInProgress) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("runId", "pre-fix");
                d.put("batch", batch.size());
                d.put("entries", getMusicEntries.size());
                d.put("uiCount", getMusicEntryUiCount);
                d.put("deezerReady", getMusicDeezerTracksReady);
                Debug701426Log.log(this, "MainActivity.flushGetMusicReachBatch",
                        "Reach batch forcing full rebuild", "B,E", d);
            } catch (Exception ignored) {}
            // #endregion
            refreshGetMusicResultsVisible(true);
        }
    }

    private void buildSoulseekSearchUI() {
        soulseekUiMode = SOULSEEK_UI_SEARCH;
        prepareSoulseekBrowserChrome();
        final boolean getMusic = isGetMusicUnifiedUi();
        browserStatusTitle = getMusic ? getMusicStatusTitle() : getString(R.string.status_soulseek);
        updateStatusBarTitle();
        if (getMusic) updateReachBrowserHintForGetMusic();
        else updateReachBrowserHint(R.string.reach_hint_search);
        containerBrowserItems.removeAllViews();

        Button back = createListButton(getString(R.string.common_back));
        back.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                returnFromSoulseek();
            }
        });
        containerBrowserItems.addView(back);

        if (!ConnectivityHelper.isOnline(this)) {
            if (containerBrowserItems.getChildCount() > 0) containerBrowserItems.getChildAt(0).requestFocus();
            return;
        }

        String typeLabel = getString(getMusic ? R.string.get_music_type_search : R.string.soulseek_type_search);
        Button typeSearch = createListButton(typeLabel);
        typeSearch.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                if (getMusic) openGetMusicSearchKeyboard();
                else openSoulseekSearchKeyboard();
            }
        });
        containerBrowserItems.addView(typeSearch);

        List<String> recent = getMusic
                ? GetMusicSearchHistory.load(prefs) : SoulseekSearchHistory.load(prefs);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("runId", "pre-fix");
            d.put("getMusic", getMusic);
            d.put("recentCount", recent != null ? recent.size() : -1);
            d.put("online", ConnectivityHelper.isOnline(this));
            DebugF0e28cLog.log(this, "MainActivity.buildSoulseekSearchUI",
                    "search landing built", "H-EMPTY", d);
        } catch (Exception ignored) {}
        // #endregion
        if (!recent.isEmpty()) {
            createBrowserSectionHeader(getString(
                    getMusic ? R.string.get_music_recent_searches : R.string.soulseek_recent_searches));
            for (final String q : recent) {
                Button b = createListButton(q);
                b.setTag(R.id.tag_soulseek_recent_query, q);
                b.setOnClickListener(new View.OnClickListener() {
                    @Override
                    public void onClick(View v) {
                        clickFeedback();
                        if (getMusic) openGetMusicSearchKeyboard(q);
                        else openSoulseekSearchKeyboard(q);
                    }
                });
                containerBrowserItems.addView(b);
            }
        }
        if (containerBrowserItems.getChildCount() > 0) containerBrowserItems.getChildAt(0).requestFocus();
    }

    private void finishSoulseekSearchEntry() {
        final String q = typedPassword.trim();
        final boolean getMusic = getMusicFromEntryPoint;
        if (getMusic) {
            openGetMusicScreen(true);
            if (q.length() > 0 && requireInternet(R.string.toast_internet_required)) {
                getMusicMode = GetMusicSources.resolveMode(prefs, soulseekActive(), deezerActive());
                fetchGetMusicResults(q);
            }
            return;
        }
        openSoulseekScreen(true);
        if (q.length() > 0 && requireInternet(R.string.soulseek_wifi_required)) {
            fetchSoulseekResults(q);
        }
    }

    private void fetchSoulseekResults(final String query) {
        if (query == null || query.trim().isEmpty()) return;
        if (!soulseekActive()) {
            Toast.makeText(this, getString(R.string.soulseek_reach_disabled), Toast.LENGTH_LONG).show();
            return;
        }
        if (!requireInternet(R.string.soulseek_wifi_required)) return;
        if (!requireReachPeerConnectivity()) return;
        soulseekLastQuery = query.trim();
        SoulseekSearchHistory.remember(prefs, soulseekLastQuery);
        soulseekSearchInProgress = true;
        syncStatusBarSearchThrobber();
        soulseekResultsVisibleCount = SOULSEEK_PAGE_SIZE;
        soulseekResults.clear();
        soulseekResultKeys.clear();
        soulseekOrganizedEntries.clear();
        soulseekBrowseContainer = null;
        synchronized (soulseekPendingUi) {
            soulseekPendingUi.clear();
        }
        soulseekUiHandler.removeCallbacks(soulseekUiFlushRunnable);
        soulseekUiFlushScheduled = false;
        buildSoulseekResultsShell();
        SoulseekClient client = ensureSoulseekClient();
        if (client == null) {
            soulseekSearchInProgress = false;
            syncStatusBarSearchThrobber();
            Toast.makeText(this, getString(R.string.soulseek_reach_disabled), Toast.LENGTH_LONG).show();
            return;
        }
        client.search(soulseekLastQuery);
    }

