    private void applyThemedPlayerModeIcon(ImageView iv, String iconKey, int fallbackResId) {
        android.graphics.Bitmap bmp = ThemeManager.getPlaybackModeIcon(iconKey);
        if (bmp != null) {
            iv.setImageBitmap(bmp);
            iv.clearColorFilter();
        } else {
            iv.setImageResource(fallbackResId);
            iv.clearColorFilter();
        }
    }
    private void updatePlayerUI() {
        // 2026-07-18 — First NP paint clears track-change status throbber.
        if (com.solar.launcher.ui.UiBusy.isBusy(com.solar.launcher.ui.UiBusy.REASON_TRACK_CHANGE)) {
            com.solar.launcher.ui.UiBusy.clear(com.solar.launcher.ui.UiBusy.REASON_TRACK_CHANGE);
        }
        try {
            if (playback.isRadioActive() && mediaSuite != null) {
                if (playback.isFmActive()) {
                    mediaSuite.ensureFmRdsPolling();
                    // 2026-07-15 — FM: light bind (skips unchanged text/art). Heavy status icons
                    // only when not mid-wheel (status indicators rebuild drawables).
                    mediaSuite.bindRadioNowPlayingUi();
                    if (mediaSuite.radioScrubMode
                            == com.solar.launcher.radio.RadioScrubMode.TUNE_FM) {
                        syncFmTuneScrubUi();
                    } else {
                        // Track count N/M rare for pure FM; skip status icon thrash on every call.
                        updateMusicTrackCountUi();
                    }
                    return;
                }
                mediaSuite.stopFmRdsPolling();
                mediaSuite.bindRadioNowPlayingUi();
                updateMusicTrackCountUi();
                updatePlayerStatusIndicators();
                updatePlaybackStatusIcon();
                return;
            }
            if (mediaSuite != null) {
                mediaSuite.stopFmRdsPolling();
            }
            if (playback.isPodcastActive() && podcastIjkPlayer != null) {
                boolean playing = false;
                try {
                    playing = podcastIjkPlayer.isPlaying();
                } catch (Exception ignored) {}
                if (playing) {
                    if (ivAlbumArt != null) ivAlbumArt.setAlpha(1.0f);
                    if (ivAlbumArt3d != null) ivAlbumArt3d.setAlpha(1.0f);
                    ivPauseOverlay.setVisibility(View.GONE);
                    progressHandler.post(updateProgressTask);
                    if (mediaSessionShim != null && android.os.Build.VERSION.SDK_INT >= 21) {
                        mediaSessionShim.getClass().getMethod("setPlaying", int.class)
                                .invoke(mediaSessionShim, podcastIjkPlayer.getCurrentPosition());
                    }
                } else {
                    if (ivAlbumArt != null) ivAlbumArt.setAlpha(0.4f);
                    if (ivAlbumArt3d != null) ivAlbumArt3d.setAlpha(0.4f);
                    ivPauseOverlay.setVisibility(View.VISIBLE);
                    progressHandler.removeCallbacks(updateProgressTask);
                    if (mediaSessionShim != null && android.os.Build.VERSION.SDK_INT >= 21) {
                        int pos = 0;
                        try {
                            pos = podcastIjkPlayer.getCurrentPosition();
                        } catch (Exception ignored) {}
                        mediaSessionShim.getClass().getMethod("setPaused", int.class).invoke(mediaSessionShim, pos);
                    }
                }
                updatePlayerStatusIndicators();
                updatePlaybackStatusIcon();
                if (npOverlay != null && npOverlay.isVisualizerShowing()) syncVisualizerMetadata();
                syncAvrcpTrackInfo(false);
                return;
            }
            if (isMusicIjkActive()) {
                boolean playing = false;
                try {
                    playing = musicIjkPlayer.isPlaying();
                } catch (Exception ignored) {}
                if (playing) {
                    if (ivAlbumArt != null) ivAlbumArt.setAlpha(1.0f);
                    if (ivAlbumArt3d != null) ivAlbumArt3d.setAlpha(1.0f);
                    ivPauseOverlay.setVisibility(View.GONE);
                    progressHandler.post(updateProgressTask);
                    if (mediaSessionShim != null && android.os.Build.VERSION.SDK_INT >= 21) {
                        mediaSessionShim.getClass().getMethod("setPlaying", int.class)
                                .invoke(mediaSessionShim, musicIjkPlayer.getCurrentPosition());
                    }
                } else {
                    if (ivAlbumArt != null) ivAlbumArt.setAlpha(0.4f);
                    if (ivAlbumArt3d != null) ivAlbumArt3d.setAlpha(0.4f);
                    ivPauseOverlay.setVisibility(View.VISIBLE);
                    progressHandler.removeCallbacks(updateProgressTask);
                    if (mediaSessionShim != null && android.os.Build.VERSION.SDK_INT >= 21) {
                        int pos = 0;
                        try {
                            pos = musicIjkPlayer.getCurrentPosition();
                        } catch (Exception ignored) {}
                        mediaSessionShim.getClass().getMethod("setPaused", int.class).invoke(mediaSessionShim, pos);
                    }
                }
                updatePlayerStatusIndicators();
                updatePlaybackStatusIcon();
                if (npOverlay != null && npOverlay.isVisualizerShowing()) syncVisualizerMetadata();
                syncAvrcpTrackInfo(false);
                return;
            }
            if (mediaPlayer != null && mediaPlayer.isPlaying()) {
                if (ivAlbumArt != null) ivAlbumArt.setAlpha(1.0f);
                if (ivAlbumArt3d != null) ivAlbumArt3d.setAlpha(1.0f);
                ivPauseOverlay.setVisibility(View.GONE);
                progressHandler.post(updateProgressTask);

                // 🚀 [스크린 오프 완벽 제어 3단계] 재생 상태(PLAYING)를 시스템에 신고하여 제어권 유지
                if (mediaSessionShim != null && android.os.Build.VERSION.SDK_INT >= 21) {
                    mediaSessionShim.getClass().getMethod("setPlaying", int.class)
                            .invoke(mediaSessionShim, mediaPlayer.getCurrentPosition());
                }
            } else {
                if (ivAlbumArt != null) ivAlbumArt.setAlpha(0.4f);
                if (ivAlbumArt3d != null) ivAlbumArt3d.setAlpha(0.4f);
                ivPauseOverlay.setVisibility(View.VISIBLE);
                progressHandler.removeCallbacks(updateProgressTask);

                // 일시정지 상태(PAUSED) 신고
                if (mediaSessionShim != null && android.os.Build.VERSION.SDK_INT >= 21) {
                    int pos = mediaPlayer == null ? 0 : mediaPlayer.getCurrentPosition();
                    mediaSessionShim.getClass().getMethod("setPaused", int.class).invoke(mediaSessionShim, pos);
                }
            }
            updatePlayerStatusIndicators();
            updatePlaybackStatusIcon();
            if (npOverlay != null && npOverlay.isVisualizerShowing()) syncVisualizerMetadata();
            syncAvrcpTrackInfo(false);
        } catch (Exception e) {
        }
    }

    /** Push title/artist/position to y1-track-info for Y1Bridge + AVRCP trampolines. */
    private void syncAvrcpTrackInfo(boolean trackChanged) {
        boolean podcastActive = playback.isPodcastActive() && podcastIjkPlayer != null;
        boolean playing = false;
        boolean hasPlayer = podcastActive || mediaPlayer != null;
        try {
            if (podcastActive) {
                playing = podcastIjkPlayer.isPlaying();
            } else if (mediaPlayer != null) {
                playing = mediaPlayer.isPlaying();
            }
        } catch (Exception ignored) {}
        if (!hasPlayer && !playback.hasAnyQueue()) return;
        try {
            String title = "";
            String artist = "";
            String album = "";
            // Match Now Playing screen text exactly (what the user expects on the TV).
            if (tvPlayerTitle != null) {
                title = stripReachProgressPrefix(String.valueOf(tvPlayerTitle.getText()));
            }
            if (tvPlayerArtist != null) {
                artist = String.valueOf(tvPlayerArtist.getText());
            }
            if (tvPlayerAlbum != null) {
                album = String.valueOf(tvPlayerAlbum.getText());
            }
            title = filterAvrcpDisplayField(title);
            artist = filterAvrcpDisplayField(artist);
            album = filterAvrcpDisplayField(album);
            PlayQueue.QueueItem cur = playback.currentItem();
            if (title.isEmpty()) {
                if (cur != null) {
                    if (cur.kind == PlayQueue.ItemKind.PODCAST_EPISODE && cur.episode != null) {
                        title = cur.episode.title != null ? cur.episode.title : "";
                        artist = cur.podcastShowTitle != null ? cur.podcastShowTitle : "";
                    } else if (cur.file != null) {
                        title = cur.streamMeta();
                        if (cur.kind == PlayQueue.ItemKind.REACH_STREAM
                                && cur.reachPeerUsername != null) {
                            artist = cur.reachPeerUsername;
                        }
                    }
                }
            }
            if (title.isEmpty()) title = "Unknown";
            int duration = 0;
            int position = 0;
            if (podcastActive) {
                try {
                    duration = podcastIjkPlayer.getDuration();
                    position = podcastIjkPlayer.getCurrentPosition();
                } catch (Exception ignored) {}
                if (duration <= 0) duration = playbackDurationForScrub();
            } else if (hasPlayer) {
                try {
                    duration = mediaPlayer.getDuration();
                    position = mediaPlayer.getCurrentPosition();
                } catch (Exception ignored) {}
            }
            if (!podcastActive && duration <= 0) duration = playbackDurationForScrub();

            try {
                com.solar.launcher.scrobble.ScrobbleManager.onPlaybackStateChange(this,
                        title, artist, album, duration, position, playing, trackChanged,
                        podcastActive, cur, mediaSuite != null && mediaSuite.isVideoPlaying());
            } catch (Exception ignored) {}

            if (avrcpTrackInfoWriter == null) return;
            if (connectedA2dpAddress != null) {
                kickY1BridgeMediaService();
            }
            avrcpTrackInfoWriter.syncFromPlayback(
                    title, artist, album, duration, position, playing, trackChanged);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("titleLen", title.length());
                d.put("artistLen", artist.length());
                d.put("duration", duration);
                d.put("playing", playing);
                d.put("a2dp", connectedA2dpAddress != null);
                d.put("trackChanged", trackChanged);
                DebugAgentLog.log(this, "MainActivity.syncAvrcpTrackInfo", "sync", "H-AV1", d);
            } catch (Exception ignored) {}
            // #endregion
        } catch (Exception ignored) {}
    }

  /** Drop loading/buffering placeholder copy — TVs reject empty-looking metadata. */
    private static String filterAvrcpDisplayField(String s) {
        if (s == null) return "";
        String t = s.trim();
        if (t.isEmpty() || "Loading...".equals(t) || "Loading…".equals(t)
                || "Buffering...".equals(t) || "Buffering…".equals(t) || "null".equalsIgnoreCase(t)) return "";
        if (t.startsWith("Corrupted")) return "";
        return t;
    }

    /** Start Koensayr Y1Bridge so mtkbt can bind MediaPlaybackService for AVRCP metadata. */
    private void kickY1BridgeMediaService() {
        try {
            Intent bridge = new Intent("com.android.music.MediaPlaybackService");
            bridge.setClassName("com.koensayr.y1.bridge", "com.koensayr.y1.bridge.MediaBridgeService");
            startService(bridge);
        } catch (Exception ignored) {}
    }

    /** adb: am start -n com.solar.launcher/.MainActivity --ez solar_adb_avrcp_harness true */
    private void scheduleAdbAvrcpHarnessIfRequested(Intent intent) {
        if (intent == null || !intent.getBooleanExtra("solar_adb_avrcp_harness", false)) return;
        final String btAddr = intent.getStringExtra("solar_adb_bt_addr");
        intent.removeExtra("solar_adb_avrcp_harness");
        intent.removeExtra("solar_adb_bt_addr");
        scheduleAdbAvrcpHarness(btAddr != null ? btAddr : "50:BA:02:58:D7:39");
    }

    private void handlePairingPinPromptIfRequested(Intent intent) {
        if (intent == null || !intent.getBooleanExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_PROMPT, false)) return;
        String address = intent.getStringExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_ADDRESS);
        String name = intent.getStringExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_NAME);
        intent.removeExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_PROMPT);
        intent.removeExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_ADDRESS);
        intent.removeExtra(BluetoothAudioRepair.EXTRA_PAIR_PIN_NAME);
        openBtPairingPinKeyboard(address, name);
    }

    private void finishAvrcpHarnessPlayback(String btAddr) {
        BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
        BluetoothDevice dev = ba != null ? ba.getRemoteDevice(btAddr) : null;
        boolean a2dp = dev != null && isBluetoothAudioConnected(dev);
        SolarAdbTest.avrcpHarness("a2dp", "connected=" + a2dp + " addr=" + connectedA2dpAddress);
        if (!a2dp) {
            SolarAdbTest.fail("a2dp_not_connected");
            return;
        }
        if (avrcpTrackInfoWriter != null) avrcpTrackInfoWriter.ensureReady();
        kickY1BridgeMediaService();
        if (!playback.hasAnyQueue()) {
            SolarAdbTest.fail("no_queue_play_music_first");
            return;
        }
        if (currentScreenState != STATE_PLAYER) {
            changeScreen(STATE_PLAYER);
        }
        boolean mpPlaying = false;
        try {
            mpPlaying = mediaPlayer != null && mediaPlayer.isPlaying();
        } catch (Exception ignored) {}
        if (!mpPlaying) {
            if (playback.musicPlaylist().isEmpty()) {
                SolarAdbTest.fail("music_playlist_empty");
                return;
            }
            isPausedByHand = false;
            routeAudioToBluetoothA2dp();
            prepareMusicTrack(playback.musicIndex());
            new Handler().postDelayed(new Runnable() {
                @Override public void run() {
                    verifyAvrcpHarnessPlayback();
                }
            }, 6000);
            return;
        }
        verifyAvrcpHarnessPlayback();
    }

    private void verifyAvrcpHarnessPlayback() {
        routeAudioToBluetoothA2dp();
        syncAvrcpTrackInfo(true);
        boolean playing = false;
        try {
            playing = mediaPlayer != null && mediaPlayer.isPlaying();
        } catch (Exception ignored) {}
        SolarAdbTest.avrcpHarness("playback", "playing=" + playing
                + " btName=" + (audioManager != null ? audioManager.getParameters("bluetooth_a2dp") : "null"));
        if (playing) {
            SolarAdbTest.pass("playing_a2dp_metadata_synced");
        } else {
            SolarAdbTest.fail("playback_not_started");
        }
    }

    private void scheduleAdbAvrcpHarness(final String btAddr) {
        SolarAdbTest.avrcpHarness("start", "addr=" + btAddr);
        new Handler().postDelayed(new Runnable() {
            @Override public void run() {
                applyBluetoothPowerState(true);
                ensureA2dpProfile();
                new Handler().postDelayed(new Runnable() {
                    @Override public void run() {
                        BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
                        if (ba == null || !ba.isEnabled()) {
                            SolarAdbTest.fail("bt_not_on");
                            return;
                        }
                        BluetoothDevice dev = ba.getRemoteDevice(btAddr);
                        connectBluetoothAudio(dev, true);
                        new Handler().postDelayed(new Runnable() {
                            @Override public void run() {
                                boolean a2dp = isBluetoothAudioConnected(dev);
                                if (!a2dp) {
                                    connectBluetoothAudio(dev, true);
                                    new Handler().postDelayed(new Runnable() {
                                        @Override public void run() {
                                            finishAvrcpHarnessPlayback(btAddr);
                                        }
                                    }, 8000);
                                    return;
                                }
                                finishAvrcpHarnessPlayback(btAddr);
                            }
                        }, 8000);
                    }
                }, 6000);
            }
        }, 2000);
    }

    /** Called from MediaSessionShim (API 21+) for screen-off transport keys. */
    public boolean handleMediaSessionKey(int keyCode) {
        if (!isScreenOffControlEnabled) return false;
        if (DeviceFeatures.isY1()) {
            if (Y1InputKeys.isVolumeDownKey(keyCode)) { adjustVolume(false); clickFeedback(); return true; }
            if (Y1InputKeys.isVolumeUpKey(keyCode)) { adjustVolume(true); clickFeedback(); return true; }
        }
        // ponytail: Y1 wheel shares 126/127 with AVRCP — consume here so MediaSession does not play/pause.
        if (Y1InputKeys.isWheelKey(keyCode)) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("keyCode", keyCode);
                DebugSessionLog.log("MainActivity.handleMediaSessionKey", "wheel consumed screen off", "H-SOFF1", d);
            } catch (Exception ignored) {}
            // #endregion
            return true;
        }
        if (isMediaPrevKey(keyCode) || isMediaNextKey(keyCode)) {
            return false; // ponytail: side prev/next while screen off — let system handle if needed
        }
        if (keyCode == KeyEvent.KEYCODE_MEDIA_PLAY_PAUSE || keyCode == 85 || keyCode == 86) {
            playOrPauseMusic(); clickFeedback(); return true;
        }
        return false;
    }

    private void playOrPauseMusic() {
        try {
            if (playback.isRadioActive() && mediaSuite != null) {
                mediaSuite.toggleRadioPlayPause();
                clickFeedback();
                return;
            }
            if (currentScreenState == MediaSuiteHost.STATE_VIDEO_PLAYER && mediaSuite != null) {
                mediaSuite.toggleVideoPlayPause();
                clickFeedback();
                return;
            }
            // #region agent log
            boolean mpNull = mediaPlayer == null;
            boolean musicEmpty = !playback.isPodcastActive() && !hasMusicPlaybackQueue();
            boolean podEmpty = playback.isPodcastActive() && playback.podcastQueue().isEmpty();
            boolean playing = !mpNull && mediaPlayer.isPlaying();
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("mpNull", mpNull);
                d.put("musicEmpty", musicEmpty);
                d.put("podEmpty", podEmpty);
                d.put("wasPlaying", playing);
                d.put("uiBusy", com.solar.launcher.ui.UiBusy.isBusy());
                d.put("contextMenu", themedContextMenu != null && themedContextMenu.isShowing());
                d.put("queueTier", contextMenuInQueueTier);
                Debug0f5debLog.log(this, "MainActivity.playOrPauseMusic",
                        "playOrPause no UiBusy arm", "H4", d);
            } catch (Exception ignored) {}
            // #endregion
            if (!playback.isPodcastActive() && !hasMusicPlaybackQueue()) return;
            if (playback.isPodcastActive() && playback.podcastQueue().isEmpty()) return;
            if (playback.isPodcastActive()) {
                if (podcastIjkPlayer == null) {
                    isPausedByHand = false;
                    preparePodcastEpisode(playback.podcastIndex());
                    return;
                }
                if (podcastIjkPlayer.isPlaying()) {
                    podcastIjkPlayer.pause();
                    isPausedByHand = true;
                    flushPodcastResumeIfNeeded();
                } else {
                    podcastIjkPlayer.start();
                    applyPlaybackSpeed();
                    isPausedByHand = false;
                    if (connectedA2dpAddress != null) {
                        routeAudioToBluetoothA2dp();
                    }
                }
                updatePlayerUI();
                return;
            }
            // 2026-07-15 — Music IJK (software EQ) play/pause.
            if (isMusicIjkActive()) {
                if (musicIjkPlayer.isPlaying()) {
                    saveAudiobookBookmarkIfNeeded();
                    musicIjkPlayer.pause();
                    isPausedByHand = true;
                } else {
                    musicIjkPlayer.start();
                    isPausedByHand = false;
                    if (connectedA2dpAddress != null) {
                        routeAudioToBluetoothA2dp();
                    }
                }
                updatePlayerUI();
                return;
            }
            if (mediaPlayer == null) {
                isPausedByHand = false;
                prepareMusicTrack(playback.musicIndex());
                return;
            }
            if (mediaPlayer.isPlaying()) {
                saveAudiobookBookmarkIfNeeded();
                mediaPlayer.pause();
                isPausedByHand = true;
                flushPodcastResumeIfNeeded();
            } else {
                mediaPlayer.start();
                applyPlaybackSpeed();
                isPausedByHand = false;
                if (connectedA2dpAddress != null) {
                    routeAudioToBluetoothA2dp();
                }
            }
            updatePlayerUI();
        } catch (Throwable e) {
        }
    }
    private void nextTrack() {
        lastTrackChangeTime = System.currentTimeMillis();
        saveAudiobookBookmarkIfNeeded();
        if (avrcpTrackInfoWriter != null) avrcpTrackInfoWriter.markTrackChange();
        finalizeReachStreamHandoff();
        int next = playback.nextIndex(repeatMode > 0);
        if (next < 0) {
            if (deezerPlaylistPlayback != null && deezerPlaylistPlaybackIndex >= 0
                    && deezerPlaylistPlaybackIndex + 1 < deezerPlaylistPlayback.size()) {
                advanceDeezerPlaylistIfNeeded();
                return;
            }
            if (repeatMode == 0) {
                try {
                    if (mediaPlayer != null && mediaPlayer.isPlaying()) {
                        mediaPlayer.pause();
                        isPausedByHand = true;
                        updatePlayerUI();
                    }
                } catch (Exception ignored) {}
                persistPlaybackQueue();
            }
            return;
        }
        playback.setQueueIndex(next);
        PlayQueue.QueueItem item = playback.currentItem();
        if (item == null) return;
        if (item.kind == PlayQueue.ItemKind.PODCAST_EPISODE) {
            preparePodcastEpisode(playback.podcastIndex());
        } else {
            prepareMusicTrack(playback.musicIndex());
            updateMusicTrackCountUi();
        }
        persistPlaybackQueue();
        refreshContextQueueTierIfOpen();
    }

    private void prevTrack() {
        lastTrackChangeTime = System.currentTimeMillis();
        if (avrcpTrackInfoWriter != null) avrcpTrackInfoWriter.markTrackChange();
        finalizeReachStreamHandoff();
        int prev = playback.prevIndex(repeatMode > 0);
        if (prev < 0) return;
        playback.setQueueIndex(prev);
        PlayQueue.QueueItem item = playback.currentItem();
        if (item == null) return;
        if (item.kind == PlayQueue.ItemKind.PODCAST_EPISODE) {
            preparePodcastEpisode(playback.podcastIndex());
        } else {
            prepareMusicTrack(playback.musicIndex());
            updateMusicTrackCountUi();
        }
        persistPlaybackQueue();
        refreshContextQueueTierIfOpen();
    }

    private boolean isScreenOff() {
        try {
            PowerManager pm = (PowerManager) getSystemService(Context.POWER_SERVICE);
            if (android.os.Build.VERSION.SDK_INT >= 20) {
                return !pm.isInteractive();
            } else {
                return !pm.isScreenOn();
            }
        } catch (Exception e) {
            return false;
        }
    }

